import React, { useState } from 'react';
import { Product, OrderItem, Order } from '../types';
import { Search, ShoppingCart, Trash2, CheckCircle } from 'lucide-react';

interface POSProps {
  products: Product[];
  onPlaceOrder: (order: Partial<Order>) => void;
}

const POS: React.FC<POSProps> = ({ products, onPlaceOrder }) => {
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('Todos');

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(search.toLowerCase()) && 
    (filter === 'Todos' || p.category === filter)
  );

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        return prev.map(item => 
          item.productId === product.id 
            ? { ...item, quantity: item.quantity + 1 } 
            : item
        );
      }
      return [...prev, { 
        productId: product.id, 
        name: product.name, 
        price: product.price, 
        quantity: 1 
      }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.productId !== productId));
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const handleFinish = () => {
    if (cart.length === 0) return;
    onPlaceOrder({
      items: cart,
      total,
      type: 'takeout',
      status: 'pending',
    });
    setCart([]);
    alert("Venda realizada com sucesso!");
  };

  return (
    <div className="flex h-[calc(100vh-2rem)] gap-6">
      {/* Products Grid */}
      <div className="flex-1 flex flex-col gap-4 overflow-hidden">
        <div className="flex gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar produto..."
              className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <select 
            className="border rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-indigo-500"
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          >
            <option>Todos</option>
            {Array.from(new Set(products.map(p => p.category))).map(cat => (
              <option key={cat}>{cat}</option>
            ))}
          </select>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 pr-2">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              className="bg-white p-4 rounded-2xl border hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col gap-2 group"
            >
              <img src={product.image} className="w-full h-32 object-cover rounded-xl mb-2" alt={product.name} />
              <h3 className="font-semibold text-slate-800 line-clamp-1">{product.name}</h3>
              <p className="text-indigo-600 font-bold">R$ {product.price.toFixed(2)}</p>
              <p className="text-xs text-slate-400">Estoque: {product.stock}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-96 bg-white border rounded-2xl flex flex-col overflow-hidden shadow-sm">
        <div className="p-6 border-b flex items-center justify-between">
          <h2 className="text-lg font-bold flex items-center gap-2">
            <ShoppingCart size={20} className="text-indigo-600" />
            Venda Atual
          </h2>
          <span className="bg-indigo-100 text-indigo-700 text-xs px-2 py-1 rounded-full font-bold">
            {cart.length} itens
          </span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 text-sm gap-2">
              <ShoppingCart size={48} strokeWidth={1} />
              <p>Carrinho vazio</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex justify-between items-start group">
                <div className="flex-1">
                  <p className="font-medium text-slate-800">{item.name}</p>
                  <p className="text-sm text-slate-500">{item.quantity}x R$ {item.price.toFixed(2)}</p>
                </div>
                <div className="flex items-center gap-3">
                  <p className="font-bold text-slate-700">R$ {(item.price * item.quantity).toFixed(2)}</p>
                  <button 
                    onClick={() => removeFromCart(item.productId)}
                    className="p-1 text-slate-300 hover:text-red-500 transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 border-t bg-slate-50 space-y-4">
          <div className="flex justify-between items-center text-xl font-bold">
            <span>Total</span>
            <span className="text-indigo-600">R$ {total.toFixed(2)}</span>
          </div>
          <button 
            disabled={cart.length === 0}
            onClick={handleFinish}
            className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 disabled:bg-slate-300 disabled:cursor-not-allowed"
          >
            <CheckCircle size={20} />
            Finalizar Pedido (F12)
          </button>
        </div>
      </div>
    </div>
  );
};

export default POS;

import React from 'react';
import { Table, Order } from '../types';
import { Users, CreditCard, Utensils } from 'lucide-react';

interface TablesProps {
  tables: Table[];
  orders: Order[];
}

const Tables: React.FC<TablesProps> = ({ tables, orders }) => {
  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const getTableIcon = (status: Table['status']) => {
    switch (status) {
      case 'available': return <Utensils size={24} />;
      case 'occupied': return <Users size={24} />;
      case 'billing': return <CreditCard size={24} />;
      default: return <Utensils size={24} />;
    }
  };

  return (
    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
      {tables.map(table => (
        <button
          key={table.id}
          className={`aspect-square p-6 rounded-3xl border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-lg ${getTableStatusColor(table.status)}`}
        >
          <div className="text-current">{getTableIcon(table.status)}</div>
          <div className="text-center">
            <h3 className="text-2xl font-black">Mesa {table.id}</h3>
            <p className="text-xs uppercase font-bold opacity-75">{table.status}</p>
          </div>
          {table.status === 'occupied' && (
            <div className="mt-2 text-sm font-bold bg-white/50 px-3 py-1 rounded-full">
              R$ 142,50
            </div>
          )}
        </button>
      ))}
    </div>
  );
};

export default Tables;

import React from 'react';
import { Order } from '../types';
import { Clock, Check } from 'lucide-react';

interface KDSProps {
  orders: Order[];
  onUpdateStatus: (id: string, status: Order['status']) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, onUpdateStatus }) => {
  const activeOrders = orders.filter(o => ['pending', 'preparing'].includes(o.status));

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
      {activeOrders.map(order => (
        <div key={order.id} className="bg-white border-2 border-slate-200 rounded-2xl flex flex-col shadow-sm overflow-hidden">
          <div className={`p-4 flex justify-between items-center ${order.status === 'pending' ? 'bg-red-50 text-red-700' : 'bg-amber-50 text-amber-700'}`}>
            <div className="flex items-center gap-2">
              <span className="font-black text-xl">#{order.id.slice(-4)}</span>
              <span className="text-xs font-bold uppercase tracking-wider">{order.type}</span>
            </div>
            <div className="flex items-center gap-1 font-bold text-sm">
              <Clock size={16} />
              12m
            </div>
          </div>

          <div className="flex-1 p-4 space-y-3">
            {order.items.map((item, idx) => (
              <div key={idx} className="flex gap-3">
                <span className="bg-slate-100 text-slate-700 font-bold px-2 py-1 rounded text-sm min-w-[2rem] text-center">
                  {item.quantity}
                </span>
                <span className="font-semibold text-slate-800">{item.name}</span>
              </div>
            ))}
          </div>

          <div className="p-4 border-t bg-slate-50 flex gap-2">
            {order.status === 'pending' ? (
              <button 
                onClick={() => onUpdateStatus(order.id, 'preparing')}
                className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors"
              >
                Começar
