            ) : (
              <button 
                onClick={() => onUpdateStatus(order.id, 'ready')}
                className="flex-1 bg-emerald-600 text-white py-3 rounded-xl font-bold hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2"
              >
                <Check size={20} />
                Pronto
              </button>
            )}
          </div>
