import React, { useState } from 'react';
import { User, UserRole, AuditLog, Permission } from '../types';
import { ROLE_DEFAULT_PERMISSIONS } from '../constants';
import { 
  UserPlus, Shield, Mail, MoreVertical, ShieldCheck, UserCog, 
  ChefHat, Wallet, Utensils, History, Users, Search, Activity,
  X, Check, Lock
} from 'lucide-react';

interface UsersPanelProps {
  users: User[];
  auditLogs: AuditLog[];
  onAddUser: (user: Partial<User>) => void;
  onUpdateRole: (id: string, role: UserRole) => void;
}

const ALL_PERMISSIONS: { id: Permission; label: string; group: string; description: string }[] = [
  { id: 'dashboard_view', label: 'Painel AI', group: 'Gestão', description: 'Visualiza insights estratégicos e métricas' },
  { id: 'cmv_analysis', label: 'Análise CMV', group: 'Gestão', description: 'Acesso às recomendações de custo e lucro' },
  { id: 'finance_view', label: 'Financeiro', group: 'Administrativo', description: 'Visualiza contas e balanço financeiro' },
  { id: 'users_manage', label: 'Equipe', group: 'Administrativo', description: 'Gerencia membros e permissões' },
  { id: 'pos_access', label: 'Acesso PDV', group: 'Operacional', description: 'Realiza vendas no caixa' },
  { id: 'tables_manage', label: 'Mesas', group: 'Operacional', description: 'Abre e fecha mesas de atendimento' },
  { id: 'kds_view', label: 'Cozinha (KDS)', group: 'Operacional', description: 'Monitora pedidos na cozinha' },
  { id: 'delivery_manage', label: 'Entregas', group: 'Operacional', description: 'Gerencia motoboys e entregas' },
  { id: 'inventory_edit', label: 'Estoque', group: 'Operacional', description: 'Altera quantidades e custos de produtos' },
];

const UsersPanel: React.FC<UsersPanelProps> = ({ users, auditLogs, onAddUser, onUpdateRole }) => {
  const [activeSubTab, setActiveSubTab] = useState<'team' | 'audit'>('team');
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);

  // Modal states
  const [newName, setNewName] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [newRole, setNewRole] = useState<UserRole>('WAITER');
  const [newPermissions, setNewPermissions] = useState<Permission[]>(ROLE_DEFAULT_PERMISSIONS.WAITER);

  const getRoleIcon = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return <ShieldCheck className="text-indigo-600" size={18} />;
      case 'MANAGER': return <UserCog className="text-amber-600" size={18} />;
      case 'CHEF': return <ChefHat className="text-rose-600" size={18} />;
      case 'CASHIER': return <Wallet className="text-emerald-600" size={18} />;
      case 'WAITER': return <Utensils className="text-blue-600" size={18} />;
    }
  };

  const getRoleBadgeClass = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return 'bg-indigo-50 text-indigo-700 border-indigo-100';
      case 'MANAGER': return 'bg-amber-50 text-amber-700 border-amber-100';
      case 'CHEF': return 'bg-rose-50 text-rose-700 border-rose-100';
      case 'CASHIER': return 'bg-emerald-50 text-emerald-700 border-emerald-100';
      case 'WAITER': return 'bg-blue-50 text-blue-700 border-blue-100';
    }
  };

  const getActionBadgeClass = (action: string) => {
    switch (action) {
      case 'VENDA': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'LOGIN': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'ESTOQUE': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'ADMIN': return 'bg-rose-50 text-rose-700 border-rose-200';
      default: return 'bg-slate-50 text-slate-700 border-slate-200';
    }
  };

  const handleRoleChange = (role: UserRole) => {
    setNewRole(role);
    setNewPermissions(ROLE_DEFAULT_PERMISSIONS[role] || []);
  };

  const togglePermission = (id: Permission) => {
    setNewPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSave = () => {
    if (!newName || !newEmail) return;
    onAddUser({
      name: newName,
      email: newEmail,
      role: newRole,
      permissions: newPermissions
    });
    setShowModal(false);
    resetForm();
  };

  const resetForm = () => {
    setNewName('');
    setNewEmail('');
    setNewRole('WAITER');
    setNewPermissions(ROLE_DEFAULT_PERMISSIONS.WAITER);
  };

  const filteredLogs = auditLogs.filter(log => 
    log.userName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.action.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
          <button 
            onClick={() => setActiveSubTab('team')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'team' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Users size={18} />
            Equipe
          </button>
          <button 
            onClick={() => setActiveSubTab('audit')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'audit' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <History size={18} />
            Auditoria
          </button>
        </div>

        {activeSubTab === 'team' ? (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
          >
            <UserPlus size={20} />
            Configurar Acesso
          </button>
        ) : (
          <div className="relative w-full md:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Filtrar logs..." 
              className="w-full pl-10 pr-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        )}
      </div>

      {activeSubTab === 'team' ? (
        <>
          <div className="bg-white rounded-3xl border shadow-sm overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Função / Nível</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Permissões Ativas</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Status</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {users.map(user => (
                  <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500 border">
                          {user.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-bold text-slate-800">{user.name}</p>
                          <p className="text-xs text-slate-400 flex items-center gap-1">
                            <Mail size={12} /> {user.email}
                          </p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-bold ${getRoleBadgeClass(user.role)}`}>
                        {getRoleIcon(user.role)}
                        {user.role}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-wrap gap-1 max-w-[200px]">
                        {user.permissions.slice(0, 3).map(p => (
                          <span key={p} className="text-[10px] bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded font-medium">
                            {ALL_PERMISSIONS.find(ap => ap.id === p)?.label}
                          </span>
                        ))}
                        {user.permissions.length > 3 && (
                          <span className="text-[10px] text-slate-400 font-bold">+{user.permissions.length - 3}</span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <span className={`w-2 h-2 rounded-full ${user.status === 'online' ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></span>
                        <span className="text-sm text-slate-600 capitalize">{user.status}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-600 transition-colors">
                        <MoreVertical size={18} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      ) : (
        /* Auditoria content remains the same... */
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-2">
              <Activity className="text-indigo-600" size={20} />
              <h3 className="font-bold text-slate-800">Log de Atividades do Sistema</h3>
            </div>
            <p className="text-xs text-slate-500 font-medium">Exibindo os últimos {filteredLogs.length} eventos</p>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Horário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Ação</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Descrição</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredLogs.map(log => (
                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <p className="text-sm font-medium text-slate-800">
                        {log.timestamp.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </p>
                      <p className="text-xs text-slate-400">
                        {log.timestamp.toLocaleDateString('pt-BR')}
                      </p>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center font-bold text-xs text-slate-500 border">
                          {log.userName.charAt(0)}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-slate-800">{log.userName}</p>
                          <p className="text-[10px] uppercase font-black text-slate-400 tracking-tighter">{log.userRole}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-md border text-[10px] font-black tracking-wider uppercase ${getActionBadgeClass(log.action)}`}>
                        {log.action}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <p className="text-sm text-slate-600 font-medium">{log.description}</p>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal de Cadastro Granular */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-2 rounded-xl text-white">
                  <UserPlus size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Configurar Novo Acesso</h2>
                  <p className="text-xs text-slate-500 font-medium">Defina os privilégios exatos do membro da equipe.</p>
                </div>
              </div>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white rounded-full transition-colors text-slate-400">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {/* Basic Info Section */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase text-slate-500 tracking-wider">Nome Completo</label>
                  <input 
                    type="text" 
                    placeholder="Ex: Carlos Alberto"
                    className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    value={newName}
                    onChange={(e) => setNewName(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase text-slate-500 tracking-wider">E-mail Profissional</label>
                  <input 
                    type="email" 
                    placeholder="carlos@seunegocio.com"
                    className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    value={newEmail}
                    onChange={(e) => setNewEmail(e.target.value)}
                  />
                </div>
              </div>

              {/* Role Presets */}
              <div className="space-y-4">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2">
                  <Shield size={14} className="text-indigo-600" /> Cargo Sugerido (Preset de Permissões)
                </label>
                <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
                  {(['WAITER', 'CASHIER', 'CHEF', 'MANAGER', 'ADMIN'] as UserRole[]).map(role => (
                    <button
                      key={role}
                      onClick={() => handleRoleChange(role)}
                      className={`px-3 py-3 rounded-xl border-2 transition-all text-xs font-bold flex flex-col items-center gap-2 ${
                        newRole === role 
                        ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100' 
                        : 'bg-white border-slate-100 text-slate-500 hover:border-indigo-200'
                      }`}
                    >
                      <span className="opacity-80">{getRoleIcon(role)}</span>
                      {role}
                    </button>
                  ))}
                </div>
              </div>

              {/* Granular Permissions Section */}
              <div className="space-y-4">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2">
                  <Lock size={14} className="text-indigo-600" /> Permissões Individuais
                </label>

                <div className="space-y-6">
                  {['Gestão', 'Administrativo', 'Operacional'].map(group => (
                    <div key={group} className="space-y-3">
                      <h4 className="text-[10px] font-black uppercase text-slate-400 border-b pb-1">{group}</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {ALL_PERMISSIONS.filter(p => p.group === group).map(perm => (
                          <button
                            key={perm.id}
                            onClick={() => togglePermission(perm.id)}
                            className={`flex items-start gap-4 p-3 rounded-2xl border-2 transition-all text-left group ${
                              newPermissions.includes(perm.id)
                              ? 'border-emerald-500 bg-emerald-50/30'
                              : 'border-slate-50 hover:border-slate-200 bg-slate-50/50'
                            }`}
                          >
                            <div className={`mt-0.5 w-5 h-5 rounded flex items-center justify-center transition-colors ${
                              newPermissions.includes(perm.id) ? 'bg-emerald-500 text-white' : 'bg-white border-2 border-slate-200'
                            }`}>
                              {newPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}
                            </div>
                            <div>
                              <p className={`text-sm font-bold ${newPermissions.includes(perm.id) ? 'text-emerald-900' : 'text-slate-700'}`}>
                                {perm.label}
                              </p>
                              <p className="text-[10px] text-slate-500 font-medium leading-tight">
                                {perm.description}
                              </p>
                            </div>
                          </button>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-6 border-t bg-slate-50 flex gap-4 justify-end">
              <button 
                onClick={() => setShowModal(false)}
                className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-white transition-colors border border-transparent hover:border-slate-200"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSave}
                disabled={!newName || !newEmail}
                className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Criar Acesso
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersPanel;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import POS from './components/POS';
import Tables from './components/Tables';
import KDS from './components/KDS';
import AIInsights from './components/AIInsights';
import UsersPanel from './components/UsersPanel';
import { 
  INITIAL_PRODUCTS, 
  INITIAL_TABLES, 
  INITIAL_COURIERS,
  INITIAL_USERS,
  INITIAL_AUDIT_LOGS,
  ROLE_DEFAULT_PERMISSIONS as INITIAL_ROLE_PERMISSIONS
} from './constants';
import { Product, Table, Order, Courier, FinancialRecord, User, UserRole, AuditLog, Permission } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Plus, Download, Filter } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    addLog('u3', 'KDS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado como ${newUser.role}`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    const oldUser = users.find(u => u.id === id);
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
    addLog('u1', 'ADMIN', `Cargo de ${oldUser?.name} alterado de ${oldUser?.role} para ${role}`);
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
    addLog('u1', 'ADMIN', `Permissões do cargo ${role} foram atualizadas.`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 bg-white p-6 rounded-3xl border shadow-sm">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-bold">Vendas Recentes</h3>
                  <div className="flex gap-2">
                    <button className="p-2 hover:bg-slate-50 rounded-lg"><Filter size={20} /></button>
                    <button className="p-2 hover:bg-slate-50 rounded-lg"><Download size={20} /></button>
                  </div>
                </div>
                <div className="h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[
                      { name: 'Seg', sales: 4000 },
                      { name: 'Ter', sales: 3000 },
                      { name: 'Qua', sales: 2000 },
                      { name: 'Qui', sales: 2780 },
                      { name: 'Sex', sales: 1890 },
                      { name: 'Sáb', sales: 2390 },
                      { name: 'Dom', sales: 3490 },
                    ]}>
                      <defs>
                        <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                          <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} />
                      <YAxis axisLine={false} tickLine={false} />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col">
                <h3 className="text-xl font-bold mb-6">Top Pratos</h3>
                <div className="flex-1 space-y-6">
                  {products.slice(0, 4).map((p, i) => (
                    <div key={p.id} className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-100 rounded-xl flex items-center justify-center font-bold text-slate-500">
                        #{i + 1}
                      </div>
                      <div className="flex-1">
                        <p className="font-semibold text-slate-800">{p.name}</p>
                        <p className="text-xs text-slate-500">{Math.floor(Math.random() * 100)} vendidos este mês</p>
                      </div>
                      <div className="text-indigo-600 font-bold">
                        R$ {p.price}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        );
      case 'pos':
        return <POS products={products} onPlaceOrder={handlePlaceOrder} />;
      case 'tables':
        return <Tables tables={tables} orders={orders} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'delivery':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-bold">Gestão de Entregas</h2>
              <button className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold flex items-center gap-2">
                <Plus size={20} /> Novo Motoboy
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {couriers.map(courier => (
                <div key={courier.id} className="bg-white border p-6 rounded-2xl shadow-sm">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="text-lg font-bold">{courier.name}</h3>
                      <p className="text-slate-500 text-sm">{courier.phone}</p>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                      courier.status === 'available' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                    }`}>
                      {courier.status}
                    </span>
                  </div>
                  <div className="border-t pt-4">
                    <p className="text-sm font-bold text-slate-700 mb-2">Pedidos Atuais:</p>
                    <div className="space-y-2">
                      <p className="text-sm text-slate-500 italic">Nenhuma entrega em curso.</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'inventory':
        return (
          <div className="bg-white rounded-3xl border shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center">
              <h2 className="text-xl font-bold">Estoque de Produtos</h2>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-bold">Exportar CSV</button>
            </div>
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Produto</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Categoria</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Custo</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Preço Venda</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Qtd. Estoque</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {products.map(product => (
                  <tr key={product.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-semibold">{product.name}</td>
                    <td className="px-6 py-4 text-slate-500">{product.category}</td>
                    <td className="px-6 py-4">R$ {product.cost.toFixed(2)}</td>
                    <td className="px-6 py-4">R$ {product.price.toFixed(2)}</td>
                    <td className="px-6 py-4 font-mono font-bold">{product.stock}</td>
                    <td className="px-6 py-4">
                      {product.stock < 15 ? (
                        <span className="bg-red-100 text-red-600 px-2 py-1 rounded-full text-xs font-bold">Crítico</span>
                      ) : (
                        <span className="bg-emerald-100 text-emerald-600 px-2 py-1 rounded-full text-xs font-bold">OK</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      case 'ai-cmv':
        return (
          <div className="space-y-6">
            <div className="bg-indigo-900 text-white p-8 rounded-3xl">
              <h2 className="text-2xl font-bold mb-2">Otimização de CMV com IA</h2>
              <p className="text-indigo-200">Nossa IA analisa constantemente seus custos vs preços de mercado para sugerir margens ideais.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {products.slice(0, 4).map(p => {
                const cmv = (p.cost / p.price) * 100;
                return (
                  <div key={p.id} className="bg-white border-2 border-slate-100 p-6 rounded-2xl">
                    <div className="flex justify-between items-start mb-4">
                      <h3 className="font-bold text-lg">{p.name}</h3>
                      <div className={`px-3 py-1 rounded-lg font-bold ${cmv > 35 ? 'bg-rose-100 text-rose-700' : 'bg-emerald-100 text-emerald-700'}`}>
                        CMV: {cmv.toFixed(1)}%
                      </div>
                    </div>
                    <div className="space-y-3">
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-500">Custo Atual:</span>
                        <span className="font-bold text-slate-700">R$ {p.cost.toFixed(2)}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-500">Preço Venda:</span>
                        <span className="font-bold text-slate-700">R$ {p.price.toFixed(2)}</span>
                      </div>
                      <div className="pt-4 border-t mt-4">
                        <p className="text-xs font-bold text-indigo-600 uppercase mb-2">Sugestão da IA:</p>
                        <p className="text-sm text-slate-600 italic">"O custo da proteína subiu 12%. Recomendamos ajustar o preço para R$ {(p.price * 1.08).toFixed(2)} para manter a margem de 30%."</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">Unidade Centro - São Paulo</h2>
            <h1 className="text-3xl font-black text-slate-800 text-capitalize">
              {activeTab === 'dashboard' ? 'Bem-vindo, Gestor' : 
               activeTab === 'pos' ? 'Caixa Operacional' : 
               activeTab === 'users' ? 'Gestão de Equipe' :
               activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="font-bold text-slate-800">Cozinha: Aberta</p>
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Sincronizado
              </p>
            </div>
            <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-black border-2 border-indigo-200">
              JS
            </div>
          </div>
        </header>

        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, UserRole, AuditLog, Permission } from '../types';
import { 
  UserPlus, Shield, Mail, MoreVertical, ShieldCheck, UserCog, 
  ChefHat, Wallet, Utensils, History, Users, Search, Activity,
  X, Check, Lock, Settings2, Edit3, Briefcase
} from 'lucide-react';

interface UsersPanelProps {
  users: User[];
  auditLogs: AuditLog[];
  rolePermissions: Record<UserRole, Permission[]>;
  onAddUser: (user: Partial<User>) => void;
  onUpdateRole: (id: string, role: UserRole) => void;
  onUpdateRolePermissions: (role: UserRole, permissions: Permission[]) => void;
}

const ALL_PERMISSIONS: { id: Permission; label: string; group: string; description: string }[] = [
  { id: 'dashboard_view', label: 'Painel AI', group: 'Gestão', description: 'Visualiza insights estratégicos e métricas' },
  { id: 'cmv_analysis', label: 'Análise CMV', group: 'Gestão', description: 'Acesso às recomendações de custo e lucro' },
  { id: 'finance_view', label: 'Financeiro', group: 'Administrativo', description: 'Visualiza contas e balanço financeiro' },
  { id: 'users_manage', label: 'Equipe', group: 'Administrativo', description: 'Gerencia membros e permissões' },
  { id: 'pos_access', label: 'Acesso PDV', group: 'Operacional', description: 'Realiza vendas no caixa' },
  { id: 'tables_manage', label: 'Mesas', group: 'Operacional', description: 'Abre e fecha mesas de atendimento' },
  { id: 'kds_view', label: 'Cozinha (KDS)', group: 'Operacional', description: 'Monitora pedidos na cozinha' },
  { id: 'delivery_manage', label: 'Entregas', group: 'Operacional', description: 'Gerencia motoboys e entregas' },
  { id: 'inventory_edit', label: 'Estoque', group: 'Operacional', description: 'Altera quantidades e custos de produtos' },
];

const UsersPanel: React.FC<UsersPanelProps> = ({ 
  users, 
  auditLogs, 
  rolePermissions, 
  onAddUser, 
  onUpdateRole, 
  onUpdateRolePermissions 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'team' | 'roles' | 'audit'>('team');
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingRole, setEditingRole] = useState<UserRole | null>(null);

  // Modal states for adding user
  const [newName, setNewName] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [newRole, setNewRole] = useState<UserRole>('WAITER');
  const [newPermissions, setNewPermissions] = useState<Permission[]>(rolePermissions.WAITER);

  // States for editing role presets
  const [rolePresetPermissions, setRolePresetPermissions] = useState<Permission[]>([]);

  const getRoleIcon = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return <ShieldCheck className="text-indigo-600" size={18} />;
      case 'MANAGER': return <UserCog className="text-amber-600" size={18} />;
      case 'CHEF': return <ChefHat className="text-rose-600" size={18} />;
      case 'CASHIER': return <Wallet className="text-emerald-600" size={18} />;
      case 'WAITER': return <Utensils className="text-blue-600" size={18} />;
    }
  };

  const getRoleBadgeClass = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return 'bg-indigo-50 text-indigo-700 border-indigo-100';
      case 'MANAGER': return 'bg-amber-50 text-amber-700 border-amber-100';
      case 'CHEF': return 'bg-rose-50 text-rose-700 border-rose-100';
      case 'CASHIER': return 'bg-emerald-50 text-emerald-700 border-emerald-100';
      case 'WAITER': return 'bg-blue-50 text-blue-700 border-blue-100';
    }
  };

  const getActionBadgeClass = (action: string) => {
    switch (action) {
      case 'VENDA': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'LOGIN': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'ESTOQUE': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'ADMIN': return 'bg-rose-50 text-rose-700 border-rose-200';
      default: return 'bg-slate-50 text-slate-700 border-slate-200';
    }
  };

  const handleRoleChange = (role: UserRole) => {
    setNewRole(role);
    setNewPermissions(rolePermissions[role] || []);
  };

  const togglePermission = (id: Permission) => {
    setNewPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSaveUser = () => {
    if (!newName || !newEmail) return;
    onAddUser({
      name: newName,
      email: newEmail,
      role: newRole,
      permissions: newPermissions
    });
    setShowModal(false);
    resetForm();
  };

  const resetForm = () => {
    setNewName('');
    setNewEmail('');
    setNewRole('WAITER');
    setNewPermissions(rolePermissions.WAITER);
  };

  const openEditRole = (role: UserRole) => {
    setEditingRole(role);
    setRolePresetPermissions([...rolePermissions[role]]);
  };

  const togglePresetPermission = (id: Permission) => {
    setRolePresetPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSaveRolePreset = () => {
    if (editingRole) {
      onUpdateRolePermissions(editingRole, rolePresetPermissions);
      setEditingRole(null);
    }
  };

  const filteredLogs = auditLogs.filter(log => 
    log.userName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.action.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
          <button 
            onClick={() => setActiveSubTab('team')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'team' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Users size={18} />
            Equipe
          </button>
          <button 
            onClick={() => setActiveSubTab('roles')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'roles' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Briefcase size={18} />
            Cargos
          </button>
          <button 
            onClick={() => setActiveSubTab('audit')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'audit' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <History size={18} />
            Auditoria
          </button>
        </div>

        {activeSubTab === 'team' ? (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
          >
            <UserPlus size={20} />
            Configurar Acesso
          </button>
        ) : (
          activeSubTab === 'audit' && (
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Filtrar logs..." 
                className="w-full pl-10 pr-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          )
        )}
      </div>

      {activeSubTab === 'team' ? (
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in fade-in duration-500">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b">
              <tr>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Função / Nível</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Permissões Ativas</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Status</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500 border">
                        {user.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800">{user.name}</p>
                        <p className="text-xs text-slate-400 flex items-center gap-1">
                          <Mail size={12} /> {user.email}
                        </p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-bold ${getRoleBadgeClass(user.role)}`}>
                      {getRoleIcon(user.role)}
                      {user.role}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-wrap gap-1 max-w-[200px]">
                      {user.permissions.slice(0, 3).map(p => (
                        <span key={p} className="text-[10px] bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded font-medium">
                          {ALL_PERMISSIONS.find(ap => ap.id === p)?.label}
                        </span>
                      ))}
                      {user.permissions.length > 3 && (
                        <span className="text-[10px] text-slate-400 font-bold">+{user.permissions.length - 3}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <span className={`w-2 h-2 rounded-full ${user.status === 'online' ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></span>
                      <span className="text-sm text-slate-600 capitalize">{user.status}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-600 transition-colors">
                      <MoreVertical size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : activeSubTab === 'roles' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-4 duration-500">
          {(['ADMIN', 'MANAGER', 'CHEF', 'CASHIER', 'WAITER'] as UserRole[]).map(role => (
            <div key={role} className="bg-white rounded-3xl border shadow-sm p-6 flex flex-col gap-4 group hover:shadow-md transition-shadow">
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-3">
                  <div className={`p-3 rounded-2xl ${getRoleBadgeClass(role)}`}>
                    {getRoleIcon(role)}
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800">{role}</h3>
                    <p className="text-xs text-slate-500">{rolePermissions[role].length} permissões padrão</p>
                  </div>
                </div>
                <button 
                  onClick={() => openEditRole(role)}
                  className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition-all opacity-0 group-hover:opacity-100"
                >
                  <Edit3 size={18} />
                </button>
              </div>
              <div className="flex flex-wrap gap-1.5 mt-2">
                {rolePermissions[role].slice(0, 6).map(p => (
                  <span key={p} className="text-[10px] px-2 py-0.5 rounded-full border bg-slate-50 text-slate-600 font-semibold">
                    {ALL_PERMISSIONS.find(ap => ap.id === p)?.label}
                  </span>
                ))}
                {rolePermissions[role].length > 6 && (
                  <span className="text-[10px] text-slate-400 font-bold self-center">+{rolePermissions[role].length - 6}</span>
                )}
              </div>
              <div className="mt-auto pt-4 border-t flex justify-between items-center">
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-tighter">Preset do Sistema</p>
                <button 
                  onClick={() => openEditRole(role)}
                  className="text-xs font-bold text-indigo-600 hover:underline flex items-center gap-1"
                >
                  <Settings2 size={12} /> Configurar Preset
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-2">
              <Activity className="text-indigo-600" size={20} />
              <h3 className="font-bold text-slate-800">Log de Atividades do Sistema</h3>
            </div>
            <p className="text-xs text-slate-500 font-medium">Exibindo os últimos {filteredLogs.length} eventos</p>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Horário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Ação</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Descrição</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredLogs.map(log => (
                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <p className="text-sm font-medium text-slate-800">
                        {log.timestamp.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </p>
                      <p className="text-xs text-slate-400">
                        {log.timestamp.toLocaleDateString('pt-BR')}
                      </p>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center font-bold text-xs text-slate-500 border">
                          {log.userName.charAt(0)}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-slate-800">{log.userName}</p>
                          <p className="text-[10px] uppercase font-black text-slate-400 tracking-tighter">{log.userRole}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-md border text-[10px] font-black tracking-wider uppercase ${getActionBadgeClass(log.action)}`}>
                        {log.action}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <p className="text-sm text-slate-600 font-medium">{log.description}</p>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal: New User */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-2 rounded-xl text-white">
                  <UserPlus size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Configurar Novo Acesso</h2>
                  <p className="text-xs text-slate-500 font-medium">Defina os privilégios exatos do membro da equipe.</p>
                </div>
              </div>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white rounded-full transition-colors text-slate-400">
                <X size={20} />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase text-slate-500 tracking-wider">Nome Completo</label>
                  <input type="text" placeholder="Ex: Carlos Alberto" className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all" value={newName} onChange={(e) => setNewName(e.target.value)} />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase text-slate-500 tracking-wider">E-mail Profissional</label>
                  <input type="email" placeholder="carlos@seunegocio.com" className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all" value={newEmail} onChange={(e) => setNewEmail(e.target.value)} />
                </div>
              </div>
              <div className="space-y-4">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2"><Shield size={14} className="text-indigo-600" /> Cargo Sugerido</label>
                <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
                  {(['WAITER', 'CASHIER', 'CHEF', 'MANAGER', 'ADMIN'] as UserRole[]).map(role => (
                    <button key={role} onClick={() => handleRoleChange(role)} className={`px-3 py-3 rounded-xl border-2 transition-all text-xs font-bold flex flex-col items-center gap-2 ${newRole === role ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-500 hover:border-indigo-200'}`}>
                      <span className="opacity-80">{getRoleIcon(role)}</span>{role}
                    </button>
                  ))}
                </div>
              </div>
              <div className="space-y-4">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2"><Lock size={14} className="text-indigo-600" /> Permissões Individuais</label>
                <div className="space-y-6">
                  {['Gestão', 'Administrativo', 'Operacional'].map(group => (
                    <div key={group} className="space-y-3">
                      <h4 className="text-[10px] font-black uppercase text-slate-400 border-b pb-1">{group}</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {ALL_PERMISSIONS.filter(p => p.group === group).map(perm => (
                          <button key={perm.id} onClick={() => togglePermission(perm.id)} className={`flex items-start gap-4 p-3 rounded-2xl border-2 transition-all text-left ${newPermissions.includes(perm.id) ? 'border-emerald-500 bg-emerald-50/30' : 'border-slate-50 bg-slate-50/50'}`}>
                            <div className={`mt-0.5 w-5 h-5 rounded flex items-center justify-center ${newPermissions.includes(perm.id) ? 'bg-emerald-500 text-white' : 'bg-white border-2 border-slate-200'}`}>{newPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}</div>
                            <div>
                              <p className={`text-sm font-bold ${newPermissions.includes(perm.id) ? 'text-emerald-900' : 'text-slate-700'}`}>{perm.label}</p>
                              <p className="text-[10px] text-slate-500 leading-tight">{perm.description}</p>
                            </div>
                          </button>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
            <div className="p-6 border-t bg-slate-50 flex gap-4 justify-end">
              <button onClick={() => setShowModal(false)} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-white border border-transparent hover:border-slate-200">Cancelar</button>
              <button onClick={handleSaveUser} disabled={!newName || !newEmail} className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-lg disabled:opacity-50">Criar Acesso</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Edit Role Preset */}
      {editingRole && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-500 p-2 rounded-xl text-white">
                  <Settings2 size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Editar Preset: {editingRole}</h2>
                  <p className="text-xs text-slate-500 font-medium">As alterações afetarão apenas novos usuários criados com este preset.</p>
                </div>
              </div>
              <button onClick={() => setEditingRole(null)} className="p-2 hover:bg-white rounded-full text-slate-400"><X size={20} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-6">
              {['Gestão', 'Administrativo', 'Operacional'].map(group => (
                <div key={group} className="space-y-3">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 border-b pb-1">{group}</h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {ALL_PERMISSIONS.filter(p => p.group === group).map(perm => (
                      <button key={perm.id} onClick={() => togglePresetPermission(perm.id)} className={`flex items-start gap-4 p-3 rounded-2xl border-2 transition-all text-left ${rolePresetPermissions.includes(perm.id) ? 'border-amber-500 bg-amber-50/30' : 'border-slate-50 bg-slate-50/50'}`}>
                        <div className={`mt-0.5 w-5 h-5 rounded flex items-center justify-center ${rolePresetPermissions.includes(perm.id) ? 'bg-amber-500 text-white' : 'bg-white border-2 border-slate-200'}`}>{rolePresetPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}</div>
                        <div>
                          <p className={`text-sm font-bold ${rolePresetPermissions.includes(perm.id) ? 'text-amber-900' : 'text-slate-700'}`}>{perm.label}</p>
                          <p className="text-[10px] text-slate-500 leading-tight">{perm.description}</p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
            <div className="p-6 border-t bg-slate-50 flex gap-4 justify-end">
              <button onClick={() => setEditingRole(null)} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-white border border-transparent hover:border-slate-200">Cancelar</button>
              <button onClick={handleSaveRolePreset} className="bg-amber-500 text-white px-8 py-3 rounded-xl font-bold hover:bg-amber-600 shadow-lg">Salvar Preset</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersPanel;

export type OrderStatus = 'pending' | 'preparing' | 'ready' | 'delivered' | 'cancelled';

export type UserRole = 'ADMIN' | 'MANAGER' | 'WAITER' | 'CASHIER' | 'CHEF';

export type Permission = 
  | 'dashboard_view' 
  | 'pos_access' 
  | 'tables_manage' 
  | 'kds_view' 
  | 'delivery_manage' 
  | 'inventory_edit' 
  | 'finance_view' 
  | 'cmv_analysis' 
  | 'users_manage';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  createdAt: Date;
  customerName?: string;
  courierId?: string;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

import React, { useState } from 'react';
import { User, UserRole, AuditLog, Permission } from '../types';
import { 
  UserPlus, Shield, Mail, MoreVertical, ShieldCheck, UserCog, 
  ChefHat, Wallet, Utensils, History, Users, Search, Activity,
  X, Check, Lock, Settings2, Edit3, Briefcase, FileText
} from 'lucide-react';

interface UsersPanelProps {
  users: User[];
  auditLogs: AuditLog[];
  rolePermissions: Record<UserRole, Permission[]>;
  onAddUser: (user: Partial<User>) => void;
  onUpdateRole: (id: string, role: UserRole) => void;
  onUpdateRolePermissions: (role: UserRole, permissions: Permission[]) => void;
}

const ALL_PERMISSIONS: { id: Permission; label: string; group: string; description: string }[] = [
  { id: 'dashboard_view', label: 'Painel AI', group: 'Gestão', description: 'Visualiza insights estratégicos e métricas' },
  { id: 'cmv_analysis', label: 'Análise CMV', group: 'Gestão', description: 'Acesso às recomendações de custo e lucro' },
  { id: 'finance_view', label: 'Financeiro', group: 'Administrativo', description: 'Visualiza contas e balanço financeiro' },
  { id: 'users_manage', label: 'Equipe', group: 'Administrativo', description: 'Gerencia membros e permissões' },
  { id: 'pos_access', label: 'Acesso PDV', group: 'Operacional', description: 'Realiza vendas no caixa' },
  { id: 'tables_manage', label: 'Mesas', group: 'Operacional', description: 'Abre e fecha mesas de atendimento' },
  { id: 'kds_view', label: 'Cozinha (KDS)', group: 'Operacional', description: 'Monitora pedidos na cozinha' },
  { id: 'delivery_manage', label: 'Entregas', group: 'Operacional', description: 'Gerencia motoboys e entregas' },
  { id: 'inventory_edit', label: 'Estoque', group: 'Operacional', description: 'Altera quantidades e custos de produtos' },
];

const UsersPanel: React.FC<UsersPanelProps> = ({ 
  users, 
  auditLogs, 
  rolePermissions, 
  onAddUser, 
  onUpdateRole, 
  onUpdateRolePermissions 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'team' | 'roles' | 'audit'>('team');
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingRole, setEditingRole] = useState<UserRole | null>(null);

  // Modal states for adding user
  const [newName, setNewName] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [newRole, setNewRole] = useState<UserRole>('WAITER');
  const [newPermissions, setNewPermissions] = useState<Permission[]>(rolePermissions.WAITER);
  const [newObservations, setNewObservations] = useState('');

  // States for editing role presets
  const [rolePresetPermissions, setRolePresetPermissions] = useState<Permission[]>([]);

  const getRoleIcon = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return <ShieldCheck className="text-indigo-600" size={18} />;
      case 'MANAGER': return <UserCog className="text-amber-600" size={18} />;
      case 'CHEF': return <ChefHat className="text-rose-600" size={18} />;
      case 'CASHIER': return <Wallet className="text-emerald-600" size={18} />;
      case 'WAITER': return <Utensils className="text-blue-600" size={18} />;
    }
  };

  const getRoleBadgeClass = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return 'bg-indigo-50 text-indigo-700 border-indigo-100';
      case 'MANAGER': return 'bg-amber-50 text-amber-700 border-amber-100';
      case 'CHEF': return 'bg-rose-50 text-rose-700 border-rose-100';
      case 'CASHIER': return 'bg-emerald-50 text-emerald-700 border-emerald-100';
      case 'WAITER': return 'bg-blue-50 text-blue-700 border-blue-100';
    }
  };

  const getActionBadgeClass = (action: string) => {
    switch (action) {
      case 'VENDA': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'LOGIN': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'ESTOQUE': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'ADMIN': return 'bg-rose-50 text-rose-700 border-rose-200';
      default: return 'bg-slate-50 text-slate-700 border-slate-200';
    }
  };

  const handleRoleChange = (role: UserRole) => {
    setNewRole(role);
    setNewPermissions(rolePermissions[role] || []);
  };

  const togglePermission = (id: Permission) => {
    setNewPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSaveUser = () => {
    if (!newName || !newEmail) return;
    onAddUser({
      name: newName,
      email: newEmail,
      role: newRole,
      permissions: newPermissions,
      observations: newObservations
    });
    setShowModal(false);
    resetForm();
  };

  const resetForm = () => {
    setNewName('');
    setNewEmail('');
    setNewRole('WAITER');
    setNewPermissions(rolePermissions.WAITER);
    setNewObservations('');
  };

  const openEditRole = (role: UserRole) => {
    setEditingRole(role);
    setRolePresetPermissions([...rolePermissions[role]]);
  };

  const togglePresetPermission = (id: Permission) => {
    setRolePresetPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSaveRolePreset = () => {
    if (editingRole) {
      onUpdateRolePermissions(editingRole, rolePresetPermissions);
      setEditingRole(null);
    }
  };

  const filteredLogs = auditLogs.filter(log => 
    log.userName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.action.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
          <button 
            onClick={() => setActiveSubTab('team')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'team' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Users size={18} />
            Equipe
          </button>
          <button 
            onClick={() => setActiveSubTab('roles')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'roles' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Briefcase size={18} />
            Cargos
          </button>
          <button 
            onClick={() => setActiveSubTab('audit')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'audit' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <History size={18} />
            Auditoria
          </button>
        </div>

        {activeSubTab === 'team' ? (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
          >
            <UserPlus size={20} />
            Configurar Acesso
          </button>
        ) : (
          activeSubTab === 'audit' && (
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Filtrar logs..." 
                className="w-full pl-10 pr-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          )
        )}
      </div>

      {activeSubTab === 'team' ? (
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in fade-in duration-500">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b">
              <tr>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Função / Nível</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Permissões Ativas</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Status</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500 border">
                        {user.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800">{user.name}</p>
                        <p className="text-xs text-slate-400 flex items-center gap-1">
                          <Mail size={12} /> {user.email}
                        </p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-bold ${getRoleBadgeClass(user.role)}`}>
                      {getRoleIcon(user.role)}
                      {user.role}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-wrap gap-1 max-w-[200px]">
                      {user.permissions.slice(0, 3).map(p => (
                        <span key={p} className="text-[10px] bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded font-medium">
                          {ALL_PERMISSIONS.find(ap => ap.id === p)?.label}
                        </span>
                      ))}
                      {user.permissions.length > 3 && (
                        <span className="text-[10px] text-slate-400 font-bold">+{user.permissions.length - 3}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <span className={`w-2 h-2 rounded-full ${user.status === 'online' ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></span>
                      <span className="text-sm text-slate-600 capitalize">{user.status}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-600 transition-colors">
                      <MoreVertical size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : activeSubTab === 'roles' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-4 duration-500">
          {(['ADMIN', 'MANAGER', 'CHEF', 'CASHIER', 'WAITER'] as UserRole[]).map(role => (
            <div key={role} className="bg-white rounded-3xl border shadow-sm p-6 flex flex-col gap-4 group hover:shadow-md transition-shadow">
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-3">
                  <div className={`p-3 rounded-2xl ${getRoleBadgeClass(role)}`}>
                    {getRoleIcon(role)}
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800">{role}</h3>
                    <p className="text-xs text-slate-500">{rolePermissions[role].length} permissões padrão</p>
                  </div>
                </div>
                <button 
                  onClick={() => openEditRole(role)}
                  className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition-all opacity-0 group-hover:opacity-100"
                >
                  <Edit3 size={18} />
                </button>
              </div>
              <div className="flex flex-wrap gap-1.5 mt-2">
                {rolePermissions[role].slice(0, 6).map(p => (
                  <span key={p} className="text-[10px] px-2 py-0.5 rounded-full border bg-slate-50 text-slate-600 font-semibold">
                    {ALL_PERMISSIONS.find(ap => ap.id === p)?.label}
                  </span>
                ))}
                {rolePermissions[role].length > 6 && (
                  <span className="text-[10px] text-slate-400 font-bold self-center">+{rolePermissions[role].length - 6}</span>
                )}
              </div>
              <div className="mt-auto pt-4 border-t flex justify-between items-center">
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-tighter">Preset do Sistema</p>
                <button 
                  onClick={() => openEditRole(role)}
                  className="text-xs font-bold text-indigo-600 hover:underline flex items-center gap-1"
                >
                  <Settings2 size={12} /> Configurar Preset
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-2">
              <Activity className="text-indigo-600" size={20} />
              <h3 className="font-bold text-slate-800">Log de Atividades do Sistema</h3>
            </div>
            <p className="text-xs text-slate-500 font-medium">Exibindo os últimos {filteredLogs.length} eventos</p>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Horário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Ação</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Descrição</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredLogs.map(log => (
                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <p className="text-sm font-medium text-slate-800">
                        {log.timestamp.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </p>
                      <p className="text-xs text-slate-400">
                        {log.timestamp.toLocaleDateString('pt-BR')}
                      </p>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center font-bold text-xs text-slate-500 border">
                          {log.userName.charAt(0)}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-slate-800">{log.userName}</p>
                          <p className="text-[10px] uppercase font-black text-slate-400 tracking-tighter">{log.userRole}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-md border text-[10px] font-black tracking-wider uppercase ${getActionBadgeClass(log.action)}`}>
                        {log.action}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <p className="text-sm text-slate-600 font-medium">{log.description}</p>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal: New User */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-2 rounded-xl text-white">
                  <UserPlus size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Configurar Novo Acesso</h2>
                  <p className="text-xs text-slate-500 font-medium">Defina os privilégios exatos do membro da equipe.</p>
                </div>
              </div>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white rounded-full transition-colors text-slate-400">
                <X size={20} />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
