                </div>
              </div>

              {/* Role Presets */}
              <div className="space-y-4">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2"><Shield size={14} className="text-indigo-600" /> Cargo Sugerido</label>
                <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
                  {(['WAITER', 'CASHIER', 'CHEF', 'MANAGER', 'ADMIN'] as UserRole[]).map(role => (
                    <button key={role} onClick={() => handleRoleChange(role)} className={`px-3 py-3 rounded-xl border-2 transition-all text-xs font-bold flex flex-col items-center gap-2 ${newRole === role ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-500 hover:border-indigo-200'}`}>
                      <span className="opacity-80">{getRoleIcon(role)}</span>{role}
                    </button>
                  ))}
                </div>
              </div>

              {/* Permissions */}
              <div className="space-y-4">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2"><Lock size={14} className="text-indigo-600" /> Permissões Individuais</label>
                <div className="space-y-6">
                  {['Gestão', 'Administrativo', 'Operacional'].map(group => (
                    <div key={group} className="space-y-3">
