                          <button key={perm.id} onClick={() => togglePermission(perm.id)} className={`flex items-start gap-4 p-3 rounded-2xl border-2 transition-all text-left ${newPermissions.includes(perm.id) ? 'border-emerald-500 bg-emerald-50/30' : 'border-slate-50 bg-slate-50/50'}`}>
                            <div className={`mt-0.5 w-5 h-5 rounded flex items-center justify-center ${newPermissions.includes(perm.id) ? 'bg-emerald-500 text-white' : 'bg-white border-2 border-slate-200'}`}>{newPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}</div>
                            <div>
                              <p className={`text-sm font-bold ${newPermissions.includes(perm.id) ? 'text-emerald-900' : 'text-slate-700'}`}>{perm.label}</p>
                              <p className="text-[10px] text-slate-500 leading-tight">{perm.description}</p>
                            </div>
                          </button>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* New: Observations Field */}
              <div className="space-y-2">
                <label className="text-xs font-black uppercase text-slate-500 tracking-wider flex items-center gap-2">
                  <FileText size={14} className="text-indigo-600" /> Observações Internas
                </label>
                <textarea 
                  rows={3}
                  placeholder="Informações adicionais sobre o funcionário, restrições ou notas de RH..."
                  className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none text-sm text-slate-600"
                  value={newObservations}
                  onChange={(e) => setNewObservations(e.target.value)}
                />
              </div>
            </div>

            <div className="p-6 border-t bg-slate-50 flex gap-4 justify-end">
              <button onClick={() => setShowModal(false)} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-white border border-transparent hover:border-slate-200">Cancelar</button>
              <button onClick={handleSaveUser} disabled={!newName || !newEmail} className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-lg disabled:opacity-50">Criar Acesso</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Edit Role Preset */}
      {editingRole && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-500 p-2 rounded-xl text-white">
                  <Settings2 size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Editar Preset: {editingRole}</h2>
                  <p className="text-xs text-slate-500 font-medium">As alterações afetarão apenas novos usuários criados com este preset.</p>
                </div>
              </div>
              <button onClick={() => setEditingRole(null)} className="p-2 hover:bg-white rounded-full text-slate-400"><X size={20} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-6">
              {['Gestão', 'Administrativo', 'Operacional'].map(group => (
                <div key={group} className="space-y-3">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 border-b pb-1">{group}</h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {ALL_PERMISSIONS.filter(p => p.group === group).map(perm => (
                      <button key={perm.id} onClick={() => togglePresetPermission(perm.id)} className={`flex items-start gap-4 p-3 rounded-2xl border-2 transition-all text-left ${rolePresetPermissions.includes(perm.id) ? 'border-amber-500 bg-amber-50/30' : 'border-slate-50 bg-slate-50/50'}`}>
                        <div className={`mt-0.5 w-5 h-5 rounded flex items-center justify-center ${rolePresetPermissions.includes(perm.id) ? 'bg-amber-500 text-white' : 'bg-white border-2 border-slate-200'}`}>{rolePresetPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}</div>
                        <div>
                          <p className={`text-sm font-bold ${rolePresetPermissions.includes(perm.id) ? 'text-amber-900' : 'text-slate-700'}`}>{perm.label}</p>
                          <p className="text-[10px] text-slate-500 leading-tight">{perm.description}</p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
            <div className="p-6 border-t bg-slate-50 flex gap-4 justify-end">
              <button onClick={() => setEditingRole(null)} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-white border border-transparent hover:border-slate-200">Cancelar</button>
              <button onClick={handleSaveRolePreset} className="bg-amber-500 text-white px-8 py-3 rounded-xl font-bold hover:bg-amber-600 shadow-lg">Salvar Preset</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersPanel;

export type OrderStatus = 'pending' | 'preparing' | 'ready' | 'delivered' | 'cancelled';

export type UserRole = 'ADMIN' | 'MANAGER' | 'WAITER' | 'CASHIER' | 'CHEF';

export type Permission = 
  | 'dashboard_view' 
  | 'pos_access' 
  | 'tables_manage' 
  | 'kds_view' 
  | 'delivery_manage' 
  | 'inventory_edit' 
  | 'finance_view' 
  | 'cmv_analysis' 
  | 'users_manage';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  createdAt: Date;
  customerName?: string;
  courierId?: string;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

