                        <span className="bg-emerald-100 text-emerald-600 px-2 py-1 rounded-full text-xs font-bold">OK</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      case 'ai-cmv':
        return (
          <div className="space-y-6">
            <div className="bg-indigo-900 text-white p-8 rounded-3xl">
              <h2 className="text-2xl font-bold mb-2">Otimização de CMV com IA</h2>
              <p className="text-indigo-200">Nossa IA analisa constantemente seus custos vs preços de mercado para sugerir margens ideais.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {products.slice(0, 4).map(p => {
                const cmv = (p.cost / p.price) * 100;
                return (
                  <div key={p.id} className="bg-white border-2 border-slate-100 p-6 rounded-2xl">
                    <div className="flex justify-between items-start mb-4">
                      <h3 className="font-bold text-lg">{p.name}</h3>
                      <div className={`px-3 py-1 rounded-lg font-bold ${cmv > 35 ? 'bg-rose-100 text-rose-700' : 'bg-emerald-100 text-emerald-700'}`}>
                        CMV: {cmv.toFixed(1)}%
                      </div>
                    </div>
                    <div className="space-y-3">
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-500">Custo Atual:</span>
                        <span className="font-bold text-slate-700">R$ {p.cost.toFixed(2)}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-500">Preço Venda:</span>
                        <span className="font-bold text-slate-700">R$ {p.price.toFixed(2)}</span>
                      </div>
                      <div className="pt-4 border-t mt-4">
                        <p className="text-xs font-bold text-indigo-600 uppercase mb-2">Sugestão da IA:</p>
                        <p className="text-sm text-slate-600 italic">"O custo da proteína subiu 12%. Recomendamos ajustar o preço para R$ {(p.price * 1.08).toFixed(2)} para manter a margem de 30%."</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">Unidade Centro - São Paulo</h2>
            <h1 className="text-3xl font-black text-slate-800 text-capitalize">
              {activeTab === 'dashboard' ? 'Bem-vindo, Gestor' : 
               activeTab === 'pos' ? 'Caixa Operacional' : 
               activeTab === 'users' ? 'Gestão de Equipe' :
               activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="font-bold text-slate-800">Cozinha: Aberta</p>
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Sincronizado
              </p>
            </div>
            <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-black border-2 border-indigo-200">
              JS
            </div>
          </div>
        </header>

        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, UserRole, AuditLog, Permission } from '../types';
import { 
  UserPlus, Shield, Mail, MoreVertical, ShieldCheck, UserCog, 
  ChefHat, Wallet, Utensils, History, Users, Search, Activity,
  X, Check, Lock, Settings2, Edit3, Briefcase, FileText, Calendar
} from 'lucide-react';

interface UsersPanelProps {
  users: User[];
  auditLogs: AuditLog[];
  rolePermissions: Record<UserRole, Permission[]>;
  onAddUser: (user: Partial<User>) => void;
  onUpdateRole: (id: string, role: UserRole) => void;
  onUpdateRolePermissions: (role: UserRole, permissions: Permission[]) => void;
}

const ALL_PERMISSIONS: { id: Permission; label: string; group: string; description: string }[] = [
  { id: 'dashboard_view', label: 'Painel AI', group: 'Gestão', description: 'Visualiza insights estratégicos e métricas' },
  { id: 'cmv_analysis', label: 'Análise CMV', group: 'Gestão', description: 'Acesso às recomendações de custo e lucro' },
  { id: 'finance_view', label: 'Financeiro', group: 'Administrativo', description: 'Visualiza contas e balanço financeiro' },
  { id: 'users_manage', label: 'Equipe', group: 'Administrativo', description: 'Gerencia membros e permissões' },
  { id: 'pos_access', label: 'Acesso PDV', group: 'Operacional', description: 'Realiza vendas no caixa' },
  { id: 'tables_manage', label: 'Mesas', group: 'Operacional', description: 'Abre e fecha mesas de atendimento' },
  { id: 'kds_view', label: 'Cozinha (KDS)', group: 'Operacional', description: 'Monitora pedidos na cozinha' },
  { id: 'delivery_manage', label: 'Entregas', group: 'Operacional', description: 'Gerencia motoboys e entregas' },
  { id: 'inventory_edit', label: 'Estoque', group: 'Operacional', description: 'Altera quantidades e custos de produtos' },
];

const UsersPanel: React.FC<UsersPanelProps> = ({ 
  users, 
  auditLogs, 
  rolePermissions, 
  onAddUser, 
  onUpdateRole, 
  onUpdateRolePermissions 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'team' | 'roles' | 'audit'>('team');
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingRole, setEditingRole] = useState<UserRole | null>(null);

  // Modal states for adding user
  const [newName, setNewName] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [newRole, setNewRole] = useState<UserRole>('WAITER');
  const [newPermissions, setNewPermissions] = useState<Permission[]>(rolePermissions.WAITER);
  const [newObservations, setNewObservations] = useState('');

  // States for editing role presets
  const [rolePresetPermissions, setRolePresetPermissions] = useState<Permission[]>([]);

  const getRoleIcon = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return <ShieldCheck className="text-indigo-600" size={18} />;
      case 'MANAGER': return <UserCog className="text-amber-600" size={18} />;
      case 'CHEF': return <ChefHat className="text-rose-600" size={18} />;
      case 'CASHIER': return <Wallet className="text-emerald-600" size={18} />;
      case 'WAITER': return <Utensils className="text-blue-600" size={18} />;
    }
  };

  const getRoleBadgeClass = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return 'bg-indigo-50 text-indigo-700 border-indigo-100';
      case 'MANAGER': return 'bg-amber-50 text-amber-700 border-amber-100';
      case 'CHEF': return 'bg-rose-50 text-rose-700 border-rose-100';
      case 'CASHIER': return 'bg-emerald-50 text-emerald-700 border-emerald-100';
      case 'WAITER': return 'bg-blue-50 text-blue-700 border-blue-100';
    }
  };

  const getActionBadgeClass = (action: string) => {
    switch (action) {
      case 'VENDA': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'LOGIN': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'ESTOQUE': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'ADMIN': return 'bg-rose-50 text-rose-700 border-rose-200';
      default: return 'bg-slate-50 text-slate-700 border-slate-200';
    }
  };

  const handleRoleChange = (role: UserRole) => {
    setNewRole(role);
    setNewPermissions(rolePermissions[role] || []);
  };

  const togglePermission = (id: Permission) => {
    setNewPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSaveUser = () => {
    if (!newName || !newEmail) return;
    onAddUser({
      name: newName,
      email: newEmail,
      role: newRole,
      permissions: newPermissions,
      observations: newObservations
    });
    setShowModal(false);
    resetForm();
  };

  const resetForm = () => {
    setNewName('');
    setNewEmail('');
    setNewRole('WAITER');
    setNewPermissions(rolePermissions.WAITER);
    setNewObservations('');
  };

  const openEditRole = (role: UserRole) => {
    setEditingRole(role);
    setRolePresetPermissions([...rolePermissions[role]]);
  };

  const togglePresetPermission = (id: Permission) => {
    setRolePresetPermissions(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  const handleSaveRolePreset = () => {
    if (editingRole) {
      onUpdateRolePermissions(editingRole, rolePresetPermissions);
      setEditingRole(null);
    }
  };

  const filteredLogs = auditLogs.filter(log => 
    log.userName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.action.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
          <button 
            onClick={() => setActiveSubTab('team')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'team' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Users size={18} />
            Equipe
          </button>
          <button 
            onClick={() => setActiveSubTab('roles')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'roles' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Briefcase size={18} />
            Cargos
          </button>
          <button 
            onClick={() => setActiveSubTab('audit')}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-bold transition-all ${activeSubTab === 'audit' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <History size={18} />
            Auditoria
          </button>
        </div>

        {activeSubTab === 'team' ? (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
          >
            <UserPlus size={20} />
            Configurar Acesso
          </button>
        ) : (
          activeSubTab === 'audit' && (
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Filtrar logs..." 
                className="w-full pl-10 pr-4 py-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          )
        )}
      </div>

      {activeSubTab === 'team' ? (
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in fade-in duration-500">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b">
              <tr>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Função / Nível</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Permissões Ativas</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm">Status</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-sm text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500 border">
                        {user.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800">{user.name}</p>
                        <p className="text-xs text-slate-400 flex items-center gap-1">
                          <Mail size={12} /> {user.email}
                        </p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-bold ${getRoleBadgeClass(user.role)}`}>
                      {getRoleIcon(user.role)}
                      {user.role}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-wrap gap-1 max-w-[200px]">
                      {user.permissions.slice(0, 3).map(p => (
                        <span key={p} className="text-[10px] bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded font-medium">
                          {ALL_PERMISSIONS.find(ap => ap.id === p)?.label}
                        </span>
                      ))}
                      {user.permissions.length > 3 && (
                        <span className="text-[10px] text-slate-400 font-bold">+{user.permissions.length - 3}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <span className={`w-2 h-2 rounded-full ${user.status === 'online' ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></span>
                      <span className="text-sm text-slate-600 capitalize">{user.status}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-600 transition-colors">
                      <MoreVertical size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : activeSubTab === 'roles' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-4 duration-500">
          {(['ADMIN', 'MANAGER', 'CHEF', 'CASHIER', 'WAITER'] as UserRole[]).map(role => (
            <div key={role} className="bg-white rounded-3xl border shadow-sm p-6 flex flex-col gap-4 group hover:shadow-md transition-shadow">
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-3">
                  <div className={`p-3 rounded-2xl ${getRoleBadgeClass(role)}`}>
                    {getRoleIcon(role)}
