        </div>
      ) : (
        <div className="bg-white rounded-3xl border shadow-sm overflow-hidden animate-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-2">
              <Activity className="text-indigo-600" size={20} />
              <h3 className="font-bold text-slate-800">Log de Atividades do Sistema</h3>
            </div>
            <p className="text-xs text-slate-500 font-medium">Exibindo os últimos {filteredLogs.length} eventos</p>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Horário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Usuário</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Ação</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Descrição</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredLogs.map(log => (
                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <p className="text-sm font-medium text-slate-800">
                        {log.timestamp.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </p>
                      <p className="text-xs text-slate-400">
                        {log.timestamp.toLocaleDateString('pt-BR')}
                      </p>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center font-bold text-xs text-slate-500 border">
                          {log.userName.charAt(0)}
