const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    addLog('u3', 'KDS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      createdAt: new Date(),
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado como ${newUser.role}`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    const oldUser = users.find(u => u.id === id);
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
    addLog('u1', 'ADMIN', `Cargo de ${oldUser?.name} alterado de ${oldUser?.role} para ${role}`);
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
    addLog('u1', 'ADMIN', `Permissões do cargo ${role} foram atualizadas.`);
  };

  // Table Management Actions
  const handleUpdateTable = (tableId: number, items: OrderItem[], status: Table['status']) => {
    setTables(prev => prev.map(t => {
      if (t.id === tableId) {
        const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        return { ...t, items, status, total };
      }
      return t;
    }));
  };

  const handleCloseTable = (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => {
    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: table.items,
      total: table.total,
      status: 'delivered',
      type: 'table',
      paymentMethod,
      isFiscalIssued: isFiscal
    };

    setOrders(prev => [newOrder, ...prev]);
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], total: 0, status: 'cleaning' } : t));
    addLog('u1', 'MESA', `Mesa ${tableId} fechada. Total R$ ${table.total.toFixed(2)} (${paymentMethod})`);

    // Simulated cleaning time
    setTimeout(() => {
      setTables(prev => prev.map(t => t.id === tableId && t.status === 'cleaning' ? { ...t, status: 'available' } : t));
    }, 5000);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 bg-white p-6 rounded-3xl border shadow-sm">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-bold">Vendas Recentes</h3>
                  <div className="flex gap-2">
                    <button className="p-2 hover:bg-slate-50 rounded-lg"><Filter size={20} /></button>
                    <button className="p-2 hover:bg-slate-50 rounded-lg"><Download size={20} /></button>
                  </div>
                </div>
                <div className="h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[
                      { name: 'Seg', sales: 4000 },
                      { name: 'Ter', sales: 3000 },
                      { name: 'Qua', sales: 2000 },
                      { name: 'Qui', sales: 2780 },
                      { name: 'Sex', sales: 1890 },
                      { name: 'Sáb', sales: 2390 },
                      { name: 'Dom', sales: 3490 },
                    ]}>
                      <defs>
                        <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                          <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} />
                      <YAxis axisLine={false} tickLine={false} />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col">
                <h3 className="text-xl font-bold mb-6">Top Pratos</h3>
                <div className="flex-1 space-y-6">
                  {products.slice(0, 4).map((p, i) => (
                    <div key={p.id} className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-100 rounded-xl flex items-center justify-center font-bold text-slate-500">
                        #{i + 1}
                      </div>
                      <div className="flex-1">
                        <p className="font-semibold text-slate-800">{p.name}</p>
                        <p className="text-xs text-slate-500">{Math.floor(Math.random() * 100)} vendidos este mês</p>
                      </div>
                      <div className="text-indigo-600 font-bold">R$ {p.price}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        );
      case 'pos':
        return <POS products={products} onPlaceOrder={handlePlaceOrder} />;
      case 'tables':
        return <Tables tables={tables} products={products} onUpdateTable={handleUpdateTable} onCloseTable={handleCloseTable} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'delivery':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-bold">Gestão de Entregas</h2>
              <button className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold flex items-center gap-2">
                <Plus size={20} /> Novo Motoboy
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {couriers.map(courier => (
                <div key={courier.id} className="bg-white border p-6 rounded-2xl shadow-sm">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="text-lg font-bold">{courier.name}</h3>
                      <p className="text-slate-500 text-sm">{courier.phone}</p>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                      courier.status === 'available' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                    }`}>
                      {courier.status}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'inventory':
        return (
          <div className="bg-white rounded-3xl border shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center">
              <h2 className="text-xl font-bold">Estoque de Produtos</h2>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-bold">Exportar CSV</button>
            </div>
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Produto</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Preço Venda</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Qtd. Estoque</th>
                  <th className="px-6 py-4 font-bold text-slate-500 text-sm">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {products.map(product => (
                  <tr key={product.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-semibold">{product.name}</td>
                    <td className="px-6 py-4">R$ {product.price.toFixed(2)}</td>
                    <td className="px-6 py-4 font-mono font-bold">{product.stock}</td>
                    <td className="px-6 py-4">
                      {product.stock < 15 ? (
                        <span className="bg-red-100 text-red-600 px-2 py-1 rounded-full text-xs font-bold">Crítico</span>
                      ) : (
                        <span className="bg-emerald-100 text-emerald-600 px-2 py-1 rounded-full text-xs font-bold">OK</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      case 'ai-cmv':
        return (
          <div className="space-y-6">
            <div className="bg-indigo-900 text-white p-8 rounded-3xl">
              <h2 className="text-2xl font-bold mb-2">Otimização de CMV com IA</h2>
              <p className="text-indigo-200">Margens inteligentes para o seu negócio.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {products.slice(0, 4).map(p => {
                const cmv = (p.cost / p.price) * 100;
                return (
                  <div key={p.id} className="bg-white border-2 border-slate-100 p-6 rounded-2xl">
                    <h3 className="font-bold text-lg mb-2">{p.name}</h3>
                    <div className={`px-3 py-1 inline-block rounded-lg font-bold ${cmv > 35 ? 'bg-rose-100 text-rose-700' : 'bg-emerald-100 text-emerald-700'}`}>
                      CMV: {cmv.toFixed(1)}%
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">Unidade Centro - São Paulo</h2>
            <h1 className="text-3xl font-black text-slate-800 text-capitalize">
              {activeTab === 'dashboard' ? 'Bem-vindo, Gestor' : 
               activeTab === 'pos' ? 'Caixa Operacional' : 
               activeTab === 'users' ? 'Gestão de Equipe' :
               activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="font-bold text-slate-800">Cozinha: Aberta</p>
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Sincronizado
              </p>
            </div>
            <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-black border-2 border-indigo-200">JS</div>
          </div>
        </header>
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Table, Order, Product, OrderItem, PaymentMethod } from '../types';
import { 
  Users, CreditCard, Utensils, X, Plus, Trash2, 
  Receipt, Wallet, Smartphone, Banknote, ShieldCheck,
  CheckCircle2, Printer, Search
} from 'lucide-react';

interface TablesProps {
  tables: Table[];
  products: Product[];
  onUpdateTable: (tableId: number, items: OrderItem[], status: Table['status']) => void;
  onCloseTable: (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => void;
}

const Tables: React.FC<TablesProps> = ({ tables, products, onUpdateTable, onCloseTable }) => {
  const [selectedTable, setSelectedTable] = useState<Table | null>(null);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [isFiscalEmission, setIsFiscalEmission] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [productSearch, setProductSearch] = useState('');

  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const openTable = (table: Table) => {
    if (table.status === 'available') {
      onUpdateTable(table.id, [], 'occupied');
      setSelectedTable({ ...table, status: 'occupied', items: [], total: 0 });
    } else {
      setSelectedTable(table);
    }
  };

  const addToTable = (product: Product) => {
    if (!selectedTable) return;
    const existing = selectedTable.items.find(i => i.productId === product.id);
    let newItems: OrderItem[];
    if (existing) {
      newItems = selectedTable.items.map(i => i.productId === product.id ? { ...i, quantity: i.quantity + 1 } : i);
    } else {
      newItems = [...selectedTable.items, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    }
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
  };

  const removeFromTable = (productId: string) => {
    if (!selectedTable) return;
    const newItems = selectedTable.items.filter(i => i.productId !== productId);
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
  };

  const handleProcessPayment = (method: PaymentMethod) => {
    if (!selectedTable) return;
    setIsProcessing(true);
    // Simulation of communication with SEFAZ / Digital Certificate
    setTimeout(() => {
      onCloseTable(selectedTable.id, method, isFiscalEmission);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
    }, 2000);
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()));

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
        {tables.map(table => (
          <button
            key={table.id}
            onClick={() => openTable(table)}
            disabled={table.status === 'cleaning'}
            className={`aspect-square p-6 rounded-[2rem] border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${getTableStatusColor(table.status)} shadow-sm`}
          >
            <div className="text-current">
              {table.status === 'available' ? <Utensils size={32} /> : 
               table.status === 'occupied' ? <Users size={32} /> : 
               table.status === 'billing' ? <CreditCard size={32} /> : <Utensils size={32} className="animate-spin" />}
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-black">Mesa {table.id}</h3>
              <p className="text-[10px] uppercase font-black tracking-widest opacity-60">{table.status}</p>
            </div>
            {table.total > 0 && (
              <div className="mt-1 text-sm font-black bg-white/60 px-4 py-1.5 rounded-2xl shadow-sm">
                R$ {table.total.toFixed(2)}
              </div>
            )}
          </button>
        ))}
      </div>

      {/* Modal: Table Consumption / Launch */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-6xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[85vh] animate-in zoom-in-95 duration-300">
            {/* Menu Side */}
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-black text-slate-800">Cardápio</h2>
                  <div className="relative w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      type="text" 
                      placeholder="Buscar produto..."
                      className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                      value={productSearch}
                      onChange={(e) => setProductSearch(e.target.value)}
                    />
                  </div>
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                  {['Todos', 'Lanches', 'Bebidas', 'Entradas', 'Sobremesas'].map(cat => (
                    <button key={cat} className="px-4 py-1.5 rounded-full bg-slate-100 text-slate-600 text-xs font-bold hover:bg-indigo-600 hover:text-white transition-all">
                      {cat}
                    </button>
                  ))}
                </div>
              </div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 md:grid-cols-3 gap-4">
                {filteredProducts.map(product => (
                  <button
                    key={product.id}
                    onClick={() => addToTable(product)}
                    className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col gap-1 group shadow-sm"
                  >
                    <div className="w-full h-24 bg-slate-100 rounded-2xl mb-2 overflow-hidden">
                      <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                    </div>
                    <p className="font-black text-slate-800 text-sm truncate">{product.name}</p>
                    <p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p>
                  </button>
                ))}
              </div>
            </div>

            {/* Cart Side */}
            <div className="w-[400px] flex flex-col bg-white">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-xl"><Utensils size={20} /></div>
                  <h2 className="text-xl font-black">Consumo Mesa {selectedTable.id}</h2>
                </div>
                <button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full transition-colors">
                  <X size={24} />
                </button>
              </div>
              <div className="flex-1 overflow-y-auto p-8 space-y-4">
                {selectedTable.items.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-50">
                    <Utensils size={64} strokeWidth={1} />
                    <p className="font-bold">Mesa vazia. Adicione produtos.</p>
                  </div>
                ) : (
                  selectedTable.items.map(item => (
                    <div key={item.productId} className="flex justify-between items-center group bg-slate-50 p-4 rounded-2xl border border-transparent hover:border-indigo-100 transition-all">
                      <div className="flex-1">
                        <p className="font-black text-slate-800 text-sm">{item.name}</p>
                        <p className="text-xs text-slate-500 font-bold">{item.quantity}x R$ {item.price.toFixed(2)}</p>
                      </div>
                      <div className="flex items-center gap-4">
                        <p className="font-black text-indigo-600">R$ {(item.price * item.quantity).toFixed(2)}</p>
                        <button onClick={() => removeFromTable(item.productId)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors">
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
              <div className="p-8 border-t bg-slate-50/50 space-y-6">
                <div className="flex justify-between items-center text-2xl font-black text-slate-800">
                  <span>Subtotal</span>
                  <span className="text-indigo-600">R$ {selectedTable.total.toFixed(2)}</span>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <button className="flex flex-col items-center justify-center gap-2 p-4 bg-white border-2 border-slate-200 rounded-3xl text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all font-bold group">
                    <Printer size={20} className="group-hover:animate-bounce" />
                    <span className="text-xs">Pré-Conta</span>
                  </button>
                  <button 
                    disabled={selectedTable.items.length === 0}
                    onClick={() => setShowPaymentModal(true)}
                    className="flex flex-col items-center justify-center gap-2 p-4 bg-indigo-600 text-white rounded-3xl hover:bg-indigo-700 transition-all font-black shadow-lg shadow-indigo-100 disabled:opacity-50 disabled:grayscale"
                  >
                    <Receipt size={20} />
                    <span className="text-xs">Fechar Mesa</span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Payment & Fiscal Certificate */}
      {showPaymentModal && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-emerald-600 text-white">
              <div className="flex items-center gap-4">
                <div className="bg-white/20 p-3 rounded-2xl shadow-inner"><Wallet size={24} /></div>
                <div>
                  <h2 className="text-2xl font-black">Finalizar Mesa {selectedTable.id}</h2>
                  <p className="text-xs font-bold opacity-80 uppercase tracking-widest">Processamento de Pagamento</p>
                </div>
              </div>
              <button onClick={() => setShowPaymentModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>

            <div className="p-10 space-y-10">
              <div className="text-center space-y-2">
                <p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor a Pagar</p>
                <h1 className="text-6xl font-black text-slate-800">R$ {selectedTable.total.toFixed(2)}</h1>
              </div>

              {/* Fiscal Options */}
              <div className={`p-6 rounded-[2rem] border-2 transition-all flex items-center justify-between group cursor-pointer ${isFiscalEmission ? 'bg-indigo-50 border-indigo-500' : 'bg-slate-50 border-slate-100'}`} onClick={() => setIsFiscalEmission(!isFiscalEmission)}>
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl shadow-sm ${isFiscalEmission ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-400'}`}>
                    <ShieldCheck size={24} />
                  </div>
                  <div>
                    <p className="font-black text-slate-800">Emissão de Cupom Fiscal</p>
                    <p className="text-xs font-bold text-slate-500">Utilizar Certificado Digital A1 v.2.4.0</p>
                  </div>
                </div>
                <div className={`w-12 h-6 rounded-full relative transition-all ${isFiscalEmission ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                  <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-all ${isFiscalEmission ? 'translate-x-6' : 'translate-x-0'}`}></div>
                </div>
              </div>

              {/* Payment Methods */}
              <div className="space-y-4">
                <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Escolha o Método</p>
                <div className="grid grid-cols-2 gap-4">
                  {[
                    { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'emerald' },
                    { id: 'cartao_credito', label: 'C. Crédito', icon: CreditCard, color: 'indigo' },
                    { id: 'cartao_debito', label: 'C. Débito', icon: CreditCard, color: 'blue' },
                    { id: 'pix', label: 'PIX Instantâneo', icon: Smartphone, color: 'teal' },
                  ].map(method => (
                    <button
                      key={method.id}
                      disabled={isProcessing}
                      onClick={() => handleProcessPayment(method.id as PaymentMethod)}
                      className="p-6 rounded-3xl border-2 border-slate-100 bg-slate-50/50 hover:bg-white hover:border-indigo-500 hover:shadow-xl hover:scale-105 transition-all text-left flex flex-col gap-4 group active:scale-95"
                    >
                      <div className="p-3 bg-white shadow-sm border rounded-2xl w-fit group-hover:bg-indigo-600 group-hover:text-white transition-all">
                        <method.icon size={24} />
                      </div>
                      <p className="font-black text-slate-800">{method.label}</p>
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in">
                <div className="relative">
                  <div className="w-24 h-24 border-4 border-indigo-100 rounded-full animate-ping absolute opacity-20"></div>
