                          <button 
                            key={role}
                            onClick={() => handleRoleTemplateSelect(role)}
                            className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all text-left ${newRole === role ? 'bg-indigo-50 border-indigo-100' : 'hover:bg-slate-50'}`}
                          >
                            <div className={`p-3 rounded-xl ${getRoleBadgeClass(role)}`}>
                              {getRoleIcon(role)}
                            </div>
                            <div className="flex-1">
                              <p className={`font-black text-sm ${newRole === role ? 'text-indigo-900' : 'text-slate-800'}`}>{ROLE_DETAILS[role].label}</p>
                              <p className="text-[10px] font-medium text-slate-500 leading-tight">{ROLE_DETAILS[role].description}</p>
                            </div>
                            {newRole === role && (
                              <div className="w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center shadow-lg shadow-indigo-100">
                                <Check size={18} strokeWidth={3} />
                              </div>
                            )}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Secão 3: Permissões Granulares */}
              <div className="space-y-6">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                  <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
                    <span className="w-6 h-px bg-slate-200"></span> Permissões Customizadas
                  </h3>
                  <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                      type="text" 
                      placeholder="Buscar permissão..." 
                      className="w-full pl-10 pr-4 py-2 text-sm bg-white border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                      value={permSearch}
                      onChange={(e) => setPermSearch(e.target.value)}
                    />
                  </div>
                </div>

                <div className="space-y-10">
                  {['Gestão', 'Administrativo', 'Operacional'].map(group => {
                    const permsInGroup = filteredPermissions.filter(p => p.group === group);
                    if (permsInGroup.length === 0) return null;

                    const groupPermIds = permsInGroup.map(p => p.id);
                    const allInGroupSelected = groupPermIds.every(p => newPermissions.includes(p));
                    const someInGroupSelected = groupPermIds.some(p => newPermissions.includes(p)) && !allInGroupSelected;

                    return (
                      <div key={group} className="space-y-4">
                        <div className="flex justify-between items-center bg-slate-50/50 p-3 rounded-2xl border border-slate-100">
                          <h4 className="text-xs font-black uppercase text-indigo-600 tracking-wider flex items-center gap-2">
                            <Lock size={14} /> {group}
                          </h4>
                          <button 
                            onClick={() => toggleGroupPermissions(group)}
                            className={`flex items-center gap-2 px-4 py-1.5 rounded-xl text-[10px] font-black uppercase transition-all ${
                              allInGroupSelected 
                                ? 'bg-rose-50 text-rose-600 border border-rose-100' 
                                : 'bg-indigo-50 text-indigo-700 border border-indigo-100 hover:bg-indigo-100'
                            }`}
                          >
                            {allInGroupSelected ? <Square size={12} /> : someInGroupSelected ? <CheckSquare size={12} /> : <CheckSquare size={12} />}
                            {allInGroupSelected ? 'Desmarcar Grupo' : 'Selecionar Grupo'}
                          </button>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {permsInGroup.map(perm => {
                            const isSelected = newPermissions.includes(perm.id);
                            return (
                              <button key={perm.id} onClick={() => togglePermission(perm.id)} className={`flex items-start gap-5 p-5 rounded-[1.5rem] border-2 transition-all text-left group relative ${isSelected ? 'border-emerald-500 bg-emerald-50/20 shadow-lg shadow-emerald-50/50' : 'border-slate-50 bg-slate-50/40 hover:bg-white hover:border-slate-200'}`}>
                                <div className={`mt-0.5 w-6 h-6 rounded-lg flex items-center justify-center border-2 transition-all ${isSelected ? 'bg-emerald-500 border-emerald-500 text-white scale-110' : 'bg-white border-slate-200 text-transparent group-hover:border-slate-300'}`}>
                                  <Check size={16} strokeWidth={4} />
                                </div>
                                <div>
                                  <p className={`text-sm font-black ${isSelected ? 'text-emerald-900' : 'text-slate-800'}`}>{perm.label}</p>
                                  <p className={`text-[10px] font-medium leading-relaxed mt-1 ${isSelected ? 'text-emerald-700/70' : 'text-slate-500'}`}>{perm.description}</p>
                                </div>
                                {isSelected && (
                                  <div className="absolute top-2 right-2 flex gap-1">
                                    <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></span>
                                  </div>
                                )}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Secão 4: Observações */}
              <div className="space-y-6">
                <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
                  <span className="w-6 h-px bg-slate-200"></span> Observações Internas
                </h3>
                <div className="relative group">
                  <FileText className="absolute left-5 top-5 text-slate-300 group-focus-within:text-indigo-500 transition-colors" size={20} />
                  <textarea 
                    rows={4}
                    placeholder="Notas adicionais sobre competências, restrições ou anotações administrativas..."
                    className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all resize-none text-sm font-medium text-slate-600"
                    value={newObservations}
                    onChange={(e) => setNewObservations(e.target.value)}
                  />
                </div>
              </div>
            </div>

            <div className="p-8 border-t bg-slate-50/50 flex gap-4 justify-end">
              <button onClick={() => setShowModal(false)} className="px-8 py-4 rounded-2xl font-black text-slate-500 hover:bg-white transition-all border border-transparent hover:border-slate-200 uppercase tracking-widest text-xs">Cancelar</button>
              <button onClick={handleSaveUser} disabled={!newName || !newEmail || newPermissions.length === 0} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 disabled:opacity-50 disabled:grayscale disabled:cursor-not-allowed uppercase tracking-widest text-xs flex items-center gap-2">
                <Check size={18} /> Criar Novo Acesso
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Edit Role Preset */}
      {editingRole && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-amber-50/30">
              <div className="flex items-center gap-4">
                <div className="bg-amber-500 p-3 rounded-2xl text-white shadow-lg shadow-amber-100">
                  <Settings2 size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black text-slate-800">Preset: {editingRole}</h2>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Configure as permissões padrão do cargo</p>
                </div>
              </div>
              <button onClick={() => setEditingRole(null)} className="p-2 hover:bg-white rounded-full text-slate-400"><X size={24} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {['Gestão', 'Administrativo', 'Operacional'].map(group => (
                <div key={group} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 border-b pb-1 tracking-widest">{group}</h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {ALL_PERMISSIONS.filter(p => p.group === group).map(perm => (
                      <button key={perm.id} onClick={() => togglePresetPermission(perm.id)} className={`flex items-start gap-4 p-4 rounded-2xl border-2 transition-all text-left ${rolePresetPermissions.includes(perm.id) ? 'border-amber-500 bg-amber-50/20' : 'border-slate-50 bg-slate-50/50 hover:bg-white hover:border-slate-200'}`}>
                        <div className={`mt-0.5 w-5 h-5 rounded-lg flex items-center justify-center border-2 ${rolePresetPermissions.includes(perm.id) ? 'bg-amber-500 border-amber-500 text-white' : 'bg-white border-slate-200'}`}>{rolePresetPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}</div>
                        <div>
                          <p className={`text-sm font-bold ${rolePresetPermissions.includes(perm.id) ? 'text-amber-900' : 'text-slate-700'}`}>{perm.label}</p>
                          <p className="text-[10px] text-slate-500 font-medium leading-tight mt-1">{perm.description}</p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4 justify-end">
              <button onClick={() => setEditingRole(null)} className="px-8 py-4 rounded-xl font-bold text-slate-500 hover:bg-white transition-all border border-transparent hover:border-slate-200 uppercase text-xs tracking-widest">Cancelar</button>
              <button onClick={handleSaveRolePreset} className="bg-amber-500 text-white px-10 py-4 rounded-xl font-bold hover:bg-amber-600 shadow-xl shadow-amber-100 uppercase text-xs tracking-widest">Salvar Preset</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersPanel;

export type OrderStatus = 'pending' | 'preparing' | 'ready' | 'delivered' | 'cancelled';

export type UserRole = 'ADMIN' | 'MANAGER' | 'WAITER' | 'CASHIER' | 'CHEF';

export type PaymentMethod = 'dinheiro' | 'cartao_credito' | 'cartao_debito' | 'pix' | 'vale_refeicao';

export type Permission = 
  | 'dashboard_view' 
  | 'pos_access' 
  | 'tables_manage' 
  | 'kds_view' 
  | 'delivery_manage' 
  | 'inventory_edit' 
  | 'finance_view' 
  | 'cmv_analysis' 
  | 'users_manage';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface PriceHistory {
  date: string; // ISO string para facilitar serialização/gráficos
  price: number;
  cost: number;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
  priceHistory?: PriceHistory[];
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
  observation?: string;
  seat?: string;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  createdAt: Date;
  customerName?: string;
  courierId?: string;
  paymentMethod?: PaymentMethod;
  isFiscalIssued?: boolean;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
  items: OrderItem[];
  total: number;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

