import { GoogleGenAI, Type } from "@google/genai";

export const getManagerInsights = async (salesData: any, inventoryData: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analise os seguintes dados de um restaurante e forneça 3 insights estratégicos curtos (máximo 2 frases cada) para o gestor.
  Vendas do dia: ${JSON.stringify(salesData)}
  Estoque baixo: ${JSON.stringify(inventoryData.filter((i: any) => i.stock < 10))}

  Considere CMV, lucro e eficiência operacional.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Insight Error:", error);
    return "Não foi possível carregar os insights da IA no momento.";
  }
};

export const analyzeCMV = async (products: any[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Analise o CMV destes produtos e sugira ajustes de preços se necessário. Retorne um JSON formatado com sugestões.
      Produtos: ${JSON.stringify(products)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              productName: { type: Type.STRING },
              currentCMV: { type: Type.NUMBER },
              suggestion: { type: Type.STRING },
              newPrice: { type: Type.NUMBER }
            }
          }
        }
      }
    });

    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("CMV Analysis Error:", error);
    return [];
  }
};

export const generateProductImage = async (productName: string, category: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Uma foto profissional de comida em estilo de menu de restaurante: ${productName}, categoria ${category}. Fundo neutro, iluminação de estúdio, alta resolução.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Generation Error:", error);
    return null;
  }
};

