import React, { useState } from 'react';
import { Product } from '../types';
import { CATEGORIES } from '../constants';
import { generateProductImage } from '../services/gemini';
import { 
  Edit3, Package, TrendingUp, AlertCircle, Save, X, 
  Search, Filter, Download, Plus, History, 
  Sparkles, Loader2, Image as ImageIcon, Zap
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface InventoryProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Inventory: React.FC<InventoryProps> = ({ products, onUpdateProduct }) => {
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('Todos');
  const [generatingId, setGeneratingId] = useState<string | null>(null);
  const [isGeneratingAll, setIsGeneratingAll] = useState(false);

  const handleEditClick = (product: Product) => {
    setEditingProduct({ ...product });
  };

  const handleSave = () => {
    if (editingProduct) {
      onUpdateProduct(editingProduct);
      setEditingProduct(null);
    }
  };

  const handleGenerateImage = async (product: Product) => {
    setGeneratingId(product.id);
    try {
      const imageUrl = await generateProductImage(product.name, product.category);
      if (imageUrl) {
        onUpdateProduct({ ...product, image: imageUrl });
      } else {
        alert("Não foi possível gerar a imagem no momento.");
      }
    } catch (err) {
      console.error(err);
    } finally {
      setGeneratingId(null);
    }
  };

  const handleGenerateAllMissingImages = async () => {
    const missing = products.filter(p => !p.image || p.image.includes('picsum'));
    if (missing.length === 0) {
      alert("Todos os produtos já possuem imagens!");
      return;
    }

    if (!confirm(`Deseja gerar imagens via IA para ${missing.length} produtos? Isso pode levar alguns segundos.`)) return;

    setIsGeneratingAll(true);
    for (const product of missing) {
      setGeneratingId(product.id);
      try {
        const imageUrl = await generateProductImage(product.name, product.category);
        if (imageUrl) {
          onUpdateProduct({ ...product, image: imageUrl });
        }
      } catch (err) {
        console.error(`Erro ao gerar imagem para ${product.name}:`, err);
      }
    }
    setGeneratingId(null);
    setIsGeneratingAll(false);
  };

  const filteredProducts = products.filter(p => 
    (p.name.toLowerCase().includes(searchTerm.toLowerCase())) &&
    (categoryFilter === 'Todos' || p.category === categoryFilter)
  );

  const lowStockCount = products.filter(p => p.stock < 15).length;
  const totalStockValue = products.reduce((acc, p) => acc + (p.stock * p.cost), 0);

  const chartData = editingProduct?.priceHistory?.map(h => ({
    ...h,
    dateFormatted: new Date(h.date).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })
  })) || [];

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Stats Header */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
            <Package size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Total de Itens</p>
            <p className="text-2xl font-black text-slate-800">{products.length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl">
            <AlertCircle size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Estoque Crítico</p>
            <p className="text-2xl font-black text-rose-600">{lowStockCount}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Valor em Estoque</p>
            <p className="text-2xl font-black text-slate-800">R$ {totalStockValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
        </div>
      </div>

      {/* Toolbar */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-4 rounded-3xl border shadow-sm">
        <div className="flex flex-1 gap-4 w-full md:w-auto">
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar no estoque..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="px-4 py-2 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium text-slate-600"
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value)}
          >
            <option>Todos</option>
            {CATEGORIES.map(cat => (
              <option key={cat}>{cat}</option>
            ))}
          </select>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleGenerateAllMissingImages}
            disabled={isGeneratingAll}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all border shadow-sm ${isGeneratingAll ? 'bg-slate-100 text-slate-400' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'}`}
          >
            {isGeneratingAll ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
            {isGeneratingAll ? 'Gerando...' : 'Auto-Gerar Imagens (IA)'}
          </button>
          <button className="flex items-center gap-2 bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100">
            <Plus size={20} /> Novo Produto
          </button>
        </div>
      </div>

      {/* Inventory Table */}
      <div className="bg-white rounded-3xl border shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50/80 border-b">
              <tr>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider">Produto</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider">Categoria</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider text-right">Custo</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider text-right">Preço Venda</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider text-center">Estoque</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 font-bold text-slate-500 text-xs uppercase tracking-wider text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredProducts.map(product => (
                <tr key={product.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="relative w-10 h-10 rounded-xl overflow-hidden border bg-slate-100 group">
                        {product.image ? (
                          <img src={product.image} className="w-full h-full object-cover" alt={product.name} />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-slate-300">
                            <ImageIcon size={20} />
                          </div>
                        )}
                        {(!product.image || product.image.includes('picsum')) && (
                          <button 
                            disabled={generatingId === product.id}
                            onClick={() => handleGenerateImage(product)}
                            className={`absolute inset-0 bg-indigo-600/80 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all ${generatingId === product.id ? 'opacity-100' : ''}`}
                            title="Gerar imagem com IA"
                          >
                            {generatingId === product.id ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
                          </button>
                        )}
                      </div>
                      <span className="font-bold text-slate-800">{product.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-xs font-bold text-slate-500 bg-slate-100 px-3 py-1 rounded-full">{product.category}</span>
                  </td>
                  <td className="px-6 py-4 text-right font-medium text-slate-600">R$ {product.cost.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right font-bold text-indigo-600">R$ {product.price.toFixed(2)}</td>
                  <td className="px-6 py-4 text-center">
                    <span className={`font-mono font-black ${product.stock < 15 ? 'text-rose-600' : 'text-slate-800'}`}>
                      {product.stock}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    {product.stock < 15 ? (
                      <div className="flex items-center gap-1.5 text-rose-600 font-black text-[10px] uppercase tracking-tighter">
                        <AlertCircle size={14} /> Reposição Necessária
                      </div>
                    ) : (
                      <div className="flex items-center gap-1.5 text-emerald-600 font-black text-[10px] uppercase tracking-tighter">
                        <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></div> Em estoque
                      </div>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => handleEditClick(product)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit3 size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Edit Modal */}
      {editingProduct && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">
            <div className="p-8 border-b flex justify-between items-center bg-indigo-50/30">
              <div className="flex items-center gap-4">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white">
                  <Edit3 size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black text-slate-800">Editar Produto</h2>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Gestão detalhada e histórico de preços</p>
                </div>
              </div>
              <button onClick={() => setEditingProduct(null)} className="p-3 hover:bg-white rounded-full transition-all text-slate-400">
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                {/* Coluna 1: Dados Cadastrais */}
                <div className="space-y-6">
                  <h3 className="text-sm font-black uppercase text-slate-400 border-b pb-2 tracking-widest flex items-center gap-2">
                    <Package size={16} /> Dados Principais
                  </h3>
                  <div className="grid grid-cols-1 gap-6">
                    <div className="flex gap-4 items-end">
                      <div className="flex-1 space-y-2">
                        <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Nome do Produto</label>
                        <input 
                          type="text" 
                          className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium"
                          value={editingProduct.name}
                          onChange={(e) => setEditingProduct({...editingProduct, name: e.target.value})}
                        />
                      </div>
                      <div className="w-20 h-20 rounded-2xl border bg-slate-100 overflow-hidden relative group">
                         {editingProduct.image ? (
                           <img src={editingProduct.image} className="w-full h-full object-cover" />
                         ) : (
                           <div className="w-full h-full flex items-center justify-center text-slate-300">
                             <ImageIcon size={24} />
                           </div>
                         )}
                         <button 
                          onClick={() => handleGenerateImage(editingProduct)}
                          disabled={generatingId === editingProduct.id}
                          className="absolute inset-0 bg-indigo-600/80 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all"
                         >
                            {generatingId === editingProduct.id ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
                         </button>
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Categoria</label>
                      <select 
                        className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium"
                        value={editingProduct.category}
                        onChange={(e) => setEditingProduct({...editingProduct, category: e.target.value})}
                      >
                        {CATEGORIES.map(cat => (
                          <option key={cat} value={cat}>{cat}</option>
                        ))}
                      </select>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Custo (R$)</label>
                        <input 
                          type="number" 
                          step="0.01"
                          className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium"
                          value={editingProduct.cost}
                          onChange={(e) => setEditingProduct({...editingProduct, cost: parseFloat(e.target.value) || 0})}
                        />
                      </div>
                      <div className="space-y-2">
                        <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Venda (R$)</label>
                        <input 
                          type="number" 
                          step="0.01"
                          className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium"
                          value={editingProduct.price}
                          onChange={(e) => setEditingProduct({...editingProduct, price: parseFloat(e.target.value) || 0})}
                        />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Quantidade em Estoque</label>
                      <input 
                        type="number" 
                        className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium"
                        value={editingProduct.stock}
                        onChange={(e) => setEditingProduct({...editingProduct, stock: parseInt(e.target.value) || 0})}
                      />
                    </div>
                  </div>
                </div>

                {/* Coluna 2: Análise Visual de Histórico */}
                <div className="space-y-6">
                  <h3 className="text-sm font-black uppercase text-slate-400 border-b pb-2 tracking-widest flex items-center gap-2">
                    <History size={16} /> Evolução 90 dias (Preço x Custo)
                  </h3>
                  <div className="h-[250px] w-full bg-slate-50 rounded-3xl p-4 border border-slate-100">
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                        <XAxis dataKey="dateFormatted" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 'bold', fill: '#94a3b8'}} />
                        <YAxis hide />
                        <Tooltip 
                          contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', fontWeight: 'bold'}}
                          itemStyle={{fontSize: '12px'}}
                        />
                        <Legend verticalAlign="top" align="right" iconType="circle" />
                        <Line type="monotone" dataKey="price" name="Venda" stroke="#4f46e5" strokeWidth={3} dot={{r: 4, fill: '#4f46e5', strokeWidth: 2, stroke: '#fff'}} activeDot={{r: 6}} />
                        <Line type="monotone" dataKey="cost" name="Custo" stroke="#ef4444" strokeWidth={3} strokeDasharray="5 5" dot={{r: 4, fill: '#ef4444', strokeWidth: 2, stroke: '#fff'}} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>

                  {/* Lista de Registros Recentes */}
                  <div className="space-y-3">
                    <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Registros Recentes</label>
                    <div className="bg-slate-50 rounded-2xl overflow-hidden border border-slate-100">
                      {editingProduct.priceHistory?.slice().reverse().map((record, i) => (
                        <div key={i} className="flex justify-between items-center px-4 py-3 border-b last:border-none text-xs">
                          <span className="font-bold text-slate-400">{new Date(record.date).toLocaleDateString('pt-BR')}</span>
                          <div className="flex gap-4">
                            <span className="font-bold text-slate-600">C: R$ {record.cost.toFixed(2)}</span>
                            <span className="font-black text-indigo-600">V: R$ {record.price.toFixed(2)}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-8 border-t bg-slate-50/50 flex gap-4 justify-end">
              <button 
                onClick={() => setEditingProduct(null)} 
                className="px-8 py-4 rounded-2xl font-black text-slate-500 hover:bg-white transition-all border border-transparent hover:border-slate-200 uppercase tracking-widest text-xs"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSave}
                className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 flex items-center gap-2 uppercase tracking-widest text-xs"
              >
                <Save size={18} /> Salvar e Atualizar Histórico
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

