import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Plus, Download, Filter } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    addLog('u3', 'KDS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      createdAt: new Date(),
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado como ${newUser.role}`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    const oldUser = users.find(u => u.id === id);
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
    addLog('u1', 'ADMIN', `Cargo de ${oldUser?.name} alterado de ${oldUser?.role} para ${role}`);
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
    addLog('u1', 'ADMIN', `Permissões do cargo ${role} foram atualizadas.`);
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => {
      if (p.id === updatedProduct.id) {
        const hasChanged = p.price !== updatedProduct.price || p.cost !== updatedProduct.cost;
        let newHistory = updatedProduct.priceHistory || [];

        if (hasChanged) {
          const newEntry: PriceHistory = {
            date: new Date().toISOString().split('T')[0],
            price: updatedProduct.price,
            cost: updatedProduct.cost
          };
          newHistory = [...newHistory, newEntry];
        }

        return { ...updatedProduct, priceHistory: newHistory };
      }
      return p;
    }));
    addLog('u1', 'ESTOQUE', `Produto ${updatedProduct.name} atualizado (Estoque: ${updatedProduct.stock}, Preço: R$ ${updatedProduct.price.toFixed(2)})`);
  };

  const handleUpdateTable = (tableId: number, items: OrderItem[], status: Table['status']) => {
    setTables(prev => prev.map(t => {
      if (t.id === tableId) {
        const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        return { ...t, items, status, total };
      }
      return t;
    }));
  };

  const handleCloseTable = (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => {
    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: table.items,
      total: table.total,
      status: 'delivered',
      type: 'table',
      paymentMethod,
      isFiscalIssued: isFiscal
    };

    setOrders(prev => [newOrder, ...prev]);
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], total: 0, status: 'cleaning' } : t));
    addLog('u1', 'MESA', `Mesa ${tableId} fechada. Total R$ ${table.total.toFixed(2)} (${paymentMethod})`);

    setTimeout(() => {
      setTables(prev => prev.map(t => t.id === tableId && t.status === 'cleaning' ? { ...t, status: 'available' } : t));
    }, 5000);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts 
                  products={products} 
                  onNavigateToInventory={() => setActiveTab('inventory')} 
                />
                <div className="bg-white p-6 rounded-3xl border shadow-sm">
                  <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-bold">Vendas Recentes</h3>
                    <div className="flex gap-2">
                      <button className="p-2 hover:bg-slate-50 rounded-lg"><Filter size={20} /></button>
                      <button className="p-2 hover:bg-slate-50 rounded-lg"><Download size={20} /></button>
                    </div>
                  </div>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={[
                        { name: 'Seg', sales: 4000 },
                        { name: 'Ter', sales: 3000 },
                        { name: 'Qua', sales: 2000 },
                        { name: 'Qui', sales: 2780 },
                        { name: 'Sex', sales: 1890 },
                        { name: 'Sáb', sales: 2390 },
                        { name: 'Dom', sales: 3490 },
                      ]}>
                        <defs>
                          <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} />
                        <YAxis axisLine={false} tickLine={false} />
                        <Tooltip />
                        <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit">
                <h3 className="text-xl font-bold mb-6">Top Pratos</h3>
                <div className="flex-1 space-y-6">
                  {products.slice(0, 4).map((p, i) => (
                    <div key={p.id} className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-100 rounded-xl flex items-center justify-center font-bold text-slate-500">
                        #{i + 1}
                      </div>
                      <div className="flex-1">
                        <p className="font-semibold text-slate-800">{p.name}</p>
                        <p className="text-xs text-slate-500">{Math.floor(Math.random() * 100)} vendidos este mês</p>
                      </div>
                      <div className="text-indigo-600 font-bold text-sm">R$ {p.price.toFixed(2)}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        );
      case 'pos':
        return <POS products={products} onPlaceOrder={handlePlaceOrder} />;
      case 'tables':
        return <Tables tables={tables} products={products} onUpdateTable={handleUpdateTable} onCloseTable={handleCloseTable} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={handleUpdateProduct} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'ai-cmv':
        return (
          <div className="space-y-6">
            <div className="bg-indigo-900 text-white p-8 rounded-3xl">
              <h2 className="text-2xl font-bold mb-2">Otimização de CMV com IA</h2>
              <p className="text-indigo-200">Margens inteligentes para o seu negócio.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {products.slice(0, 4).map(p => {
                const cmv = (p.cost / p.price) * 100;
                return (
                  <div key={p.id} className="bg-white border-2 border-slate-100 p-6 rounded-2xl">
                    <h3 className="font-bold text-lg mb-2">{p.name}</h3>
                    <div className={`px-3 py-1 inline-block rounded-lg font-bold ${cmv > 35 ? 'bg-rose-100 text-rose-700' : 'bg-emerald-100 text-emerald-700'}`}>
                      CMV: {cmv.toFixed(1)}%
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">Unidade Centro - São Paulo</h2>
            <h1 className="text-3xl font-black text-slate-800 text-capitalize">
              {activeTab === 'dashboard' ? 'Bem-vindo, Gestor' : 
               activeTab === 'pos' ? 'Caixa Operacional' : 
               activeTab === 'users' ? 'Gestão de Equipe' :
               activeTab === 'inventory' ? 'Estoque Central' :
               activeTab === 'finance' ? 'Gestão Financeira' :
               activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="font-bold text-slate-800">Cozinha: Aberta</p>
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Sincronizado
              </p>
            </div>
            <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-black border-2 border-indigo-200">JS</div>
          </div>
        </header>
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { FinancialRecord, Order } from '../types';
import { 
  TrendingUp, TrendingDown, DollarSign, Wallet, 
  ArrowUpRight, ArrowDownRight, Plus, Search, 
  Filter, Download, Calendar, PieChart, 
  ArrowRightLeft, FileText, CheckCircle2, AlertCircle, X, Save
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer, BarChart, Bar, Legend 
} from 'recharts';

interface FinanceProps {
  orders: Order[];
}

const Finance: React.FC<FinanceProps> = ({ orders }) => {
  const [activeView, setActiveView] = useState<'overview' | 'transactions'>('overview');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<'all' | 'income' | 'expense'>('all');

  // Form states
  const [formType, setFormType] = useState<'income' | 'expense'>('expense');
  const [formAmount, setFormAmount] = useState('');
  const [formCategory, setFormCategory] = useState('Fornecedores');
  const [formDesc, setFormDesc] = useState('');

  const [manualRecords, setManualRecords] = useState<FinancialRecord[]>([
    { id: 'm1', type: 'expense', amount: 2500, category: 'Aluguel', description: 'Aluguel Unidade Centro', date: new Date('2024-11-01') },
    { id: 'm2', type: 'expense', amount: 850, category: 'Utilidades', description: 'Conta de Luz Nov/24', date: new Date('2024-11-05') },
    { id: 'm3', type: 'expense', amount: 1200, category: 'Fornecedores', description: 'Compra de Insumos - Hortifruti', date: new Date('2024-11-10') },
  ]);

  const incomeFromOrders = useMemo(() => orders.map(order => ({
    id: order.id,
    type: 'income' as const,
    amount: order.total,
    category: 'Vendas PDV',
    description: `Pedido #${order.id.slice(-4)} (${order.type})`,
    date: order.createdAt
  })), [orders]);

  const allRecords = useMemo(() => [
    ...incomeFromOrders,
    ...manualRecords
  ].sort((a, b) => b.date.getTime() - a.date.getTime()), [incomeFromOrders, manualRecords]);

  const handleSaveRecord = () => {
    if (!formAmount || !formDesc) return;
    const newRecord: FinancialRecord = {
      id: Math.random().toString(36).substr(2, 9),
      type: formType,
      amount: parseFloat(formAmount),
      category: formCategory,
      description: formDesc,
      date: new Date()
    };
    setManualRecords([newRecord, ...manualRecords]);
    setShowAddModal(false);
    setFormAmount('');
    setFormDesc('');
  };

  const stats = useMemo(() => {
    const totalIncome = allRecords.filter(r => r.type === 'income').reduce((acc, r) => acc + r.amount, 0);
    const totalExpense = allRecords.filter(r => r.type === 'expense').reduce((acc, r) => acc + r.amount, 0);
    const netProfit = totalIncome - totalExpense;
    const avgTicket = orders.length > 0 ? totalIncome / orders.length : 0;
    return { totalIncome, totalExpense, netProfit, avgTicket };
  }, [allRecords, orders]);

  const chartData = useMemo(() => {
    return [
      { name: 'Seg', entrada: 4200, saida: 1200 },
      { name: 'Ter', entrada: 3800, saida: 1500 },
      { name: 'Qua', entrada: 5100, saida: 1100 },
      { name: 'Qui', entrada: 4900, saida: 1800 },
      { name: 'Sex', entrada: 7200, saida: 2200 },
      { name: 'Sáb', entrada: 8500, saida: 2500 },
      { name: 'Dom', entrada: 6400, saida: 1400 },
    ];
  }, []);

  const filteredRecords = allRecords.filter(r => {
    const matchesSearch = r.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          r.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = filterType === 'all' || r.type === filterType;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
          <button 
            onClick={() => setActiveView('overview')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeView === 'overview' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <PieChart size={16} /> Dashboard
          </button>
          <button 
            onClick={() => setActiveView('transactions')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeView === 'transactions' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <ArrowRightLeft size={16} /> Lançamentos
          </button>
        </div>

        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
        >
          <Plus size={18} strokeWidth={3} /> Novo Lançamento
        </button>
      </div>

      {activeView === 'overview' ? (
        <div className="space-y-8">
          {/* Stats Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform">
                <ArrowUpRight size={64} className="text-emerald-600" />
              </div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Receita Bruta</p>
              <h3 className="text-3xl font-black text-slate-800 tracking-tighter">R$ {stats.totalIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
              <div className="mt-4 flex items-center gap-1 text-emerald-500 text-xs font-bold">
                <TrendingUp size={14} /> +12% vs mês ant.
              </div>
            </div>

            <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform">
                <ArrowDownRight size={64} className="text-rose-600" />
              </div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Despesas Operacionais</p>
              <h3 className="text-3xl font-black text-slate-800 tracking-tighter">R$ {stats.totalExpense.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
              <div className="mt-4 flex items-center gap-1 text-rose-500 text-xs font-bold">
                <TrendingDown size={14} /> -3% vs mês ant.
              </div>
            </div>

            <div className="bg-gradient-to-br from-indigo-600 to-violet-700 p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:scale-110 transition-transform text-white">
                <DollarSign size={64} />
              </div>
              <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest mb-2">Lucro Líquido</p>
              <h3 className="text-3xl font-black text-white tracking-tighter">R$ {stats.netProfit.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
              <div className="mt-4 flex items-center gap-1 text-indigo-100 text-xs font-bold">
                <CheckCircle2 size={14} /> Margem de {(stats.totalIncome > 0 ? (stats.netProfit / stats.totalIncome) * 100 : 0).toFixed(1)}%
              </div>
            </div>

            <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform">
                <Wallet size={64} className="text-amber-600" />
              </div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Ticket Médio</p>
              <h3 className="text-3xl font-black text-slate-800 tracking-tighter">R$ {stats.avgTicket.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
              <div className="mt-4 flex items-center gap-1 text-amber-600 text-xs font-bold">
                <FileText size={14} /> Base: {orders.length} pedidos
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border shadow-sm">
              <div className="flex justify-between items-center mb-10">
                <div>
                  <h3 className="text-xl font-black text-slate-800 tracking-tight">Fluxo de Caixa Semanal</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Entradas vs Saídas por dia</p>
                </div>
              </div>
              <div className="h-[350px]">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient id="colorEntrada" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                      </linearGradient>
                      <linearGradient id="colorSaida" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 'bold', fill: '#94a3b8'}} />
                    <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 'bold', fill: '#94a3b8'}} />
                    <Tooltip contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', fontWeight: 'bold'}} />
                    <Area type="monotone" dataKey="entrada" stroke="#6366f1" fillOpacity={1} fill="url(#colorEntrada)" strokeWidth={4} />
                    <Area type="monotone" dataKey="saida" stroke="#f43f5e" fillOpacity={1} fill="url(#colorSaida)" strokeWidth={4} strokeDasharray="10 5" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="bg-white p-8 rounded-[3rem] border shadow-sm flex flex-col">
              <h3 className="text-xl font-black text-slate-800 tracking-tight mb-8">Composição de Gastos</h3>
              <div className="space-y-6 flex-1">
                {[
                  { label: 'Insumos', value: 45, color: 'bg-indigo-500' },
                  { label: 'Mão de Obra', value: 30, color: 'bg-violet-500' },
                  { label: 'Marketing', value: 10, color: 'bg-amber-500' },
                  { label: 'Fixas/Luz/Gás', value: 15, color: 'bg-emerald-500' },
                ].map(item => (
                  <div key={item.label} className="space-y-2">
                    <div className="flex justify-between items-center text-xs font-black uppercase tracking-widest text-slate-500">
                      <span>{item.label}</span>
                      <span className="text-slate-800">{item.value}%</span>
                    </div>
                    <div className="h-3 w-full bg-slate-100 rounded-full overflow-hidden">
                      <div className={`h-full ${item.color} rounded-full`} style={{ width: `${item.value}%` }}></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
          <div className="p-8 border-b bg-slate-50/50 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div className="relative w-full md:w-96">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Pesquisar transação..."
                className="w-full pl-12 pr-6 py-3 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50/80 border-b">
                <tr>
                  <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Data / Hora</th>
