import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { analyzeCMV } from '../services/gemini';
import { 
  BrainCircuit, Sparkles, TrendingUp, DollarSign, 
  ArrowRight, AlertCircle, CheckCircle2, RefreshCw,
  Zap, Info, Calculator, Percent
} from 'lucide-react';

interface CMVAnalysisProps {
  products: Product[];
}

interface AnalysisResult {
  productName: string;
  currentCMV: number;
  suggestion: string;
  newPrice: number;
}

const CMVAnalysis: React.FC<CMVAnalysisProps> = ({ products }) => {
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<AnalysisResult[]>([]);

  const runAnalysis = async () => {
    setLoading(true);
    try {
      const data = await analyzeCMV(products);
      setResults(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    runAnalysis();
  }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* AI Header Banner */}
      <div className="bg-gradient-to-r from-indigo-900 via-indigo-800 to-violet-900 text-white p-10 rounded-[3rem] shadow-xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-10 opacity-10 animate-pulse">
          <BrainCircuit size={180} />
        </div>
        <div className="relative z-10 max-w-2xl">
          <div className="flex items-center gap-3 mb-4">
            <div className="bg-white/10 p-2 rounded-xl backdrop-blur-md border border-white/20">
              <Sparkles size={24} className="text-amber-300" />
            </div>
            <span className="text-xs font-black uppercase tracking-[0.2em] text-indigo-300">GastroAI Intelligence</span>
          </div>
          <h2 className="text-4xl font-black mb-4 tracking-tighter">Otimização de CMV & Margens</h2>
          <p className="text-indigo-100 text-lg leading-relaxed font-medium">
            Nossa IA analisa em tempo real a flutuação dos custos de insumos e sugere ajustes estratégicos de preços para manter sua lucratividade acima da média do mercado.
          </p>
          <button 
            onClick={runAnalysis}
            disabled={loading}
            className="mt-8 bg-white text-indigo-900 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-3 shadow-2xl disabled:opacity-50"
          >
            {loading ? <RefreshCw size={18} className="animate-spin" /> : <Zap size={18} fill="currentColor" />}
            {loading ? 'Processando Inteligência...' : 'Atualizar Recomendações'}
          </button>
        </div>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {[1, 2, 3].map(i => (
            <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-4 animate-pulse">
              <div className="h-6 bg-slate-100 rounded-full w-3/4"></div>
              <div className="h-20 bg-slate-50 rounded-2xl"></div>
              <div className="flex gap-2">
                <div className="h-8 bg-slate-100 rounded-lg flex-1"></div>
                <div className="h-8 bg-slate-100 rounded-lg flex-1"></div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {results.map((res, idx) => {
            const product = products.find(p => p.name === res.productName);
            const isCritical = res.currentCMV > 35;

            return (
              <div key={idx} className={`bg-white rounded-[2.5rem] border-2 shadow-sm flex flex-col group hover:shadow-xl transition-all duration-300 ${isCritical ? 'border-rose-100' : 'border-slate-100 hover:border-indigo-200'}`}>
                <div className="p-8 space-y-6 flex-1">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1">
                      <h4 className="font-black text-xl text-slate-800 tracking-tight group-hover:text-indigo-600 transition-colors">{res.productName}</h4>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Análise de Performance</p>
                    </div>
                    {isCritical ? (
                      <div className="p-2 bg-rose-50 text-rose-600 rounded-xl" title="CMV Elevado">
                        <AlertCircle size={20} />
                      </div>
                    ) : (
                      <div className="p-2 bg-emerald-50 text-emerald-600 rounded-xl">
                        <CheckCircle2 size={20} />
                      </div>
                    )}
                  </div>

                  {/* Justificação da IA */}
                  <div className={`p-5 rounded-2xl text-xs font-bold leading-relaxed border flex gap-3 ${isCritical ? 'bg-rose-50/50 border-rose-100 text-rose-700' : 'bg-indigo-50/50 border-indigo-100 text-indigo-700'}`}>
                    <Info size={16} className="shrink-0 mt-0.5" />
                    <p>{res.suggestion}</p>
                  </div>

                  {/* Métricas Comparativas */}
                  <div className="grid grid-cols-2 gap-4">
