                        <Line type="monotone" dataKey="cost" name="Custo" stroke="#ef4444" strokeWidth={3} strokeDasharray="5 5" dot={{r: 4, fill: '#ef4444', strokeWidth: 2, stroke: '#fff'}} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>

                  <div className="space-y-3">
                    <label className="text-xs font-black uppercase text-slate-500 tracking-wider ml-1">Registros Recentes</label>
                    <div className="bg-slate-50 rounded-2xl overflow-hidden border border-slate-100">
                      {editingProduct.priceHistory?.slice().reverse().map((record, i) => (
                        <div key={i} className="flex justify-between items-center px-4 py-3 border-b last:border-none text-xs">
                          <span className="font-bold text-slate-400">{new Date(record.date).toLocaleDateString('pt-BR')}</span>
                          <div className="flex gap-4">
                            <span className="font-bold text-slate-600">C: R$ {record.cost.toFixed(2)}</span>
                            <span className="font-black text-indigo-600">V: R$ {record.price.toFixed(2)}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-8 border-t bg-slate-50/50 flex gap-4 justify-end">
