        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState } from 'react';
import { Product } from '../types';
import { CATEGORIES } from '../constants';
import { generateProductImage } from '../services/gemini';
import { 
  Edit3, Package, TrendingUp, AlertCircle, Save, X, 
  Search, Filter, Download, Plus, History, 
  Sparkles, Loader2, Image as ImageIcon, Zap, ChevronDown,
  CheckCircle2
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface InventoryProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Inventory: React.FC<InventoryProps> = ({ products, onUpdateProduct }) => {
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('Todos');
  const [generatingId, setGeneratingId] = useState<string | null>(null);
  const [isGeneratingAll, setIsGeneratingAll] = useState(false);

  const handleEditClick = (product: Product) => {
    setEditingProduct({ ...product });
  };

  const handleSave = () => {
    if (editingProduct) {
      onUpdateProduct(editingProduct);
      setEditingProduct(null);
    }
  };

  const handleGenerateImage = async (product: Product) => {
    setGeneratingId(product.id);
    try {
      const imageUrl = await generateProductImage(product.name, product.category);
      if (imageUrl) {
        onUpdateProduct({ ...product, image: imageUrl });
      } else {
        alert("Não foi possível gerar a imagem no momento.");
      }
    } catch (err) {
      console.error(err);
    } finally {
      setGeneratingId(null);
    }
  };

  const handleGenerateAllMissingImages = async () => {
    const missing = products.filter(p => !p.image || p.image.includes('picsum'));
    if (missing.length === 0) {
      alert("Todos os produtos já possuem imagens!");
      return;
    }

    if (!confirm(`Deseja gerar imagens via IA para ${missing.length} produtos? Isso pode levar alguns segundos.`)) return;

    setIsGeneratingAll(true);
    for (const product of missing) {
      setGeneratingId(product.id);
      try {
        const imageUrl = await generateProductImage(product.name, product.category);
        if (imageUrl) {
          onUpdateProduct({ ...product, image: imageUrl });
        }
      } catch (err) {
        console.error(`Erro ao gerar imagem para ${product.name}:`, err);
      }
    }
    setGeneratingId(null);
    setIsGeneratingAll(false);
  };

  const filteredProducts = products.filter(p => 
    (p.name.toLowerCase().includes(searchTerm.toLowerCase())) &&
    (categoryFilter === 'Todos' || p.category === categoryFilter)
  );

  const lowStockCount = products.filter(p => p.stock < 15).length;
  const totalStockValue = products.reduce((acc, p) => acc + (p.stock * p.cost), 0);

  const chartData = editingProduct?.priceHistory?.map(h => ({
    ...h,
    dateFormatted: new Date(h.date).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })
  })) || [];

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Stats Header */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
            <Package size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Total de Itens</p>
            <p className="text-2xl font-black text-slate-800">{products.length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl">
            <AlertCircle size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Estoque Crítico</p>
            <p className="text-2xl font-black text-rose-600">{lowStockCount}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Valor em Estoque</p>
            <p className="text-2xl font-black text-slate-800">R$ {totalStockValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
        </div>
      </div>

      {/* Toolbar / Filters Area */}
      <div className="bg-white p-6 rounded-[2rem] border shadow-sm space-y-4">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex flex-col sm:flex-row gap-4 w-full lg:w-auto flex-1">
            {/* Search Input */}
            <div className="relative flex-1 max-w-md">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Pesquisar produto ou código..." 
                className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            {/* Category Dropdown Filter */}
            <div className="relative min-w-[200px]">
              <div className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-500 pointer-events-none">
                <Filter size={16} />
              </div>
              <select 
                className="w-full pl-11 pr-10 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold text-sm text-slate-700 appearance-none cursor-pointer"
                value={categoryFilter}
                onChange={(e) => setCategoryFilter(e.target.value)}
              >
                <option value="Todos">Todas as Categorias</option>
                {CATEGORIES.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
                <ChevronDown size={16} />
              </div>
            </div>
          </div>

          <div className="flex gap-3 w-full sm:w-auto">
            <button 
              onClick={handleGenerateAllMissingImages}
              disabled={isGeneratingAll}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest transition-all border shadow-sm ${isGeneratingAll ? 'bg-slate-100 text-slate-400' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'}`}
            >
              {isGeneratingAll ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
              {isGeneratingAll ? 'Gerando...' : 'IA: Gerar Imagens'}
            </button>
            <button className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100">
              <Plus size={18} strokeWidth={3} /> Novo Produto
            </button>
          </div>
        </div>

        {/* Filter Summary Badge */}
        {categoryFilter !== 'Todos' && (
          <div className="flex items-center gap-2 animate-in slide-in-from-left-2 duration-300">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Filtrando por:</span>
            <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-[10px] font-black uppercase flex items-center gap-2 border border-indigo-200">
              {categoryFilter}
              <button onClick={() => setCategoryFilter('Todos')} className="hover:text-rose-500 transition-colors">
                <X size={12} strokeWidth={3} />
              </button>
            </span>
          </div>
        )}
      </div>

      {/* Inventory Table */}
      <div className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b">
              <tr>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Produto</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Categoria</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-right">Custo</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-right">Venda</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-center">Estoque</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Status</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredProducts.length > 0 ? filteredProducts.map(product => (
                <tr key={product.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className="relative w-12 h-12 rounded-2xl overflow-hidden border bg-slate-100 group shadow-sm">
                        {product.image ? (
                          <img src={product.image} className="w-full h-full object-cover" alt={product.name} />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-slate-300">
                            <ImageIcon size={20} />
                          </div>
                        )}
                        {(!product.image || product.image.includes('picsum')) && (
                          <button 
                            disabled={generatingId === product.id}
                            onClick={() => handleGenerateImage(product)}
                            className={`absolute inset-0 bg-indigo-600/90 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all ${generatingId === product.id ? 'opacity-100' : ''}`}
                            title="Gerar imagem com IA"
                          >
                            {generatingId === product.id ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
                          </button>
                        )}
                      </div>
                      <div>
                        <p className="font-black text-slate-800 text-sm">{product.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Cód: #{product.id.padStart(4, '0')}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <span className="text-[10px] font-black uppercase tracking-tight bg-slate-100 text-slate-600 px-3 py-1 rounded-lg border border-slate-200">{product.category}</span>
                  </td>
                  <td className="px-8 py-6 text-right font-bold text-slate-500 text-sm">R$ {product.cost.toFixed(2)}</td>
                  <td className="px-8 py-6 text-right font-black text-indigo-600 text-sm">R$ {product.price.toFixed(2)}</td>
                  <td className="px-8 py-6 text-center">
                    <span className={`font-black text-lg tracking-tighter ${product.stock < 15 ? 'text-rose-600' : 'text-slate-800'}`}>
                      {product.stock}
                    </span>
                  </td>
                  <td className="px-8 py-6">
                    {product.stock < 15 ? (
                      <div className="flex items-center gap-1.5 text-rose-600 font-black text-[9px] uppercase tracking-widest bg-rose-50 px-2 py-1 rounded-full border border-rose-100 w-fit">
                        <AlertCircle size={12} /> Reposição
                      </div>
                    ) : (
                      /* Added CheckCircle2 to fix the 'Cannot find name' error on line 251 */
                      <div className="flex items-center gap-1.5 text-emerald-600 font-black text-[9px] uppercase tracking-widest bg-emerald-50 px-2 py-1 rounded-full border border-emerald-100 w-fit">
                        <CheckCircle2 size={12} /> OK
                      </div>
                    )}
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button 
                      onClick={() => handleEditClick(product)}
                      className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all border border-transparent hover:border-indigo-100"
                    >
                      <Edit3 size={18} />
                    </button>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={7} className="px-8 py-20 text-center">
                    <div className="flex flex-col items-center justify-center gap-4 opacity-30 grayscale">
                      <div className="p-8 border-4 border-dashed rounded-full border-slate-200">
                        <Package size={64} strokeWidth={1} />
                      </div>
                      <p className="font-black uppercase tracking-widest text-sm">Nenhum produto encontrado</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Edit Modal (Mantido sem alterações, apenas para contexto de salvamento) */}
      {editingProduct && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">
            <div className="p-8 border-b flex justify-between items-center bg-indigo-50/30">
              <div className="flex items-center gap-4">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white">
                  <Edit3 size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black text-slate-800">Editar Produto</h2>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Gestão detalhada e histórico de preços</p>
                </div>
              </div>
              <button onClick={() => setEditingProduct(null)} className="p-3 hover:bg-white rounded-full transition-all text-slate-400">
                <X size={24} />
              </button>
