import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import POS from './components/POS';
import Tables from './components/Tables';
import KDS from './components/KDS';
import AIInsights from './components/AIInsights';
import UsersPanel from './components/UsersPanel';
import Inventory from './components/Inventory';
import Finance from './components/Finance';
import Delivery from './components/Delivery';
import CMVAnalysis from './components/CMVAnalysis';
import DashboardAlerts from './components/DashboardAlerts';
import { 
  INITIAL_PRODUCTS, 
  INITIAL_TABLES, 
  INITIAL_COURIERS,
  INITIAL_USERS,
  INITIAL_AUDIT_LOGS,
  ROLE_DEFAULT_PERMISSIONS as INITIAL_ROLE_PERMISSIONS
} from './constants';
import { Product, Table, Order, Courier, FinancialRecord, User, UserRole, AuditLog, Permission, OrderItem, PaymentMethod, PriceHistory } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Plus, Download, Filter } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const handleSendToKitchen = (tableId: number, items: OrderItem[]) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: items,
      total: items.reduce((acc, i) => acc + (i.price * i.quantity), 0),
      status: 'pending',
      type: 'table',
    };
    setOrders(prev => [order, ...prev]);
    addLog('u4', 'COZINHA', `Pedido da mesa ${tableId} enviado para a cozinha`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      createdAt: new Date(),
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateTable = (tableId: number, items: OrderItem[], status: Table['status']) => {
    setTables(prev => prev.map(t => {
      if (t.id === tableId) {
        const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        return { ...t, items, status, total };
      }
      return t;
    }));
  };

  const handleCloseTable = (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => {
    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: table.items,
      total: table.total,
      status: 'delivered',
      type: 'table',
      paymentMethod,
      isFiscalIssued: isFiscal
    };

    setOrders(prev => [newOrder, ...prev]);
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], total: 0, status: 'available' } : t));
    addLog('u1', 'MESA', `Mesa ${tableId} fechada. R$ ${table.total.toFixed(2)}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts 
                  products={products} 
                  onNavigateToInventory={() => setActiveTab('inventory')} 
                />
                <div className="bg-white p-6 rounded-3xl border shadow-sm">
                  <h3 className="text-xl font-bold mb-6">Faturamento Real</h3>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={[
                        { name: 'Seg', sales: 4000 },
                        { name: 'Ter', sales: 3000 },
                        { name: 'Qua', sales: 5000 },
                        { name: 'Qui', sales: 4780 },
                        { name: 'Sex', sales: 8890 },
                        { name: 'Sáb', sales: 9390 },
                        { name: 'Dom', sales: 7490 },
                      ]}>
                        <defs>
                          <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} />
                        <YAxis axisLine={false} tickLine={false} />
                        <Tooltip />
                        <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit">
                <h3 className="text-xl font-bold mb-6">Performance do Dia</h3>
                <div className="flex-1 space-y-6">
                  <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Total em Vendas</p>
                    <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                  </div>
                  <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                    <p className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-1">Pedidos Realizados</p>
                    <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      case 'pos':
        return <POS products={products} onPlaceOrder={handlePlaceOrder} />;
      case 'tables':
        return <Tables tables={tables} products={products} onUpdateTable={handleUpdateTable} onCloseTable={handleCloseTable} onSendToKitchen={handleSendToKitchen} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'delivery':
        return <Delivery orders={orders} couriers={couriers} onUpdateStatus={updateOrderStatus} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={handleUpdateProduct} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Sistema de Gestão</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right">
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Servidor Online
              </p>
              <p className="font-bold text-slate-800">Cozinha Ativa</p>
            </div>
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg shadow-indigo-100">GA</div>
          </div>
        </header>
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Table, Product, OrderItem, PaymentMethod } from '../types';
import { getObservationSuggestions } from '../services/gemini';
import { 
  Users, CreditCard, Utensils, X, Plus, Trash2, 
  Receipt, Wallet, Smartphone, Banknote, ShieldCheck,
  CheckCircle2, Printer, Search, Edit3, User as UserIcon, MessageSquare, Save,
  Minus, Sparkles, Loader2, Send, ChefHat
} from 'lucide-react';

interface TablesProps {
  tables: Table[];
  products: Product[];
  onUpdateTable: (tableId: number, items: OrderItem[], status: Table['status']) => void;
  onCloseTable: (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => void;
  onSendToKitchen: (tableId: number, items: OrderItem[]) => void;
}

const Tables: React.FC<TablesProps> = ({ tables, products, onUpdateTable, onCloseTable, onSendToKitchen }) => {
  const [selectedTable, setSelectedTable] = useState<Table | null>(null);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [isFiscalEmission, setIsFiscalEmission] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSendingToKitchen, setIsSendingToKitchen] = useState(false);
  const [showKitchenSuccess, setShowKitchenSuccess] = useState(false);
  const [productSearch, setProductSearch] = useState('');

  // States para identificação e edição
  const [activeSeat, setActiveSeat] = useState<string>('Geral');
  const [editingItemIndex, setEditingItemIndex] = useState<number | null>(null);
  const [tempObs, setTempObs] = useState('');
  const [tempSeat, setTempSeat] = useState('');
  const [tempQty, setTempQty] = useState<number>(1);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const openTable = (table: Table) => {
    if (table.status === 'available') {
      onUpdateTable(table.id, [], 'occupied');
      setSelectedTable({ ...table, status: 'occupied', items: [], total: 0 });
    } else {
      setSelectedTable(table);
    }
    setActiveSeat('Geral');
  };

  const addToTable = (product: Product) => {
    if (!selectedTable) return;

    const existingIndex = selectedTable.items.findIndex(i => 
      i.productId === product.id && 
      i.seat === activeSeat && 
      !i.observation
    );

    let newItems: OrderItem[];
    if (existingIndex > -1) {
      newItems = [...selectedTable.items];
      newItems[existingIndex] = { 
        ...newItems[existingIndex], 
        quantity: newItems[existingIndex].quantity + 1 
      };
    } else {
      newItems = [...selectedTable.items, { 
        productId: product.id, 
        name: product.name, 
        price: product.price, 
        quantity: 1,
        seat: activeSeat
      }];
    }

    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
  };

  const removeItem = (index: number) => {
    if (!selectedTable) return;
    const newItems = selectedTable.items.filter((_, i) => i !== index);
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
  };

  const startEditItem = async (index: number) => {
    const item = selectedTable!.items[index];
    setEditingItemIndex(index);
    setTempObs(item.observation || '');
    setTempSeat(item.seat || 'Geral');
    setTempQty(item.quantity);

    // Buscar sugestões inteligentes
    setLoadingSuggestions(true);
    try {
      const res = await getObservationSuggestions(item.name);
      setSuggestions(res);
    } catch (err) {
      setSuggestions(["Sem cebola", "Bem passado", "Ponto da casa", "Sem gelo"]);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  const saveItemEdit = () => {
    if (!selectedTable || editingItemIndex === null) return;

    const newItems = [...selectedTable.items];
    newItems[editingItemIndex] = {
      ...newItems[editingItemIndex],
      observation: tempObs.trim(),
      seat: tempSeat.trim() || 'Geral',
      quantity: tempQty > 0 ? tempQty : 1
    };

    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
    setEditingItemIndex(null);
  };

  const handleSendToKitchenLocal = () => {
    if (!selectedTable || selectedTable.items.length === 0) return;

    setIsSendingToKitchen(true);
    // Simular tempo de rede/processamento
    setTimeout(() => {
      onSendToKitchen(selectedTable.id, selectedTable.items);
      setIsSendingToKitchen(false);
      setShowKitchenSuccess(true);
      setTimeout(() => setShowKitchenSuccess(false), 3000);
    }, 1000);
  };

  const handleProcessPayment = (method: PaymentMethod) => {
    if (!selectedTable) return;
    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, method, isFiscalEmission);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
    }, 2000);
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()));

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
        {tables.map(table => (
          <button
            key={table.id}
            onClick={() => openTable(table)}
            disabled={table.status === 'cleaning'}
            className={`aspect-square p-6 rounded-[2rem] border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${getTableStatusColor(table.status)} shadow-sm`}
          >
            <div className="text-current">
              {table.status === 'available' ? <Utensils size={32} /> : 
               table.status === 'occupied' ? <Users size={32} /> : 
               table.status === 'billing' ? <CreditCard size={32} /> : <Utensils size={32} className="animate-spin" />}
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-black">Mesa {table.id}</h3>
              <p className="text-[10px] uppercase font-black tracking-widest opacity-60">{table.status}</p>
            </div>
            {table.total > 0 && (
              <div className="mt-1 text-sm font-black bg-white/60 px-4 py-1.5 rounded-2xl shadow-sm">
                R$ {table.total.toFixed(2)}
              </div>
            )}
          </button>
        ))}
      </div>

      {/* Modal: Consumo da Mesa */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-7xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[90vh] animate-in zoom-in-95 duration-300">

            {/* Lado Esquerdo: Menu */}
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white">
                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h2 className="text-2xl font-black text-slate-800">Cardápio Digital</h2>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Lançamento por assento em tempo real</p>
                  </div>
                  <div className="relative w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      type="text" 
                      placeholder="Pesquisar..."
                      className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                      value={productSearch}
                      onChange={(e) => setProductSearch(e.target.value)}
                    />
                  </div>
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                  {['Todos', 'Lanches', 'Bebidas', 'Entradas', 'Sobremesas'].map(cat => (
                    <button key={cat} className="px-5 py-2 rounded-full bg-slate-100 text-slate-600 text-xs font-bold hover:bg-indigo-600 hover:text-white transition-all whitespace-nowrap">
                      {cat}
                    </button>
                  ))}
                </div>
              </div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 lg:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                  <button
                    key={product.id}
                    onClick={() => addToTable(product)}
                    className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-2 group shadow-sm"
                  >
                    <div className="w-full aspect-square bg-slate-100 rounded-2xl mb-2 overflow-hidden">
                      <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                    </div>
                    <p className="font-black text-slate-800 text-sm leading-tight truncate">{product.name}</p>
                    <div className="flex justify-between items-center mt-auto">
                      <p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p>
                      <Plus size={16} className="text-slate-300 group-hover:text-indigo-600" />
                    </div>
                  </button>
                ))}
              </div>
            </div>

            {/* Lado Direito: Comanda */}
            <div className="w-[450px] flex flex-col bg-white border-l shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white">
                <div className="flex items-center gap-3">
                  <div className="p-3 bg-white/20 rounded-2xl shadow-inner"><Users size={24} /></div>
                  <div>
                    <h2 className="text-xl font-black leading-none">Mesa {selectedTable.id}</h2>
                    <p className="text-[10px] font-bold uppercase opacity-70 tracking-widest mt-1">Gestão de Itens</p>
                  </div>
                </div>
                <button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full transition-colors">
                  <X size={24} />
                </button>
              </div>

              {/* Seletor de Assento */}
              <div className="p-6 bg-slate-50 border-b space-y-3">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <UserIcon size={12} /> Lançar para:
                </p>
                <div className="flex gap-2 overflow-x-auto scrollbar-hide">
                  {['Geral', 'Cadeira 1', 'Cadeira 2', 'Cadeira 3', 'Cadeira 4', '+ Nova'].map(seat => (
                    <button 
                      key={seat}
                      onClick={() => setActiveSeat(seat)}
                      className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border-2 whitespace-nowrap ${activeSeat === seat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}
                    >
                      {seat}
                    </button>
                  ))}
                </div>
              </div>

              {/* Lista de Consumo */}
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {selectedTable.items.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40">
                    <div className="p-8 border-4 border-dashed rounded-full border-slate-200">
                      <Utensils size={64} strokeWidth={1} />
                    </div>
                    <p className="font-black uppercase tracking-tighter">Aguardando Pedidos...</p>
                  </div>
                ) : (
                  selectedTable.items.map((item, index) => (
                    <div key={index} className="bg-slate-50 rounded-[2rem] border border-slate-100 overflow-hidden hover:shadow-md transition-shadow group">
                      <div className="p-5 flex justify-between items-start">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-1">
                            <span className="text-[10px] bg-indigo-100 text-indigo-700 font-black px-2 py-0.5 rounded-full uppercase tracking-tighter">
                              {item.seat || 'Geral'}
                            </span>
                            <p className="font-black text-slate-800">{item.name}</p>
                          </div>
                          <p className="text-xs text-slate-500 font-bold">{item.quantity}x R$ {item.price.toFixed(2)}</p>

                          {item.observation ? (
                            <button 
                              onClick={() => startEditItem(index)}
                              className="mt-2 flex items-start gap-1 text-[11px] font-medium text-amber-600 bg-amber-50 p-2 rounded-xl border border-amber-100 hover:bg-amber-100 transition-colors w-full text-left"
                            >
                              <MessageSquare size={12} className="mt-0.5 shrink-0" />
                              <span className="line-clamp-2">{item.observation}</span>
                            </button>
                          ) : (
                            <button 
                              onClick={() => startEditItem(index)}
                              className="mt-2 flex items-center gap-1.5 text-[10px] font-bold text-slate-400 hover:text-indigo-600 transition-colors group/obs"
                            >
                              <div className="p-1 bg-slate-200 rounded-md group-hover/obs:bg-indigo-100 transition-colors">
                                <Plus size={10} />
                              </div>
                              Adicionar observação
                            </button>
                          )}
                        </div>
                        <div className="text-right flex flex-col items-end gap-2">
                          <p className="font-black text-indigo-600">R$ {(item.price * item.quantity).toFixed(2)}</p>
                          <div className="flex gap-1">
                            <button 
                              onClick={() => startEditItem(index)}
                              className="p-2 text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 rounded-xl transition-all"
                              title="Editar item"
                            >
                              <Edit3 size={16} />
                            </button>
                            <button 
                              onClick={() => removeItem(index)}
                              className="p-2 text-slate-400 hover:bg-rose-50 hover:text-rose-600 rounded-xl transition-all"
                              title="Remover item"
                            >
                              <Trash2 size={16} />
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>

              {/* Rodapé */}
              <div className="p-8 border-t bg-slate-50/50 space-y-6">
                <div className="flex justify-between items-center text-3xl font-black text-slate-800 tracking-tighter">
                  <span>Total</span>
                  <span className="text-indigo-600">R$ {selectedTable.total.toFixed(2)}</span>
                </div>

                {/* Ações de Pedido */}
                <div className="grid grid-cols-2 gap-4">
                  <button 
                    disabled={selectedTable.items.length === 0 || isSendingToKitchen}
                    onClick={handleSendToKitchenLocal}
                    className={`flex flex-col items-center justify-center gap-2 p-5 rounded-[1.5rem] transition-all font-black shadow-lg uppercase text-[10px] tracking-widest relative overflow-hidden ${
                      showKitchenSuccess 
                        ? 'bg-emerald-500 text-white' 
                        : 'bg-violet-600 text-white hover:bg-violet-700'
                    } disabled:opacity-50 disabled:grayscale`}
                  >
                    {isSendingToKitchen ? (
                      <Loader2 size={20} className="animate-spin" />
                    ) : showKitchenSuccess ? (
                      <CheckCircle2 size={20} className="animate-in zoom-in" />
                    ) : (
                      <ChefHat size={20} />
                    )}
                    <span>{showKitchenSuccess ? 'Enviado!' : 'Enviar Cozinha'}</span>
                  </button>

                  <button className="flex flex-col items-center justify-center gap-2 p-5 bg-white border-2 border-slate-200 rounded-[1.5rem] text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all font-bold group shadow-sm uppercase text-[10px] tracking-widest">
                    <Printer size={20} className="group-hover:scale-110 transition-transform" />
                    <span>Pré-Conta</span>
                  </button>
                </div>

                <button 
                  disabled={selectedTable.items.length === 0}
                  onClick={() => setShowPaymentModal(true)}
                  className="w-full flex items-center justify-center gap-3 p-5 bg-emerald-600 text-white rounded-[1.5rem] hover:bg-emerald-700 transition-all font-black shadow-xl shadow-emerald-100 disabled:opacity-50 disabled:grayscale uppercase text-xs tracking-widest"
                >
                  <Receipt size={20} />
                  <span>Fechar Comanda</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Detalhes do Item (Edição de Observação e Quantidade) */}
      {editingItemIndex !== null && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b bg-indigo-50/50 flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-600 text-white rounded-xl">
                   <Edit3 size={18} />
                </div>
                <div>
                  <h3 className="font-black text-slate-800">Detalhes do Item</h3>
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{selectedTable.items[editingItemIndex].name}</p>
                </div>
              </div>
              <button onClick={() => setEditingItemIndex(null)} className="text-slate-400 hover:text-slate-600 p-2"><X size={20} /></button>
            </div>
            <div className="p-8 space-y-6">
              {/* Seletor de Quantidade */}
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Ajustar Quantidade</label>
                <div className="flex items-center justify-center gap-6 bg-slate-50 p-4 rounded-3xl border border-slate-200">
                  <button 
                    onClick={() => setTempQty(Math.max(1, tempQty - 1))}
                    className="w-12 h-12 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 transition-all shadow-sm"
                  >
                    <Minus size={20} />
                  </button>
                  <span className="text-3xl font-black text-slate-800 w-12 text-center">{tempQty}</span>
                  <button 
                    onClick={() => setTempQty(tempQty + 1)}
                    className="w-12 h-12 rounded-2xl bg-indigo-600 border border-indigo-600 flex items-center justify-center text-white hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
                  >
                    <Plus size={20} />
                  </button>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Assento / Identificação</label>
                <div className="relative">
                  <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                  <input 
                    type="text" 
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold text-slate-700"
                    placeholder="Cadeira 1, Carlos..."
                    value={tempSeat}
                    onChange={(e) => setTempSeat(e.target.value)}
                  />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações do Pedido</label>
                  {loadingSuggestions && <Loader2 size={12} className="animate-spin text-indigo-500" />}
                </div>

                {/* Sugestões Inteligentes */}
                <div className="flex flex-wrap gap-2 mb-4">
                  {suggestions.map((suggestion, i) => (
                    <button 
                      key={i}
                      onClick={() => setTempObs(prev => prev ? `${prev}, ${suggestion}` : suggestion)}
                      className="px-3 py-1.5 rounded-xl bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase border border-indigo-100 hover:bg-indigo-600 hover:text-white transition-all flex items-center gap-1.5"
                    >
                      <Sparkles size={10} /> {suggestion}
                    </button>
                  ))}
                </div>

                <div className="relative group">
                  <MessageSquare className="absolute left-4 top-4 text-slate-300 group-focus-within:text-indigo-500 transition-colors" size={18} />
                  <textarea 
                    rows={3}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-slate-600 resize-none"
                    placeholder="Sem cebola, bem passado, gelo e limão..."
                    value={tempObs}
                    onChange={(e) => setTempObs(e.target.value)}
                  />
                </div>
              </div>
            </div>
            <div className="p-6 bg-slate-50 border-t flex gap-3">
              <button 
                onClick={() => setEditingItemIndex(null)}
                className="flex-1 px-4 py-4 rounded-2xl font-black text-slate-500 hover:bg-white transition-all border border-transparent hover:border-slate-200 uppercase tracking-widest text-[10px]"
              >
                Cancelar
              </button>
              <button 
                onClick={saveItemEdit}
                className="flex-1 bg-indigo-600 text-white px-4 py-4 rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 flex items-center justify-center gap-2 uppercase tracking-widest text-[10px]"
              >
                <Save size={18} /> Salvar Detalhes
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Pagamento */}
      {showPaymentModal && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-emerald-600 text-white">
              <div className="flex items-center gap-4">
                <div className="bg-white/20 p-3 rounded-2xl shadow-inner"><Wallet size={24} /></div>
                <div>
                  <h2 className="text-2xl font-black">Finalizar Mesa {selectedTable.id}</h2>
                  <p className="text-xs font-bold opacity-80 uppercase tracking-widest">Pagamento e Emissão de Documento</p>
                </div>
              </div>
              <button onClick={() => setShowPaymentModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>

            <div className="p-10 space-y-10">
              <div className="text-center space-y-2">
                <p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor Total</p>
                <h1 className="text-6xl font-black text-slate-800 tracking-tighter">R$ {selectedTable.total.toFixed(2)}</h1>
              </div>

              <div className={`p-6 rounded-[2rem] border-2 transition-all flex items-center justify-between group cursor-pointer ${isFiscalEmission ? 'bg-indigo-50 border-indigo-500 shadow-inner' : 'bg-slate-50 border-slate-100'}`} onClick={() => setIsFiscalEmission(!isFiscalEmission)}>
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl shadow-sm ${isFiscalEmission ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-400'}`}>
                    <ShieldCheck size={24} />
                  </div>
                  <div>
                    <p className="font-black text-slate-800">Emissão de NFC-e</p>
                    <p className="text-xs font-bold text-slate-500">Documento fiscal automático</p>
                  </div>
                </div>
                <div className={`w-12 h-6 rounded-full relative transition-all ${isFiscalEmission ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                  <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-all ${isFiscalEmission ? 'translate-x-6' : 'translate-x-0'}`}></div>
                </div>
              </div>

              <div className="space-y-4">
                <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Escolha o Método</p>
                <div className="grid grid-cols-2 gap-4">
                  {[
                    { id: 'dinheiro', label: 'Dinheiro', icon: Banknote },
                    { id: 'cartao_credito', label: 'C. Crédito', icon: CreditCard },
                    { id: 'cartao_debito', label: 'C. Débito', icon: CreditCard },
                    { id: 'pix', label: 'PIX Instantâneo', icon: Smartphone },
                  ].map(method => (
                    <button
                      key={method.id}
                      disabled={isProcessing}
                      onClick={() => handleProcessPayment(method.id as PaymentMethod)}
                      className="p-6 rounded-3xl border-2 border-slate-100 bg-slate-50/50 hover:bg-white hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-4 group active:scale-95"
                    >
                      <div className="p-3 bg-white shadow-sm border rounded-2xl w-fit group-hover:bg-indigo-600 group-hover:text-white transition-all">
                        <method.icon size={24} />
                      </div>
                      <p className="font-black text-slate-800">{method.label}</p>
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in">
                <div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div>
                <div className="text-center">
                  <p className="text-xl font-black text-slate-800">Processando Pagamento...</p>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

