                  {(['moto', 'bike', 'car'] as const).map(v => (
                    <button 
                      key={v}
                      onClick={() => setNewCourierVehicle(v)}
                      className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}
                    >
                      {v === 'moto' ? 'Moto' : v === 'bike' ? 'Bike' : 'Carro'}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t flex gap-3">
               <button 
                onClick={() => setShowAddCourierModal(false)}
                className="flex-1 py-4 text-xs font-black text-slate-400 uppercase tracking-widest hover:text-slate-600 transition-colors"
               >
                 Cancelar
               </button>
               <button 
                onClick={handleSaveCourier}
                className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg"
               >
                 Cadastrar
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

