import React, { useState, useMemo } from 'react';
import { Order, Courier } from '../types';
import { 
  Truck, Navigation, Clock, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, ExternalLink, Search,
  X, AlertCircle, UserCheck, Timer, Calendar,
  TrendingUp, DollarSign, Settings, Plus,
  History, Info, Save, UserPlus
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'live' | 'couriers' | 'settings'>('live');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  // Performance Filters
  const [dateFilter, setDateFilter] = useState(new Date().toISOString().split('T')[0]);

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Filtered orders by date for history
  const filteredOrdersByDate = useMemo(() => {
    return deliveryOrders.filter(o => {
      const orderDate = new Date(o.createdAt).toISOString().split('T')[0];
      return orderDate === dateFilter;
    });
  }, [deliveryOrders, dateFilter]);

  const courierStats = useMemo(() => {
    return couriers.map(c => {
      const courierDeliveries = filteredOrdersByDate.filter(o => o.courierId === c.id && o.status === 'delivered');
      return {
        ...c,
        deliveryCount: courierDeliveries.length,
        totalFees: courierDeliveries.reduce((acc, o) => acc + (o.deliveryFee || 0), 0)
      };
    });
  }, [couriers, filteredOrdersByDate]);

  const pendingDeliveries = deliveryOrders.filter(o => ['pending', 'preparing', 'ready'].includes(o.status));
  const inTransitDeliveries = deliveryOrders.filter(o => o.status === 'delivering');

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ name: newCourierName, phone: newCourierPhone, vehicleType: newCourierVehicle });
    setNewCourierName('');
    setNewCourierPhone('');
    setShowAddCourierModal(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Sub-Navigation */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        <button 
          onClick={() => setActiveSubTab('live')}
          className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'live' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Navigation size={16} /> Monitoramento
        </button>
        <button 
          onClick={() => setActiveSubTab('couriers')}
          className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'couriers' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Bike size={16} /> Gestão Motoboys
        </button>
        <button 
          onClick={() => setActiveSubTab('settings')}
          className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'settings' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Settings size={16} /> Configurações
        </button>
      </div>

      {activeSubTab === 'live' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Aguardando Coleta */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Aguardando Coleta ({pendingDeliveries.length})
            </h3>
            <div className="space-y-4">
              {pendingDeliveries.map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${order.status === 'ready' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                        {order.status === 'ready' ? 'Pronto' : 'Em Preparo'}
                      </span>
                      <h4 className="text-xl font-black text-slate-800 mt-2">#{order.id.slice(-4)}</h4>
                    </div>
                    <div className="text-right">
                      <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <p className="text-xs font-bold text-slate-500 flex items-center gap-2">
                      <MapPin size={14} className="text-rose-500" /> {order.customerAddress || 'Endereço não informado'}
                    </p>
                  </div>
                  <button 
                    onClick={() => setSelectedOrderId(order.id)}
                    disabled={order.status !== 'ready'}
                    className={`w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 shadow-lg transition-all ${order.status === 'ready' ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-100 text-slate-400'}`}
                  >
                    Atribuir Motoboy
                  </button>
                </div>
              ))}
            </div>
          </div>

          {/* Em Rota */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Navigation size={16} className="text-indigo-600" /> Em Rota ({inTransitDeliveries.length})
            </h3>
            <div className="space-y-4">
              {inTransitDeliveries.map(order => {
                const courier = couriers.find(c => c.id === order.courierId);
                return (
                  <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border shadow-sm space-y-4 border-l-4 border-l-indigo-600">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
                        <Bike size={20} />
                      </div>
                      <div>
                        <p className="text-xs font-black text-slate-800">{courier?.name || 'Motoboy'}</p>
                        <p className="text-[9px] font-bold text-slate-400 uppercase">Pedido #{order.id.slice(-4)}</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => onUpdateStatus(order.id, 'delivered')}
                      className="w-full border-2 border-emerald-100 text-emerald-600 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-50 transition-all flex items-center justify-center gap-2"
                    >
                      Finalizar Entrega
                    </button>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Resumo Rápido */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <TrendingUp size={16} /> Hoje
            </h3>
            <div className="bg-indigo-600 text-white p-8 rounded-[3rem] shadow-xl relative overflow-hidden">
               <div className="relative z-10 space-y-4">
                  <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Total Entregas</p>
                  <h2 className="text-5xl font-black tracking-tighter">{deliveryOrders.filter(o => o.status === 'delivered').length}</h2>
                  <div className="pt-4 border-t border-white/20">
                    <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Taxas Acumuladas</p>
                    <p className="text-2xl font-black">R$ {deliveryOrders.filter(o => o.status === 'delivered').reduce((acc, o) => acc + (o.deliveryFee || 0), 0).toFixed(2)}</p>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="date" 
                  className="pl-10 pr-4 py-2 bg-white border rounded-xl font-bold text-xs outline-none focus:ring-2 focus:ring-indigo-500"
                  value={dateFilter}
                  onChange={(e) => setDateFilter(e.target.value)}
                />
              </div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Filtrando performance por dia</p>
            </div>
            <button 
              onClick={() => setShowAddCourierModal(true)}
              className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg flex items-center gap-2"
            >
              <Plus size={16} /> Novo Motoboy
            </button>
          </div>

          <div className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Entregador</th>
                  <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Status Atual</th>
                  <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-center">Entregas ({dateFilter})</th>
                  <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-right">Taxas Geradas</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {courierStats.map(courier => (
                  <tr key={courier.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400">
                          <UserIcon size={20} />
                        </div>
                        <div>
                          <p className="font-black text-slate-800">{courier.name}</p>
                          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{courier.phone}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${courier.status === 'available' ? 'bg-emerald-50 text-emerald-600' : courier.status === 'delivering' ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-100 text-slate-400'}`}>
                        {courier.status === 'available' ? 'Disponível' : courier.status === 'delivering' ? 'Em Rota' : 'Offline'}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-center font-black text-slate-700 text-lg">{courier.deliveryCount}</td>
                    <td className="px-8 py-6 text-right font-black text-indigo-600">R$ {courier.totalDeliveriesFee?.toFixed(2) || courier.totalFees.toFixed(2)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeSubTab === 'settings' && (
        <div className="max-w-2xl animate-in slide-in-from-left-4 duration-500">
          <div className="bg-white p-10 rounded-[3rem] border shadow-sm space-y-8">
            <div className="flex items-center gap-4 border-b pb-6">
              <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl shadow-inner">
                <Settings size={24} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-slate-800">Parâmetros de Delivery</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Configure as regras automáticas do sistema</p>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-4">
                   <div className="p-3 bg-white rounded-xl shadow-sm text-indigo-600">
                      <DollarSign size={20} />
                   </div>
                   <div>
                      <p className="font-black text-slate-800">Taxa de Entrega Padrão</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">Aplicada a novos pedidos de delivery</p>
                   </div>
                </div>
                <div className="flex items-center gap-3">
                   <span className="text-lg font-black text-slate-400">R$</span>
                   <input 
                    type="number" 
                    step="0.50"
                    className="w-24 px-4 py-2 border rounded-xl font-black text-indigo-600 outline-none focus:ring-2 focus:ring-indigo-500 text-center"
                    value={deliveryFee}
                    onChange={(e) => onUpdateDeliveryFee(parseFloat(e.target.value) || 0)}
                   />
                </div>
              </div>

              <div className="p-6 bg-indigo-50/30 rounded-[2rem] border border-indigo-100 flex gap-4">
                 <Info size={24} className="text-indigo-600 shrink-0" />
                 <p className="text-xs font-medium text-indigo-700 leading-relaxed">
                   A taxa de entrega é integrada automaticamente ao financeiro como receita bruta e pode ser utilizada para o cálculo de repasse aos motoboys no fechamento de turno.
                 </p>
              </div>
            </div>

            <button className="w-full bg-indigo-600 text-white py-5 rounded-3xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 flex items-center justify-center gap-2">
              <Save size={20} /> Salvar Configurações
            </button>
          </div>
        </div>
      )}

      {/* Modal: Atribuir Motoboy */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center">
              <h2 className="text-xl font-black">Selecionar Motoboy</h2>
              <button onClick={() => setSelectedOrderId(null)}><X size={24} className="text-slate-400" /></button>
            </div>
            <div className="p-6 space-y-4">
              {couriers.filter(c => c.status === 'available').map(courier => (
                <button 
                  key={courier.id}
                  onClick={() => {
                    onAssignCourier(selectedOrderId, courier.id);
                    setSelectedOrderId(null);
                  }}
                  className="w-full flex items-center justify-between p-4 rounded-2xl border hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left"
                >
                  <div className="flex items-center gap-3">
                    <Bike size={20} className="text-slate-400" />
                    <span className="font-bold text-slate-800">{courier.name}</span>
                  </div>
                  <ChevronRight size={18} className="text-slate-300" />
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Novo Motoboy */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg shadow-indigo-200">
                  <UserPlus size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-black text-slate-800">Novo Motoboy</h2>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Cadastro para frotas externas</p>
                </div>
              </div>
              <button onClick={() => setShowAddCourierModal(false)} className="p-3 hover:bg-white rounded-full transition-all text-slate-400">
                <X size={24} />
              </button>
            </div>

            <div className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                <input 
                  type="text" 
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold text-slate-700"
                  placeholder="Ex: João Motoboy..."
                  value={newCourierName}
                  onChange={(e) => setNewCourierName(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telefone / WhatsApp</label>
