                  <button onClick={() => setTempQty(Math.max(1, tempQty - 1))} className="w-12 h-12 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 transition-all shadow-sm">
                    <Minus size={20} />
                  </button>
                  <span className="text-3xl font-black text-slate-800 w-12 text-center">{tempQty}</span>
                  <button onClick={() => setTempQty(tempQty + 1)} className="w-12 h-12 rounded-2xl bg-indigo-600 border border-indigo-600 flex items-center justify-center text-white hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">
                    <Plus size={20} />
                  </button>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Assento / Identificação</label>
                <div className="relative">
                  <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                  <input type="text" className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold text-slate-700" placeholder="Cadeira 1, Carlos..." value={tempSeat} onChange={(e) => setTempSeat(e.target.value)} />
                </div>
              </div>
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações do Pedido</label>
