                </div>
                <div className="flex flex-wrap gap-2 mb-4">
                  {suggestions.map((suggestion, i) => (
                    <button key={i} onClick={() => setTempObs(prev => prev ? `${prev}, ${suggestion}` : suggestion)} className="px-3 py-1.5 rounded-xl bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase border border-indigo-100 hover:bg-indigo-600 hover:text-white transition-all flex items-center gap-1.5">
                      <Sparkles size={10} /> {suggestion}
