export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface PriceHistory {
  date: string;
  price: number;
  cost: number;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
  priceHistory?: PriceHistory[];
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
  observation?: string;
  seat?: string;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  deliveryFee?: number;
  createdAt: Date;
  customerName?: string;
  customerAddress?: string;
  courierId?: string;
  paymentMethod?: PaymentMethod;
  isFiscalIssued?: boolean;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
  items: OrderItem[];
  total: number;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
  vehicleType?: 'bike' | 'moto' | 'car';
  createdAt: Date;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import POS from './components/POS';
import Tables from './components/Tables';
import KDS from './components/KDS';
import AIInsights from './components/AIInsights';
import UsersPanel from './components/UsersPanel';
import Inventory from './components/Inventory';
import Finance from './components/Finance';
import Delivery from './components/Delivery';
import CMVAnalysis from './components/CMVAnalysis';
import DashboardAlerts from './components/DashboardAlerts';
import DigitalMenuConfig from './components/DigitalMenuConfig';
import AdminSettingsComponent from './components/AdminSettings';
import { 
  INITIAL_PRODUCTS, 
  INITIAL_TABLES, 
  INITIAL_COURIERS,
  INITIAL_USERS,
  INITIAL_AUDIT_LOGS,
  ROLE_DEFAULT_PERMISSIONS as INITIAL_ROLE_PERMISSIONS
} from './constants';
import { Product, Table, Order, Courier, FinancialRecord, User, UserRole, AuditLog, Permission, OrderItem, PaymentMethod, PriceHistory, DigitalMenuSettings, AdminSettings } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Plus, Download, Filter } from 'lucide-react';

interface CashSession {
  isOpen: boolean;
  openingValue: number;
  openedAt: Date | null;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS.map(c => ({ ...c, createdAt: new Date() })));
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);
  const [globalDeliveryFee, setGlobalDeliveryFee] = useState(7.00);

  // Cardápio Digital Settings
  const [digitalMenuSettings, setDigitalMenuSettings] = useState<DigitalMenuSettings>({
    primaryColor: '#4f46e5',
    restaurantName: 'GastroAI Bistrô',
    welcomeMessage: 'Olá! Seja bem-vindo ao nosso cardápio digital. Sinta-se em casa e faça seu pedido!',
    allowOrdering: true,
    showStock: true,
    bannerUrl: 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?q=80&w=2070&auto=format&fit=crop',
    logoUrl: ''
  });

  // Admin Settings
  const [adminSettings, setAdminSettings] = useState<AdminSettings>({
    companyName: 'GastroAI Soluções Alimentares LTDA',
    cnpj: '12.345.678/0001-90',
    address: 'Av. Paulista, 1000 - Bela Vista, São Paulo - SP',
    phone: '(11) 4002-8922',
    businessHours: [
      { day: 'Segunda-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Terça-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quarta-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quinta-feira', open: '11:00', close: '23:00', isClosed: false },
      { day: 'Sexta-feira', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Sábado', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Domingo', open: '11:00', close: '20:00', isClosed: true },
    ],
    printing: {
      paperWidth: '80mm',
      autoPrintOrder: true,
      headerText: 'BEM VINDO AO GASTROAI',
      footerText: 'Obrigado e volte sempre!',
      showLogo: true
    },
    apis: {
      googleMapsKey: '',
      whatsappToken: '',
      ifoodWebhook: '',
      integrationActive: false
    }
  });

  // Controle de Caixa
  const [cashSession, setCashSession] = useState<CashSession>({
    isOpen: false,
    openingValue: 0,
    openedAt: null
  });

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({
      isOpen: true,
      openingValue: value,
      openedAt: new Date()
    });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({
      isOpen: false,
      openingValue: 0,
      openedAt: null
    });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      deliveryFee: newOrder.type === 'delivery' ? globalDeliveryFee : 0,
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const handleSendToKitchen = (tableId: number, items: OrderItem[]) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: items,
      total: items.reduce((acc, i) => acc + (i.price * i.quantity), 0),
      status: 'pending',
      type: 'table',
    };
    setOrders(prev => [order, ...prev]);
    addLog('u4', 'COZINHA', `Pedido da mesa ${tableId} enviado para a cozinha`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));

    if (status === 'delivered') {
      const order = orders.find(o => o.id === id);
      if (order?.courierId) {
        setCouriers(prev => prev.map(c => c.id === order.courierId ? { ...c, status: 'available' } : c));
      }
    }

    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAssignCourier = (orderId: string, courierId: string) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    setCouriers(prev => prev.map(c => c.id === courierId ? { ...c, status: 'delivering' } : c));
    addLog('u1', 'ENTREGA', `Entregador atribuído ao pedido #${orderId.slice(-4)}`);
  };

  const handleAddCourier = (newCourier: Partial<Courier>) => {
    const courier: Courier = {
      id: `c${Date.now()}`,
      name: newCourier.name || '',
      phone: newCourier.phone || '',
      status: 'available',
      vehicleType: newCourier.vehicleType || 'moto',
      createdAt: new Date(),
    };
    setCouriers(prev => [...prev, courier]);
    addLog('u1', 'ENTREGA', `Novo entregador cadastrado: ${courier.name}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      createdAt: new Date(),
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateTable = (tableId: number, items: OrderItem[], status: Table['status']) => {
    setTables(prev => prev.map(t => {
      if (t.id === tableId) {
        const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        return { ...t, items, status, total };
      }
      return t;
    }));
  };

  const handleCloseTable = (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => {
    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: table.items,
      total: table.total,
      status: 'delivered',
      type: 'table',
      paymentMethod,
      isFiscalIssued: isFiscal
    };

    setOrders(prev => [newOrder, ...prev]);
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], total: 0, status: 'available' } : t));
    addLog('u1', 'MESA', `Mesa ${tableId} fechada. R$ ${table.total.toFixed(2)}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts 
                  products={products} 
                  onNavigateToInventory={() => setActiveTab('inventory')} 
                />
                <div className="bg-white p-6 rounded-3xl border shadow-sm">
                  <h3 className="text-xl font-bold mb-6">Faturamento Real</h3>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={[
                        { name: 'Seg', sales: 4000 },
                        { name: 'Ter', sales: 3000 },
                        { name: 'Qua', sales: 5000 },
                        { name: 'Qui', sales: 4780 },
                        { name: 'Sex', sales: 8890 },
                        { name: 'Sáb', sales: 9390 },
                        { name: 'Dom', sales: 7490 },
                      ]}>
                        <defs>
                          <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} />
                        <YAxis axisLine={false} tickLine={false} />
                        <Tooltip />
                        <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit">
                <h3 className="text-xl font-bold mb-6">Performance do Dia</h3>
                <div className="flex-1 space-y-6">
                  <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Total em Vendas</p>
                    <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                  </div>
                  <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                    <p className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-1">Pedidos Realizados</p>
                    <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return (
          <Tables 
            tables={tables} 
            products={products} 
            orders={orders}
            cashSession={cashSession}
            onUpdateTable={handleUpdateTable} 
            onCloseTable={handleCloseTable} 
            onSendToKitchen={handleSendToKitchen}
            onOpenCash={handleOpenCash}
            onCloseCash={handleCloseCash}
          />
        );
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'digital-menu':
        return (
          <DigitalMenuConfig 
            settings={digitalMenuSettings} 
            onUpdateSettings={setDigitalMenuSettings}
            products={products}
            tables={tables}
          />
        );
      case 'settings':
        return (
          <AdminSettingsComponent 
            settings={adminSettings}
            onUpdateSettings={setAdminSettings}
          />
        );
      case 'delivery':
        return (
          <Delivery 
            orders={orders} 
            couriers={couriers} 
            onUpdateStatus={updateOrderStatus} 
            onAssignCourier={handleAssignCourier} 
            onAddCourier={handleAddCourier}
            deliveryFee={globalDeliveryFee}
            onUpdateDeliveryFee={setGlobalDeliveryFee}
          />
        );
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={handleUpdateProduct} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Sistema de Gestão</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right">
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Servidor Online
              </p>
              <p className="font-bold text-slate-800">Cozinha Ativa</p>
            </div>
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg shadow-indigo-100">GA</div>
          </div>
        </header>
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

