            <div className="p-8 border-t bg-slate-50/50 flex gap-4 justify-end">
              <button onClick={() => setShowModal(false)} className="px-8 py-4 rounded-2xl font-black text-slate-500 hover:bg-white transition-all border border-transparent hover:border-slate-200 uppercase tracking-widest text-xs">Cancelar</button>
              <button onClick={handleSaveUser} disabled={!newName || !newEmail || newPermissions.length === 0} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 disabled:opacity-50 disabled:grayscale disabled:cursor-not-allowed uppercase tracking-widest text-xs flex items-center gap-2">
                <Check size={18} /> Criar Novo Acesso
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Edit Role Preset */}
      {editingRole && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
