import React from 'react';
import { Order, OrderItem } from '../types';
import { Clock, Check, CheckCircle2 } from 'lucide-react';

interface KDSProps {
  orders: Order[];
  onUpdateStatus: (id: string, status: Order['status']) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, onUpdateStatus }) => {
  const activeOrders = orders.filter(o => ['pending', 'preparing'].includes(o.status));

  const handleSetReady = (order: Order) => {
    const itemDetails = order.items.map(item => `${item.quantity}x ${item.name}`).join(', ');
    const message = `Pedido #${order.id.slice(-4)} finalizado!\nItens concluídos: ${itemDetails}`;

    // Notificação visual para o operador da cozinha
    alert(message);
    console.log(`[KDS Notification] ${message}`);

    onUpdateStatus(order.id, 'ready');
  };

  const handleItemReady = (item: OrderItem) => {
    const message = `Item concluído: ${item.quantity}x ${item.name}`;
    alert(message);
    console.log(`[KDS Item] ${message}`);
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
      {activeOrders.map(order => (
        <div key={order.id} className="bg-white border-2 border-slate-200 rounded-2xl flex flex-col shadow-sm overflow-hidden animate-in zoom-in-95 duration-300">
          <div className={`p-4 flex justify-between items-center ${order.status === 'pending' ? 'bg-rose-50 text-rose-700 border-b border-rose-100' : 'bg-amber-50 text-amber-700 border-b border-amber-100'}`}>
            <div className="flex items-center gap-2">
              <span className="font-black text-xl">#{order.id.slice(-4)}</span>
              <span className="text-[10px] font-black uppercase tracking-widest bg-white/50 px-2 py-0.5 rounded-full">{order.type}</span>
            </div>
            <div className="flex items-center gap-1 font-bold text-xs uppercase tracking-tighter">
              <Clock size={14} />
              Preparo: 12m
            </div>
          </div>

          <div className="flex-1 p-5 space-y-4">
            {order.items.map((item, idx) => (
              <div key={idx} className="flex gap-3 items-center group/item">
                <span className="bg-slate-100 text-slate-700 font-black px-2 py-1 rounded-lg text-xs min-w-[2.2rem] text-center border border-slate-200 shadow-sm">
                  {item.quantity}
                </span>
                <div className="flex-1 min-w-0">
                  <p className="font-bold text-slate-800 leading-tight truncate">{item.name}</p>
                  {item.observation && (
                    <p className="text-[10px] font-bold text-rose-500 mt-0.5 uppercase italic truncate">* {item.observation}</p>
                  )}
                  {item.seat && (
                    <p className="text-[9px] font-black text-indigo-500 mt-0.5 uppercase tracking-tighter truncate">Assento: {item.seat}</p>
                  )}
                </div>
                <button 
                  onClick={() => handleItemReady(item)}
                  className="p-2 text-slate-300 hover:text-emerald-500 hover:bg-emerald-50 rounded-xl transition-all opacity-0 group-hover/item:opacity-100"
                  title="Marcar item individual como pronto"
                >
                  <CheckCircle2 size={18} />
                </button>
              </div>
            ))}
          </div>

          <div className="p-4 border-t bg-slate-50/50 flex gap-2">
            {order.status === 'pending' ? (
              <button 
                onClick={() => onUpdateStatus(order.id, 'preparing')}
                className="flex-1 bg-indigo-600 text-white py-4 rounded-xl font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 uppercase text-xs tracking-widest"
              >
                Iniciar Preparo
              </button>
            ) : (
              <button 
                onClick={() => handleSetReady(order)}
                className="flex-1 bg-emerald-600 text-white py-4 rounded-xl font-black hover:bg-emerald-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-emerald-100 uppercase text-xs tracking-widest"
              >
                <Check size={20} strokeWidth={3} />
                Marcar Pronto
              </button>
            )}
          </div>
        </div>
      ))}

      {activeOrders.length === 0 && (
        <div className="col-span-full h-96 flex flex-col items-center justify-center text-slate-300 gap-4 opacity-50">
          <div className="p-8 border-4 border-dashed rounded-full border-slate-200 animate-pulse">
            <Check size={64} strokeWidth={1} />
          </div>
          <p className="font-black uppercase tracking-widest text-sm">Sem pedidos pendentes na cozinha</p>
        </div>
      )}
    </div>
  );
};

