      { day: 'Segunda-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Terça-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quarta-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quinta-feira', open: '11:00', close: '23:00', isClosed: false },
      { day: 'Sexta-feira', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Sábado', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Domingo', open: '11:00', close: '20:00', isClosed: true },
    ],
    fiscal: {
      environment: 'homologacao',
      certificateStatus: 'valid',
      certificateExpiry: '15/12/2025',
      cscId: '000001',
      cscToken: 'A1B2C3D4E5',
      nextNfceNumber: 154,
      series: 1,
      taxRegRegime: 'simples_nacional'
    } as any,
    printing: {
      paperWidth: '80mm',
      autoPrintOrder: true,
      headerText: 'BEM VINDO AO GASTROAI',
      footerText: 'Obrigado e volte sempre!',
      showLogo: true
    },
    apis: {
      googleMapsKey: '',
      whatsappToken: '',
      ifoodWebhook: '',
      integrationActive: false
    }
  });

  // Controle de Caixa
  const [cashSession, setCashSession] = useState<CashSession>({
    isOpen: false,
    openingValue: 0,
    openedAt: null
  });

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({
      isOpen: true,
      openingValue: value,
      openedAt: new Date()
    });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({
      isOpen: false,
      openingValue: 0,
      openedAt: null
    });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      deliveryFee: newOrder.type === 'delivery' ? globalDeliveryFee : 0,
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const handleSendToKitchen = (tableId: number, items: OrderItem[]) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: items,
      total: items.reduce((acc, i) => acc + (i.price * i.quantity), 0),
      status: 'pending',
      type: 'table',
    };
    setOrders(prev => [order, ...prev]);
    addLog('u4', 'COZINHA', `Pedido da mesa ${tableId} enviado para a cozinha`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));

    if (status === 'delivered') {
      const order = orders.find(o => o.id === id);
      if (order?.courierId) {
        setCouriers(prev => prev.map(c => c.id === order.courierId ? { ...c, status: 'available' } : c));
      }
    }

    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAssignCourier = (orderId: string, courierId: string) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    setCouriers(prev => prev.map(c => c.id === courierId ? { ...c, status: 'delivering' } : c));
    addLog('u1', 'ENTREGA', `Entregador atribuído ao pedido #${orderId.slice(-4)}`);
  };

  const handleAddCourier = (newCourier: Partial<Courier>) => {
    const courier: Courier = {
      id: `c${Date.now()}`,
      name: newCourier.name || '',
      phone: newCourier.phone || '',
      status: 'available',
      vehicleType: newCourier.vehicleType || 'moto',
      createdAt: new Date(),
    };
    setCouriers(prev => [...prev, courier]);
    addLog('u1', 'ENTREGA', `Novo entregador cadastrado: ${courier.name}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      createdAt: new Date(),
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateTable = (tableId: number, items: OrderItem[], status: Table['status']) => {
    setTables(prev => prev.map(t => {
      if (t.id === tableId) {
        const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        return { ...t, items, status, total };
      }
      return t;
    }));
  };

  const handleCloseTable = (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => {
    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: table.items,
      total: table.total,
      status: 'delivered',
      type: 'table',
      paymentMethod,
      isFiscalIssued: isFiscal,
      fiscalKey: isFiscal ? `${Math.random().toString().slice(2, 12)}...` : undefined
    };

    setOrders(prev => [newOrder, ...prev]);
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], total: 0, status: 'available' } : t));
    addLog('u1', 'MESA', `Mesa ${tableId} fechada. R$ ${table.total.toFixed(2)} ${isFiscal ? '(Fiscal Emitido)' : ''}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts 
                  products={products} 
                  onNavigateToInventory={() => setActiveTab('inventory')} 
                />
                <div className="bg-white p-6 rounded-3xl border shadow-sm">
                  <h3 className="text-xl font-bold mb-6">Faturamento Real</h3>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={[
                        { name: 'Seg', sales: 4000 },
                        { name: 'Ter', sales: 3000 },
                        { name: 'Qua', sales: 5000 },
                        { name: 'Qui', sales: 4780 },
                        { name: 'Sex', sales: 8890 },
                        { name: 'Sáb', sales: 9390 },
                        { name: 'Dom', sales: 7490 },
                      ]}>
                        <defs>
                          <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} />
                        <YAxis axisLine={false} tickLine={false} />
                        <Tooltip />
                        <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit">
                <h3 className="text-xl font-bold mb-6">Performance do Dia</h3>
                <div className="flex-1 space-y-6">
                  <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Total em Vendas</p>
                    <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                  </div>
                  <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                    <p className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-1">Pedidos Realizados</p>
                    <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return (
          <Tables 
            tables={tables} 
            products={products} 
            orders={orders}
            cashSession={cashSession}
            onUpdateTable={handleUpdateTable} 
            onCloseTable={handleCloseTable} 
            onSendToKitchen={handleSendToKitchen}
            onOpenCash={handleOpenCash}
            onCloseCash={handleCloseCash}
          />
        );
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'digital-menu':
        return (
          <DigitalMenuConfig 
            settings={digitalMenuSettings} 
            onUpdateSettings={setDigitalMenuSettings}
            products={products}
            tables={tables}
          />
        );
      case 'settings':
        return (
          <AdminSettingsComponent 
            settings={adminSettings}
            onUpdateSettings={setAdminSettings}
          />
        );
      case 'delivery':
        return (
          <Delivery 
            orders={orders} 
            couriers={couriers} 
            onUpdateStatus={updateOrderStatus} 
            onAssignCourier={handleAssignCourier} 
            onAddCourier={handleAddCourier}
            deliveryFee={globalDeliveryFee}
            onUpdateDeliveryFee={setGlobalDeliveryFee}
          />
        );
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={handleUpdateProduct} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Sistema de Gestão</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right">
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Servidor Online
              </p>
              <p className="font-bold text-slate-800">Cozinha Ativa</p>
            </div>
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg shadow-indigo-100">GA</div>
          </div>
        </header>
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Order, Courier } from '../types';
import { 
  Truck, Navigation, Clock, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, ExternalLink, Search,
  X, AlertCircle, UserCheck, Timer, Calendar,
  TrendingUp, DollarSign, Settings, Plus,
  History, Info, Save, UserPlus, ShieldCheck,
  FileText, Loader2
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'live' | 'couriers' | 'settings'>('live');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [issuingFiscalId, setIssuingFiscalId] = useState<string | null>(null);

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  // Performance Filters
  const [dateFilter, setDateFilter] = useState(new Date().toISOString().split('T')[0]);

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Filtered orders by date for history
  const filteredOrdersByDate = useMemo(() => {
    return deliveryOrders.filter(o => {
      const orderDate = new Date(o.createdAt).toISOString().split('T')[0];
      return orderDate === dateFilter;
    });
  }, [deliveryOrders, dateFilter]);

  const courierStats = useMemo(() => {
    return couriers.map(c => {
      const courierDeliveries = filteredOrdersByDate.filter(o => o.courierId === c.id && o.status === 'delivered');
      return {
        ...c,
        deliveryCount: courierDeliveries.length,
        totalFees: courierDeliveries.reduce((acc, o) => acc + (o.deliveryFee || 0), 0)
      };
    });
  }, [couriers, filteredOrdersByDate]);

  const pendingDeliveries = deliveryOrders.filter(o => ['pending', 'preparing', 'ready'].includes(o.status));
  const inTransitDeliveries = deliveryOrders.filter(o => o.status === 'delivering');

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ name: newCourierName, phone: newCourierPhone, vehicleType: newCourierVehicle });
    setNewCourierName('');
    setNewCourierPhone('');
    setShowAddCourierModal(false);
  };

  const handleEmitFiscal = (orderId: string) => {
    setIssuingFiscalId(orderId);
    setTimeout(() => {
      // Simulação de emissão
      setIssuingFiscalId(null);
      alert("NFC-e emitida com sucesso para o pedido #" + orderId.slice(-4));
    }, 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Sub-Navigation */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        <button 
          onClick={() => setActiveSubTab('live')}
          className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'live' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Navigation size={16} /> Monitoramento
        </button>
        <button 
          onClick={() => setActiveSubTab('couriers')}
          className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'couriers' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Bike size={16} /> Gestão Motoboys
        </button>
        <button 
          onClick={() => setActiveSubTab('settings')}
          className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'settings' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Settings size={16} /> Configurações
        </button>
      </div>

      {activeSubTab === 'live' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Aguardando Coleta */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Aguardando Coleta ({pendingDeliveries.length})
            </h3>
            <div className="space-y-4">
              {pendingDeliveries.map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${order.status === 'ready' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                        {order.status === 'ready' ? 'Pronto' : 'Em Preparo'}
                      </span>
                      <h4 className="text-xl font-black text-slate-800 mt-2">#{order.id.slice(-4)}</h4>
                    </div>
                    <div className="text-right flex flex-col items-end gap-1">
                      <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                      {order.isFiscalIssued && (
                        <div className="flex items-center gap-1 text-[9px] font-black text-emerald-500 uppercase">
                           <ShieldCheck size={12} /> Fiscal OK
                        </div>
                      )}
                    </div>
                  </div>
                  <div className="space-y-2">
                    <p className="text-xs font-bold text-slate-500 flex items-center gap-2">
                      <MapPin size={14} className="text-rose-500" /> {order.customerAddress || 'Endereço não informado'}
                    </p>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                     <button 
                        onClick={() => handleEmitFiscal(order.id)}
                        disabled={issuingFiscalId === order.id}
                        className="flex items-center justify-center gap-2 py-3 bg-slate-100 text-slate-600 rounded-xl font-black text-[9px] uppercase hover:bg-indigo-50 hover:text-indigo-600 transition-all disabled:opacity-50"
                     >
                        {issuingFiscalId === order.id ? <Loader2 size={12} className="animate-spin" /> : <FileText size={12} />}
                        Fiscal
                     </button>
                     <button 
                        onClick={() => setSelectedOrderId(order.id)}
                        disabled={order.status !== 'ready'}
                        className={`py-3 rounded-xl font-black text-[9px] uppercase tracking-widest flex items-center justify-center gap-2 shadow-lg transition-all ${order.status === 'ready' ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-50 text-slate-300'}`}
                     >
                        Enviar
                     </button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Em Rota */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Navigation size={16} className="text-indigo-600" /> Em Rota ({inTransitDeliveries.length})
            </h3>
            <div className="space-y-4">
              {inTransitDeliveries.map(order => {
                const courier = couriers.find(c => c.id === order.courierId);
                return (
                  <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border shadow-sm space-y-4 border-l-4 border-l-indigo-600">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
                        <Bike size={20} />
                      </div>
                      <div className="flex-1">
                        <p className="text-xs font-black text-slate-800">{courier?.name || 'Motoboy'}</p>
                        <p className="text-[9px] font-bold text-slate-400 uppercase">Pedido #{order.id.slice(-4)}</p>
                      </div>
                      {order.isFiscalIssued && <ShieldCheck size={18} className="text-emerald-500" />}
                    </div>
                    <button 
                      onClick={() => onUpdateStatus(order.id, 'delivered')}
                      className="w-full border-2 border-emerald-100 text-emerald-600 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-50 transition-all flex items-center justify-center gap-2"
                    >
                      Finalizar Entrega
                    </button>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Resumo Rápido */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <TrendingUp size={16} /> Hoje
            </h3>
            <div className="bg-indigo-600 text-white p-8 rounded-[3rem] shadow-xl relative overflow-hidden">
               <div className="relative z-10 space-y-4">
                  <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Total Entregas</p>
                  <h2 className="text-5xl font-black tracking-tighter">{deliveryOrders.filter(o => o.status === 'delivered').length}</h2>
                  <div className="pt-4 border-t border-white/20">
                    <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Taxas Acumuladas</p>
                    <p className="text-2xl font-black">R$ {deliveryOrders.filter(o => o.status === 'delivered').reduce((acc, o) => acc + (o.deliveryFee || 0), 0).toFixed(2)}</p>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="date" 
                  className="pl-10 pr-4 py-2 bg-white border rounded-xl font-bold text-xs outline-none focus:ring-2 focus:ring-indigo-500"
                  value={dateFilter}
                  onChange={(e) => setDateFilter(e.target.value)}
                />
              </div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Filtrando performance por dia</p>
            </div>
            <button 
              onClick={() => setShowAddCourierModal(true)}
              className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg flex items-center gap-2"
            >
              <Plus size={16} /> Novo Motoboy
            </button>
          </div>

          <div className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Entregador</th>
