                          <p className="font-bold text-slate-800 text-sm line-clamp-1">{product.name}</p>
                          <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">GastroAI Choice</p>
                          <div className="flex justify-between items-center mt-2">
                             <p className="font-black text-indigo-600 text-sm">R$ {product.price.toFixed(2)}</p>
                             <button 
                              className="w-8 h-8 rounded-xl text-white flex items-center justify-center shadow-md shadow-indigo-100"
                              style={{ backgroundColor: settings.primaryColor }}
                             >
                                <Plus size={16} />
