             <div className="w-[380px] h-[780px] bg-slate-900 rounded-[3.5rem] border-[12px] border-slate-800 shadow-[0_0_100px_rgba(79,70,229,0.3)] overflow-hidden relative animate-in zoom-in-95">
                <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-6 bg-slate-800 rounded-b-3xl z-50"></div>

                <div className="h-full bg-white flex flex-col overflow-hidden relative">

                   {/* FLOW: MENU */}
