                           <h3 className="text-lg font-black text-slate-800">Meu Carrinho</h3>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-4">
                           {simCart.map(item => (
                             <div key={item.product.id} className="flex gap-4 p-4 border border-slate-100 rounded-3xl items-center">
                                <img src={item.product.image} className="w-16 h-16 rounded-2xl object-cover border" />
                                <div className="flex-1 min-w-0">
                                   <p className="font-bold text-slate-800 text-sm truncate">{item.product.name}</p>
                                   <p className="text-xs font-black text-indigo-600">R$ {item.product.price.toFixed(2)}</p>
                                </div>
                                <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-2xl">
                                   <button onClick={() => removeFromSimCart(item.product.id)} className="w-8 h-8 rounded-xl bg-white text-slate-500 shadow-sm flex items-center justify-center"><Minus size={14} /></button>
                                   <span className="font-black text-sm w-4 text-center">{item.quantity}</span>
                                   <button onClick={() => addToSimCart(item.product)} className="w-8 h-8 rounded-xl bg-white text-indigo-600 shadow-sm flex items-center justify-center"><Plus size={14} /></button>
                                </div>
                             </div>
                           ))}

                           <div className="mt-8 p-6 bg-slate-50 rounded-[2rem] space-y-3">
                              <div className="flex justify-between text-sm font-bold text-slate-400">
