                                 <span className="text-emerald-500">Grátis</span>
                              </div>
                              <div className="pt-3 border-t flex justify-between items-center font-black text-xl text-slate-800 tracking-tighter">
                                 <span>Total</span>
                                 <span>R$ {simCartTotal.toFixed(2)}</span>
                              </div>
                           </div>
                        </div>

                        <div className="p-6 border-t mt-auto">
                           <button 
                             onClick={() => setTestStep('checkout')}
                             className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl flex items-center justify-center gap-3"
                             style={{ backgroundColor: settings.primaryColor }}
                           >
                              Continuar Pedido
                              <ArrowRight size={18} />
                           </button>
                        </div>
                     </div>
                   )}

                   {/* FLOW: CHECKOUT (IDENTIFICAÇÃO E PAGAMENTO) */}
                   {testStep === 'checkout' && (
                     <div className="h-full flex flex-col animate-in slide-in-from-right-10 duration-300">
                        <div className="p-6 border-b flex items-center gap-4">
                           <button onClick={() => setTestStep('cart')} className="p-2 hover:bg-slate-100 rounded-xl transition-all"><ArrowLeft size={20} /></button>
                           <h3 className="text-lg font-black text-slate-800">Finalizar Pedido</h3>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide">
                           <div className="space-y-4">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><User size={12} /> Identificação</label>
                              <input 
                                 type="text" 
                                 placeholder="Seu Nome Completo" 
                                 className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:ring-2"
                                 style={{ "--tw-ring-color": settings.primaryColor } as any}
                                 value={customerName}
                                 onChange={(e) => setCustomerName(e.target.value)}
                              />
                              <div className="relative">
                                 <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                                 <input 
                                    type="number" 
                                    placeholder="Número da Mesa" 
                                    className="w-full pl-12 pr-6 py-4 bg-slate-50 border rounded-2xl font-bold outline-none"
                                    value={tableNumber}
                                    onChange={(e) => setTableNumber(e.target.value)}
                                 />
                              </div>
                           </div>

                           <div className="space-y-4">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> Método de Pagamento</label>
                              <div className="grid grid-cols-1 gap-3">
                                 {[
                                   { id: 'pix', label: 'PIX (Automático)', icon: Zap, color: 'text-indigo-600' },
                                   { id: 'cartao', label: 'Cartão (Pagar no Terminal)', icon: CreditCard, color: 'text-emerald-600' }
                                 ].map(method => (
                                   <button 
                                     key={method.id}
                                     onClick={() => setPaymentMethod(method.id)}
                                     className={`flex items-center justify-between p-5 rounded-[1.8rem] border-2 transition-all ${paymentMethod === method.id ? 'border-indigo-600 bg-indigo-50/50' : 'bg-slate-50 border-slate-100'}`}
                                   >
                                      <div className="flex items-center gap-4">
                                         <method.icon className={method.color} size={20} />
                                         <span className="font-black text-sm text-slate-800">{method.label}</span>
                                      </div>
                                      {paymentMethod === method.id && <CheckCircle2 size={18} className="text-indigo-600" />}
                                   </button>
                                 ))}
                              </div>
                           </div>
                        </div>

                        <div className="p-6 border-t mt-auto space-y-4">
                           <div className="flex justify-between items-center px-2">
                              <p className="text-slate-400 font-bold text-xs uppercase">Valor a Pagar</p>
                              <p className="text-2xl font-black text-slate-800 tracking-tighter">R$ {simCartTotal.toFixed(2)}</p>
                           </div>
                           <button 
                             onClick={() => setTestStep('success')}
                             disabled={!customerName || !tableNumber || !paymentMethod}
                             className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl flex items-center justify-center gap-3 transition-all disabled:opacity-50"
                             style={{ backgroundColor: settings.primaryColor }}
                           >
                              Confirmar e Enviar Pedido
                           </button>
                        </div>
                     </div>
                   )}

                   {/* FLOW: SUCCESS */}
                   {testStep === 'success' && (
                     <div className="h-full flex flex-col items-center justify-center p-10 text-center space-y-8 animate-in zoom-in-95 duration-500">
                        <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce">
                           <CheckCircle2 size={64} />
                        </div>
                        <div className="space-y-3">
                           <h3 className="text-3xl font-black text-slate-800 tracking-tighter">Pedido Realizado!</h3>
                           <p className="text-slate-500 font-medium">Seu pedido já foi enviado para a cozinha. Agora é só relaxar e aguardar.</p>
                        </div>

                        <div className="w-full p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100 space-y-4">
                           <div className="flex justify-between items-center">
                              <span className="text-[10px] font-black text-slate-400 uppercase">Número do Pedido</span>
                              <span className="font-black text-indigo-600">#GA-2025</span>
                           </div>
                           <div className="pt-4 border-t border-slate-200">
                              <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Itens</p>
                              <div className="space-y-2">
                                 {simCart.map(item => (
                                   <div key={item.product.id} className="flex justify-between text-xs font-bold text-slate-700">
                                      <span>{item.quantity}x {item.product.name}</span>
                                      <span>R$ {(item.product.price * item.quantity).toFixed(2)}</span>
                                   </div>
                                 ))}
                              </div>
                           </div>
                        </div>

                        <button 
                          onClick={resetSimulation}
                          className="w-full py-5 rounded-2xl bg-slate-900 text-white font-black text-xs uppercase tracking-widest shadow-xl"
                        >
                           Voltar ao Menu
                        </button>
                     </div>
                   )}

                </div>

                <div className="absolute bottom-1.5 left-1/2 -translate-x-1/2 w-24 h-1 bg-white/20 rounded-full"></div>
             </div>

             <div className="flex gap-4">
                <div className="flex items-center gap-3 bg-white/5 px-6 py-3 rounded-full border border-white/10">
                   <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                   <span className="text-white text-xs font-bold uppercase tracking-widest">Experiência de Teste Ativa</span>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DigitalMenuConfig;
const CreditCard = (props: any) => (
  <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucide-credit-card"><rect width="20" height="14" x="2" y="5" rx="2"/><line x1="2" x2="22" y1="10" y2="10"/></svg>
);

import React, { useState, useMemo } from 'react';
import { DigitalMenuSettings, Product, Table } from '../types';
import { 
  Smartphone, Palette, Layout, QrCode, 
  Save, Eye, Check, Smartphone as PhoneIcon,
  Plus, Image as ImageIcon, Globe, Info, 
  ArrowRight, Sparkles, Sliders, ChevronRight,
  ShoppingCart, Search, Menu as MenuIcon,
  Copy, ExternalLink, Share2, X, MousePointer2,
  ChevronLeft, Minus, MapPin, User, Wallet,
  CheckCircle2, Loader2, ArrowLeft, Zap
} from 'lucide-react';

interface DigitalMenuConfigProps {
  settings: DigitalMenuSettings;
  onUpdateSettings: (settings: DigitalMenuSettings) => void;
  products: Product[];
  tables: Table[];
}

interface SimCartItem {
  product: Product;
  quantity: number;
}

const DigitalMenuConfig: React.FC<DigitalMenuConfigProps> = ({ settings, onUpdateSettings, products, tables }) => {
  const [activeTab, setActiveTab] = useState<'visual' | 'behavior' | 'qrcode'>('visual');
  const [selectedTableQR, setSelectedTableQR] = useState<number | null>(null);
  const [showTestMode, setShowTestMode] = useState(false);
  const [isLinkCopied, setIsLinkCopied] = useState(false);

  // States para a Simulação Interativa (Experiência de Teste)
  const [testStep, setTestStep] = useState<'menu' | 'cart' | 'checkout' | 'success'>('menu');
  const [simCart, setSimCart] = useState<SimCartItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [tableNumber, setTableNumber] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('');

  const categories = Array.from(new Set(products.map(p => p.category)));
  const menuUrl = `https://gastroai.me/cardapio/${settings.restaurantName.toLowerCase().replace(/\s+/g, '-')}`;

  const handleCopyLink = () => {
    navigator.clipboard.writeText(menuUrl);
    setIsLinkCopied(true);
    setTimeout(() => setIsLinkCopied(false), 2000);
  };

  // Funções do Simulador
  const addToSimCart = (product: Product) => {
    setSimCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
  };

  const removeFromSimCart = (productId: string) => {
    setSimCart(prev => prev.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity - 1 } : item
    ).filter(item => item.quantity > 0));
  };

  const simCartTotal = useMemo(() => {
    return simCart.reduce((acc, item) => acc + (item.product.price * item.quantity), 0);
  }, [simCart]);

  const resetSimulation = () => {
    setShowTestMode(false);
    setTestStep('menu');
    setSimCart([]);
    setCustomerName('');
    setTableNumber('');
    setPaymentMethod('');
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-10rem)] animate-in fade-in duration-500">
      {/* Coluna Esquerda: Configurações */}
      <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">

        {/* Card de Link Rápido */}
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-8 rounded-[3rem] text-white shadow-xl shadow-indigo-100 flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10">
            <Share2 size={120} />
          </div>
          <div className="relative z-10 flex flex-col gap-2">
            <h3 className="text-xl font-black tracking-tight">Seu Cardápio está Online!</h3>
            <p className="text-indigo-100 text-sm font-medium">Compartilhe este link na bio do Instagram ou WhatsApp.</p>
            <div className="mt-4 flex items-center gap-2 bg-black/20 p-2 rounded-2xl backdrop-blur-md border border-white/10">
               <Globe size={14} className="text-indigo-300 ml-2" />
               <span className="text-xs font-mono font-bold truncate max-w-[200px]">{menuUrl}</span>
            </div>
          </div>
          <div className="relative z-10 flex gap-3">
             <button 
                onClick={handleCopyLink}
                className={`flex items-center gap-2 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${isLinkCopied ? 'bg-emerald-500 text-white' : 'bg-white text-indigo-600 hover:bg-indigo-50 shadow-lg'}`}
             >
                {isLinkCopied ? <Check size={16} /> : <Copy size={16} />}
                {isLinkCopied ? 'Link Copiado' : 'Copiar Link'}
             </button>
             <button 
                onClick={() => setShowTestMode(true)}
                className="flex items-center gap-2 px-6 py-4 bg-indigo-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-400 border border-indigo-400 shadow-lg transition-all"
             >
                <MousePointer2 size={16} /> Experiência de Teste
             </button>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-8">
          <div className="flex bg-slate-50 p-1.5 rounded-2xl w-fit border">
            <button 
              onClick={() => setActiveTab('visual')}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'visual' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <Palette size={16} /> Identidade Visual
            </button>
            <button 
              onClick={() => setActiveTab('behavior')}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'behavior' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <Sliders size={16} /> Regras do Menu
            </button>
            <button 
              onClick={() => setActiveTab('qrcode')}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'qrcode' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <QrCode size={16} /> QR Codes de Mesa
            </button>
          </div>

          {activeTab === 'visual' && (
            <div className="space-y-8 animate-in slide-in-from-left-4 duration-300">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cor Primária da Marca</label>
                  <div className="flex items-center gap-4">
                    <input 
                      type="color" 
                      className="w-16 h-16 rounded-2xl border-none cursor-pointer bg-transparent"
                      value={settings.primaryColor}
