              </div>
              <div className="flex flex-wrap gap-1.5 mt-2">
                {rolePermissions[role].slice(0, 6).map(p => (
                  <span key={p} className="text-[10px] px-2 py-0.5 rounded-full border bg-slate-50 text-slate-600 font-semibold">
