                           <button onClick={() => toggleGroupPermissions(group)} className="text-[10px] font-black text-slate-400 hover:text-indigo-600 uppercase">Selecionar Todos</button>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          {permsInGroup.map(perm => {
                            const isSelected = newPermissions.includes(perm.id);
                            return (
                              <button key={perm.id} onClick={() => togglePermission(perm.id)} className={`flex items-start gap-4 p-4 rounded-2xl border-2 transition-all text-left ${isSelected ? 'border-emerald-500 bg-emerald-50/20' : 'border-slate-50 bg-slate-50/40 hover:border-slate-200'}`}>
                                <div className={`mt-0.5 w-5 h-5 rounded-lg flex items-center justify-center border-2 transition-all ${isSelected ? 'bg-emerald-500 border-emerald-500 text-white' : 'bg-white border-slate-200'}`}>
                                  {isSelected && <Check size={14} strokeWidth={4} />}
                                </div>
                                <div>
                                  <p className="text-xs font-black text-slate-800">{perm.label}</p>
                                  <p className="text-[9px] font-medium text-slate-500 mt-0.5">{perm.description}</p>
                                </div>
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            <div className="p-8 border-t bg-slate-50/50 flex gap-4 justify-end">
              <button onClick={() => setShowModal(false)} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-white uppercase text-xs">Cancelar</button>
              <button onClick={handleSaveUser} disabled={!newName || !newEmail} className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-100 disabled:opacity-50 uppercase text-xs flex items-center gap-2">
                <Check size={18} /> Criar Novo Acesso
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Edit Role Preset */}
      {editingRole && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-amber-50/30">
              <div className="flex items-center gap-4">
                <div className="bg-amber-500 p-3 rounded-2xl text-white shadow-lg shadow-amber-100">
                  <Settings2 size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black text-slate-800">Preset: {editingRole}</h2>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Configure as permissões padrão do cargo</p>
                </div>
              </div>
              <button onClick={() => setEditingRole(null)} className="p-2 hover:bg-white rounded-full text-slate-400"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
              {['Gestão', 'Administrativo', 'Operacional'].map(group => {
                const permsInGroup = ALL_PERMISSIONS.filter(p => p.group === group);
                return (
                  <div key={group} className="space-y-4">
                    <h4 className="text-[10px] font-black uppercase text-slate-400 border-b pb-1 tracking-widest flex items-center gap-2">
                       <Shield size={12} className="text-amber-500" /> {group}
                    </h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {permsInGroup.map(perm => (
                        <button 
                          key={perm.id} 
                          onClick={() => {
                            const newPerms = rolePresetPermissions.includes(perm.id) 
                              ? rolePresetPermissions.filter(p => p !== perm.id) 
                              : [...rolePresetPermissions, perm.id];
                            setRolePresetPermissions(newPerms);
                          }} 
                          className={`flex items-start gap-4 p-4 rounded-2xl border-2 transition-all text-left group ${rolePresetPermissions.includes(perm.id) ? 'border-amber-500 bg-amber-50/20' : 'border-slate-50 bg-slate-50/50 hover:bg-white hover:border-slate-200'}`}
                        >
                          <div className={`mt-0.5 w-5 h-5 rounded-lg flex items-center justify-center border-2 transition-all ${rolePresetPermissions.includes(perm.id) ? 'bg-amber-500 border-amber-500 text-white' : 'bg-white border-slate-200 text-transparent group-hover:border-slate-300'}`}>
                            {rolePresetPermissions.includes(perm.id) && <Check size={14} strokeWidth={4} />}
                          </div>
                          <div>
                            <p className={`text-sm font-bold ${rolePresetPermissions.includes(perm.id) ? 'text-amber-900' : 'text-slate-700'}`}>{perm.label}</p>
                            <p className="text-[10px] text-slate-500 font-medium leading-tight mt-1">{perm.description}</p>
                          </div>
                        </button>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="p-8 border-t bg-slate-50 flex gap-4 justify-end">
              <button onClick={() => setEditingRole(null)} className="px-8 py-4 rounded-xl font-bold text-slate-500 hover:bg-white transition-all border border-transparent hover:border-slate-200 uppercase text-xs tracking-widest">Cancelar</button>
              <button onClick={handleSaveRolePreset} className="bg-amber-500 text-white px-10 py-4 rounded-xl font-bold hover:bg-amber-600 shadow-xl shadow-amber-100 uppercase text-xs tracking-widest flex items-center gap-2">
                <Save size={18} /> Salvar Preset
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersPanel;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import POS from './components/POS';
import Tables from './components/Tables';
import KDS from './components/KDS';
import AIInsights from './components/AIInsights';
import UsersPanel from './components/UsersPanel';
import Inventory from './components/Inventory';
import Finance from './components/Finance';
import Delivery from './components/Delivery';
import CMVAnalysis from './components/CMVAnalysis';
import DashboardAlerts from './components/DashboardAlerts';
import DigitalMenuConfig from './components/DigitalMenuConfig';
import AdminSettingsComponent from './components/AdminSettings';
import { 
  INITIAL_PRODUCTS, 
  INITIAL_TABLES, 
  INITIAL_COURIERS,
  INITIAL_USERS,
  INITIAL_AUDIT_LOGS,
  ROLE_DEFAULT_PERMISSIONS as INITIAL_ROLE_PERMISSIONS
} from './constants';
import { Product, Table, Order, Courier, FinancialRecord, User, UserRole, AuditLog, Permission, OrderItem, PaymentMethod, PriceHistory, DigitalMenuSettings, AdminSettings } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Plus, Download, Filter, Bell, BellRing, Check, X as CloseIcon, Smartphone, ShoppingBag } from 'lucide-react';

interface CashSession {
  isOpen: boolean;
  openingValue: number;
  openedAt: Date | null;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [incomingDigitalOrders, setIncomingDigitalOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS.map(c => ({ ...c, createdAt: new Date() })));
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);
  const [globalDeliveryFee, setGlobalDeliveryFee] = useState(7.00);

  // Cardápio Digital Settings
  const [digitalMenuSettings, setDigitalMenuSettings] = useState<DigitalMenuSettings>({
    primaryColor: '#4f46e5',
    restaurantName: 'GastroAI Bistrô',
    welcomeMessage: 'Olá! Seja bem-vindo ao nosso cardápio digital. Sinta-se em casa e faça seu pedido!',
    allowOrdering: true,
    showStock: true,
    bannerUrl: 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?q=80&w=2070&auto=format&fit=crop',
    logoUrl: ''
  });

  // Admin Settings
  const [adminSettings, setAdminSettings] = useState<AdminSettings>({
    companyName: 'GastroAI Soluções Alimentares LTDA',
    cnpj: '12.345.678/0001-90',
    address: 'Av. Paulista, 1000 - Bela Vista, São Paulo - SP',
    phone: '(11) 4002-8922',
    businessHours: [
      { day: 'Segunda-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Terça-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quarta-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quinta-feira', open: '11:00', close: '23:00', isClosed: false },
      { day: 'Sexta-feira', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Sábado', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Domingo', open: '11:00', close: '20:00', isClosed: true },
    ],
    fiscal: {
      environment: 'homologacao',
      certificateStatus: 'valid',
      certificateExpiry: '15/12/2025',
      cscId: '000001',
      cscToken: 'A1B2C3D4E5',
      nextNfceNumber: 154,
      series: 1,
      taxRegime: 'simples_nacional'
    } as any,
    printing: {
      paperWidth: '80mm',
      autoPrintOrder: true,
      headerText: 'BEM VINDO AO GASTROAI',
      footerText: 'Obrigado e volte sempre!',
      showLogo: true
    },
    apis: {
      googleMapsKey: '',
      whatsappToken: '',
      ifoodWebhook: '',
      integrationActive: false
    }
  });

  // Controle de Caixa
  const [cashSession, setCashSession] = useState<CashSession>({
    isOpen: false,
    openingValue: 0,
    openedAt: null
  });

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({
      isOpen: true,
      openingValue: value,
      openedAt: new Date()
    });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({
      isOpen: false,
      openingValue: 0,
      openedAt: null
    });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const handlePlaceOrder = (newOrder: Partial<Order>) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: [],
      total: 0,
      status: 'pending',
      type: 'takeout',
      deliveryFee: newOrder.type === 'delivery' ? globalDeliveryFee : 0,
      ...newOrder,
    } as Order;
    setOrders(prev => [order, ...prev]);
    addLog('u1', 'VENDA', `Venda realizada no valor de R$ ${order.total.toFixed(2)}`);
  };

  const handleIncomingDigitalOrder = (order: Order) => {
    setIncomingDigitalOrders(prev => [...prev, order]);
    addLog('u1', 'DIGITAL', `Novo pedido pendente da mesa ${order.tableNumber}`);
  };

  const acceptDigitalOrder = (orderId: string) => {
    const order = incomingDigitalOrders.find(o => o.id === orderId);
    if (order) {
      const acceptedOrder = { ...order, status: 'pending' as const };
      setOrders(prev => [acceptedOrder, ...prev]);
      setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));

      // Se for pedido de mesa, atualiza a mesa
      if (order.tableNumber) {
        setTables(prev => prev.map(t => 
          t.id === order.tableNumber ? { 
            ...t, 
            status: 'occupied', 
            items: [...t.items, ...order.items],
            total: t.total + order.total
          } : t
        ));
      }

      addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} ACEITO e enviado para a cozinha`);
    }
  };

  const rejectDigitalOrder = (orderId: string) => {
    setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));
    addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} RECUSADO`);
  };

  const handleSendToKitchen = (tableId: number, items: OrderItem[]) => {
    const order: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: items,
      total: items.reduce((acc, i) => acc + (i.price * i.quantity), 0),
      status: 'pending',
      type: 'table',
    };
    setOrders(prev => [order, ...prev]);
    addLog('u4', 'COZINHA', `Pedido da mesa ${tableId} enviado para a cozinha`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));

    if (status === 'delivered') {
      const order = orders.find(o => o.id === id);
      if (order?.courierId) {
        setCouriers(prev => prev.map(c => c.id === order.courierId ? { ...c, status: 'available' } : c));
      }
    }

    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const handleAssignCourier = (orderId: string, courierId: string) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    setCouriers(prev => prev.map(c => c.id === courierId ? { ...c, status: 'delivering' } : c));
    addLog('u1', 'ENTREGA', `Entregador atribuído ao pedido #${orderId.slice(-4)}`);
  };

  const handleAddCourier = (newCourier: Partial<Courier>) => {
    const courier: Courier = {
      id: `c${Date.now()}`,
      name: newCourier.name || '',
      phone: newCourier.phone || '',
      status: 'available',
      vehicleType: newCourier.vehicleType || 'moto',
      createdAt: new Date(),
    };
    setCouriers(prev => [...prev, courier]);
    addLog('u1', 'ENTREGA', `Novo entregador cadastrado: ${courier.name}`);
  };

  const handleAddUser = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      status: 'offline',
      createdAt: new Date(),
      ...userData
    } as User;
    setUsers([...users, newUser]);
    addLog('u1', 'ADMIN', `Novo usuário ${newUser.name} adicionado`);
  };

  const handleUpdateRole = (id: string, role: UserRole) => {
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
  };

  const handleUpdateRolePermissions = (role: UserRole, permissions: Permission[]) => {
    setRolePermissions(prev => ({ ...prev, [role]: permissions }));
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateTable = (tableId: number, items: OrderItem[], status: Table['status']) => {
    setTables(prev => prev.map(t => {
      if (t.id === tableId) {
        const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        return { ...t, items, status, total };
      }
      return t;
    }));
  };

  const handleCloseTable = (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean) => {
    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      tableNumber: tableId,
      createdAt: new Date(),
      items: table.items,
      total: table.total,
      status: 'delivered',
      type: 'table',
      paymentMethod,
      isFiscalIssued: isFiscal,
      fiscalKey: isFiscal ? `${Math.random().toString().slice(2, 12)}...` : undefined
    };

    setOrders(prev => [newOrder, ...prev]);
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], total: 0, status: 'available' } : t));
    addLog('u1', 'MESA', `Mesa ${tableId} fechada. R$ ${table.total.toFixed(2)} ${isFiscal ? '(Fiscal Emitido)' : ''}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts 
                  products={products} 
                  onNavigateToInventory={() => setActiveTab('inventory')} 
                />
                <div className="bg-white p-6 rounded-3xl border shadow-sm">
                  <h3 className="text-xl font-bold mb-6">Faturamento Real</h3>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={[
                        { name: 'Seg', sales: 4000 },
                        { name: 'Ter', sales: 3000 },
                        { name: 'Qua', sales: 5000 },
                        { name: 'Qui', sales: 4780 },
                        { name: 'Sex', sales: 8890 },
                        { name: 'Sáb', sales: 9390 },
                        { name: 'Dom', sales: 7490 },
                      ]}>
                        <defs>
                          <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} />
                        <YAxis axisLine={false} tickLine={false} />
                        <Tooltip />
                        <Area type="monotone" dataKey="sales" stroke="#4f46e5" fillOpacity={1} fill="url(#colorSales)" strokeWidth={3} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit">
                <h3 className="text-xl font-bold mb-6">Performance do Dia</h3>
                <div className="flex-1 space-y-6">
                  <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Total em Vendas</p>
                    <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                  </div>
                  <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                    <p className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-1">Pedidos Realizados</p>
                    <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return (
          <Tables 
            tables={tables} 
            products={products} 
            orders={orders}
            cashSession={cashSession}
            onUpdateTable={handleUpdateTable} 
            onCloseTable={handleCloseTable} 
            onSendToKitchen={handleSendToKitchen}
            onOpenCash={handleOpenCash}
            onCloseCash={handleCloseCash}
          />
        );
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'digital-menu':
        return (
          <DigitalMenuConfig 
            settings={digitalMenuSettings} 
            onUpdateSettings={setDigitalMenuSettings}
            products={products}
            tables={tables}
            onPlaceDigitalOrder={handleIncomingDigitalOrder}
          />
        );
      case 'settings':
        return (
          <AdminSettingsComponent 
            settings={adminSettings}
            onUpdateSettings={setAdminSettings}
          />
        );
      case 'delivery':
        return (
          <Delivery 
            orders={orders} 
            couriers={couriers} 
            onUpdateStatus={updateOrderStatus} 
            onAssignCourier={handleAssignCourier} 
            onAddCourier={handleAddCourier}
            deliveryFee={globalDeliveryFee}
            onUpdateDeliveryFee={setGlobalDeliveryFee}
          />
        );
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={handleUpdateProduct} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return (
          <UsersPanel 
            users={users} 
            onAddUser={handleAddUser} 
            onUpdateRole={handleUpdateRole} 
            auditLogs={auditLogs} 
            rolePermissions={rolePermissions}
            onUpdateRolePermissions={handleUpdateRolePermissions}
          />
        );
      default:
        return <div className="p-12 text-center">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Sistema de Gestão</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right">
              <p className="text-xs text-emerald-500 font-bold flex items-center justify-end gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Servidor Online
              </p>
              <p className="font-bold text-slate-800">Cozinha Ativa</p>
            </div>
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg shadow-indigo-100">GA</div>
          </div>
        </header>
        {renderContent()}
      </main>

      {/* ALERTAS DE NOVOS PEDIDOS DIGITAIS */}
      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-4 border-indigo-600 rounded-[2.5rem] shadow-2xl p-6 flex flex-col gap-4 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-125 transition-transform duration-500">
                <BellRing size={64} className="text-indigo-600 animate-bounce" />
              </div>

              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner">
                  <Smartphone size={32} />
                </div>
                <div>
                  <h4 className="font-black text-slate-800 leading-tight">Novo Pedido Digital!</h4>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Mesa {order.tableNumber} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>

              <div className="space-y-2 border-y py-4 border-slate-100">
                {order.items.slice(0, 2).map((item, i) => (
                  <p key={i} className="text-xs font-bold text-slate-600 flex justify-between">
                    <span>{item.quantity}x {item.name}</span>
                    <span className="text-slate-400">R$ {(item.price * item.quantity).toFixed(2)}</span>
                  </p>
                ))}
                {order.items.length > 2 && <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">+ {order.items.length - 2} itens</p>}
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => rejectDigitalOrder(order.id)}
                  className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-50 hover:text-rose-600 transition-all flex items-center justify-center gap-2"
                >
                  <CloseIcon size={16} /> Recusar
                </button>
                <button 
                  onClick={() => acceptDigitalOrder(order.id)}
                  className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
                >
                  <Check size={16} strokeWidth={4} /> Aceitar e Preparar
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { DigitalMenuSettings, Product, Table, Order } from '../types';
import { 
  Smartphone, Palette, Layout, QrCode, 
  Save, Eye, Check, Smartphone as PhoneIcon,
  Plus, Image as ImageIcon, Globe, Info, 
  ArrowRight, Sparkles, Sliders, ChevronRight,
  ShoppingCart, Search, Menu as MenuIcon,
  Copy, ExternalLink, Share2, X, MousePointer2,
  ChevronLeft, Minus, MapPin, User, Wallet,
  CheckCircle2, Loader2, ArrowLeft, Zap
} from 'lucide-react';

interface DigitalMenuConfigProps {
  settings: DigitalMenuSettings;
  onUpdateSettings: (settings: DigitalMenuSettings) => void;
  products: Product[];
  tables: Table[];
  onPlaceDigitalOrder: (order: Order) => void;
}

interface SimCartItem {
  product: Product;
  quantity: number;
}

const DigitalMenuConfig: React.FC<DigitalMenuConfigProps> = ({ settings, onUpdateSettings, products, tables, onPlaceDigitalOrder }) => {
  const [activeTab, setActiveTab] = useState<'visual' | 'behavior' | 'qrcode'>('visual');
  const [selectedTableQR, setSelectedTableQR] = useState<number | null>(null);
  const [showTestMode, setShowTestMode] = useState(false);
  const [isLinkCopied, setIsLinkCopied] = useState(false);

  // States para a Simulação Interativa (Experiência de Teste)
  const [testStep, setTestStep] = useState<'menu' | 'cart' | 'checkout' | 'success'>('menu');
  const [simCart, setSimCart] = useState<SimCartItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [tableNumber, setTableNumber] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('');

  const categories = Array.from(new Set(products.map(p => p.category)));
  const menuUrl = `https://gastroai.me/cardapio/${settings.restaurantName.toLowerCase().replace(/\s+/g, '-')}`;

  const handleCopyLink = () => {
    navigator.clipboard.writeText(menuUrl);
    setIsLinkCopied(true);
    setTimeout(() => setIsLinkCopied(false), 2000);
  };

  // Funções do Simulador
  const addToSimCart = (product: Product) => {
    setSimCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
  };

  const removeFromSimCart = (productId: string) => {
    setSimCart(prev => prev.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity - 1 } : item
    ).filter(item => item.quantity > 0));
  };

  const simCartTotal = useMemo(() => {
    return simCart.reduce((acc, item) => acc + (item.product.price * item.quantity), 0);
  }, [simCart]);

  const resetSimulation = () => {
    setShowTestMode(false);
    setTestStep('menu');
    setSimCart([]);
    setCustomerName('');
    setTableNumber('');
    setPaymentMethod('');
  };

  const handleFinishSimulation = () => {
    // Transforma o carrinho simulado em um pedido real para o sistema aceitar
    const finalOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date(),
      items: simCart.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        price: item.product.price,
        quantity: item.quantity,
        seat: `Mesa ${tableNumber}`
      })),
      total: simCartTotal,
      status: 'pending',
      type: 'table',
      tableNumber: parseInt(tableNumber) || 1,
      customerName: customerName,
      paymentMethod: paymentMethod as any
    };

    onPlaceDigitalOrder(finalOrder);
    setTestStep('success');
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-10rem)] animate-in fade-in duration-500">
