                                   <button 
                                     key={method.id}
                                     onClick={() => setPaymentMethod(method.id)}
                                     className={`flex items-center justify-between p-5 rounded-[1.8rem] border-2 transition-all ${paymentMethod === method.id ? 'border-indigo-600 bg-indigo-50/50' : 'bg-slate-50 border-slate-100'}`}
                                   >
                                      <div className="flex items-center gap-4">
                                         <method.icon className={method.color} size={20} />
                                         <span className="font-black text-sm text-slate-800">{method.label}</span>
                                      </div>
                                      {paymentMethod === method.id && <CheckCircle2 size={18} className="text-indigo-600" />}
                                   </button>
                                 ))}
                              </div>
                           </div>
                        </div>

                        <div className="p-6 border-t mt-auto space-y-4">
