                             className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl flex items-center justify-center gap-3 transition-all disabled:opacity-50"
                             style={{ backgroundColor: settings.primaryColor }}
                           >
                              Confirmar e Enviar Pedido
                           </button>
                        </div>
                     </div>
                   )}

                   {/* FLOW: SUCCESS */}
                   {testStep === 'success' && (
                     <div className="h-full flex flex-col items-center justify-center p-10 text-center space-y-8 animate-in zoom-in-95 duration-500">
                        <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce">
                           <CheckCircle2 size={64} />
                        </div>
                        <div className="space-y-3">
                           <h3 className="text-3xl font-black text-slate-800 tracking-tighter">Pedido Realizado!</h3>
                           <p className="text-slate-500 font-medium">Seu pedido já foi enviado para a cozinha. Agora é só relaxar e aguardar.</p>
                        </div>

                        <div className="w-full p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100 space-y-4">
                           <div className="flex justify-between items-center">
                              <span className="text-[10px] font-black text-slate-400 uppercase">Número do Pedido</span>
                              <span className="font-black text-indigo-600">#GA-2025</span>
                           </div>
                           <div className="pt-4 border-t border-slate-200">
                              <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Itens</p>
                              <div className="space-y-2">
                                 {simCart.map(item => (
                                   <div key={item.product.id} className="flex justify-between text-xs font-bold text-slate-700">
                                      <span>{item.quantity}x {item.product.name}</span>
                                      <span>R$ {(item.product.price * item.quantity).toFixed(2)}</span>
                                   </div>
                                 ))}
                              </div>
                           </div>
                        </div>

                        <button 
                          onClick={resetSimulation}
                          className="w-full py-5 rounded-2xl bg-slate-900 text-white font-black text-xs uppercase tracking-widest shadow-xl"
                        >
                           Voltar ao Menu
                        </button>
                     </div>
                   )}

                </div>

                <div className="absolute bottom-1.5 left-1/2 -translate-x-1/2 w-24 h-1 bg-white/20 rounded-full"></div>
             </div>

             <div className="flex gap-4">
                <div className="flex items-center gap-3 bg-white/5 px-6 py-3 rounded-full border border-white/10">
                   <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                   <span className="text-white text-xs font-bold uppercase tracking-widest">Experiência de Teste Ativa</span>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

