                   {order.tableNumber && <span className="text-[10px] font-black uppercase tracking-widest bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full">Mesa {order.tableNumber}</span>}
                </div>
              </div>
              <div className="flex flex-col items-end gap-1">
                <div className="flex items-center gap-1 font-bold text-xs uppercase tracking-tighter">
                  <Clock size={14} />
                  12m
                </div>
                {order.customerName && (
                  <p className="text-[10px] font-black uppercase text-indigo-500 flex items-center gap-1">
                     <User size={10} /> {order.customerName.split(' ')[0]}
                  </p>
                )}
              </div>
            </div>

            <div className="flex-1 p-6 space-y-4">
              {order.items.map((item, idx) => (
                <div key={idx} className="flex gap-4 items-start group/item">
                  <span className="bg-slate-100 text-slate-700 font-black px-2 py-1 rounded-xl text-xs min-w-[2.2rem] text-center border border-slate-200 shadow-sm mt-0.5">
                    {item.quantity}
                  </span>
                  <div className="flex-1 min-w-0">
                    <p className="font-bold text-slate-800 leading-tight">{item.name}</p>
                    {item.observation && (
                      <p className="text-[10px] font-bold text-rose-500 mt-1 uppercase italic">* {item.observation}</p>
                    )}
                  </div>
                  <button 
                    onClick={() => handleItemReady(item)}
                    className="p-2 text-slate-300 hover:text-emerald-500 hover:bg-emerald-50 rounded-xl transition-all opacity-0 group-hover/item:opacity-100"
                  >
                    <CheckCircle2 size={18} />
                  </button>
                </div>
              ))}
            </div>

            <div className="p-6 border-t bg-slate-50/50 flex gap-2">
              {order.status === 'pending' ? (
                <button 
                  onClick={() => onUpdateStatus(order.id, 'preparing')}
                  className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 uppercase text-xs tracking-widest"
                >
                  Iniciar Preparo
                </button>
              ) : (
                <button 
                  onClick={() => handleSetReady(order)}
                  className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-black hover:bg-emerald-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-emerald-100 uppercase text-xs tracking-widest"
                >
                  <Check size={20} strokeWidth={3} />
                  Marcar Pronto
                </button>
              )}
            </div>
          </div>
        );
      })}

      {activeOrders.length === 0 && (
        <div className="col-span-full h-96 flex flex-col items-center justify-center text-slate-300 gap-4 opacity-50">
          <div className="p-8 border-4 border-dashed rounded-full border-slate-200 animate-pulse">
            <Check size={64} strokeWidth={1} />
          </div>
          <p className="font-black uppercase tracking-widest text-sm">Sem pedidos pendentes na cozinha</p>
        </div>
      )}
    </div>
  );
};

