import React, { useMemo } from 'react';
import { Order, OrderStatus } from '../types';
import { 
  Clock, Check, CheckCircle2, Smartphone, 
  User, Truck, Package, Flag, ChevronRight, 
  ChefHat, Timer, MapPin, AlertCircle
} from 'lucide-react';

interface KDSProps {
  orders: Order[];
  onUpdateStatus: (id: string, status: OrderStatus) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, onUpdateStatus }) => {
  // Filtragem dos pedidos por status para as colunas do Kanban
  const columns = useMemo(() => ({
    preparing: orders.filter(o => ['pending', 'preparing'].includes(o.status)),
    ready: orders.filter(o => o.status === 'ready'),
    delivering: orders.filter(o => o.status === 'delivering'),
    delivered: orders.filter(o => o.status === 'delivered').slice(0, 10), // Últimos 10 finalizados
  }), [orders]);

  const getStatusConfig = (status: string) => {
    switch (status) {
      case 'preparing': return { label: 'Em Produção', icon: ChefHat, color: 'bg-rose-500', bg: 'bg-rose-50/30' };
      case 'ready': return { label: 'Prontos', icon: Package, color: 'bg-amber-500', bg: 'bg-amber-50/30' };
      case 'delivering': return { label: 'Em Entrega', icon: Truck, color: 'bg-indigo-500', bg: 'bg-indigo-50/30' };
      case 'delivered': return { label: 'Finalizados', icon: Flag, color: 'bg-emerald-500', bg: 'bg-emerald-50/30' };
      default: return { label: 'Status', icon: Clock, color: 'bg-slate-500', bg: 'bg-slate-50' };
    }
  };

  const OrderCard = ({ order }: { order: Order }) => {
    const isDigital = order.customerName || order.tableNumber;
    const timeElapsed = Math.floor((new Date().getTime() - new Date(order.createdAt).getTime()) / 60000);

    return (
      <div className="bg-white border-2 border-slate-100 rounded-[2rem] shadow-sm hover:shadow-md hover:border-indigo-100 transition-all group animate-in slide-in-from-bottom-2 duration-300">
        <div className="p-5 border-b border-slate-50 flex justify-between items-start">
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <span className="font-black text-lg text-slate-800">#{order.id.slice(-4)}</span>
              {isDigital && (
                <div className="bg-indigo-600 text-white p-1 rounded-md" title="Pedido via Cardápio Digital">
                  <Smartphone size={12} />
                </div>
              )}
            </div>
            <div className="flex flex-wrap gap-1">
               <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-slate-100 text-slate-500 border border-slate-200">
                 {order.type}
               </span>
               {order.tableNumber && (
                 <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-700 border border-indigo-200">
                   Mesa {order.tableNumber}
                 </span>
               )}
            </div>
          </div>
          <div className="text-right">
             <div className={`flex items-center gap-1 text-[10px] font-bold uppercase ${timeElapsed > 15 ? 'text-rose-500' : 'text-slate-400'}`}>
                <Timer size={12} />
                {timeElapsed}m
             </div>
             {order.customerName && (
               <p className="text-[9px] font-black text-indigo-500 mt-1 uppercase flex items-center justify-end gap-1">
                 <User size={10} /> {order.customerName.split(' ')[0]}
               </p>
             )}
          </div>
        </div>

        <div className="p-5 space-y-3">
          {order.items.map((item, idx) => (
            <div key={idx} className="flex gap-3 text-xs">
               <span className="font-black text-slate-400">{item.quantity}x</span>
               <div className="flex-1 min-w-0">
                  <p className="font-bold text-slate-700 truncate">{item.name}</p>
                  {item.observation && (
                    <p className="text-[9px] font-bold text-rose-400 italic mt-0.5 truncate">{item.observation}</p>
                  )}
               </div>
            </div>
          ))}
        </div>

        <div className="p-4 bg-slate-50/50 border-t rounded-b-[2rem]">
          {order.status === 'pending' || order.status === 'preparing' ? (
            <button 
              onClick={() => onUpdateStatus(order.id, 'ready')}
              className="w-full bg-emerald-600 text-white py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-emerald-50"
            >
              <Check size={16} strokeWidth={4} /> Marcar Pronto
            </button>
          ) : order.status === 'ready' ? (
            <button 
              onClick={() => onUpdateStatus(order.id, order.type === 'delivery' ? 'delivering' : 'delivered')}
