                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables tables={tables} products={products} orders={orders} cashSession={cashSession} onUpdateTable={(id, items, status) => setTables(t => t.map(x => x.id === id ? {...x, items, status, total: items.reduce((a,b)=>a+(b.price*b.quantity),0)} : x))} onCloseTable={(id, method, fiscal) => {}} onSendToKitchen={() => {}} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={handleIncomingDigitalOrder} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
