                  <h4 className="font-black text-slate-800">Pedido Digital: {order.type === 'delivery' ? 'Delivery' : 'Mesa ' + order.tableNumber}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => rejectDigitalOrder(order.id)} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => acceptDigitalOrder(order.id)} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar e Iniciar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

