interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee,
  onAddFinancialRecord
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'monitor' | 'couriers' | 'settlement' | 'settings'>('monitor');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<Courier | null>(null);
  const [issuingFiscalId, setIssuingFiscalId] = useState<string | null>(null);

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Cálculo de valores pendentes para acerto
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      // Pedidos entregues por este motoboy que ainda não foram "acertados"
      // Na vida real, teríamos um flag isSettled, aqui simularemos com pedidos de status 'delivered'
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');

      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);

      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, // O que a empresa deve ao motoboy
        cashCollected, // O que o motoboy deve à empresa (recebido em dinheiro)
        balance: totalFees - cashCollected // Se positivo, empresa paga motoboy. Se negativo, motoboy devolve dinheiro.
      };
    });
  }, [couriers, deliveryOrders]);

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      vehicleType: newCourierVehicle 
    });
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setShowAddCourierModal(false);
  };

  const handleRealizeSettlement = (settlement: any) => {
    const { courier, balance, totalFees, cashCollected } = settlement;

    // 1. Gerar registro financeiro
    if (balance > 0) {
      // Empresa paga o motoboy (Saída)
      onAddFinancialRecord({
        type: 'expense',
        amount: balance,
        category: 'Pagamento de Entregadores',
        description: `Acerto de contas: ${courier.name} (Taxas: R$${totalFees.toFixed(2)} - Dinheiro: R$${cashCollected.toFixed(2)})`,
        date: new Date()
      });
    } else if (balance < 0) {
      // Motoboy devolve dinheiro à empresa (Entrada)
      onAddFinancialRecord({
        type: 'income',
        amount: Math.abs(balance),
        category: 'Acerto de Motoboy',
        description: `Devolução de troco/dinheiro: ${courier.name} (Saldo excedente de dinheiro em espécie)`,
        date: new Date()
      });
    }

    // 2. Feedback visual e reset (Na vida real, marcaríamos as ordens como isSettled: true)
    alert(`Acerto de ${courier.name} realizado com sucesso!\nRegistro enviado ao financeiro.`);
    setShowSettlementModal(null);
  };

  const handleEmitFiscal = (orderId: string) => {
    setIssuingFiscalId(orderId);
    setTimeout(() => {
      setIssuingFiscalId(null);
      alert("NFC-e emitida com sucesso para o pedido #" + orderId.slice(-4));
    }, 1500);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Top Nav Refatorado */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        <button onClick={() => setActiveSubTab('monitor')} className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'monitor' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
          <Navigation size={16} /> Monitor de Entregas
        </button>
        <button onClick={() => setActiveSubTab('couriers')} className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'couriers' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
          <UserCheck size={16} /> Meus Motoboys
        </button>
        <button onClick={() => setActiveSubTab('settlement')} className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'settlement' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
          <Wallet size={16} /> Acerto de Contas
        </button>
        <button onClick={() => setActiveSubTab('settings')} className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'settings' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
          <Settings size={16} /> Regras
        </button>
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Aguardando Motoboy */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Pedidos Prontos ({deliveryOrders.filter(o => o.status === 'ready').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'ready').map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors group">
                  <div className="flex justify-between items-start">
                    <div>
                      <span className="text-[10px] font-black px-3 py-1 rounded-full bg-emerald-100 text-emerald-700 uppercase tracking-tighter">PRONTO</span>
                      <h4 className="text-xl font-black text-slate-800 mt-2">#{order.id.slice(-4)}</h4>
                    </div>
                    <div className="text-right">
                       <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                       <p className="text-[9px] font-bold text-slate-400 uppercase">{order.paymentMethod}</p>
                    </div>
