                  >
                    Atribuir Motoboy
                  </button>
                </div>
              ))}
            </div>
          </div>

          {/* Em Rota de Entrega */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Navigation size={16} className="text-indigo-600" /> Motoboys em Rota ({deliveryOrders.filter(o => o.status === 'delivering').length})
