                      <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                        <Bike size={24} />
                      </div>
                      <div>
                        <p className="text-sm font-black text-slate-800">{courier?.name || 'Não identificado'}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Saiu às {order.createdAt.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                      </div>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Pedido</p>
                       <p className="text-xs font-bold text-slate-700">#{order.id.slice(-4)} • R$ {order.total.toFixed(2)}</p>
                    </div>
                    <button 
