                    <span className="font-black text-emerald-400">R$ {deliveryOrders.filter(o => o.status === 'delivered').reduce((a, b) => a + (b.deliveryFee || 0), 0).toFixed(2)}</span>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

