    }
  });

  const [cashSession, setCashSession] = useState<CashSession>({
    isOpen: false,
    openingValue: 0,
    openedAt: null
  });

  const [mockWhatsAppNotify, setMockWhatsAppNotify] = useState<{title: string, msg: string} | null>(null);

  const triggerWhatsAppMock = (title: string, msg: string) => {
    setMockWhatsAppNotify({ title, msg });
    setTimeout(() => setMockWhatsAppNotify(null), 5000);
  };

  const handleAddFinancialRecord = (record: Partial<FinancialRecord>) => {
    const newRecord: FinancialRecord = {
      id: Math.random().toString(36).substr(2, 9),
      type: record.type || 'expense',
      amount: record.amount || 0,
      category: record.category || 'Outros',
      description: record.description || 'Lançamento manual',
      date: record.date || new Date()
    };
    setFinancialRecords(prev => [newRecord, ...prev]);
    addLog('u1', 'FINANCEIRO', `Novo lançamento: ${newRecord.description}`);
  };

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({ isOpen: true, openingValue: value, openedAt: new Date() });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({ isOpen: false, openingValue: 0, openedAt: null });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const handleIncomingDigitalOrder = (order: Order) => {
    setIncomingDigitalOrders(prev => [...prev, order]);
    addLog('u1', 'DIGITAL', `Novo pedido digital (${order.type === 'delivery' ? 'Delivery' : 'Mesa ' + order.tableNumber})`);
  };

  const acceptDigitalOrder = (orderId: string) => {
    const order = incomingDigitalOrders.find(o => o.id === orderId);
    if (order) {
      const acceptedOrder = { ...order, status: 'preparing' as const, deliveryFee: globalDeliveryFee };
      setOrders(prev => [acceptedOrder, ...prev]);
      setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));

      if (order.type === 'table' && order.tableNumber) {
        setTables(prev => prev.map(t => 
          t.id === order.tableNumber ? { 
            ...t, 
            status: 'occupied', 
            items: [...t.items, ...order.items],
            total: t.total + order.total
          } : t
        ));
      }

      triggerWhatsAppMock(
        "✅ Pedido Aceito!", 
        `Olá ${order.customerName}, seu pedido #${orderId.slice(-4)} foi aceito e já está em produção!`
      );

      addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} ACEITO`);
    }
  };

  const rejectDigitalOrder = (orderId: string) => {
    setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));
    addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} RECUSADO`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    const order = orders.find(o => o.id === id);
    if (!order) return;

    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));

    if (order.type === 'delivery') {
      if (status === 'ready') {
        triggerWhatsAppMock("🥘 Pedido Pronto!", `Seu pedido #${id.slice(-4)} está pronto e aguardando o entregador.`);
      } else if (status === 'delivering') {
        triggerWhatsAppMock("🛵 Saiu para Entrega!", `Boa notícia ${order.customerName}! O motoboy já saiu para o seu endereço.`);
      } else if (status === 'delivered') {
        triggerWhatsAppMock("🏁 Pedido Entregue!", `Tudo certo! Seu pedido #${id.slice(-4)} foi finalizado. Bom apetite!`);
      }
    }

    if (status === 'delivered' && order.courierId) {
      setCouriers(prev => prev.map(c => c.id === order.courierId ? { ...c, status: 'available' } : c));
    }

    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const assignCourier = (orderId: string, courierId: string) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    setCouriers(prev => prev.map(c => c.id === courierId ? { ...c, status: 'delivering' } : c));
    addLog('u1', 'DELIVERY', `Motoboy ${courierId} atribuído ao pedido #${orderId.slice(-4)}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts products={products} onNavigateToInventory={() => setActiveTab('inventory')} />
                <div className="bg-white p-6 rounded-3xl border shadow-sm h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{ name: 'Seg', sales: 4000 }, { name: 'Ter', sales: 3000 }, { name: 'Qua', sales: 5000 }, { name: 'Qui', sales: 4780 }, { name: 'Sex', sales: 8890 }, { name: 'Sáb', sales: 9390 }, { name: 'Dom', sales: 7490 }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fill="#4f46e51a" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit gap-6">
                <h3 className="text-xl font-bold">Resumo Diário</h3>
                <div className="p-6 bg-slate-50 rounded-2xl border">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables tables={tables} products={products} orders={orders} cashSession={cashSession} onUpdateTable={(id, items, status) => setTables(t => t.map(x => x.id === id ? {...x, items, status, total: items.reduce((a,b)=>a+(b.price*b.quantity),0)} : x))} onCloseTable={(id, method, fiscal) => {}} onSendToKitchen={() => {}} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'delivery':
        return <Delivery 
          orders={orders} 
          couriers={couriers} 
          deliveryFee={globalDeliveryFee}
          onUpdateStatus={updateOrderStatus} 
          onAssignCourier={assignCourier}
          onAddCourier={(c) => setCouriers(prev => [...prev, { ...c, id: `c${Date.now()}`, status: 'available', createdAt: new Date() } as Courier])}
          onUpdateDeliveryFee={setGlobalDeliveryFee}
          onAddFinancialRecord={handleAddFinancialRecord}
        />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={handleIncomingDigitalOrder} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={(p) => setProducts(prev => prev.map(x => x.id === p.id ? p : x))} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return <UsersPanel users={users} auditLogs={auditLogs} rolePermissions={rolePermissions} onAddUser={(u) => setUsers(prev => [...prev, { ...u, id: `u${Date.now()}`, status: 'online', createdAt: new Date() } as User])} onUpdateRole={()=>{}} onUpdateRolePermissions={()=>{}} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black">GA</div>
        </header>
        {renderContent()}
      </main>

      {mockWhatsAppNotify && (
        <div className="fixed top-8 right-8 z-[300] w-full max-w-sm px-4 animate-in slide-in-from-right-10">
           <div className="bg-white border-l-4 border-emerald-500 rounded-2xl shadow-2xl p-4 flex gap-4 items-center ring-1 ring-black/5">
              <div className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-emerald-100">
                 <MessageCircle size={24} />
              </div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase text-emerald-600 flex justify-between">
                    <span>WhatsApp Cliente</span>
                    <span className="text-slate-300">Agora</span>
                 </p>
                 <p className="text-sm font-black text-slate-800 mt-0.5">{mockWhatsAppNotify.title}</p>
                 <p className="text-xs font-medium text-slate-500 line-clamp-2">{mockWhatsAppNotify.msg}</p>
              </div>
           </div>
        </div>
      )}

      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-2 border-indigo-600 rounded-[2rem] shadow-2xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center">
                  {order.type === 'delivery' ? <ShoppingBag size={24} /> : <Smartphone size={24} />}
                </div>
                <div>
                  <h4 className="font-black text-slate-800">Pedido Digital: {order.type === 'delivery' ? 'Delivery' : 'Mesa ' + order.tableNumber}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => rejectDigitalOrder(order.id)} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => acceptDigitalOrder(order.id)} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar e Iniciar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

export type OrderStatus = 'pending' | 'preparing' | 'ready' | 'delivering' | 'delivered' | 'cancelled';

export type UserRole = 'ADMIN' | 'MANAGER' | 'WAITER' | 'CASHIER' | 'CHEF';

export type PaymentMethod = 'dinheiro' | 'cartao_credito' | 'cartao_debito' | 'pix' | 'vale_refeicao';

export type Permission = 
  | 'dashboard_view' 
  | 'pos_access' 
  | 'tables_manage' 
  | 'kds_view' 
  | 'delivery_manage' 
  | 'inventory_edit' 
  | 'finance_view' 
  | 'cmv_analysis' 
  | 'users_manage'
  | 'digital_menu_manage'
  | 'admin_settings_manage'
  | 'fiscal_manage';

export interface BusinessHours {
  day: string;
  open: string;
  close: string;
  isClosed: boolean;
}

export interface FiscalSettings {
  environment: 'homologacao' | 'producao';
  certificateStatus: 'valid' | 'expired' | 'missing';
  certificateExpiry?: string;
  cscId: string;
  cscToken: string;
  nextNfceNumber: number;
  series: number;
  taxRegime: 'simples_nacional' | 'lucro_presumido' | 'lucro_real';
}

export interface AdminSettings {
  companyName: string;
  cnpj: string;
  address: string;
  phone: string;
  businessHours: BusinessHours[];
  fiscal: FiscalSettings;
  printing: {
    paperWidth: '58mm' | '80mm';
    autoPrintOrder: boolean;
    headerText: string;
    footerText: string;
    showLogo: boolean;
  };
  apis: {
    googleMapsKey: string;
    whatsappToken: string;
    ifoodWebhook: string;
    integrationActive: boolean;
  };
}

export interface DigitalMenuSettings {
  primaryColor: string;
  restaurantName: string;
  welcomeMessage: string;
  allowOrdering: boolean;
  showStock: boolean;
  bannerUrl: string;
  logoUrl: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface PriceHistory {
  date: string;
  price: number;
  cost: number;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
  priceHistory?: PriceHistory[];
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
  observation?: string;
  seat?: string;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  deliveryFee?: number;
  createdAt: Date;
  customerName?: string;
  customerPhone?: string;
  customerAddress?: string;
  courierId?: string;
  paymentMethod?: PaymentMethod;
  isFiscalIssued?: boolean;
  fiscalKey?: string;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
  items: OrderItem[];
  total: number;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
  pixKey?: string;
  vehicleType?: 'bike' | 'moto' | 'car';
  createdAt: Date;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

import React, { useState, useMemo } from 'react';
import { DigitalMenuSettings, Product, Table, Order } from '../types';
import { 
  Smartphone, Palette, QrCode, 
  Save, Eye, Check, 
  Plus, Globe, 
  ShoppingCart, Copy, Share2, X, MousePointer2,
  Minus, MapPin, User, Wallet,
  CheckCircle2, ArrowLeft, MessageCircle,
  Bike, Home, UserCircle, Phone
} from 'lucide-react';

interface DigitalMenuConfigProps {
  settings: DigitalMenuSettings;
  onUpdateSettings: (settings: DigitalMenuSettings) => void;
  products: Product[];
  tables: Table[];
  onPlaceDigitalOrder: (order: Order) => void;
}

interface SimCartItem {
  product: Product;
  quantity: number;
}

const DigitalMenuConfig: React.FC<DigitalMenuConfigProps> = ({ settings, onUpdateSettings, products, tables, onPlaceDigitalOrder }) => {
  const [activeTab, setActiveTab] = useState<'visual' | 'behavior' | 'qrcode'>('visual');
  const [showTestMode, setShowTestMode] = useState(false);
  const [isLinkCopied, setIsLinkCopied] = useState(false);

  // States para a Simulação Interativa
  const [orderType, setOrderType] = useState<'table' | 'delivery'>('table');
  const [testStep, setTestStep] = useState<'welcome' | 'menu' | 'cart' | 'checkout' | 'success'>('welcome');
  const [simCart, setSimCart] = useState<SimCartItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [tableNumber, setTableNumber] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('');

  const categories = Array.from(new Set(products.map(p => p.category)));
  const menuUrl = `https://gastroai.me/cardapio/${settings.restaurantName.toLowerCase().replace(/\s+/g, '-')}`;

  const handleCopyLink = () => {
    navigator.clipboard.writeText(menuUrl);
    setIsLinkCopied(true);
    setTimeout(() => setIsLinkCopied(false), 2000);
  };

  const addToSimCart = (product: Product) => {
    setSimCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
  };

  const removeFromSimCart = (productId: string) => {
    setSimCart(prev => prev.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity - 1 } : item
    ).filter(item => item.quantity > 0));
  };

  const simCartTotal = useMemo(() => {
    return simCart.reduce((acc, item) => acc + (item.product.price * item.quantity), 0);
  }, [simCart]);

  const resetSimulation = () => {
    setShowTestMode(false);
    setTestStep('welcome');
    setSimCart([]);
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setTableNumber('');
    setPaymentMethod('');
  };

  const handleFinishSimulation = () => {
    const finalOrder: Order = {
      id: `DIG-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      createdAt: new Date(),
      items: simCart.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        price: item.product.price,
        quantity: item.quantity,
      })),
      total: simCartTotal + (orderType === 'delivery' ? 7 : 0),
      status: 'pending',
      type: orderType,
      tableNumber: orderType === 'table' ? parseInt(tableNumber) : undefined,
      customerName: customerName,
      customerPhone: customerPhone,
      customerAddress: orderType === 'delivery' ? customerAddress : undefined,
      paymentMethod: paymentMethod as any
    };

    onPlaceDigitalOrder(finalOrder);
    setTestStep('success');
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-10rem)] animate-in fade-in duration-500">
      {/* Coluna Esquerda: Configurações */}
      <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-8 rounded-[3rem] text-white shadow-xl shadow-indigo-100 flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10"><Share2 size={120} /></div>
          <div className="relative z-10 flex flex-col gap-2">
            <h3 className="text-xl font-black tracking-tight">Cardápio Digital Ativo</h3>
            <p className="text-indigo-100 text-sm font-medium">Aceite pedidos de Mesa e Delivery com facilidade.</p>
            <div className="mt-4 flex items-center gap-2 bg-black/20 p-2 rounded-2xl backdrop-blur-md border border-white/10">
               <Globe size={14} className="text-indigo-300 ml-2" />
               <span className="text-xs font-mono font-bold truncate max-w-[200px]">{menuUrl}</span>
            </div>
          </div>
          <div className="relative z-10 flex gap-3">
             <button onClick={handleCopyLink} className={`flex items-center gap-2 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${isLinkCopied ? 'bg-emerald-500 text-white' : 'bg-white text-indigo-600 hover:bg-indigo-50 shadow-lg'}`}>
                {isLinkCopied ? <Check size={16} /> : <Copy size={16} />}
                {isLinkCopied ? 'Link Copiado' : 'Copiar Link'}
             </button>
             <button onClick={() => setShowTestMode(true)} className="flex items-center gap-2 px-6 py-4 bg-indigo-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-400 border border-indigo-400 shadow-lg transition-all">
                <MousePointer2 size={16} /> Ver Simulador
             </button>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-8">
           <div className="flex bg-slate-50 p-1.5 rounded-2xl w-fit border">
            <button onClick={() => setActiveTab('visual')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'visual' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}>
              <Palette size={16} /> Visual
            </button>
            <button onClick={() => setActiveTab('behavior')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'behavior' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}>
              <Smartphone size={16} /> Comportamento
            </button>
          </div>

          {activeTab === 'visual' && (
            <div className="space-y-6 animate-in slide-in-from-left-4">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cor Primária</label>
                <div className="flex items-center gap-4">
                  <input type="color" className="w-16 h-16 rounded-2xl cursor-pointer" value={settings.primaryColor} onChange={(e) => onUpdateSettings({ ...settings, primaryColor: e.target.value })} />
                  <span className="text-sm font-mono text-slate-500 font-bold">{settings.primaryColor}</span>
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Restaurante</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl outline-none font-bold" value={settings.restaurantName} onChange={(e) => onUpdateSettings({ ...settings, restaurantName: e.target.value })} />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Preview Mobile Simulator */}
      <div className="w-full lg:w-[400px] flex flex-col gap-4">
        <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2 ml-4">
          <Eye size={16} /> Mobile Preview
        </h3>
        <div className="flex-1 bg-slate-900 rounded-[3.5rem] border-[12px] border-slate-800 shadow-2xl overflow-hidden relative group">
           <div className="h-full bg-white flex flex-col items-center justify-center p-12 text-center gap-6">
              <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center animate-bounce">
                 <Smartphone size={48} />
              </div>
              <div>
                 <p className="font-black text-slate-800">Simulador Mobile</p>
                 <p className="text-xs text-slate-400 mt-2">Teste a experiência de delivery do seu cliente.</p>
              </div>
           </div>
           <button onClick={() => setShowTestMode(true)} className="absolute inset-0 bg-indigo-600/20 backdrop-blur-[2px] opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center z-40">
              <div className="bg-white text-indigo-600 px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl">Abrir Simulador</div>
           </button>
        </div>
      </div>

      {/* MODAL SIMULATOR */}
      {showTestMode && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="absolute top-8 right-8"><button onClick={resetSimulation} className="p-4 bg-white/10 text-white rounded-full"><X size={32} /></button></div>
          <div className="w-[380px] h-[780px] bg-slate-900 rounded-[3.5rem] border-[12px] border-slate-800 shadow-2xl overflow-hidden relative">
             <div className="h-full bg-white flex flex-col relative overflow-hidden">
                {testStep === 'welcome' && (
                  <div className="h-full flex flex-col items-center justify-center p-8 text-center gap-10 animate-in fade-in zoom-in-95">
                     <div className="w-24 h-24 bg-indigo-50 rounded-[2rem] flex items-center justify-center"><img src={settings.logoUrl || 'https://picsum.photos/200'} className="w-16 h-16 rounded-xl object-cover" /></div>
                     <div className="space-y-3">
                        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">{settings.restaurantName}</h2>
                        <p className="text-sm font-medium text-slate-500 leading-relaxed">{settings.welcomeMessage}</p>
                     </div>
                     <div className="w-full flex flex-col gap-4">
                        <button onClick={() => { setOrderType('table'); setTestStep('menu'); }} className="w-full py-6 bg-slate-100 rounded-[2rem] flex items-center justify-center gap-4 hover:border-indigo-600 border-2 border-transparent transition-all">
                           <QrCode className="text-indigo-600" />
                           <div className="text-left"><p className="font-black text-slate-800 text-sm">Estou na Mesa</p><p className="text-[9px] font-bold text-slate-400 uppercase">Peça por QR Code</p></div>
                        </button>
                        <button onClick={() => { setOrderType('delivery'); setTestStep('menu'); }} className="w-full py-6 bg-slate-100 rounded-[2rem] flex items-center justify-center gap-4 hover:border-rose-600 border-2 border-transparent transition-all">
                           <Bike className="text-rose-600" />
                           <div className="text-left"><p className="font-black text-slate-800 text-sm">Delivery Online</p><p className="text-[9px] font-bold text-slate-400 uppercase">Receba em casa</p></div>
                        </button>
                     </div>
                  </div>
                )}

                {testStep === 'menu' && (
                  <div className="h-full flex flex-col animate-in slide-in-from-right-10">
                     <div className="h-40 shrink-0 relative bg-indigo-600 flex items-end p-6 overflow-hidden">
                        <img src={settings.bannerUrl} className="absolute inset-0 w-full h-full object-cover opacity-50" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                        <div className="relative z-10 text-white">
                           <h3 className="text-2xl font-black">{settings.restaurantName}</h3>
                           <p className="text-xs font-bold opacity-80 uppercase tracking-widest">{orderType === 'table' ? 'Mesa' : 'Delivery'}</p>
                        </div>
                     </div>
                     <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-24">
                        <div className="flex gap-2 overflow-x-auto scrollbar-hide">
                           {categories.map(cat => <button key={cat} className="px-4 py-2 rounded-full bg-slate-50 border text-[10px] font-black uppercase whitespace-nowrap">{cat}</button>)}
                        </div>
                        {products.map(product => (
                           <div key={product.id} className="flex gap-4 p-4 border rounded-[2rem] items-center">
                              <img src={product.image} className="w-16 h-16 rounded-xl object-cover" />
                              <div className="flex-1">
                                 <p className="font-bold text-slate-800 text-sm">{product.name}</p>
                                 <p className="font-black text-indigo-600 text-xs">R$ {product.price.toFixed(2)}</p>
                              </div>
                              <button onClick={() => addToSimCart(product)} className="w-8 h-8 rounded-lg text-white flex items-center justify-center" style={{ backgroundColor: settings.primaryColor }}><Plus size={16} /></button>
                           </div>
                        ))}
                     </div>
                     <div className="absolute bottom-6 inset-x-6">
                        <button onClick={() => setTestStep('cart')} disabled={simCart.length === 0} className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3" style={{ backgroundColor: settings.primaryColor }}>
                           <ShoppingCart size={18} /> Meu Carrinho ({simCart.reduce((a,b)=>a+b.quantity, 0)})
                        </button>
                     </div>
                  </div>
                )}

                {testStep === 'cart' && (
                  <div className="h-full flex flex-col animate-in slide-in-from-right-10">
                     <div className="p-6 border-b flex items-center gap-4">
                        <button onClick={() => setTestStep('menu')} className="p-2 hover:bg-slate-100 rounded-xl"><ArrowLeft size={20} /></button>
                        <h3 className="text-lg font-black text-slate-800">Meu Pedido</h3>
                     </div>
                     <div className="flex-1 overflow-y-auto p-6 space-y-4">
                        {simCart.map(item => (
                           <div key={item.product.id} className="flex justify-between items-center p-4 border rounded-2xl">
                              <div className="flex-1"><p className="font-bold text-sm">{item.product.name}</p><p className="text-xs text-indigo-600 font-black">R$ {item.product.price.toFixed(2)}</p></div>
                              <div className="flex items-center gap-3 bg-slate-100 p-1 rounded-xl">
                                 <button onClick={() => removeFromSimCart(item.product.id)} className="w-6 h-6 bg-white rounded-lg flex items-center justify-center shadow-sm"><Minus size={12} /></button>
                                 <span className="font-black text-xs">{item.quantity}</span>
                                 <button onClick={() => addToSimCart(item.product)} className="w-6 h-6 bg-white rounded-lg flex items-center justify-center shadow-sm"><Plus size={12} /></button>
                              </div>
                           </div>
                        ))}
                        <div className="bg-slate-50 p-6 rounded-[2rem] border mt-8 space-y-2">
                           <div className="flex justify-between text-xs font-bold text-slate-400"><span>Subtotal</span><span>R$ {simCartTotal.toFixed(2)}</span></div>
                           {orderType === 'delivery' && <div className="flex justify-between text-xs font-bold text-slate-400"><span>Taxa de Entrega</span><span>R$ 7.00</span></div>}
                           <div className="pt-2 border-t flex justify-between font-black text-xl text-slate-800"><span>Total</span><span>R$ {(simCartTotal + (orderType === 'delivery' ? 7 : 0)).toFixed(2)}</span></div>
                        </div>
                     </div>
                     <div className="p-6 border-t mt-auto">
                        <button onClick={() => setTestStep('checkout')} className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl" style={{ backgroundColor: settings.primaryColor }}>Finalizar Pedido</button>
                     </div>
                  </div>
                )}

                {testStep === 'checkout' && (
                  <div className="h-full flex flex-col animate-in slide-in-from-right-10">
                     <div className="p-6 border-b flex items-center gap-4">
                        <button onClick={() => setTestStep('cart')} className="p-2 hover:bg-slate-100 rounded-xl"><ArrowLeft size={20} /></button>
                        <h3 className="text-lg font-black text-slate-800">Checkout</h3>
                     </div>
                     <div className="flex-1 overflow-y-auto p-6 space-y-6">
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><User size={12} /> Seus Dados</label>
                           <input type="text" placeholder="Seu Nome" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" value={customerName} onChange={(e)=>setCustomerName(e.target.value)} />
                           <input type="tel" placeholder="WhatsApp (DDD)" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" value={customerPhone} onChange={(e)=>setCustomerPhone(e.target.value)} />
                        </div>
                        {orderType === 'delivery' ? (
                          <div className="space-y-4">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><MapPin size={12} /> Endereço de Entrega</label>
                             <textarea rows={3} placeholder="Rua, Número, Bairro e Referência" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold resize-none" value={customerAddress} onChange={(e)=>setCustomerAddress(e.target.value)} />
                          </div>
                        ) : (
                           <div className="space-y-4">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><QrCode size={12} /> Localização</label>
                              <input type="number" placeholder="Número da Mesa" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" value={tableNumber} onChange={(e)=>setTableNumber(e.target.value)} />
                           </div>
                        )}
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> Forma de Pagamento</label>
                           <div className="grid grid-cols-1 gap-2">
                              {['PIX', 'Cartão (Entregador)', 'Dinheiro'].map(method => (
                                 <button key={method} onClick={()=>setPaymentMethod(method)} className={`p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${paymentMethod === method ? 'border-indigo-600 bg-indigo-50' : 'bg-slate-50 border-slate-100'}`}>
                                    <span className="font-bold text-sm">{method}</span>
                                    {paymentMethod === method && <CheckCircle2 size={18} className="text-indigo-600" />}
                                 </button>
                              ))}
                           </div>
                        </div>
                     </div>
                     <div className="p-6 border-t mt-auto">
                        <button onClick={handleFinishSimulation} disabled={!customerName || !customerPhone || (orderType === 'delivery' ? !customerAddress : !tableNumber) || !paymentMethod} className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl disabled:opacity-50" style={{ backgroundColor: settings.primaryColor }}>Enviar Pedido ao Restaurante</button>
                     </div>
                  </div>
                )}

                {testStep === 'success' && (
                  <div className="h-full flex flex-col items-center justify-center p-10 text-center space-y-8 animate-in zoom-in-95">
                     <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-xl shadow-emerald-50"><CheckCircle2 size={64} /></div>
                     <div className="space-y-3">
                        <h3 className="text-3xl font-black text-slate-800 tracking-tighter">Tudo pronto!</h3>
                        <p className="text-slate-500 font-medium leading-relaxed">Seu pedido foi enviado com sucesso. Você receberá atualizações de status via WhatsApp.</p>
                     </div>
                     <div className="w-full p-6 bg-slate-50 rounded-[2rem] border text-left space-y-4">
                        <div className="flex items-center gap-3"><div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><MessageCircle size={16} /></div><p className="text-[10px] font-black uppercase text-indigo-600">Acompanhamento Ativo</p></div>
                        <p className="text-xs font-medium text-slate-600">Fique atento às notificações de status: Produção, Entrega e Concluído.</p>
                     </div>
                     <button onClick={resetSimulation} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl">Entendido</button>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DigitalMenuConfig;

import React, { useState, useMemo } from 'react';
import { Order, Courier, FinancialRecord } from '../types';
import { 
  Navigation, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, X, UserCheck, 
  TrendingUp, Settings, Plus,
  Save, UserPlus, Wallet, ArrowRightLeft,
  Banknote, QrCode
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee,
  onAddFinancialRecord
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'monitor' | 'couriers' | 'settlement' | 'settings'>('monitor');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<any | null>(null);

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Cálculo de acerto de contas por motoboy
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      // Filtra pedidos entregues por este motoboy
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);

      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, 
        cashCollected,
        balance: totalFees - cashCollected // Se positivo, empresa paga motoboy. Se negativo, motoboy devolve dinheiro.
      };
    });
  }, [couriers, deliveryOrders]);

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      vehicleType: newCourierVehicle 
    });
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setShowAddCourierModal(false);
  };

  const handleRealizeSettlement = (data: any) => {
    const { courier, balance, totalFees, cashCollected } = data;

    // Gerar registro financeiro
    onAddFinancialRecord({
      type: balance >= 0 ? 'expense' : 'income',
      amount: Math.abs(balance),
      category: 'Acerto Motoboy',
      description: `Acerto com ${courier.name}. Taxas: R$${totalFees.toFixed(2)} | Dinheiro recolhido: R$${cashCollected.toFixed(2)}`,
      date: new Date()
    });

    alert(`Acerto de ${courier.name} concluído com sucesso e registrado no financeiro!`);
    setShowSettlementModal(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navegação Secundária */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        {[
          { id: 'monitor', label: 'Monitor Entregas', icon: Navigation },
          { id: 'couriers', label: 'Meus Motoboys', icon: UserCheck },
          { id: 'settlement', label: 'Acerto de Contas', icon: Wallet },
          { id: 'settings', label: 'Regras', icon: Settings }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Coluna 1: Prontos (Aguardando Motoboy) */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Prontos para Saída ({deliveryOrders.filter(o => o.status === 'ready').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'ready').map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="text-xl font-black text-slate-800">#{order.id.slice(-4)}</h4>
                      <p className="text-[10px] font-bold text-amber-600 uppercase">Aguardando Motoboy</p>
                    </div>
                    <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                  </div>
                  <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                    <MapPin size={14} className="text-rose-500" />
                    <span className="truncate">{order.customerAddress}</span>
                  </div>
                  <button 
                    onClick={() => setSelectedOrderId(order.id)}
                    className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all"
                  >
                    Atribuir Entregador
                  </button>
                </div>
              ))}
            </div>
          </div>

          {/* Coluna 2: Em Rota (Monitorando Rua) */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Navigation size={16} className="text-indigo-600" /> Em Rota de Entrega ({deliveryOrders.filter(o => o.status === 'delivering').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'delivering').map(order => {
                const courier = couriers.find(c => c.id === order.courierId);
                return (
                  <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border shadow-sm space-y-4 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-1 h-full bg-indigo-600"></div>
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center"><Bike size={24} /></div>
                      <div>
                        <p className="text-sm font-black text-slate-800">{courier?.name || 'Motoboy'}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Saiu às {order.createdAt.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                      </div>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border text-xs font-bold text-slate-700 flex justify-between items-center">
                       <span>Pedido #{order.id.slice(-4)}</span>
                       <span className="text-indigo-600">R$ {order.total.toFixed(2)}</span>
                    </div>
                    <button 
                      onClick={() => onUpdateStatus(order.id, 'delivered')}
                      className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-700 transition-all"
                    >
                      Confirmar Entrega
                    </button>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Coluna 3: Painel Motoboy (Mini Estatísticas) */}
          <div className="space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2"><TrendingUp size={16} /> Painel Motoboy</h3>
            <div className="bg-gradient-to-br from-slate-800 to-slate-900 text-white p-8 rounded-[3rem] shadow-xl space-y-8">
               <div className="space-y-2">
                  <p className="text-[10px] font-black uppercase opacity-60 tracking-widest">Dinheiro na Rua</p>
                  <h2 className="text-4xl font-black text-amber-400">R$ {deliveryOrders.filter(o => o.status === 'delivering' && o.paymentMethod === 'dinheiro').reduce((a, b) => a + b.total, 0).toFixed(2)}</h2>
               </div>
               <div className="pt-8 border-t border-white/10 space-y-4">
                  <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase opacity-60">Entregadores Online</span><span className="font-black">{couriers.filter(c => c.status !== 'offline').length}</span></div>
                  <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase opacity-60">Taxas Acumuladas</span><span className="font-black text-emerald-400">R$ {deliveryOrders.filter(o => o.status === 'delivered').reduce((a, b) => a + (b.deliveryFee || 0), 0).toFixed(2)}</span></div>
               </div>
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-slate-800">Equipe de Entrega</h3>
             <button onClick={() => setShowAddCourierModal(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-indigo-100">
                <Plus size={18} /> Cadastrar Entregador
             </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {couriers.map(courier => (
              <div key={courier.id} className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-6 group hover:shadow-xl transition-all">
                <div className="flex items-center gap-4">
                   <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-[1.5rem] flex items-center justify-center font-black text-xl">{courier.name.charAt(0)}</div>
                   <div>
                     <h4 className="font-black text-slate-800">{courier.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase">{courier.vehicleType} • {courier.status}</p>
                   </div>
                </div>
                <div className="space-y-4">
                   <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl"><Phone size={16} className="text-slate-400" /><span className="text-xs font-bold">{courier.phone}</span></div>
                   <div className="flex items-center gap-3 p-4 bg-indigo-50 rounded-2xl border border-indigo-100"><QrCode size={16} className="text-indigo-600" /><div className="flex-1 overflow-hidden"><p className="text-[9px] font-black text-indigo-400 uppercase">PIX</p><p className="text-xs font-bold text-indigo-700 truncate">{courier.pixKey || 'Não cadastrado'}</p></div></div>
                </div>
                <div className="flex gap-2"><button className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest">Editar</button><button className="flex-1 py-3 border text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest">Inativar</button></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'settlement' && (
        <div className="space-y-8 animate-in slide-in-from-right-4">
           <div className="bg-indigo-600 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-xl shadow-indigo-100">
              <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter">Acerto de Contas</h2><p className="text-indigo-100 font-medium">Concilie taxas de entrega e dinheiro em espécie.</p></div>
              <ArrowRightLeft size={64} className="opacity-20" />
           </div>
           <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b"><tr><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase">Entregador</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Taxas</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Dinheiro em Mão</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Saldo</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-center">Ações</th></tr></thead>
                 <tbody className="divide-y">
                    {courierSettlementData.map((data, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                          <td className="px-10 py-8 font-black text-slate-800">{data.courier.name}</td>
                          <td className="px-10 py-8 text-right font-black text-emerald-600">R$ {data.totalFees.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-rose-600">R$ {data.cashCollected.toFixed(2)}</td>
                          <td className={`px-10 py-8 text-right font-black ${data.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(data.balance).toFixed(2)}</td>
                          <td className="px-10 py-8 text-center"><button onClick={() => setShowSettlementModal(data)} disabled={data.orderCount === 0} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30">Realizar Acerto</button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal de Atribuição de Motoboy */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div><h2 className="text-xl font-black">Chamar Entregador</h2><p className="text-[10px] font-bold text-slate-400 uppercase">Pedido #{selectedOrderId.slice(-4)}</p></div><button onClick={() => setSelectedOrderId(null)} className="p-2 hover:bg-white rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-3">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Disponíveis agora</p>
              {couriers.filter(c => c.status === 'available').map(courier => (
                <button key={courier.id} onClick={() => { onAssignCourier(selectedOrderId, courier.id); setSelectedOrderId(null); }} className="w-full flex items-center justify-between p-5 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left group">
                  <div className="flex items-center gap-4"><div className="p-3 bg-white shadow-sm border rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><Bike size={20} /></div><div><p className="font-black text-slate-800">{courier.name}</p><p className="text-[9px] font-bold text-slate-400 uppercase">{courier.vehicleType}</p></div></div>
                  <ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600 transition-all" />
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Cadastro Entregador */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div className="flex items-center gap-4"><div className="bg-indigo-600 p-3 rounded-2xl text-white"><UserPlus size={24} /></div><h2 className="text-xl font-black">Novo Entregador</h2></div><button onClick={() => setShowAddCourierModal(false)}><X size={24} className="text-slate-400" /></button></div>
            <div className="p-8 space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierName} onChange={(e)=>setNewCourierName(e.target.value)} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telefone</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierPhone} onChange={(e)=>setNewCourierPhone(e.target.value)} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave PIX (Para acertos)</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierPix} onChange={(e)=>setNewCourierPix(e.target.value)} /></div>
              <div className="grid grid-cols-3 gap-2">{(['moto', 'bike', 'car'] as const).map(v => (<button key={v} onClick={() => setNewCourierVehicle(v)} className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>{v}</button>))}</div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowAddCourierModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase text-[10px]">Cancelar</button><button onClick={handleSaveCourier} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl">Cadastrar</button></div>
          </div>
        </div>
      )}

      {/* Modal: Acerto de Contas */}
      {showSettlementModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white w-full max-w-lg rounded-[3.5rem] shadow-2xl p-10 text-center space-y-8 animate-in zoom-in-95">
              <div className="w-24 h-24 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mx-auto shadow-xl"><Wallet size={48} /></div>
              <div className="space-y-2"><h3 className="text-3xl font-black text-slate-800 tracking-tighter">Confirmar Acerto?</h3><p className="text-slate-500 font-medium">Fechando o saldo de <strong>{showSettlementModal.courier.name}</strong> para o financeiro.</p></div>
              <div className="bg-slate-50 p-8 rounded-[2.5rem] space-y-4 border text-left">
                 <div className="flex justify-between items-center text-xs font-bold text-slate-500"><span>Taxas Acumuladas</span><span className="text-emerald-600">+ R$ {showSettlementModal.totalFees.toFixed(2)}</span></div>
                 <div className="flex justify-between items-center text-xs font-bold text-slate-500"><span>Dinheiro em Mão</span><span className="text-rose-600">- R$ {showSettlementModal.cashCollected.toFixed(2)}</span></div>
                 <div className="pt-4 border-t flex justify-between items-center"><span className="text-sm font-black text-slate-800 uppercase tracking-widest">Saldo a {showSettlementModal.balance >= 0 ? 'Pagar' : 'Receber'}</span><span className={`text-2xl font-black ${showSettlementModal.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(showSettlementModal.balance).toFixed(2)}</span></div>
              </div>
              <div className="flex gap-4"><button onClick={() => setShowSettlementModal(null)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button><button onClick={() => handleRealizeSettlement(showSettlementModal)} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl">Confirmar Acerto</button></div>
              {showSettlementModal.courier.pixKey && (<div className="p-4 bg-indigo-50 rounded-2xl flex items-center justify-center gap-3"><QrCode size={18} className="text-indigo-600" /><p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate">PIX: {showSettlementModal.courier.pixKey}</p></div>)}
          </div>
        </div>
      )}

    </div>
  );
};

