    allowOrdering: true,
    showStock: true,
    bannerUrl: 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?q=80&w=2070&auto=format&fit=crop',
    logoUrl: ''
  });

  // Admin Settings
  const [adminSettings, setAdminSettings] = useState<AdminSettings>({
    companyName: 'GastroAI Soluções Alimentares LTDA',
    cnpj: '12.345.678/0001-90',
    address: 'Av. Paulista, 1000 - Bela Vista, São Paulo - SP',
    phone: '(11) 4002-8922',
    businessHours: [
      { day: 'Segunda-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Terça-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quarta-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quinta-feira', open: '11:00', close: '23:00', isClosed: false },
      { day: 'Sexta-feira', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Sábado', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Domingo', open: '11:00', close: '20:00', isClosed: true },
    ],
    fiscal: {
      environment: 'homologacao',
      certificateStatus: 'valid',
      certificateExpiry: '15/12/2025',
      cscId: '000001',
      cscToken: 'A1B2C3D4E5',
      nextNfceNumber: 154,
      series: 1,
      taxRegime: 'simples_nacional'
    } as any,
    printing: {
      paperWidth: '80mm',
      autoPrintOrder: true,
      headerText: 'BEM VINDO AO GASTROAI',
      footerText: 'Obrigado e volte sempre!',
      showLogo: true
    },
    apis: {
      googleMapsKey: '',
      whatsappToken: '',
      ifoodWebhook: '',
      integrationActive: false
    }
  });

  const [cashSession, setCashSession] = useState<CashSession>({
    isOpen: false,
    openingValue: 0,
    openedAt: null
  });

  const [mockWhatsAppNotify, setMockWhatsAppNotify] = useState<{title: string, msg: string} | null>(null);

  const triggerWhatsAppMock = (title: string, msg: string) => {
    setMockWhatsAppNotify({ title, msg });
    setTimeout(() => setMockWhatsAppNotify(null), 5000);
  };

  const handleAddFinancialRecord = (record: Partial<FinancialRecord>) => {
    const newRecord: FinancialRecord = {
      id: Math.random().toString(36).substr(2, 9),
      type: record.type || 'expense',
      amount: record.amount || 0,
      category: record.category || 'Outros',
      description: record.description || 'Lançamento manual',
      date: record.date || new Date()
    };
    setFinancialRecords(prev => [newRecord, ...prev]);
    addLog('u1', 'FINANCEIRO', `Novo lançamento: ${newRecord.description}`);
  };

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({ isOpen: true, openingValue: value, openedAt: new Date() });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({ isOpen: false, openingValue: 0, openedAt: null });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const handleIncomingDigitalOrder = (order: Order) => {
    setIncomingDigitalOrders(prev => [...prev, order]);
    addLog('u1', 'DIGITAL', `Novo pedido digital (${order.type === 'delivery' ? 'Delivery' : 'Mesa ' + order.tableNumber})`);
  };

  const acceptDigitalOrder = (orderId: string) => {
    const order = incomingDigitalOrders.find(o => o.id === orderId);
    if (order) {
      const acceptedOrder = { ...order, status: 'preparing' as const, deliveryFee: globalDeliveryFee };
      setOrders(prev => [acceptedOrder, ...prev]);
      setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));

      if (order.type === 'table' && order.tableNumber) {
        setTables(prev => prev.map(t => 
          t.id === order.tableNumber ? { 
            ...t, 
            status: 'occupied', 
            items: [...t.items, ...order.items],
            total: t.total + order.total
          } : t
        ));
      }

      triggerWhatsAppMock(
        "✅ Pedido Aceito!", 
        `Olá ${order.customerName}, seu pedido #${orderId.slice(-4)} foi aceito e já está em produção!`
      );

      addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} ACEITO`);
    }
  };

  const rejectDigitalOrder = (orderId: string) => {
    setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));
    addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} RECUSADO`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    const order = orders.find(o => o.id === id);
    if (!order) return;

    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));

    // Notificações simuladas automáticas via WhatsApp
    if (order.type === 'delivery') {
      if (status === 'preparing') {
        triggerWhatsAppMock("🥘 Em Produção!", `Olá ${order.customerName}, seu pedido #${id.slice(-4)} já está sendo preparado pela nossa cozinha.`);
      } else if (status === 'ready') {
        triggerWhatsAppMock("📦 Pedido Pronto!", `Seu pedido #${id.slice(-4)} está pronto e aguardando o entregador.`);
      } else if (status === 'delivering') {
        triggerWhatsAppMock("🛵 Saiu para Entrega!", `Boa notícia ${order.customerName}! O motoboy já saiu com o seu pedido.`);
      } else if (status === 'delivered') {
        triggerWhatsAppMock("🏁 Pedido Entregue!", `Tudo certo! Seu pedido #${id.slice(-4)} foi concluído. Bom apetite!`);
      }
    }

    if (status === 'delivered' && order.courierId) {
      setCouriers(prev => prev.map(c => c.id === order.courierId ? { ...c, status: 'available' } : c));
    }

    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const assignCourier = (orderId: string, courierId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return;

    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    setCouriers(prev => prev.map(c => c.id === courierId ? { ...c, status: 'delivering' } : c));

    triggerWhatsAppMock("🛵 Saiu para Entrega!", `Boa notícia ${order.customerName}! O entregador já saiu com seu pedido #${orderId.slice(-4)}.`);
    addLog('u1', 'DELIVERY', `Motoboy ${courierId} atribuído ao pedido #${orderId.slice(-4)}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts products={products} onNavigateToInventory={() => setActiveTab('inventory')} />
                <div className="bg-white p-6 rounded-3xl border shadow-sm h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{ name: 'Seg', sales: 4000 }, { name: 'Ter', sales: 3000 }, { name: 'Qua', sales: 5000 }, { name: 'Qui', sales: 4780 }, { name: 'Sex', sales: 8890 }, { name: 'Sáb', sales: 9390 }, { name: 'Dom', sales: 7490 }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fill="#4f46e51a" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit gap-6">
                <h3 className="text-xl font-bold">Resumo Diário</h3>
                <div className="p-6 bg-slate-50 rounded-2xl border">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables tables={tables} products={products} orders={orders} cashSession={cashSession} onUpdateTable={(id, items, status) => setTables(t => t.map(x => x.id === id ? {...x, items, status, total: items.reduce((a,b)=>a+(b.price*b.quantity),0)} : x))} onCloseTable={(id, method, fiscal) => {}} onSendToKitchen={() => {}} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} />;
      case 'kds':
        return <KDS orders={orders} onUpdateStatus={updateOrderStatus} />;
      case 'delivery':
        return <Delivery 
          orders={orders} 
          couriers={couriers} 
          deliveryFee={globalDeliveryFee}
          onUpdateStatus={updateOrderStatus} 
          onAssignCourier={assignCourier}
          onAddCourier={(c) => setCouriers(prev => [...prev, { ...c, id: `c${Date.now()}`, status: 'available', createdAt: new Date() } as Courier])}
          onUpdateDeliveryFee={setGlobalDeliveryFee}
          onAddFinancialRecord={handleAddFinancialRecord}
        />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={handleIncomingDigitalOrder} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={(p) => setProducts(prev => prev.map(x => x.id === p.id ? p : x))} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return <UsersPanel users={users} auditLogs={auditLogs} rolePermissions={rolePermissions} onAddUser={(u) => setUsers(prev => [...prev, { ...u, id: `u${Date.now()}`, status: 'online', createdAt: new Date() } as User])} onUpdateRole={()=>{}} onUpdateRolePermissions={()=>{}} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black">GA</div>
        </header>
        {renderContent()}
      </main>

      {/* WHATSAPP NOTIFICATION MOCK (VISIBLE ON ADMIN SIDE TOO) */}
      {mockWhatsAppNotify && (
        <div className="fixed top-8 right-8 z-[300] w-full max-w-sm px-4 animate-in slide-in-from-right-10">
           <div className="bg-white border-l-4 border-emerald-500 rounded-2xl shadow-2xl p-4 flex gap-4 items-center ring-1 ring-black/5">
              <div className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-emerald-100"><MessageCircle size={24} /></div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase text-emerald-600 flex justify-between"><span>Simulação WhatsApp Cliente</span><span className="text-slate-300">Agora</span></p>
                 <p className="text-sm font-black text-slate-800 mt-0.5">{mockWhatsAppNotify.title}</p>
                 <p className="text-xs font-medium text-slate-500 line-clamp-2">{mockWhatsAppNotify.msg}</p>
              </div>
           </div>
        </div>
      )}

      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-2 border-indigo-600 rounded-[2rem] shadow-2xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center">
                  {order.type === 'delivery' ? <ShoppingBag size={24} /> : <Smartphone size={24} />}
                </div>
                <div>
                  <h4 className="font-black text-slate-800">Novo Pedido: {order.type === 'delivery' ? 'Delivery' : 'Mesa ' + order.tableNumber}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => rejectDigitalOrder(order.id)} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => acceptDigitalOrder(order.id)} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Order, OrderStatus, Courier } from '../types';
import { 
  Clock, Check, CheckCircle2, Smartphone, 
  User, Truck, Package, Flag, ChevronRight, 
  ChefHat, Timer, Bike, AlertCircle, X
} from 'lucide-react';

interface KDSProps {
  orders: Order[];
  couriers: Courier[];
  onUpdateStatus: (id: string, status: OrderStatus) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, couriers, onUpdateStatus, onAssignCourier }) => {
  const [dispatchModalOrder, setDispatchModalOrder] = useState<Order | null>(null);

  const columns = useMemo(() => ({
    preparing: orders.filter(o => ['pending', 'preparing'].includes(o.status)),
    ready: orders.filter(o => o.status === 'ready'),
    delivering: orders.filter(o => o.status === 'delivering'),
    delivered: orders.filter(o => o.status === 'delivered').slice(0, 10),
  }), [orders]);

  const getStatusConfig = (status: string) => {
    switch (status) {
      case 'preparing': return { label: 'Produção', icon: ChefHat, color: 'bg-rose-500', bg: 'bg-rose-50/30' };
      case 'ready': return { label: 'Prontos / Despacho', icon: Package, color: 'bg-amber-500', bg: 'bg-amber-50/30' };
      case 'delivering': return { label: 'Em Rota', icon: Bike, color: 'bg-indigo-500', bg: 'bg-indigo-50/30' };
      case 'delivered': return { label: 'Finalizados', icon: Flag, color: 'bg-emerald-500', bg: 'bg-emerald-50/30' };
      default: return { label: 'Status', icon: Clock, color: 'bg-slate-500', bg: 'bg-slate-50' };
    }
  };

  const OrderCard: React.FC<{ order: Order }> = ({ order }) => {
    const timeElapsed = Math.floor((new Date().getTime() - new Date(order.createdAt).getTime()) / 60000);
    const courier = couriers.find(c => c.id === order.courierId);

    return (
      <div className="bg-white border-2 border-slate-100 rounded-[2rem] shadow-sm hover:shadow-md transition-all group animate-in slide-in-from-bottom-2 duration-300 overflow-hidden">
        <div className="p-5 border-b border-slate-50 flex justify-between items-start">
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <span className="font-black text-lg text-slate-800">#{order.id.slice(-4)}</span>
              {order.customerName && <Smartphone size={12} className="text-indigo-600" />}
            </div>
            <div className="flex flex-wrap gap-1">
               <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full border ${order.type === 'delivery' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                 {order.type}
               </span>
               {order.tableNumber && (
                 <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-700 border border-indigo-200">
                   Mesa {order.tableNumber}
                 </span>
               )}
            </div>
          </div>
          <div className="text-right">
             <div className={`flex items-center gap-1 text-[10px] font-bold uppercase ${timeElapsed > 20 ? 'text-rose-500' : 'text-slate-400'}`}>
                <Timer size={12} /> {timeElapsed}m
             </div>
          </div>
        </div>

        <div className="p-5 space-y-2">
          {order.items.map((item, idx) => (
            <div key={idx} className="flex gap-2 text-xs">
               <span className="font-black text-slate-400">{item.quantity}x</span>
               <p className="font-bold text-slate-700 truncate">{item.name}</p>
            </div>
          ))}
        </div>

        {order.status === 'delivering' && courier && (
          <div className="px-5 py-3 bg-indigo-50 border-t border-indigo-100 flex items-center gap-2">
            <Bike size={14} className="text-indigo-600" />
            <span className="text-[10px] font-black text-indigo-700 uppercase truncate">{courier.name}</span>
          </div>
        )}

        <div className="p-4 bg-slate-50/50 border-t">
          {order.status === 'preparing' ? (
            <button 
              onClick={() => onUpdateStatus(order.id, 'ready')}
              className="w-full bg-emerald-600 text-white py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-emerald-50"
            >
              <Check size={16} strokeWidth={4} /> Concluir Preparo
            </button>
          ) : order.status === 'ready' ? (
            order.type === 'delivery' ? (
              <button 
                onClick={() => setDispatchModalOrder(order)}
                className="w-full bg-rose-600 text-white py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-rose-50"
              >
                <Truck size={16} /> Selecionar Motoboy
              </button>
            ) : (
              <button 
                onClick={() => onUpdateStatus(order.id, 'delivered')}
                className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-50"
              >
                <CheckCircle2 size={16} /> Entregar na Mesa
              </button>
            )
          ) : order.status === 'delivering' ? (
            <button 
              onClick={() => onUpdateStatus(order.id, 'delivered')}
              className="w-full bg-slate-800 text-white py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all flex items-center justify-center gap-2"
            >
              <Flag size={16} /> Confirmar Entrega
            </button>
          ) : (
            <div className="flex items-center justify-center gap-2 text-[10px] font-black text-emerald-600 uppercase">
              <CheckCircle2 size={16} /> Entregue
            </div>
          )}
        </div>
      </div>
    );
  };

  const KanbanColumn: React.FC<{ status: keyof typeof columns; orders: Order[] }> = ({ status, orders }) => {
    const config = getStatusConfig(status as string);
    const Icon = config.icon;

    return (
      <div className={`flex flex-col w-80 min-w-[20rem] h-full rounded-[2.5rem] ${config.bg} border-2 border-slate-100 overflow-hidden`}>
        <div className="p-6 flex items-center justify-between border-b bg-white">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-xl text-white ${config.color} shadow-lg shadow-current/20`}>
              <Icon size={18} />
            </div>
            <div>
              <h3 className="font-black text-slate-800 text-sm uppercase tracking-tighter">{config.label}</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase">{orders.length} {orders.length === 1 ? 'Pedido' : 'Pedidos'}</p>
            </div>
          </div>
        </div>
        <div className="flex-1 p-4 overflow-y-auto space-y-4 custom-scrollbar">
          {orders.length > 0 ? (
            orders.map(order => <OrderCard key={order.id} order={order} />)
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-20 space-y-2 grayscale">
               <Icon size={48} />
               <p className="text-[10px] font-black uppercase tracking-widest">Vazio</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="flex gap-6 h-[calc(100vh-14rem)] overflow-x-auto pb-4 custom-scrollbar relative">
      <KanbanColumn status="preparing" orders={columns.preparing} />
      <KanbanColumn status="ready" orders={columns.ready} />
      <KanbanColumn status="delivering" orders={columns.delivering} />
      <KanbanColumn status="delivered" orders={columns.delivered} />

      {/* Modal de Despacho Rápido no KDS */}
      {dispatchModalOrder && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b flex justify-between items-center bg-rose-50/50">
                 <div>
                    <h2 className="text-xl font-black text-slate-800">Despachar Pedido</h2>
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest mt-1">Pedido #{dispatchModalOrder.id.slice(-4)}</p>
                 </div>
                 <button onClick={() => setDispatchModalOrder(null)} className="p-2 hover:bg-white rounded-full text-slate-400 transition-colors"><X size={24} /></button>
              </div>
              <div className="p-8 space-y-4">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Selecione o Entregador</p>
                 <div className="grid grid-cols-1 gap-3">
                    {couriers.filter(c => c.status !== 'offline').map(courier => {
                      const activeDeliveries = orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length;
                      return (
                        <button 
                           key={courier.id} 
                           onClick={() => {
                              onAssignCourier(dispatchModalOrder.id, courier.id);
                              setDispatchModalOrder(null);
                           }}
                           className="w-full flex items-center justify-between p-4 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all group"
                        >
                           <div className="flex items-center gap-4">
                              <div className="w-12 h-12 bg-white rounded-xl shadow-sm border flex items-center justify-center text-slate-400 group-hover:text-indigo-600 transition-colors">
                                 <Bike size={24} />
                              </div>
                              <div className="text-left">
                                 <p className="font-black text-slate-800">{courier.name}</p>
                                 <p className={`text-[9px] font-black uppercase ${activeDeliveries > 0 ? 'text-amber-500' : 'text-emerald-500'}`}>
                                    {activeDeliveries > 0 ? `${activeDeliveries} Entrega(s) em curso` : 'Livre agora'}
                                 </p>
                              </div>
                           </div>
                           <ChevronRight size={18} className="text-slate-300 group-hover:text-indigo-600 group-hover:translate-x-1 transition-all" />
                        </button>
                      );
                    })}
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default KDS;

import React, { useState, useMemo } from 'react';
import { Order, Courier, FinancialRecord } from '../types';
import { 
  Navigation, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, X, UserCheck, 
  TrendingUp, Settings, Plus,
  Save, UserPlus, Wallet, ArrowRightLeft,
  Banknote, QrCode, ClipboardList, Timer, Clock
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee,
  onAddFinancialRecord
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'monitor' | 'couriers' | 'settlement' | 'settings'>('monitor');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<any | null>(null);

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Cálculo de carga de trabalho por motoboy
  const courierStats = useMemo(() => {
    return couriers.map(courier => {
      const activeOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivering');
      const completedOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');

      return {
        ...courier,
        activeCount: activeOrders.length,
        completedCount: completedOrders.length
      };
    });
  }, [couriers, deliveryOrders]);

  // Cálculo de acerto de contas
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);

      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, 
        cashCollected,
        balance: totalFees - cashCollected
      };
    });
  }, [couriers, deliveryOrders]);

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      vehicleType: newCourierVehicle 
    });
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setShowAddCourierModal(false);
  };

  const handleRealizeSettlement = (data: any) => {
    const { courier, balance, totalFees, cashCollected } = data;
    onAddFinancialRecord({
      type: balance >= 0 ? 'expense' : 'income',
      amount: Math.abs(balance),
      category: 'Acerto Motoboy',
      description: `Acerto com ${courier.name}. Taxas: R$${totalFees.toFixed(2)} | Dinheiro recolhido: R$${cashCollected.toFixed(2)}`,
      date: new Date()
    });
    alert(`Acerto de ${courier.name} concluído com sucesso!`);
    setShowSettlementModal(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navegação Secundária */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        {[
          { id: 'monitor', label: 'Monitor Despacho', icon: Navigation },
          { id: 'couriers', label: 'Equipe de Motoboys', icon: UserCheck },
          { id: 'settlement', label: 'Acertos Financeiros', icon: Wallet },
          { id: 'settings', label: 'Configurações', icon: Settings }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Coluna 1: Prontos (Aguardando Despacho) */}
          <div className="lg:col-span-4 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Aguardando Motoboy ({deliveryOrders.filter(o => o.status === 'ready').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'ready').length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center opacity-30 p-12 text-center grayscale">
                   <Timer size={48} className="mb-4" />
                   <p className="text-xs font-black uppercase tracking-widest">Nenhum pedido pronto para saída</p>
                </div>
              ) : (
                deliveryOrders.filter(o => o.status === 'ready').map(order => (
                  <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="text-xl font-black text-slate-800">#{order.id.slice(-4)}</h4>
                        <div className="flex items-center gap-1 mt-1 text-[9px] font-black uppercase text-amber-600">
                           <Clock size={12} /> {Math.floor((Date.now() - new Date(order.createdAt).getTime()) / 60000)}m aguardando
                        </div>
                      </div>
                      <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                    </div>
                    <div className="flex items-start gap-2 text-xs font-medium text-slate-500 bg-slate-50 p-3 rounded-2xl border border-slate-100">
                      <MapPin size={16} className="text-rose-500 shrink-0 mt-0.5" />
                      <span className="line-clamp-2 leading-relaxed">{order.customerAddress}</span>
                    </div>
                    <button 
                      onClick={() => setSelectedOrderId(order.id)}
                      className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg"
                    >
                      Selecionar Entregador
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Coluna 2: Status dos Motoboys em Rota */}
          <div className="lg:col-span-8 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Bike size={16} className="text-indigo-600" /> Motoboys em Atividade
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               {courierStats.filter(c => c.status !== 'offline').map(courier => (
                  <div key={courier.id} className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden flex flex-col">
                     <div className="p-6 border-b flex justify-between items-center bg-slate-50/50">
                        <div className="flex items-center gap-4">
                           <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center font-black">
                              {courier.name.charAt(0)}
                           </div>
                           <div>
                              <p className="font-black text-slate-800">{courier.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{courier.vehicleType}</p>
                           </div>
                        </div>
                        <div className="text-right">
                           <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${courier.activeCount > 0 ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {courier.activeCount > 0 ? `${courier.activeCount} Em Rota` : 'Disponível'}
                           </span>
                        </div>
                     </div>

                     <div className="flex-1 p-6 space-y-4">
                        {orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length > 0 ? (
                           <div className="space-y-3">
                              {orders.filter(o => o.courierId === courier.id && o.status === 'delivering').map(order => (
                                 <div key={order.id} className="flex items-center justify-between p-4 bg-indigo-50/30 border border-indigo-100 rounded-2xl">
                                    <div className="flex items-center gap-3">
                                       <div className="w-8 h-8 bg-indigo-600 text-white rounded-lg flex items-center justify-center text-[10px] font-black">
                                          #{order.id.slice(-4)}
                                       </div>
                                       <div>
                                          <p className="text-[10px] font-black text-slate-700 uppercase">{order.customerName?.split(' ')[0]}</p>
                                          <p className="text-[9px] font-bold text-slate-400">Saiu há {Math.floor((Date.now() - new Date(order.createdAt).getTime()) / 60000)}m</p>
                                       </div>
                                    </div>
                                    <button 
                                       onClick={() => onUpdateStatus(order.id, 'delivered')}
                                       className="p-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 transition-colors shadow-lg shadow-emerald-100"
                                       title="Confirmar Entrega"
                                    >
                                       <CheckCircle2 size={16} />
                                    </button>
                                 </div>
                              ))}
                           </div>
                        ) : (
                           <div className="h-24 flex flex-col items-center justify-center border-2 border-dashed rounded-[2rem] border-slate-100 opacity-40">
                              <ClipboardList size={24} className="text-slate-300" />
                              <p className="text-[10px] font-black uppercase mt-1">Nenhuma entrega ativa</p>
                           </div>
                        )}
                     </div>

                     <div className="p-4 bg-slate-50 border-t flex justify-between items-center px-8">
                        <div className="text-center">
                           <p className="text-[8px] font-black uppercase text-slate-400">Total Hoje</p>
                           <p className="text-sm font-black text-slate-700">{courier.completedCount}</p>
                        </div>
                        <div className="h-6 w-px bg-slate-200"></div>
                        <div className="text-center">
                           <p className="text-[8px] font-black uppercase text-slate-400">Taxas Acumuladas</p>
                           <p className="text-sm font-black text-emerald-600">R$ {(courier.completedCount * deliveryFee).toFixed(2)}</p>
                        </div>
                     </div>
                  </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-slate-800">Equipe de Entrega</h3>
             <button onClick={() => setShowAddCourierModal(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-indigo-100">
                <Plus size={18} /> Cadastrar Entregador
             </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {couriers.map(courier => (
              <div key={courier.id} className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-6 group hover:shadow-xl transition-all">
                <div className="flex items-center gap-4">
                   <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-[1.5rem] flex items-center justify-center font-black text-xl">{courier.name.charAt(0)}</div>
                   <div>
                     <h4 className="font-black text-slate-800">{courier.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase">{courier.vehicleType} • {courier.status}</p>
                   </div>
                </div>
                <div className="space-y-4">
                   <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl"><Phone size={16} className="text-slate-400" /><span className="text-xs font-bold">{courier.phone}</span></div>
                   <div className="flex items-center gap-3 p-4 bg-indigo-50 rounded-2xl border border-indigo-100"><QrCode size={16} className="text-indigo-600" /><div className="flex-1 overflow-hidden"><p className="text-[9px] font-black text-indigo-400 uppercase">PIX</p><p className="text-xs font-bold text-indigo-700 truncate">{courier.pixKey || 'Não cadastrado'}</p></div></div>
                </div>
                <div className="flex gap-2"><button className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest">Editar</button><button className="flex-1 py-3 border text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest">Inativar</button></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'settlement' && (
        <div className="space-y-8 animate-in slide-in-from-right-4">
           <div className="bg-indigo-600 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-xl shadow-indigo-100">
              <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter">Acerto de Contas</h2><p className="text-indigo-100 font-medium">Concilie taxas de entrega e dinheiro em espécie.</p></div>
              <ArrowRightLeft size={64} className="opacity-20" />
           </div>
           <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b"><tr><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase">Entregador</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Taxas</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Dinheiro em Mão</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Saldo</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-center">Ações</th></tr></thead>
                 <tbody className="divide-y">
                    {courierSettlementData.map((data, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                          <td className="px-10 py-8 font-black text-slate-800">{data.courier.name}</td>
                          <td className="px-10 py-8 text-right font-black text-emerald-600">R$ {data.totalFees.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-rose-600">R$ {data.cashCollected.toFixed(2)}</td>
                          <td className={`px-10 py-8 text-right font-black ${data.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(data.balance).toFixed(2)}</td>
                          <td className="px-10 py-8 text-center"><button onClick={() => setShowSettlementModal(data)} disabled={data.orderCount === 0} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30">Realizar Acerto</button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal de Seleção de Motoboy (Despacho Principal) */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div><h2 className="text-xl font-black text-slate-800">Despachar Pedido</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Pedido #{selectedOrderId.slice(-4)}</p></div><button onClick={() => setSelectedOrderId(null)} className="p-2 hover:bg-white rounded-full transition-colors"><X size={24} /></button></div>
