              {couriers.filter(c => c.status !== 'offline').length > 0 ? (
                 couriers.filter(c => c.status !== 'offline').map(courier => {
                   const activeDeliveries = orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length;
                   return (
                      <button key={courier.id} onClick={() => { onAssignCourier(selectedOrderId, courier.id); setSelectedOrderId(null); }} className="w-full flex items-center justify-between p-5 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left group">
                        <div className="flex items-center gap-4">
                           <div className="p-3 bg-white shadow-sm border rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
                              <Bike size={24} />
                           </div>
                           <div>
                              <p className="font-black text-slate-800">{courier.name}</p>
                              <div className="flex items-center gap-1.5 mt-0.5">
                                 <div className={`w-1.5 h-1.5 rounded-full ${activeDeliveries > 0 ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                                 <p className="text-[9px] font-black uppercase text-slate-400">
                                    {activeDeliveries > 0 ? `${activeDeliveries} entregas ativas` : 'Livre'}
                                 </p>
                              </div>
                           </div>
                        </div>
                        <ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600 transition-all" />
                      </button>
                   );
                 })
              ) : (
                 <div className="p-12 text-center opacity-30 grayscale flex flex-col items-center">
                    <UserPlus size={48} className="mb-4" />
                    <p className="text-xs font-black uppercase">Nenhum motoboy logado</p>
                 </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Cadastro Entregador */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div className="flex items-center gap-4"><div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg"><UserPlus size={24} /></div><h2 className="text-xl font-black">Novo Entregador</h2></div><button onClick={() => setShowAddCourierModal(false)} className="p-2 hover:bg-white rounded-full"><X size={24} className="text-slate-400" /></button></div>
            <div className="p-8 space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none border-slate-100 focus:border-indigo-500 transition-colors" value={newCourierName} onChange={(e)=>setNewCourierName(e.target.value)} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none border-slate-100 focus:border-indigo-500 transition-colors" value={newCourierPhone} onChange={(e)=>setNewCourierPhone(e.target.value)} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave PIX</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none border-slate-100 focus:border-indigo-500 transition-colors" value={newCourierPix} onChange={(e)=>setNewCourierPix(e.target.value)} /></div>
              <div className="grid grid-cols-3 gap-2">{(['moto', 'bike', 'car'] as const).map(v => (<button key={v} onClick={() => setNewCourierVehicle(v)} className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-400'}`}>{v}</button>))}</div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowAddCourierModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase text-[10px]">Cancelar</button><button onClick={handleSaveCourier} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl">Cadastrar</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Delivery;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import POS from './components/POS';
import Tables from './components/Tables';
import KDS from './components/KDS';
import AIInsights from './components/AIInsights';
import UsersPanel from './components/UsersPanel';
import Inventory from './components/Inventory';
import Finance from './components/Finance';
import Delivery from './components/Delivery';
import CMVAnalysis from './components/CMVAnalysis';
import DashboardAlerts from './components/DashboardAlerts';
import DigitalMenuConfig from './components/DigitalMenuConfig';
import AdminSettingsComponent from './components/AdminSettings';
import { 
  INITIAL_PRODUCTS, 
  INITIAL_TABLES, 
  INITIAL_COURIERS,
  INITIAL_USERS,
  INITIAL_AUDIT_LOGS,
  ROLE_DEFAULT_PERMISSIONS as INITIAL_ROLE_PERMISSIONS
} from './constants';
import { Product, Table, Order, Courier, FinancialRecord, User, UserRole, AuditLog, Permission, OrderItem, PaymentMethod, PriceHistory, DigitalMenuSettings, AdminSettings } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Plus, Download, Filter, Bell, BellRing, Check, X as CloseIcon, Smartphone, ShoppingBag, MessageCircle } from 'lucide-react';

interface CashSession {
  isOpen: boolean;
  openingValue: number;
  openedAt: Date | null;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [tables, setTables] = useState<Table[]>(INITIAL_TABLES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [incomingDigitalOrders, setIncomingDigitalOrders] = useState<Order[]>([]);
  const [couriers, setCouriers] = useState<Courier[]>(INITIAL_COURIERS.map(c => ({ ...c, createdAt: new Date(), pixKey: 'financeiro@restaurante.com' })));
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(INITIAL_AUDIT_LOGS);
  const [rolePermissions, setRolePermissions] = useState<Record<UserRole, Permission[]>>(INITIAL_ROLE_PERMISSIONS as Record<UserRole, Permission[]>);
  const [globalDeliveryFee, setGlobalDeliveryFee] = useState(7.00);
  const [financialRecords, setFinancialRecords] = useState<FinancialRecord[]>([]);

  // Cardápio Digital Settings
  const [digitalMenuSettings, setDigitalMenuSettings] = useState<DigitalMenuSettings>({
    primaryColor: '#4f46e5',
    restaurantName: 'GastroAI Bistrô',
    welcomeMessage: 'Olá! Seja bem-vindo ao nosso cardápio digital. Sinta-se em casa e faça seu pedido!',
    allowOrdering: true,
    showStock: true,
    bannerUrl: 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?q=80&w=2070&auto=format&fit=crop',
    logoUrl: ''
  });

  // Admin Settings
  const [adminSettings, setAdminSettings] = useState<AdminSettings>({
    companyName: 'GastroAI Soluções Alimentares LTDA',
    cnpj: '12.345.678/0001-90',
    address: 'Av. Paulista, 1000 - Bela Vista, São Paulo - SP',
    phone: '(11) 4002-8922',
    businessHours: [
      { day: 'Segunda-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Terça-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quarta-feira', open: '11:00', close: '22:00', isClosed: false },
      { day: 'Quinta-feira', open: '11:00', close: '23:00', isClosed: false },
      { day: 'Sexta-feira', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Sábado', open: '11:00', close: '00:00', isClosed: false },
      { day: 'Domingo', open: '11:00', close: '20:00', isClosed: true },
    ],
    fiscal: {
      environment: 'homologacao',
      certificateStatus: 'valid',
      certificateExpiry: '15/12/2025',
      cscId: '000001',
      cscToken: 'A1B2C3D4E5',
      nextNfceNumber: 154,
      series: 1,
      taxRegime: 'simples_nacional'
    } as any,
    printing: {
      paperWidth: '80mm',
      autoPrintOrder: true,
      headerText: 'BEM VINDO AO GASTROAI',
      footerText: 'Obrigado e volte sempre!',
      showLogo: true
    },
    apis: {
      googleMapsKey: '',
      whatsappToken: '',
      ifoodWebhook: '',
      integrationActive: false
    }
  });

  const [cashSession, setCashSession] = useState<CashSession>({
    isOpen: false,
    openingValue: 0,
    openedAt: null
  });

  const [mockWhatsAppNotify, setMockWhatsAppNotify] = useState<{title: string, msg: string} | null>(null);

  const triggerWhatsAppMock = (title: string, msg: string) => {
    setMockWhatsAppNotify({ title, msg });
    setTimeout(() => setMockWhatsAppNotify(null), 5000);
  };

  const handleAddFinancialRecord = (record: Partial<FinancialRecord>) => {
    const newRecord: FinancialRecord = {
      id: Math.random().toString(36).substr(2, 9),
      type: record.type || 'expense',
      amount: record.amount || 0,
      category: record.category || 'Outros',
      description: record.description || 'Lançamento manual',
      date: record.date || new Date()
    };
    setFinancialRecords(prev => [newRecord, ...prev]);
    addLog('u1', 'FINANCEIRO', `Novo lançamento: ${newRecord.description}`);
  };

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({ isOpen: true, openingValue: value, openedAt: new Date() });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({ isOpen: false, openingValue: 0, openedAt: null });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const handleIncomingDigitalOrder = (order: Order) => {
    setIncomingDigitalOrders(prev => [...prev, order]);
    addLog('u1', 'DIGITAL', `Novo pedido digital (${order.type === 'delivery' ? 'Delivery' : 'Mesa ' + order.tableNumber})`);
  };

  const acceptDigitalOrder = (orderId: string) => {
    const order = incomingDigitalOrders.find(o => o.id === orderId);
    if (order) {
      const acceptedOrder = { ...order, status: 'preparing' as const, deliveryFee: globalDeliveryFee };
      setOrders(prev => [acceptedOrder, ...prev]);
      setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));

      if (order.type === 'table' && order.tableNumber) {
        setTables(prev => prev.map(t => 
          t.id === order.tableNumber ? { 
            ...t, 
            status: 'occupied', 
            items: [...t.items, ...order.items],
            total: t.total + order.total
          } : t
        ));
      }

      triggerWhatsAppMock(
        "✅ Pedido Aceito!", 
        `Olá ${order.customerName}, seu pedido #${orderId.slice(-4)} foi aceito e já está em produção!`
      );

      addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} ACEITO`);
    }
  };

  const rejectDigitalOrder = (orderId: string) => {
    setIncomingDigitalOrders(prev => prev.filter(o => o.id !== orderId));
    addLog('u1', 'DIGITAL', `Pedido #${orderId.slice(-4)} RECUSADO`);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    const order = orders.find(o => o.id === id);
    if (!order) return;

    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));

    if (order.type === 'delivery') {
      if (status === 'preparing') {
        triggerWhatsAppMock("🥘 Em Produção!", `Olá ${order.customerName}, seu pedido #${id.slice(-4)} já está sendo preparado pela nossa cozinha.`);
      } else if (status === 'ready') {
        triggerWhatsAppMock("📦 Pedido Pronto!", `Seu pedido #${id.slice(-4)} está pronto e aguardando o entregador.`);
      } else if (status === 'delivered') {
        triggerWhatsAppMock("🏁 Pedido Entregue!", `Tudo certo! Seu pedido #${id.slice(-4)} foi concluído. Bom apetite!`);
      }
    }

    if (status === 'delivered' && order.courierId) {
      setCouriers(prev => prev.map(c => c.id === order.courierId ? { ...c, status: 'available' } : c));
    }

    addLog('u3', 'STATUS', `Pedido #${id.slice(-4)} alterado para ${status}`);
  };

  const assignCourier = (orderId: string, courierId: string) => {
    const order = orders.find(o => o.id === orderId);
    const courier = couriers.find(c => c.id === courierId);
    if (!order || !courier) return;

    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    setCouriers(prev => prev.map(c => c.id === courierId ? { ...c, status: 'delivering' } : c));

    triggerWhatsAppMock("🛵 Saiu para Entrega!", `Boa notícia ${order.customerName}! O entregador ${courier.name} já saiu com seu pedido #${orderId.slice(-4)}.`);
    addLog('u1', 'DELIVERY', `Pedido #${orderId.slice(-4)} despachado com ${courier.name}`);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts products={products} onNavigateToInventory={() => setActiveTab('inventory')} />
                <div className="bg-white p-6 rounded-3xl border shadow-sm h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{ name: 'Seg', sales: 4000 }, { name: 'Ter', sales: 3000 }, { name: 'Qua', sales: 5000 }, { name: 'Qui', sales: 4780 }, { name: 'Sex', sales: 8890 }, { name: 'Sáb', sales: 9390 }, { name: 'Dom', sales: 7490 }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fill="#4f46e51a" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit gap-6">
                <h3 className="text-xl font-bold">Resumo Diário</h3>
                <div className="p-6 bg-slate-50 rounded-2xl border">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables tables={tables} products={products} orders={orders} cashSession={cashSession} onUpdateTable={(id, items, status) => setTables(t => t.map(x => x.id === id ? {...x, items, status, total: items.reduce((a,b)=>a+(b.price*b.quantity),0)} : x))} onCloseTable={(id, method, fiscal) => {}} onSendToKitchen={() => {}} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} />;
      case 'kds':
        return <KDS orders={orders} couriers={couriers} onUpdateStatus={updateOrderStatus} onAssignCourier={assignCourier} />;
      case 'delivery':
        return <Delivery 
          orders={orders} 
          couriers={couriers} 
          deliveryFee={globalDeliveryFee}
          onUpdateStatus={updateOrderStatus} 
          onAssignCourier={assignCourier}
          onAddCourier={(c) => setCouriers(prev => [...prev, { ...c, id: `c${Date.now()}`, status: 'available', createdAt: new Date() } as Courier])}
          onUpdateDeliveryFee={setGlobalDeliveryFee}
          onAddFinancialRecord={handleAddFinancialRecord}
        />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={handleIncomingDigitalOrder} />;
      case 'finance':
        return <Finance orders={orders} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={(p) => setProducts(prev => prev.map(x => x.id === p.id ? p : x))} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'users':
        return <UsersPanel users={users} auditLogs={auditLogs} rolePermissions={rolePermissions} onAddUser={(u) => setUsers(prev => [...prev, { ...u, id: `u${Date.now()}`, status: 'online', createdAt: new Date() } as User])} onUpdateRole={()=>{}} onUpdateRolePermissions={()=>{}} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black">GA</div>
        </header>
        {renderContent()}
      </main>

      {/* WHATSAPP NOTIFICATION MOCK */}
      {mockWhatsAppNotify && (
        <div className="fixed top-8 right-8 z-[300] w-full max-w-sm px-4 animate-in slide-in-from-right-10">
           <div className="bg-white border-l-4 border-emerald-500 rounded-2xl shadow-2xl p-4 flex gap-4 items-center ring-1 ring-black/5">
              <div className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-emerald-100"><MessageCircle size={24} /></div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase text-emerald-600 flex justify-between"><span>WhatsApp Cliente</span><span className="text-slate-300">Agora</span></p>
                 <p className="text-sm font-black text-slate-800 mt-0.5">{mockWhatsAppNotify.title}</p>
                 <p className="text-xs font-medium text-slate-500 line-clamp-2">{mockWhatsAppNotify.msg}</p>
              </div>
           </div>
        </div>
      )}

      {/* PEDIDOS DIGITAIS ENTRANDO */}
      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-2 border-indigo-600 rounded-[2rem] shadow-2xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center">
                  {order.type === 'delivery' ? <ShoppingBag size={24} /> : <Smartphone size={24} />}
                </div>
                <div>
                  <h4 className="font-black text-slate-800">Novo Pedido Digital</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => rejectDigitalOrder(order.id)} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => acceptDigitalOrder(order.id)} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

export type OrderStatus = 'pending' | 'preparing' | 'ready' | 'delivering' | 'delivered' | 'cancelled';

export type UserRole = 'ADMIN' | 'MANAGER' | 'WAITER' | 'CASHIER' | 'CHEF';

export type PaymentMethod = 'dinheiro' | 'cartao_credito' | 'cartao_debito' | 'pix' | 'vale_refeicao';

export type Permission = 
  | 'dashboard_view' 
  | 'pos_access' 
  | 'tables_manage' 
  | 'kds_view' 
  | 'delivery_manage' 
  | 'inventory_edit' 
  | 'finance_view' 
  | 'cmv_analysis' 
  | 'users_manage'
  | 'digital_menu_manage'
  | 'admin_settings_manage'
  | 'fiscal_manage';

export interface BusinessHours {
  day: string;
  open: string;
  close: string;
  isClosed: boolean;
}

export interface FiscalSettings {
  environment: 'homologacao' | 'producao';
  certificateStatus: 'valid' | 'expired' | 'missing';
  certificateExpiry?: string;
  cscId: string;
  cscToken: string;
  nextNfceNumber: number;
  series: number;
  taxRegime: 'simples_nacional' | 'lucro_presumido' | 'lucro_real';
}

export interface AdminSettings {
  companyName: string;
  cnpj: string;
  address: string;
  phone: string;
  businessHours: BusinessHours[];
  fiscal: FiscalSettings;
  printing: {
    paperWidth: '58mm' | '80mm';
    autoPrintOrder: boolean;
    headerText: string;
    footerText: string;
    showLogo: boolean;
  };
  apis: {
    googleMapsKey: string;
    whatsappToken: string;
    ifoodWebhook: string;
    integrationActive: boolean;
  };
}

export interface DigitalMenuSettings {
  primaryColor: string;
  restaurantName: string;
  welcomeMessage: string;
  allowOrdering: boolean;
  showStock: boolean;
  bannerUrl: string;
  logoUrl: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface PriceHistory {
  date: string;
  price: number;
  cost: number;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
  priceHistory?: PriceHistory[];
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
  observation?: string;
  seat?: string;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  deliveryFee?: number;
  createdAt: Date;
  customerName?: string;
  customerPhone?: string;
  customerAddress?: string;
  courierId?: string;
  paymentMethod?: PaymentMethod;
  isFiscalIssued?: boolean;
  fiscalKey?: string;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
  items: OrderItem[];
  total: number;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
  pixKey?: string;
  dailyFee?: number;
  vehicleType?: 'bike' | 'moto' | 'car';
  createdAt: Date;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

import React, { useState, useMemo } from 'react';
import { Order, Courier, FinancialRecord } from '../types';
import { 
  Navigation, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, X, UserCheck, 
  TrendingUp, Settings, Plus,
  Save, UserPlus, Wallet, ArrowRightLeft,
  Banknote, QrCode, ClipboardList, Timer, Clock,
  Coins, CreditCard, DollarSign, Calculator, AlertTriangle
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee,
  onAddFinancialRecord
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'monitor' | 'couriers' | 'settlement' | 'settings'>('monitor');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<any | null>(null);

  // Settlement Multimeios
  const [settlementPayments, setSettlementPayments] = useState<{ [key: string]: number }>({
    dinheiro: 0,
    pix: 0,
    cartao: 0
  });

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierDailyFee, setNewCourierDailyFee] = useState('0');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Cálculo de acerto de contas por motoboy
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);
      const dailyFee = courier.dailyFee || 0;

      // Saldo Final = (Taxas + Diária) - O que ele recebeu em dinheiro
      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, 
        cashCollected,
        dailyFee,
        balance: (totalFees + dailyFee) - cashCollected
      };
    });
  }, [couriers, deliveryOrders]);

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      dailyFee: parseFloat(newCourierDailyFee) || 0,
      vehicleType: newCourierVehicle 
    });
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setNewCourierDailyFee('0');
    setShowAddCourierModal(false);
  };

  const openSettlement = (data: any) => {
    setShowSettlementModal(data);
    // Reset payments state based on balance
    setSettlementPayments({
      dinheiro: data.balance > 0 ? data.balance : 0,
      pix: 0,
      cartao: 0
    });
  };

  const handleRealizeSettlement = () => {
    if (!showSettlementModal) return;
    const { courier, balance, totalFees, dailyFee, cashCollected } = showSettlementModal;

    const totalSelected = Object.values(settlementPayments).reduce((a, b) => a + b, 0);

    // Validar se o total bate com o saldo (em valor absoluto se estiver recebendo, ou valor real se pagando)
    if (Math.abs(totalSelected - Math.abs(balance)) > 0.01) {
      alert("A soma dos valores informados não confere com o saldo do acerto!");
      return;
    }

    // Criar registros financeiros para cada modalidade
    Object.entries(settlementPayments).forEach(([method, amount]) => {
      if (amount > 0) {
        onAddFinancialRecord({
          type: balance >= 0 ? 'expense' : 'income',
          amount: amount,
          category: 'Acerto Motoboy',
          description: `Acerto com ${courier.name} (${method.toUpperCase()}). Taxas: R$${totalFees.toFixed(2)} | Diária: R$${dailyFee.toFixed(2)} | Dinheiro rua: R$${cashCollected.toFixed(2)}`,
          date: new Date()
        });
      }
    });

    alert(`Acerto de ${courier.name} finalizado com sucesso via multimeios!`);
    setShowSettlementModal(null);
  };

  const totalSettlementInput = Object.values(settlementPayments).reduce((a, b) => a + b, 0);
  const remainingSettlement = showSettlementModal ? Math.abs(showSettlementModal.balance) - totalSettlementInput : 0;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navegação Secundária */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        {[
          { id: 'monitor', label: 'Monitor Despacho', icon: Navigation },
          { id: 'couriers', label: 'Equipe de Motoboys', icon: UserCheck },
          { id: 'settlement', label: 'Acertos Financeiros', icon: Wallet },
          { id: 'settings', label: 'Configurações', icon: Settings }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-4 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Aguardando Motoboy ({deliveryOrders.filter(o => o.status === 'ready').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'ready').map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="text-xl font-black text-slate-800">#{order.id.slice(-4)}</h4>
                      <p className="text-[9px] font-black uppercase text-amber-600 flex items-center gap-1 mt-1"><Clock size={12} /> {Math.floor((Date.now() - new Date(order.createdAt).getTime()) / 60000)}m aguardando</p>
                    </div>
                    <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                  </div>
                  <div className="flex items-start gap-2 text-xs font-medium text-slate-500 bg-slate-50 p-3 rounded-2xl border">
                    <MapPin size={16} className="text-rose-500 shrink-0 mt-0.5" />
                    <span className="line-clamp-2 leading-relaxed">{order.customerAddress}</span>
                  </div>
                  <button onClick={() => setSelectedOrderId(order.id)} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-lg">Atribuir Entregador</button>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2"><Bike size={16} className="text-indigo-600" /> Motoboys em Atividade</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               {courierSettlementData.filter(c => c.courier.status !== 'offline').map(data => (
                  <div key={data.courier.id} className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden flex flex-col">
                     <div className="p-6 border-b flex justify-between items-center bg-slate-50/50">
                        <div className="flex items-center gap-4">
                           <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center font-black">{data.courier.name.charAt(0)}</div>
                           <div>
                              <p className="font-black text-slate-800">{data.courier.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{data.courier.vehicleType}</p>
                           </div>
                        </div>
                        <div className="text-right">
                           <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${data.courier.status === 'delivering' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {data.courier.status === 'delivering' ? 'Em Rota' : 'Livre'}
                           </span>
                        </div>
                     </div>
                     <div className="p-6 bg-indigo-50/30 flex justify-between items-center mx-4 my-2 rounded-2xl border border-indigo-100">
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Diária Fixa</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.dailyFee.toFixed(2)}</p>
                        </div>
                        <div className="h-6 w-px bg-indigo-100"></div>
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Taxas Acumuladas</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.totalFees.toFixed(2)}</p>
                        </div>
                     </div>
                     <div className="flex-1 p-6 space-y-3">
                        {deliveryOrders.filter(o => o.courierId === data.courier.id && o.status === 'delivering').map(order => (
                           <div key={order.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl shadow-sm">
                              <div className="flex items-center gap-3">
                                 <div className="w-8 h-8 bg-indigo-600 text-white rounded-lg flex items-center justify-center text-[10px] font-black">#{order.id.slice(-4)}</div>
                                 <p className="text-[10px] font-black text-slate-700 uppercase">{order.customerName?.split(' ')[0]}</p>
                              </div>
                              <button onClick={() => onUpdateStatus(order.id, 'delivered')} className="p-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 shadow-lg shadow-emerald-100"><CheckCircle2 size={16} /></button>
                           </div>
                        ))}
                     </div>
                  </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-slate-800">Equipe de Entrega</h3>
             <button onClick={() => setShowAddCourierModal(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-indigo-100"><Plus size={18} /> Cadastrar Entregador</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {couriers.map(courier => (
              <div key={courier.id} className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-6 group hover:shadow-xl transition-all">
                <div className="flex items-center gap-4">
                   <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-[1.5rem] flex items-center justify-center font-black text-xl">{courier.name.charAt(0)}</div>
                   <div>
                     <h4 className="font-black text-slate-800">{courier.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">R$ {(courier.dailyFee || 0).toFixed(2)} diária • {courier.vehicleType}</p>
                   </div>
                </div>
                <div className="space-y-4">
                   <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl"><Phone size={16} className="text-slate-400" /><span className="text-xs font-bold">{courier.phone}</span></div>
                   <div className="flex items-center gap-3 p-4 bg-indigo-50 rounded-2xl border border-indigo-100"><QrCode size={16} className="text-indigo-600" /><div className="flex-1 overflow-hidden"><p className="text-[9px] font-black text-indigo-400 uppercase">PIX</p><p className="text-xs font-bold text-indigo-700 truncate">{courier.pixKey || 'Não cadastrado'}</p></div></div>
                </div>
                <div className="flex gap-2"><button className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest">Editar</button><button className="flex-1 py-3 border text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest">Inativar</button></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'settlement' && (
        <div className="space-y-8 animate-in slide-in-from-right-4">
           <div className="bg-indigo-600 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-xl shadow-indigo-100">
              <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter">Acerto Financeiro</h2><p className="text-indigo-100 font-medium">Concilie taxas, diárias e dinheiro recebido em mãos.</p></div>
              <ArrowRightLeft size={64} className="opacity-20" />
           </div>
           <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b"><tr><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase">Entregador</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Diária</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Taxas</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Dinheiro em Mão</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Saldo Final</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-center">Ações</th></tr></thead>
                 <tbody className="divide-y">
                    {courierSettlementData.map((data, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                          <td className="px-10 py-8 font-black text-slate-800">{data.courier.name}</td>
                          <td className="px-10 py-8 text-right font-black text-indigo-400">R$ {data.dailyFee.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-emerald-600">R$ {data.totalFees.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-rose-600">R$ {data.cashCollected.toFixed(2)}</td>
                          <td className={`px-10 py-8 text-right font-black ${data.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(data.balance).toFixed(2)}</td>
                          <td className="px-10 py-8 text-center"><button onClick={() => openSettlement(data)} disabled={data.orderCount === 0 && data.dailyFee === 0} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30 shadow-lg shadow-indigo-100">Realizar Acerto</button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal de Seleção de Motoboy (Despacho) */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div><h2 className="text-xl font-black text-slate-800">Despachar Pedido</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Pedido #{selectedOrderId.slice(-4)}</p></div><button onClick={() => setSelectedOrderId(null)} className="p-2 hover:bg-white rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-3">
              {couriers.filter(c => c.status !== 'offline').map(courier => {
                const active = orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length;
                return (
                   <button key={courier.id} onClick={() => { onAssignCourier(selectedOrderId, courier.id); setSelectedOrderId(null); }} className="w-full flex items-center justify-between p-5 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left group">
                     <div className="flex items-center gap-4">
                        <div className="p-3 bg-white shadow-sm border rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><Bike size={24} /></div>
                        <div><p className="font-black text-slate-800">{courier.name}</p><p className="text-[9px] font-black uppercase text-slate-400">{active > 0 ? `${active} entregas ativas` : 'Livre'}</p></div>
                     </div>
                     <ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600" />
                   </button>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Cadastro Entregador (Incluindo Diária) */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div className="flex items-center gap-4"><div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg"><UserPlus size={24} /></div><h2 className="text-xl font-black">Novo Entregador</h2></div><button onClick={() => setShowAddCourierModal(false)} className="p-2 hover:bg-white rounded-full"><X size={24} className="text-slate-400" /></button></div>
            <div className="p-8 space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierName} onChange={(e)=>setNewCourierName(e.target.value)} /></div>
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierPhone} onChange={(e)=>setNewCourierPhone(e.target.value)} /></div>
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Diária (R$)</label><input type="number" className="w-full px-5 py-4 bg-slate-50 border-2 border-indigo-100 rounded-2xl font-black text-indigo-600 outline-none" value={newCourierDailyFee} onChange={(e)=>setNewCourierDailyFee(e.target.value)} /></div>
              </div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave PIX</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierPix} onChange={(e)=>setNewCourierPix(e.target.value)} /></div>
              <div className="grid grid-cols-3 gap-2">{(['moto', 'bike', 'car'] as const).map(v => (<button key={v} onClick={() => setNewCourierVehicle(v)} className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>{v}</button>))}</div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowAddCourierModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase text-[10px]">Cancelar</button><button onClick={handleSaveCourier} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl">Cadastrar</button></div>
          </div>
        </div>
      )}

      {/* NOVO Modal: Acerto Financeiro Multimeios */}
      {showSettlementModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b bg-indigo-600 text-white flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-white/20 rounded-2xl shadow-inner"><Wallet size={24} /></div>
                    <div>
                       <h2 className="text-xl font-black">Acerto: {showSettlementModal.courier.name}</h2>
                       <p className="text-[10px] font-bold uppercase tracking-widest opacity-80">Conciliação Multimeios</p>
                    </div>
                 </div>
                 <button onClick={() => setShowSettlementModal(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button>
              </div>

              <div className="p-8 flex flex-col lg:flex-row gap-8">
                 {/* Resumo Esquerda */}
                 <div className="flex-1 space-y-4">
                    <div className="bg-slate-50 p-6 rounded-[2rem] border space-y-4">
                       <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Resumo do Período</p>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Diária</span><span>+ R$ {showSettlementModal.dailyFee.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Taxas</span><span>+ R$ {showSettlementModal.totalFees.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Dinheiro rua</span><span className="text-rose-500">- R$ {showSettlementModal.cashCollected.toFixed(2)}</span></div>
                       <div className="pt-4 border-t flex justify-between items-center">
                          <span className="font-black text-slate-800">Saldo Final</span>
                          <span className={`text-2xl font-black ${showSettlementModal.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(showSettlementModal.balance).toFixed(2)}</span>
                       </div>
                    </div>
                    {showSettlementModal.balance < 0 && (
                       <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl flex gap-3 text-rose-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">O motoboy possui mais dinheiro em espécie do que tem a receber. Ele deve devolver a diferença.</p>
                       </div>
                    )}
                 </div>

                 {/* Checkout Direita */}
                 <div className="flex-1 space-y-4">
                    <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Como o acerto será pago?</p>
                    <div className="space-y-3">
                       {[
                         { id: 'dinheiro', label: 'Dinheiro', icon: Banknote },
                         { id: 'pix', label: 'PIX', icon: QrCode },
                         { id: 'cartao', label: 'Cartão / Depósito', icon: CreditCard }
                       ].map(m => (
                          <div key={m.id} className="relative group">
                             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><m.icon size={18} /></div>
                             <input 
                               type="number" 
                               placeholder={m.label}
                               className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black outline-none focus:border-indigo-500 transition-all"
                               value={settlementPayments[m.id] || ''}
                               onChange={(e) => setSettlementPayments({...settlementPayments, [m.id]: parseFloat(e.target.value) || 0})}
                             />
                          </div>
                       ))}
                    </div>

                    <div className="p-6 bg-indigo-50 rounded-[2rem] space-y-2 border border-indigo-100">
                       <div className="flex justify-between items-center text-[10px] font-black uppercase text-indigo-400"><span>Restante</span><span>Status</span></div>
                       <div className="flex justify-between items-center">
                          <span className={`text-xl font-black ${remainingSettlement === 0 ? 'text-emerald-500' : 'text-indigo-600'}`}>R$ {remainingSettlement.toFixed(2)}</span>
                          <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${remainingSettlement === 0 ? 'bg-emerald-500 text-white' : 'bg-indigo-200 text-indigo-700'}`}>
                             {remainingSettlement === 0 ? 'Conferido' : 'Pendente'}
                          </span>
                       </div>
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setShowSettlementModal(null)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                 <button 
                  onClick={handleRealizeSettlement} 
                  disabled={remainingSettlement !== 0}
                  className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-30 disabled:grayscale transition-all"
                 >
                    Confirmar e Gerar Lançamentos
                 </button>
              </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Delivery;

import React, { useState, useMemo } from 'react';
import { Order, Courier, FinancialRecord } from '../types';
import { 
  Navigation, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, X, UserCheck, 
  TrendingUp, Settings, Plus,
  Save, UserPlus, Wallet, ArrowRightLeft,
  Banknote, QrCode, ClipboardList, Timer, Clock,
  Coins, CreditCard, DollarSign, Calculator, AlertTriangle
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateDeliveryFee,
  onAddFinancialRecord
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'monitor' | 'couriers' | 'settlement' | 'settings'>('monitor');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<any | null>(null);

  // Settlement Multimeios
  const [settlementPayments, setSettlementPayments] = useState<{ [key: string]: number }>({
    dinheiro: 0,
    pix: 0,
    cartao: 0
  });

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierDailyFee, setNewCourierDailyFee] = useState('0');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Cálculo de acerto de contas por motoboy
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);
      const dailyFee = courier.dailyFee || 0;

      // Saldo Final = (Taxas + Diária) - O que ele recebeu em dinheiro
      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, 
        cashCollected,
        dailyFee,
        balance: (totalFees + dailyFee) - cashCollected
      };
    });
  }, [couriers, deliveryOrders]);

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;
    onAddCourier({ 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      dailyFee: parseFloat(newCourierDailyFee) || 0,
      vehicleType: newCourierVehicle 
    });
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setNewCourierDailyFee('0');
    setShowAddCourierModal(false);
  };

  const openSettlement = (data: any) => {
    setShowSettlementModal(data);
    // Reset payments state based on balance
    setSettlementPayments({
      dinheiro: data.balance > 0 ? data.balance : 0,
      pix: 0,
      cartao: 0
    });
  };

  const handleRealizeSettlement = () => {
    if (!showSettlementModal) return;
    const { courier, balance, totalFees, dailyFee, cashCollected } = showSettlementModal;

    // Fix: cast to number[] to handle potential unknown return type from Object.values
    const totalSelected = (Object.values(settlementPayments) as number[]).reduce((a, b) => a + b, 0);

    // Validar se o total bate com o saldo (em valor absoluto se estiver recebendo, ou valor real se pagando)
    // Fix: using totalSelected which is now confirmed as number type
    if (Math.abs(totalSelected - Math.abs(balance)) > 0.01) {
      alert("A soma dos valores informados não confere com o saldo do acerto!");
      return;
    }

    // Criar registros financeiros para cada modalidade
    Object.entries(settlementPayments).forEach(([method, amount]) => {
      // Fix: explicitly cast amount to number for comparison and usage
      if ((amount as number) > 0) {
        onAddFinancialRecord({
          type: balance >= 0 ? 'expense' : 'income',
          amount: amount as number,
          category: 'Acerto Motoboy',
          description: `Acerto com ${courier.name} (${method.toUpperCase()}). Taxas: R$${totalFees.toFixed(2)} | Diária: R$${dailyFee.toFixed(2)} | Dinheiro rua: R$${cashCollected.toFixed(2)}`,
          date: new Date()
        });
      }
    });

    alert(`Acerto de ${courier.name} finalizado com sucesso via multimeios!`);
    setShowSettlementModal(null);
  };

  // Fix: explicitly cast Object.values to number[] to avoid unknown type issues in arithmetic
  const totalSettlementInput = (Object.values(settlementPayments) as number[]).reduce((a, b) => a + b, 0);
  // Fix: ensures remainingSettlement calculation is safe with correctly typed totalSettlementInput
  const remainingSettlement = showSettlementModal ? Math.abs(showSettlementModal.balance) - totalSettlementInput : 0;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navegação Secundária */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        {[
          { id: 'monitor', label: 'Monitor Despacho', icon: Navigation },
          { id: 'couriers', label: 'Equipe de Motoboys', icon: UserCheck },
          { id: 'settlement', label: 'Acertos Financeiros', icon: Wallet },
          { id: 'settings', label: 'Configurações', icon: Settings }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-4 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Aguardando Motoboy ({deliveryOrders.filter(o => o.status === 'ready').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'ready').map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="text-xl font-black text-slate-800">#{order.id.slice(-4)}</h4>
                      <p className="text-[9px] font-black uppercase text-amber-600 flex items-center gap-1 mt-1"><Clock size={12} /> {Math.floor((Date.now() - new Date(order.createdAt).getTime()) / 60000)}m aguardando</p>
                    </div>
                    <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                  </div>
                  <div className="flex items-start gap-2 text-xs font-medium text-slate-500 bg-slate-50 p-3 rounded-2xl border">
                    <MapPin size={16} className="text-rose-500 shrink-0 mt-0.5" />
                    <span className="line-clamp-2 leading-relaxed">{order.customerAddress}</span>
                  </div>
                  <button onClick={() => setSelectedOrderId(order.id)} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-lg">Atribuir Entregador</button>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2"><Bike size={16} className="text-indigo-600" /> Motoboys em Atividade</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               {courierSettlementData.filter(c => c.courier.status !== 'offline').map(data => (
                  <div key={data.courier.id} className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden flex flex-col">
                     <div className="p-6 border-b flex justify-between items-center bg-slate-50/50">
                        <div className="flex items-center gap-4">
                           <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center font-black">{data.courier.name.charAt(0)}</div>
                           <div>
                              <p className="font-black text-slate-800">{data.courier.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{data.courier.vehicleType}</p>
                           </div>
                        </div>
                        <div className="text-right">
                           <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${data.courier.status === 'delivering' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {data.courier.status === 'delivering' ? 'Em Rota' : 'Livre'}
                           </span>
                        </div>
                     </div>
                     <div className="p-6 bg-indigo-50/30 flex justify-between items-center mx-4 my-2 rounded-2xl border border-indigo-100">
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Diária Fixa</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.dailyFee.toFixed(2)}</p>
                        </div>
                        <div className="h-6 w-px bg-indigo-100"></div>
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Taxas Acumuladas</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.totalFees.toFixed(2)}</p>
                        </div>
                     </div>
                     <div className="flex-1 p-6 space-y-3">
                        {deliveryOrders.filter(o => o.courierId === data.courier.id && o.status === 'delivering').map(order => (
                           <div key={order.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl shadow-sm">
                              <div className="flex items-center gap-3">
                                 <div className="w-8 h-8 bg-indigo-600 text-white rounded-lg flex items-center justify-center text-[10px] font-black">#{order.id.slice(-4)}</div>
                                 <p className="text-[10px] font-black text-slate-700 uppercase">{order.customerName?.split(' ')[0]}</p>
                              </div>
                              <button onClick={() => onUpdateStatus(order.id, 'delivered')} className="p-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 shadow-lg shadow-emerald-100"><CheckCircle2 size={16} /></button>
                           </div>
                        ))}
                     </div>
                  </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-slate-800">Equipe de Entrega</h3>
             <button onClick={() => setShowAddCourierModal(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-indigo-100"><Plus size={18} /> Cadastrar Entregador</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {couriers.map(courier => (
              <div key={courier.id} className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-6 group hover:shadow-xl transition-all">
                <div className="flex items-center gap-4">
                   <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-[1.5rem] flex items-center justify-center font-black text-xl">{courier.name.charAt(0)}</div>
                   <div>
                     <h4 className="font-black text-slate-800">{courier.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">R$ {(courier.dailyFee || 0).toFixed(2)} diária • {courier.vehicleType}</p>
                   </div>
                </div>
                <div className="space-y-4">
                   <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl"><Phone size={16} className="text-slate-400" /><span className="text-xs font-bold">{courier.phone}</span></div>
                   <div className="flex items-center gap-3 p-4 bg-indigo-50 rounded-2xl border border-indigo-100"><QrCode size={16} className="text-indigo-600" /><div className="flex-1 overflow-hidden"><p className="text-[9px] font-black text-indigo-400 uppercase">PIX</p><p className="text-xs font-bold text-indigo-700 truncate">{courier.pixKey || 'Não cadastrado'}</p></div></div>
                </div>
                <div className="flex gap-2"><button className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest">Editar</button><button className="flex-1 py-3 border text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest">Inativar</button></div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'settlement' && (
        <div className="space-y-8 animate-in slide-in-from-right-4">
           <div className="bg-indigo-600 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-xl shadow-indigo-100">
              <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter">Acerto Financeiro</h2><p className="text-indigo-100 font-medium">Concilie taxas, diárias e dinheiro recebido em mãos.</p></div>
              <ArrowRightLeft size={64} className="opacity-20" />
           </div>
           <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b"><tr><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase">Entregador</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Diária</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Taxas</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Dinheiro em Mão</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Saldo Final</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-center">Ações</th></tr></thead>
                 <tbody className="divide-y">
                    {courierSettlementData.map((data, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                          <td className="px-10 py-8 font-black text-slate-800">{data.courier.name}</td>
                          <td className="px-10 py-8 text-right font-black text-indigo-400">R$ {data.dailyFee.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-emerald-600">R$ {data.totalFees.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-rose-600">R$ {data.cashCollected.toFixed(2)}</td>
                          <td className={`px-10 py-8 text-right font-black ${data.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(data.balance).toFixed(2)}</td>
                          <td className="px-10 py-8 text-center"><button onClick={() => openSettlement(data)} disabled={data.orderCount === 0 && data.dailyFee === 0} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30 shadow-lg shadow-indigo-100">Realizar Acerto</button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal de Seleção de Motoboy (Despacho) */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div><h2 className="text-xl font-black text-slate-800">Despachar Pedido</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Pedido #{selectedOrderId.slice(-4)}</p></div><button onClick={() => setSelectedOrderId(null)} className="p-2 hover:bg-white rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-3">
              {couriers.filter(c => c.status !== 'offline').map(courier => {
                const active = orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length;
                return (
                   <button key={courier.id} onClick={() => { onAssignCourier(selectedOrderId, courier.id); setSelectedOrderId(null); }} className="w-full flex items-center justify-between p-5 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left group">
                     <div className="flex items-center gap-4">
                        <div className="p-3 bg-white shadow-sm border rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><Bike size={24} /></div>
                        <div><p className="font-black text-slate-800">{courier.name}</p><p className="text-[9px] font-black uppercase text-slate-400">{active > 0 ? `${active} entregas ativas` : 'Livre'}</p></div>
                     </div>
                     <ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600" />
                   </button>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Cadastro Entregador (Incluindo Diária) */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div className="flex items-center gap-4"><div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg"><UserPlus size={24} /></div><h2 className="text-xl font-black">Novo Entregador</h2></div><button onClick={() => setShowAddCourierModal(false)} className="p-2 hover:bg-white rounded-full"><X size={24} className="text-slate-400" /></button></div>
            <div className="p-8 space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierName} onChange={(e)=>setNewCourierName(e.target.value)} /></div>
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierPhone} onChange={(e)=>setNewCourierPhone(e.target.value)} /></div>
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Diária (R$)</label><input type="number" className="w-full px-5 py-4 bg-slate-50 border-2 border-indigo-100 rounded-2xl font-black text-indigo-600 outline-none" value={newCourierDailyFee} onChange={(e)=>setNewCourierDailyFee(e.target.value)} /></div>
              </div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave PIX</label><input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={newCourierPix} onChange={(e)=>setNewCourierPix(e.target.value)} /></div>
              <div className="grid grid-cols-3 gap-2">{(['moto', 'bike', 'car'] as const).map(v => (<button key={v} onClick={() => setNewCourierVehicle(v)} className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>{v}</button>))}</div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowAddCourierModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase text-[10px]">Cancelar</button><button onClick={handleSaveCourier} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl">Cadastrar</button></div>
          </div>
        </div>
      )}

      {/* NOVO Modal: Acerto Financeiro Multimeios */}
      {showSettlementModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b bg-indigo-600 text-white flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-white/20 rounded-2xl shadow-inner"><Wallet size={24} /></div>
                    <div>
                       <h2 className="text-xl font-black">Acerto: {showSettlementModal.courier.name}</h2>
                       <p className="text-[10px] font-bold uppercase tracking-widest opacity-80">Conciliação Multimeios</p>
                    </div>
                 </div>
                 <button onClick={() => setShowSettlementModal(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button>
              </div>

              <div className="p-8 flex flex-col lg:flex-row gap-8">
                 {/* Resumo Esquerda */}
                 <div className="flex-1 space-y-4">
                    <div className="bg-slate-50 p-6 rounded-[2rem] border space-y-4">
                       <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Resumo do Período</p>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Diária</span><span>+ R$ {showSettlementModal.dailyFee.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Taxas</span><span>+ R$ {showSettlementModal.totalFees.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Dinheiro rua</span><span className="text-rose-500">- R$ {showSettlementModal.cashCollected.toFixed(2)}</span></div>
                       <div className="pt-4 border-t flex justify-between items-center">
                          <span className="font-black text-slate-800">Saldo Final</span>
                          <span className={`text-2xl font-black ${showSettlementModal.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(showSettlementModal.balance).toFixed(2)}</span>
                       </div>
                    </div>
                    {showSettlementModal.balance < 0 && (
                       <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl flex gap-3 text-rose-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">O motoboy possui mais dinheiro em espécie do que tem a receber. Ele deve devolver a diferença.</p>
                       </div>
                    )}
                 </div>

                 {/* Checkout Direita */}
                 <div className="flex-1 space-y-4">
                    <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Como o acerto será pago?</p>
                    <div className="space-y-3">
                       {[
                         { id: 'dinheiro', label: 'Dinheiro', icon: Banknote },
                         { id: 'pix', label: 'PIX', icon: QrCode },
                         { id: 'cartao', label: 'Cartão / Depósito', icon: CreditCard }
                       ].map(m => (
                          <div key={m.id} className="relative group">
                             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><m.icon size={18} /></div>
                             <input 
                               type="number" 
                               placeholder={m.label}
                               className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black outline-none focus:border-indigo-500 transition-all"
                               value={settlementPayments[m.id] || ''}
                               onChange={(e) => setSettlementPayments({...settlementPayments, [m.id]: parseFloat(e.target.value) || 0})}
                             />
                          </div>
                       ))}
                    </div>

                    <div className="p-6 bg-indigo-50 rounded-[2rem] space-y-2 border border-indigo-100">
                       <div className="flex justify-between items-center text-[10px] font-black uppercase text-indigo-400"><span>Restante</span><span>Status</span></div>
                       <div className="flex justify-between items-center">
                          <span className={`text-xl font-black ${remainingSettlement === 0 ? 'text-emerald-500' : 'text-indigo-600'}`}>R$ {remainingSettlement.toFixed(2)}</span>
                          <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${remainingSettlement === 0 ? 'bg-emerald-500 text-white' : 'bg-indigo-200 text-indigo-700'}`}>
                             {remainingSettlement === 0 ? 'Conferido' : 'Pendente'}
                          </span>
                       </div>
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setShowSettlementModal(null)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                 <button 
                  onClick={handleRealizeSettlement} 
                  disabled={remainingSettlement !== 0}
                  className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-30 disabled:grayscale transition-all"
                 >
                    Confirmar e Gerar Lançamentos
                 </button>
              </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Delivery;

export type OrderStatus = 'pending' | 'preparing' | 'ready' | 'delivering' | 'delivered' | 'cancelled';

export type UserRole = 'ADMIN' | 'MANAGER' | 'WAITER' | 'CASHIER' | 'CHEF';

export type PaymentMethod = 'dinheiro' | 'cartao_credito' | 'cartao_debito' | 'pix' | 'vale_refeicao' | 'conta_cliente';

export type Permission = 
  | 'dashboard_view' 
  | 'pos_access' 
  | 'tables_manage' 
  | 'kds_view' 
  | 'delivery_manage' 
  | 'inventory_edit' 
  | 'finance_view' 
  | 'cmv_analysis' 
  | 'users_manage'
  | 'digital_menu_manage'
  | 'admin_settings_manage'
  | 'fiscal_manage'
  | 'customers_manage';

export interface Customer {
  id: string;
  name: string;
  document: string; // CPF ou CNPJ
  phone: string;
  email?: string;
  address?: string;
  balance: number; // Saldo devedor (positivo = deve ao restaurante)
  createdAt: Date;
  history: CustomerTransaction[];
}

export interface CustomerTransaction {
  id: string;
  type: 'debit' | 'credit'; // debit = compra (aumenta divida), credit = pagamento (diminui divida)
  amount: number;
  description: string;
  date: Date;
  paymentMethod?: string;
}

export interface BusinessHours {
  day: string;
  open: string;
  close: string;
  isClosed: boolean;
}

export interface FiscalSettings {
  environment: 'homologacao' | 'producao';
  certificateStatus: 'valid' | 'expired' | 'missing';
  certificateExpiry?: string;
  cscId: string;
  cscToken: string;
  nextNfceNumber: number;
  series: number;
  taxRegime: 'simples_nacional' | 'lucro_presumido' | 'lucro_real';
}

export interface AdminSettings {
  companyName: string;
  cnpj: string;
  address: string;
  phone: string;
  businessHours: BusinessHours[];
  fiscal: FiscalSettings;
  printing: {
    paperWidth: '58mm' | '80mm';
    autoPrintOrder: boolean;
    headerText: string;
    footerText: string;
    showLogo: boolean;
  };
  apis: {
    googleMapsKey: string;
    whatsappToken: string;
    ifoodWebhook: string;
    integrationActive: boolean;
  };
}

export interface DigitalMenuSettings {
  primaryColor: string;
  restaurantName: string;
  welcomeMessage: string;
  allowOrdering: boolean;
  showStock: boolean;
  bannerUrl: string;
  logoUrl: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  permissions: Permission[];
  avatar?: string;
  status: 'online' | 'offline';
  lastAccess?: Date;
  observations?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  action: string;
  description: string;
  timestamp: Date;
}

export interface PriceHistory {
  date: string;
  price: number;
  cost: number;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  image?: string;
  priceHistory?: PriceHistory[];
}

export interface OrderItem {
  productId: string;
  name: string;
  quantity: number;
  price: number;
  observation?: string;
  seat?: string;
}

export interface Order {
  id: string;
  tableNumber?: number;
  type: 'table' | 'delivery' | 'takeout';
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  deliveryFee?: number;
  createdAt: Date;
  customerName?: string;
  customerPhone?: string;
  customerAddress?: string;
  courierId?: string;
  customerId?: string; // Link para conta fiado
  paymentMethod?: PaymentMethod;
  isFiscalIssued?: boolean;
  fiscalKey?: string;
}

export interface Table {
  id: number;
  status: 'available' | 'occupied' | 'billing' | 'cleaning';
  currentOrderId?: string;
  items: OrderItem[];
  total: number;
}

export interface Courier {
  id: string;
  name: string;
  status: 'available' | 'delivering' | 'offline';
  phone: string;
  pixKey?: string;
  dailyFee?: number;
  vehicleType?: 'bike' | 'moto' | 'car';
  createdAt: Date;
}

export interface FinancialRecord {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  category: string;
  description: string;
  date: Date;
}

