import React, { useState, useMemo } from 'react';
import { Customer, CustomerTransaction, FinancialRecord } from '../types';
import { 
  UserPlus, Search, Phone, Mail, MapPin, 
  FileText, History, Wallet, ArrowDownCircle, 
  ArrowUpCircle, X, Check, Save, Plus,
  DollarSign, MoreVertical, CreditCard, Banknote, Smartphone,
  AlertCircle, ChevronRight
} from 'lucide-react';

interface CustomersPanelProps {
  customers: Customer[];
  onAddCustomer: (customer: Partial<Customer>) => void;
  onUpdateCustomer: (id: string, updates: Partial<Customer>) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const CustomersPanel: React.FC<CustomersPanelProps> = ({ 
  customers, 
  onAddCustomer, 
  onUpdateCustomer,
  onAddFinancialRecord 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [showBaixaModal, setShowBaixaModal] = useState<Customer | null>(null);

  // Baixa Form
  const [baixaAmount, setBaixaAmount] = useState('');
  const [baixaMethod, setBaixaMethod] = useState<string>('dinheiro');

  // Customer Form
  const [formName, setFormName] = useState('');
  const [formDoc, setFormDoc] = useState('');
  const [formPhone, setFormPhone] = useState('');
  const [formEmail, setFormEmail] = useState('');
  const [formAddress, setFormAddress] = useState('');

  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.document.includes(searchTerm)
  );

  const handleSaveCustomer = () => {
    if (!formName || !formDoc) return;
    onAddCustomer({
      name: formName,
      document: formDoc,
      phone: formPhone,
      email: formEmail,
      address: formAddress,
      balance: 0,
      history: []
    });
    setShowAddModal(false);
    resetForm();
  };

  const resetForm = () => {
    setFormName('');
    setFormDoc('');
    setFormPhone('');
    setFormEmail('');
    setFormAddress('');
  };

  const handleBaixa = () => {
    if (!showBaixaModal || !baixaAmount) return;
    const amount = parseFloat(baixaAmount);

    const transaction: CustomerTransaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'credit',
      amount: amount,
      description: `Pagamento recebido via ${baixaMethod.toUpperCase()}`,
      date: new Date(),
      paymentMethod: baixaMethod
    };

    const newBalance = showBaixaModal.balance - amount;
    onUpdateCustomer(showBaixaModal.id, {
      balance: newBalance,
      history: [transaction, ...showBaixaModal.history]
    });

    onAddFinancialRecord({
      type: 'income',
      amount: amount,
      category: 'Recebimento Fiado',
      description: `Baixa de conta: ${showBaixaModal.name}`,
      date: new Date()
    });

    setShowBaixaModal(null);
    setBaixaAmount('');
    alert("Baixa realizada com sucesso!");
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="relative w-full md:w-96">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por nome ou CPF/CNPJ..." 
            className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
        >
          <UserPlus size={18} /> Novo Cliente
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Lista de Clientes */}
        <div className="lg:col-span-2 space-y-4 max-h-[70vh] overflow-y-auto pr-2 custom-scrollbar">
          {filteredCustomers.map(customer => (
            <div 
              key={customer.id} 
              className={`bg-white p-6 rounded-[2.5rem] border-2 transition-all cursor-pointer group ${selectedCustomer?.id === customer.id ? 'border-indigo-600 shadow-xl' : 'border-transparent hover:border-slate-200 shadow-sm'}`}
              onClick={() => setSelectedCustomer(customer)}
            >
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-5">
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center font-black text-xl ${customer.balance > 0 ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'}`}>
                    {customer.name.charAt(0)}
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-800">{customer.name}</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{customer.document}</p>
                  </div>
                </div>
                <div className="text-right">
                   <p className="text-[10px] font-black uppercase text-slate-400 tracking-tighter">Saldo Devedor</p>
                   <p className={`text-2xl font-black tracking-tighter ${customer.balance > 0 ? 'text-rose-600' : 'text-emerald-600'}`}>
                     R$ {customer.balance.toFixed(2)}
                   </p>
                </div>
              </div>

              <div className="mt-6 pt-6 border-t flex flex-wrap gap-4 items-center justify-between">
                <div className="flex gap-4">
                  <div className="flex items-center gap-2 text-xs font-bold text-slate-500">
                    <Phone size={14} className="text-indigo-500" /> {customer.phone}
                  </div>
                  {customer.email && (
                    <div className="flex items-center gap-2 text-xs font-bold text-slate-500">
                      <Mail size={14} className="text-indigo-500" /> {customer.email}
                    </div>
                  )}
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={(e) => { e.stopPropagation(); setShowBaixaModal(customer); }}
                    className="px-4 py-2 bg-emerald-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-emerald-100 hover:bg-emerald-600"
                  >
                    Dar Baixa
                  </button>
                  <button className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-slate-100 transition-colors">
                    <MoreVertical size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Detalhes e Histórico */}
        <div className="bg-white rounded-[3rem] border shadow-sm flex flex-col h-[70vh] overflow-hidden">
          {selectedCustomer ? (
            <>
              <div className="p-8 border-b bg-slate-50/50 flex justify-between items-center">
                <div>
                   <h3 className="font-black text-slate-800">Extrato da Conta</h3>
                   <p className="text-xs font-bold text-slate-400 uppercase">{selectedCustomer.name}</p>
                </div>
                <History size={24} className="text-indigo-300" />
              </div>
              <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
                {selectedCustomer.history.length > 0 ? selectedCustomer.history.map(t => (
                  <div key={t.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                     <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${t.type === 'debit' ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                           {t.type === 'debit' ? <ArrowUpCircle size={16} /> : <ArrowDownCircle size={16} />}
                        </div>
                        <div>
                           <p className="text-[11px] font-black text-slate-700 leading-tight">{t.description}</p>
                           <p className="text-[9px] font-bold text-slate-400 uppercase">{t.date.toLocaleDateString()} {t.date.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                        </div>
                     </div>
                     <p className={`font-black text-sm ${t.type === 'debit' ? 'text-rose-600' : 'text-emerald-600'}`}>
                        {t.type === 'debit' ? '+' : '-'} R$ {t.amount.toFixed(2)}
                     </p>
                  </div>
                )) : (
                  <div className="h-full flex flex-col items-center justify-center text-center opacity-30 grayscale p-10">
                     <FileText size={48} className="mb-4" />
                     <p className="text-xs font-black uppercase tracking-widest">Sem movimentação registrada</p>
                  </div>
                )}
              </div>
              <div className="p-8 border-t bg-indigo-600 text-white">
                 <div className="flex justify-between items-center">
                    <span className="text-xs font-bold uppercase tracking-widest opacity-80">Saldo Consolidado</span>
                    <span className="text-3xl font-black">R$ {selectedCustomer.balance.toFixed(2)}</span>
                 </div>
              </div>
            </>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-400 gap-4 opacity-50 grayscale">
              <UserCircle size={64} strokeWidth={1} />
              <p className="font-bold text-sm uppercase tracking-widest">Selecione um cliente para ver o extrato detalhado</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal: Novo Cliente */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg shadow-indigo-200">
                       <UserPlus size={24} />
                    </div>
                    <h2 className="text-2xl font-black text-slate-800">Cadastrar Cliente</h2>
                 </div>
                 <button onClick={() => setShowAddModal(false)} className="p-2 hover:bg-white rounded-full"><X size={24} className="text-slate-400" /></button>
              </div>
              <div className="p-8 space-y-6">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome / Razão Social</label>
                    <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={formName} onChange={(e)=>setFormName(e.target.value)} />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">CPF / CNPJ</label>
                       <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={formDoc} onChange={(e)=>setFormDoc(e.target.value)} />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telefone</label>
                       <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={formPhone} onChange={(e)=>setFormPhone(e.target.value)} />
                    </div>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail</label>
                    <input type="email" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={formEmail} onChange={(e)=>setFormEmail(e.target.value)} />
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Endereço</label>
                    <textarea rows={2} className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none resize-none" value={formAddress} onChange={(e)=>setFormAddress(e.target.value)} />
                 </div>
              </div>
              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setShowAddModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-[10px]">Cancelar</button>
                 <button onClick={handleSaveCustomer} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl">Salvar Cadastro</button>
              </div>
           </div>
        </div>
      )}

      {/* Modal: Baixa de Pagamento */}
      {showBaixaModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
           <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b bg-emerald-600 text-white flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-white/20 rounded-2xl"><DollarSign size={24} /></div>
                    <div>
                       <h2 className="text-xl font-black">Baixa de Pagamento</h2>
                       <p className="text-[10px] font-bold uppercase opacity-80">{showBaixaModal.name}</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBaixaModal(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button>
              </div>

              <div className="p-10 space-y-8">
                 <div className="bg-slate-50 p-6 rounded-[2rem] border text-center space-y-1">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Saldo Atual Devedor</p>
                    <p className="text-4xl font-black text-slate-800 tracking-tighter">R$ {showBaixaModal.balance.toFixed(2)}</p>
                 </div>

                 <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor do Recebimento (R$)</label>
                       <input 
                        type="number" 
                        className="w-full px-8 py-6 bg-slate-50 border-2 border-indigo-100 rounded-[2rem] text-4xl font-black text-indigo-600 outline-none focus:border-indigo-500 text-center" 
                        value={baixaAmount}
                        onChange={(e)=>setBaixaAmount(e.target.value)}
                        placeholder="0,00"
                        autoFocus
                       />
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                       {[
                         { id: 'dinheiro', label: 'Dinheiro', icon: Banknote },
                         { id: 'pix', label: 'PIX', icon: Smartphone },
                         { id: 'cartao', label: 'Cartão', icon: CreditCard }
                       ].map(m => (
                          <button 
                            key={m.id} 
                            onClick={() => setBaixaMethod(m.id)}
                            className={`flex items-center gap-3 p-4 rounded-2xl border-2 transition-all font-bold text-sm ${baixaMethod === m.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-slate-200'}`}
                          >
                             <m.icon size={18} /> {m.label}
                          </button>
                       ))}
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setShowBaixaModal(null)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                 <button onClick={handleBaixa} disabled={!baixaAmount} className="flex-1 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-emerald-100 disabled:opacity-50">Confirmar Recebimento</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default CustomersPanel;

import React, { useState, useMemo } from 'react';
import { Table, Product, OrderItem, PaymentMethod, Order, Customer } from '../types';
import { getObservationSuggestions } from '../services/gemini';
import { 
  Users, CreditCard, Utensils, X, Plus, Trash2, 
  Receipt, Wallet, Smartphone, Banknote, ShieldCheck,
  CheckCircle2, Printer, Search, Edit3, User as UserIcon, MessageSquare, Save,
  Minus, Sparkles, Loader2, Send, ChefHat, Lock, Unlock, Coins, 
  History, DollarSign, ArrowRightLeft, PieChart, UserCircle
} from 'lucide-react';

interface TablesProps {
  tables: Table[];
  products: Product[];
  orders: Order[];
  customers: Customer[];
  cashSession: {
    isOpen: boolean;
    openingValue: number;
    openedAt: Date | null;
  };
  onUpdateTable: (tableId: number, items: OrderItem[], status: Table['status']) => void;
  onCloseTable: (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean, customerId?: string) => void;
  onSendToKitchen: (tableId: number, items: OrderItem[]) => void;
  onOpenCash: (value: number) => void;
  onCloseCash: () => void;
}

const Tables: React.FC<TablesProps> = ({ 
  tables, products, orders, customers, cashSession, 
  onUpdateTable, onCloseTable, onSendToKitchen, onOpenCash, onCloseCash 
}) => {
  const [selectedTable, setSelectedTable] = useState<Table | null>(null);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showCashModal, setShowCashModal] = useState(false);
  const [showCustomerSelection, setShowCustomerSelection] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string>('');

  const [isFiscalEmission, setIsFiscalEmission] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSendingToKitchen, setIsSendingToKitchen] = useState(false);
  const [showKitchenSuccess, setShowKitchenSuccess] = useState(false);
  const [productSearch, setProductSearch] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');

  const [openingValueInput, setOpeningValueInput] = useState('0');

  const cashReport = useMemo(() => {
    if (!cashSession.openedAt) return null;
    const sessionOrders = orders.filter(o => o.createdAt >= cashSession.openedAt!);
    const totalsByMethod = { dinheiro: 0, cartao_credito: 0, cartao_debito: 0, pix: 0, vale_refeicao: 0, conta_cliente: 0 };
    sessionOrders.forEach(o => { if (o.paymentMethod) totalsByMethod[o.paymentMethod] += o.total; });
    const totalSales = Object.values(totalsByMethod).reduce((a, b) => a + b, 0);
    return { totalsByMethod, totalSales, expectedFinalValue: totalSales + cashSession.openingValue, count: sessionOrders.length };
  }, [orders, cashSession]);

  const [activeSeat, setActiveSeat] = useState<string>('Geral');
  const [editingItemIndex, setEditingItemIndex] = useState<number | null>(null);
  const [tempObs, setTempObs] = useState('');
  const [tempSeat, setTempSeat] = useState('');
  const [tempQty, setTempQty] = useState<number>(1);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const filteredCustomerList = useMemo(() => 
    customers.filter(c => c.name.toLowerCase().includes(customerSearch.toLowerCase())),
    [customers, customerSearch]
  );

  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const openTable = (table: Table) => {
    if (!cashSession.isOpen) {
      alert("Por favor, abra o caixa antes de realizar atendimentos.");
      setShowCashModal(true);
      return;
    }
    if (table.status === 'available') {
      onUpdateTable(table.id, [], 'occupied');
      setSelectedTable({ ...table, status: 'occupied', items: [], total: 0 });
    } else {
      setSelectedTable(table);
    }
    setActiveSeat('Geral');
  };

  const addToTable = (product: Product) => {
    if (!selectedTable) return;
    const existingIndex = selectedTable.items.findIndex(i => i.productId === product.id && i.seat === activeSeat && !i.observation);
    let newItems: OrderItem[];
    if (existingIndex > -1) {
      newItems = [...selectedTable.items];
      newItems[existingIndex] = { ...newItems[existingIndex], quantity: newItems[existingIndex].quantity + 1 };
    } else {
      newItems = [...selectedTable.items, { productId: product.id, name: product.name, price: product.price, quantity: 1, seat: activeSeat }];
    }
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
  };

  const removeItem = (index: number) => {
    if (!selectedTable) return;
    const newItems = selectedTable.items.filter((_, i) => i !== index);
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
  };

  const startEditItem = async (index: number) => {
    const item = selectedTable!.items[index];
    setEditingItemIndex(index);
    setTempObs(item.observation || '');
    setTempSeat(item.seat || 'Geral');
    setTempQty(item.quantity);
    setLoadingSuggestions(true);
    try {
      const res = await getObservationSuggestions(item.name);
      setSuggestions(res);
    } catch (err) {
      setSuggestions(["Sem cebola", "Bem passado", "Ponto da casa", "Sem gelo"]);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  const saveItemEdit = () => {
    if (!selectedTable || editingItemIndex === null) return;
    const newItems = [...selectedTable.items];
    newItems[editingItemIndex] = { ...newItems[editingItemIndex], observation: tempObs.trim(), seat: tempSeat.trim() || 'Geral', quantity: tempQty > 0 ? tempQty : 1 };
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied');
    setEditingItemIndex(null);
  };

  const handleSendToKitchenLocal = () => {
    if (!selectedTable || selectedTable.items.length === 0) return;
    setIsSendingToKitchen(true);
    setTimeout(() => {
      onSendToKitchen(selectedTable.id, selectedTable.items);
      setIsSendingToKitchen(false);
      setShowKitchenSuccess(true);
      setTimeout(() => setShowKitchenSuccess(false), 3000);
    }, 1000);
  };

  const handleProcessPayment = (method: PaymentMethod) => {
    if (!selectedTable) return;

    if (method === 'conta_cliente') {
      setShowCustomerSelection(true);
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, method, isFiscalEmission);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
    }, 2000);
  };

  const finishFiadoPayment = () => {
    if (!selectedTable || !selectedCustomerId) return;
    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, 'conta_cliente', isFiscalEmission, selectedCustomerId);
      setIsProcessing(false);
      setShowCustomerSelection(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
      setSelectedCustomerId('');
      setCustomerSearch('');
    }, 1500);
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()));

  return (
    <div className="space-y-6">
      {/* Barra de Gestão Superior */}
      <div className="flex justify-between items-center bg-white p-6 rounded-[2rem] border shadow-sm">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setShowCashModal(true)}
            className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-lg ${cashSession.isOpen ? 'bg-emerald-500 text-white shadow-emerald-100' : 'bg-rose-500 text-white shadow-rose-100'}`}
          >
            {cashSession.isOpen ? <Unlock size={20} /> : <Lock size={20} />}
            Caixa {cashSession.isOpen ? 'Aberto' : 'Fechado'}
          </button>

          {cashSession.isOpen && (
            <div className="flex gap-4">
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial</p>
                  <p className="font-black text-slate-700">R$ {cashSession.openingValue.toFixed(2)}</p>
               </div>
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Vendas Atual</p>
                  <p className="font-black text-indigo-600">R$ {cashReport?.totalSales.toFixed(2)}</p>
               </div>
            </div>
          )}
        </div>
        <div className="flex gap-3">
           <div className="relative w-64">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="text" placeholder="Pesquisar mesa..." className="w-full pl-12 pr-6 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-sm" />
           </div>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
        {tables.map(table => (
          <button key={table.id} onClick={() => openTable(table)} disabled={table.status === 'cleaning'} className={`aspect-square p-6 rounded-[2rem] border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${getTableStatusColor(table.status)} shadow-sm`}>
            <div className="text-current">{table.status === 'available' ? <Utensils size={32} /> : table.status === 'occupied' ? <Users size={32} /> : table.status === 'billing' ? <CreditCard size={32} /> : <Utensils size={32} className="animate-spin" />}</div>
            <div className="text-center"><h3 className="text-2xl font-black">Mesa {table.id}</h3><p className="text-[10px] uppercase font-black tracking-widest opacity-60">{table.status}</p></div>
            {table.total > 0 && <div className="mt-1 text-sm font-black bg-white/60 px-4 py-1.5 rounded-2xl shadow-sm">R$ {table.total.toFixed(2)}</div>}
          </button>
        ))}
      </div>

      {/* Modal: Caixa */}
      {showCashModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 flex flex-col">
              <div className={`p-8 border-b flex justify-between items-center text-white ${cashSession.isOpen ? 'bg-indigo-600' : 'bg-rose-500'}`}>
                 <div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl shadow-inner">{cashSession.isOpen ? <Unlock size={24} /> : <Lock size={24} />}</div><div><h2 className="text-2xl font-black">{cashSession.isOpen ? 'Fechar Caixa' : 'Abrir Novo Caixa'}</h2><p className="text-xs font-bold opacity-80 uppercase tracking-widest">{cashSession.isOpen ? 'Conferência de Valores' : 'Início de Turno'}</p></div></div>
                 <button onClick={() => setShowCashModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-10 space-y-8">
                 {!cashSession.isOpen ? (
                    <div className="space-y-6 text-center">
                       <p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor de Fundo / Troco</p>
                       <div className="relative max-w-[300px] mx-auto"><span className="absolute left-6 top-1/2 -translate-y-1/2 text-3xl font-black text-slate-300">R$</span><input type="number" className="w-full pl-20 pr-8 py-6 bg-slate-50 border-2 border-slate-100 rounded-[2rem] text-5xl font-black text-slate-800 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-center" value={openingValueInput} onChange={(e) => setOpeningValueInput(e.target.value)} autoFocus /></div>
                       <button onClick={() => { onOpenCash(parseFloat(openingValueInput) || 0); setShowCashModal(false); }} className="w-full bg-indigo-600 text-white py-6 rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-indigo-700 transition-all">Confirmar Abertura</button>
                    </div>
                 ) : (
                    <div className="space-y-8">
                       <div className="grid grid-cols-2 gap-6">
                          <div className="bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total em Vendas</p><h4 className="text-3xl font-black text-slate-800 tracking-tighter">R$ {cashReport?.totalSales.toFixed(2)}</h4></div>
                          <div className="bg-emerald-50 p-6 rounded-[2.5rem] border border-emerald-100"><p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Saldo Esperado</p><h4 className="text-3xl font-black text-emerald-700 tracking-tighter">R$ {cashReport?.expectedFinalValue.toFixed(2)}</h4></div>
                       </div>
                       <div className="space-y-3">
                          {[{ id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' }, { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' }, { id: 'conta_cliente', label: 'Fiado (Conta Cliente)', icon: UserCircle, color: 'text-rose-500' }].map(method => (
                             <div key={method.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                <div className="flex items-center gap-4"><div className={`p-2 bg-white rounded-xl ${method.color}`}><method.icon size={18} /></div><p className="font-black text-slate-700 text-sm">{method.label}</p></div>
                                <p className="font-black text-slate-800">R$ {cashReport?.totalsByMethod[method.id as keyof typeof cashReport.totalsByMethod].toFixed(2)}</p>
                             </div>
                          ))}
                       </div>
                       <button onClick={() => { if(confirm("Deseja fechar o caixa?")) { onCloseCash(); setShowCashModal(false); } }} className="w-full bg-rose-500 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-rose-100 hover:bg-rose-600 transition-all flex items-center justify-center gap-2"><Lock size={18} /> Encerrar Turno</button>
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Modal: Comanda */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-7xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white"><div className="flex justify-between items-center mb-6"><div><h2 className="text-2xl font-black text-slate-800">Cardápio Digital</h2><p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Lançamento por assento em tempo real</p></div><div className="relative w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Pesquisar..." className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" value={productSearch} onChange={(e) => setProductSearch(e.target.value)} /></div></div></div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 lg:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                  <button key={product.id} onClick={() => addToTable(product)} className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-2 group shadow-sm">
                    <div className="w-full aspect-square bg-slate-100 rounded-2xl mb-2 overflow-hidden"><img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" /></div>
                    <p className="font-black text-slate-800 text-sm truncate">{product.name}</p>
                    <div className="flex justify-between items-center mt-auto"><p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p><Plus size={16} className="text-slate-300 group-hover:text-indigo-600" /></div>
                  </button>
                ))}
              </div>
            </div>
            <div className="w-[450px] flex flex-col bg-white border-l shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white"><div className="flex items-center gap-3"><div className="p-3 bg-white/20 rounded-2xl shadow-inner"><Users size={24} /></div><div><h2 className="text-xl font-black">Mesa {selectedTable.id}</h2><p className="text-[10px] font-bold uppercase opacity-70 tracking-widest mt-1">Gestão de Itens</p></div></div><button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
              <div className="p-6 bg-slate-50 border-b space-y-3"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><UserIcon size={12} /> Lançar para:</p><div className="flex gap-2 overflow-x-auto scrollbar-hide">{['Geral', 'Cadeira 1', 'Cadeira 2', 'Cadeira 3', '+ Nova'].map(seat => (<button key={seat} onClick={() => setActiveSeat(seat)} className={`px-4 py-2 rounded-xl text-xs font-bold border-2 whitespace-nowrap transition-all ${activeSeat === seat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}>{seat}</button>))}</div></div>
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {selectedTable.items.length === 0 ? (<div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40"><div className="p-8 border-4 border-dashed rounded-full border-slate-200"><Utensils size={64} strokeWidth={1} /></div><p className="font-black uppercase tracking-tighter">Aguardando Pedidos...</p></div>) : 
                (selectedTable.items.map((item, index) => (
