            </div>
          </div>
        </div>
      )}

      {/* Modal de Pagamento Refatorado com Fiado */}
      {showPaymentModal && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col">
            {!showCustomerSelection ? (
              <>
                <div className="p-8 border-b flex justify-between items-center bg-emerald-600 text-white"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><Wallet size={24} /></div><div><h2 className="text-2xl font-black">Finalizar Mesa {selectedTable.id}</h2><p className="text-xs font-bold opacity-80 uppercase tracking-widest">Pagamento e Emissão</p></div></div><button onClick={() => setShowPaymentModal(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                <div className="p-10 space-y-10">
                  <div className="text-center space-y-2"><p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor Total</p><h1 className="text-6xl font-black text-slate-800 tracking-tighter">R$ {selectedTable.total.toFixed(2)}</h1></div>
                  <div className="space-y-4">
                    <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Escolha o Método</p>
                    <div className="grid grid-cols-2 gap-4">
                      {[
                        { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' },
                        { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' },
                        { id: 'cartao_credito', label: 'Crédito', icon: CreditCard, color: 'text-indigo-700' },
                        { id: 'conta_cliente', label: 'Lançar Fiado', icon: UserCircle, color: 'text-rose-500' },
                      ].map(method => (
                        <button key={method.id} disabled={isProcessing} onClick={() => handleProcessPayment(method.id as PaymentMethod)} className="p-6 rounded-3xl border-2 border-slate-100 bg-slate-50/50 hover:bg-white hover:border-indigo-500 transition-all text-left flex flex-col gap-4 group active:scale-95">
                          <div className={`p-3 bg-white shadow-sm border rounded-2xl w-fit ${method.color} group-hover:scale-110 transition-transform`}><method.icon size={24} /></div>
                          <p className="font-black text-slate-800">{method.label}</p>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            ) : (
              <div className="animate-in slide-in-from-right-10 duration-300">
                 <div className="p-8 border-b bg-rose-600 text-white flex justify-between items-center"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><UserCircle size={24} /></div><div><h2 className="text-xl font-black">Selecionar Cliente</h2><p className="text-xs font-bold uppercase opacity-80">Lançamento em Conta Fiado</p></div></div><button onClick={() => setShowCustomerSelection(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                 <div className="p-8 space-y-6">
                    <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Nome do cliente..." className="w-full pl-12 pr-6 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={customerSearch} onChange={(e)=>setCustomerSearch(e.target.value)} /></div>
                    <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar">
                       {filteredCustomerList.map(c => (
                          <button key={c.id} onClick={() => setSelectedCustomerId(c.id)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedCustomerId === c.id ? 'border-rose-600 bg-rose-50' : 'border-slate-50 bg-white hover:border-slate-200'}`}>
                             <div className="text-left"><p className="font-black text-slate-800">{c.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{c.document}</p></div>
                             {selectedCustomerId === c.id && <CheckCircle2 size={24} className="text-rose-600" />}
                          </button>
                       ))}
                    </div>
                 </div>
                 <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowCustomerSelection(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Voltar</button><button onClick={finishFiadoPayment} disabled={!selectedCustomerId || isProcessing} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-50">Lançar Fiado (R$ {selectedTable.total.toFixed(2)})</button></div>
              </div>
            )}

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in"><div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div><p className="text-xl font-black text-slate-800">Finalizando Operação...</p></div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

