  const [globalDeliveryFee, setGlobalDeliveryFee] = useState(7.00);
  const [financialRecords, setFinancialRecords] = useState<FinancialRecord[]>([]);

  // Clientes e Fiado
  const [customers, setCustomers] = useState<Customer[]>([
    { id: 'ct1', name: 'Marcos de Almeida', document: '123.456.789-00', phone: '(11) 95555-4444', email: 'marcos@email.com', balance: 450.00, createdAt: new Date(), history: [
      { id: 't1', type: 'debit', amount: 450.00, description: 'Consumo Mesa 04', date: new Date(Date.now() - 1000 * 60 * 60 * 24) }
    ] },
    { id: 'ct2', name: 'Empresa Tecnologia LTDA', document: '99.888.777/0001-99', phone: '(11) 4004-0000', balance: 0, createdAt: new Date(), history: [] }
  ]);

  const [digitalMenuSettings, setDigitalMenuSettings] = useState<DigitalMenuSettings>({
    primaryColor: '#4f46e5',
