      cscToken: 'A1B2C3D4E5',
      nextNfceNumber: 154,
      series: 1,
      taxRegime: 'simples_nacional'
    } as any,
    printing: { paperWidth: '80mm', autoPrintOrder: true, headerText: 'BEM VINDO AO GASTROAI', footerText: 'Obrigado e volte sempre!', showLogo: true },
    apis: { googleMapsKey: '', whatsappToken: '', ifoodWebhook: '', integrationActive: false }
  });

  const [cashSession, setCashSession] = useState<CashSession>({ isOpen: false, openingValue: 0, openedAt: null });
