    type: 'income' as const,
    amount: order.total,
    category: 'Vendas PDV',
    description: `Pedido #${order.id.slice(-4)} (${order.type})`,
    date: order.createdAt,
    status: 'paid' as const
  })), [orders]);

  const allRecords = useMemo(() => [
    ...incomeFromOrders,
    ...manualRecords
  ].sort((a, b) => b.date.getTime() - a.date.getTime()), [incomeFromOrders, manualRecords]);

  // Cálculos de Projeção (A pagar e A receber)
  const financialProjection = useMemo(() => {
    // 1. Recebíveis de Fiado
    const totalFiadoReceivable = customers.reduce((acc, c) => acc + (c.balance > 0 ? c.balance : 0), 0);

    // 2. A Pagar aos Motoboys (Cálculo simplificado: Diária + Taxas pendentes)
    // No cenário real, isso viria do monitor de despacho
    const totalMotoboyPayable = couriers.reduce((acc, c) => {
      // Simulação: estamos devendo a diária do dia para cada um que não está offline
      return acc + (c.status !== 'offline' ? (c.dailyFee || 0) : 0);
    }, 0);

    // 3. Fornecedores Pendentes (Registros com status pending)
    const totalPendingExpenses = manualRecords
      .filter(r => r.type === 'expense' && r.status === 'pending')
      .reduce((acc, r) => acc + r.amount, 0);

    return {
      fiado: totalFiadoReceivable,
      motoboy: totalMotoboyPayable,
      fornecedores: totalPendingExpenses,
      totalPayable: totalMotoboyPayable + totalPendingExpenses,
      totalReceivable: totalFiadoReceivable
    };
  }, [customers, couriers, manualRecords]);

  const handleSaveRecord = () => {
    if (!formAmount || !formDesc) return;
    onAddRecord({
      type: formType,
      amount: parseFloat(formAmount),
      category: formCategory,
      description: formDesc,
      status: formStatus,
      date: new Date()
    });
    setShowAddModal(false);
    setFormAmount('');
    setFormDesc('');
  };

  const stats = useMemo(() => {
    const totalIncome = allRecords.filter(r => r.type === 'income' && r.status === 'paid').reduce((acc, r) => acc + r.amount, 0);
    const totalExpense = allRecords.filter(r => r.type === 'expense' && r.status === 'paid').reduce((acc, r) => acc + r.amount, 0);
    const netProfit = totalIncome - totalExpense;
    return { totalIncome, totalExpense, netProfit };
  }, [allRecords]);

  const filteredRecords = allRecords.filter(r => {
    const matchesSearch = r.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          r.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = filterType === 'all' || r.type === filterType;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
