                <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm relative overflow-hidden group">
                   <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform"><TrendingUp size={64} className="text-emerald-600" /></div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Lucro Líquido (Realizado)</p>
                   <h3 className="text-4xl font-black text-slate-800 tracking-tighter">R$ {stats.netProfit.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                   <div className="mt-4 flex items-center gap-2">
                      <span className="px-2 py-0.5 rounded-lg bg-emerald-50 text-emerald-600 text-[10px] font-black uppercase">Saldo em Conta</span>
                   </div>
                </div>

                <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden text-white">
                   <div className="absolute top-0 right-0 p-6 opacity-10"><DollarSign size={64} /></div>
                   <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest mb-2">Previsão Real (Realizado + Projetado)</p>
                   <h3 className="text-4xl font-black tracking-tighter">R$ {(stats.netProfit + financialProjection.totalReceivable - financialProjection.totalPayable).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                   <div className="mt-4 flex items-center gap-3">
                      <div className="flex -space-x-2">
                        {customers.slice(0, 3).map((c, i) => <div key={i} className="w-6 h-6 rounded-full bg-white/20 border border-indigo-400 flex items-center justify-center text-[8px] font-black">{c.name.charAt(0)}</div>)}
                      </div>
                      <p className="text-[10px] font-bold text-indigo-100">Incluindo recebíveis e débitos</p>
                   </div>
                </div>
             </div>

             <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
