                <div className="space-y-4">
                   <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3"><div className="p-2 bg-emerald-50 text-emerald-600 rounded-xl"><UserCircle size={18} /></div><span className="text-xs font-bold text-slate-600">Fiado a Receber</span></div>
                      <span className="text-sm font-black text-emerald-600">+ R$ {financialProjection.fiado.toFixed(2)}</span>
                   </div>
                   <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3"><div className="p-2 bg-rose-50 text-rose-600 rounded-xl"><Bike size={18} /></div><span className="text-xs font-bold text-slate-600">Pagar Motoboys</span></div>
                      <span className="text-sm font-black text-rose-600">- R$ {financialProjection.motoboy.toFixed(2)}</span>
                   </div>
                   <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3"><div className="p-2 bg-amber-50 text-amber-600 rounded-xl"><Truck size={18} /></div><span className="text-xs font-bold text-slate-600">Fornecedores Pend.</span></div>
                      <span className="text-sm font-black text-amber-600">- R$ {financialProjection.fornecedores.toFixed(2)}</span>
