                </div>
                <button onClick={() => setActiveView('agenda')} className="w-full py-3 bg-slate-50 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-100 transition-all">Ver Detalhes da Agenda</button>
