              <div className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={[{name:'Seg', e:4200, s:1200},{name:'Ter', e:3800, s:1500},{name:'Qua', e:5100, s:1100},{name:'Qui', e:4900, s:1800},{name:'Sex', e:7200, s:2200},{name:'Sab', e:8500, s:2500},{name:'Dom', e:6400, s:1400}]}>
                    <defs>
                      <linearGradient id="colorE" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/><stop offset="95%" stopColor="#6366f1" stopOpacity={0}/></linearGradient>
