                 <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg"><Receipt size={24} /></div>
                 <h2 className="text-2xl font-black text-slate-800">Novo Lançamento</h2>
              </div>
              <button onClick={() => setShowAddModal(false)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><X size={24} /></button>
            </div>
            <div className="p-10 space-y-6">
              <div className="grid grid-cols-2 gap-4 bg-slate-100 p-2 rounded-2xl">
                <button onClick={() => setFormType('income')} className={`py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${formType === 'income' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500'}`}>Receita</button>
                <button onClick={() => setFormType('expense')} className={`py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${formType === 'expense' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500'}`}>Despesa</button>
              </div>

              <div className="grid grid-cols-2 gap-4 bg-slate-50 p-2 rounded-2xl border">
                <button onClick={() => setFormStatus('paid')} className={`py-2 rounded-lg font-black text-[9px] uppercase tracking-widest transition-all ${formStatus === 'paid' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400'}`}>Pago / Recebido</button>
                <button onClick={() => setFormStatus('pending')} className={`py-2 rounded-lg font-black text-[9px] uppercase tracking-widest transition-all ${formStatus === 'pending' ? 'bg-amber-500 text-white shadow-sm' : 'text-slate-400'}`}>Agendar (A Pagar/Receber)</button>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor (R$)</label>
                <input type="number" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-500 font-black text-2xl" value={formAmount} onChange={(e) => setFormAmount(e.target.value)} placeholder="0,00" />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                <select className="w-full px-6 py-4 bg-slate-50 border rounded-2xl font-bold" value={formCategory} onChange={(e)=>setFormCategory(e.target.value)}>
                   {formType === 'expense' ? ['Fornecedores', 'Utilidades (Luz/Água)', 'Aluguel', 'Salários', 'Marketing', 'Impostos', 'Outros'].map(c => <option key={c} value={c}>{c}</option>) : ['Vendas PDV', 'Aportes', 'Reembolsos', 'Outros'].map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input type="text" className="w-full px-6 py-4 bg-slate-50 border rounded-2xl outline-none font-medium" value={formDesc} onChange={(e) => setFormDesc(e.target.value)} placeholder="Ex: Compra de carnes - Açougue Central" />
              </div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4">
              <button onClick={() => setShowAddModal(false)} className="flex-1 py-4 font-black text-slate-500 uppercase tracking-widest text-[10px]">Cancelar</button>
              <button onClick={handleSaveRecord} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 shadow-xl shadow-indigo-100"><Save size={18} /> Confirmar Lançamento</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

