    // Se for fiado, atualizar conta do cliente
    if (method === 'conta_cliente' && customerId) {
      const customer = customers.find(c => c.id === customerId);
      if (customer) {
        const transaction: CustomerTransaction = {
          id: `t${Date.now()}`,
          type: 'debit',
          amount: table.total,
          description: `Consumo Mesa ${tableId} (Pedido #${newOrder.id})`,
          date: new Date()
        };
        handleUpdateCustomer(customerId, {
          balance: customer.balance + table.total,
          history: [transaction, ...customer.history]
        });
      }
    } else {
      // Se não for fiado, gera registro financeiro imediato de entrada
      handleAddFinancialRecord({
        type: 'income',
        amount: table.total,
        category: 'Vendas Mesa',
        description: `Mesa ${tableId} - Pagamento: ${method}`,
        date: new Date()
      });
    }

    addLog('u1', 'VENDA', `Mesa ${tableId} encerrada. Total: R$ ${table.total.toFixed(2)}`);
  };

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({ isOpen: true, openingValue: value, openedAt: new Date() });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({ isOpen: false, openingValue: 0, openedAt: null });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts products={products} onNavigateToInventory={() => setActiveTab('inventory')} />
                <div className="bg-white p-6 rounded-3xl border shadow-sm h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{ name: 'Seg', sales: 4000 }, { name: 'Ter', sales: 3000 }, { name: 'Qua', sales: 5000 }, { name: 'Qui', sales: 4780 }, { name: 'Sex', sales: 8890 }, { name: 'Sáb', sales: 9390 }, { name: 'Dom', sales: 7490 }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fill="#4f46e51a" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit gap-6">
                <h3 className="text-xl font-bold">Resumo Diário</h3>
                <div className="p-6 bg-slate-50 rounded-2xl border">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
                <div className="p-6 bg-rose-50 rounded-2xl border border-rose-100">
                  <p className="text-xs font-black text-rose-400 uppercase tracking-widest">Saldo em Fiado</p>
                  <p className="text-2xl font-black text-rose-600">R$ {customers.reduce((a,b)=>a+b.balance,0).toFixed(2)}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables tables={tables} products={products} orders={orders} customers={customers} cashSession={cashSession} onUpdateTable={(id, items, status) => setTables(t => t.map(x => x.id === id ? {...x, items, status, total: items.reduce((a,b)=>a+(b.price*b.quantity),0)} : x))} onCloseTable={handleCloseTable} onSendToKitchen={() => {}} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} />;
      case 'customers':
        return <CustomersPanel customers={customers} onAddCustomer={handleAddCustomer} onUpdateCustomer={handleUpdateCustomer} onAddFinancialRecord={handleAddFinancialRecord} />;
      case 'delivery':
        return <Delivery orders={orders} couriers={couriers} deliveryFee={globalDeliveryFee} onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o))} onAssignCourier={(orderId, courierId) => setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o))} onAddCourier={(c) => setCouriers(prev => [...prev, { ...c, id: `c${Date.now()}`, status: 'available', createdAt: new Date() } as Courier])} onUpdateDeliveryFee={setGlobalDeliveryFee} onAddFinancialRecord={handleAddFinancialRecord} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={(p) => setProducts(prev => prev.map(x => x.id === p.id ? p : x))} />;
      case 'finance':
        return <Finance 
          orders={orders} 
          customers={customers} 
          couriers={couriers} 
          manualRecords={financialRecords} 
          onAddRecord={handleAddFinancialRecord} 
          onUpdateRecord={handleUpdateFinancialRecord}
          onUpdateCustomer={handleUpdateCustomer}
        />;
      case 'users':
        return <UsersPanel users={users} auditLogs={auditLogs} rolePermissions={rolePermissions} onAddUser={(u) => setUsers(prev => [...prev, { ...u, id: `u${Date.now()}`, status: 'online', createdAt: new Date() } as User])} onUpdateRole={()=>{}} onUpdateRolePermissions={()=>{}} />;
      case 'kds':
        return <KDS orders={orders} couriers={couriers} onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o))} onAssignCourier={(orderId, courierId) => setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o))} />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={(order) => setIncomingDigitalOrders(prev => [...prev, order])} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'settings':
        return <AdminSettingsComponent settings={adminSettings} onUpdateSettings={setAdminSettings} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black">GA</div>
        </header>
        {renderContent()}
      </main>

      {/* WHATSAPP NOTIFICATION MOCK */}
      {mockWhatsAppNotify && (
        <div className="fixed top-8 right-8 z-[300] w-full max-w-sm px-4 animate-in slide-in-from-right-10">
           <div className="bg-white border-l-4 border-emerald-500 rounded-2xl shadow-2xl p-4 flex gap-4 items-center ring-1 ring-black/5">
              <div className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-emerald-100"><MessageCircle size={24} /></div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase text-emerald-600 flex justify-between"><span>WhatsApp Cliente</span><span className="text-slate-300">Agora</span></p>
                 <p className="text-sm font-black text-slate-800 mt-0.5">{mockWhatsAppNotify.title}</p>
                 <p className="text-xs font-medium text-slate-500 line-clamp-2">{mockWhatsAppNotify.msg}</p>
              </div>
           </div>
        </div>
      )}

      {/* PEDIDOS DIGITAIS ENTRANDO */}
      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-2 border-indigo-600 rounded-[2rem] shadow-2xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center">
                  {order.type === 'delivery' ? <ShoppingBag size={24} /> : <Smartphone size={24} />}
                </div>
                <div>
                  <h4 className="font-black text-slate-800">Novo Pedido Digital</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => { setIncomingDigitalOrders(prev => prev.filter(o => o.id !== order.id)); addLog('u1', 'DIGITAL', `Pedido #${order.id.slice(-4)} RECUSADO`); }} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => {
                   const acceptedOrder = { ...order, status: 'preparing' as const, deliveryFee: globalDeliveryFee };
                   setOrders(prev => [acceptedOrder, ...prev]);
                   setIncomingDigitalOrders(prev => prev.filter(o => o.id !== order.id));
                   if (order.type === 'table' && order.tableNumber) {
                     setTables(prev => prev.map(t => t.id === order.tableNumber ? { ...t, status: 'occupied', items: [...t.items, ...order.items], total: t.total + order.total } : t));
                   }
                   triggerWhatsAppMock("✅ Pedido Aceito!", `Olá ${order.customerName}, seu pedido #${order.id.slice(-4)} foi aceito!`);
                   addLog('u1', 'DIGITAL', `Pedido #${order.id.slice(-4)} ACEITO`);
                }} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { FinancialRecord, Order, Customer, Courier, CustomerTransaction } from '../types';
import { 
  TrendingUp, TrendingDown, DollarSign, Wallet, 
  Plus, Search, Calendar, PieChart, 
  ArrowRightLeft, FileText, CheckCircle2, X, Save,
  Bike, Truck, ArrowRight, History,
  Building2, UserCircle, AlertTriangle, ArrowUpCircle, ArrowDownCircle
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer, Legend, Cell,
  PieChart as RePieChart, Pie
} from 'recharts';

interface FinanceProps {
  orders: Order[];
  customers: Customer[];
  couriers: Courier[];
  manualRecords: FinancialRecord[];
  onAddRecord: (record: Partial<FinancialRecord>) => void;
  onUpdateRecord: (id: string, updates: Partial<FinancialRecord>) => void;
  onUpdateCustomer: (id: string, updates: Partial<Customer>) => void;
}

const Finance: React.FC<FinanceProps> = ({ 
  orders, 
  customers, 
  couriers, 
  manualRecords, 
  onAddRecord, 
  onUpdateRecord,
  onUpdateCustomer 
}) => {
  const [activeView, setActiveView] = useState<'overview' | 'transactions' | 'agenda'>('overview');
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<'all' | 'income' | 'expense'>('all');

  // Form states
  const [formType, setFormType] = useState<'income' | 'expense'>('expense');
  const [formAmount, setFormAmount] = useState('');
  const [formCategory, setFormCategory] = useState('Fornecedores');
  const [formDesc, setFormDesc] = useState('');
  const [formStatus, setFormStatus] = useState<'pending' | 'paid'>('paid');

  const incomeFromOrders = useMemo(() => orders.map(order => ({
    id: order.id,
    type: 'income' as const,
    amount: order.total,
    category: 'Vendas PDV',
    description: `Pedido #${order.id.slice(-4)} (${order.type})`,
    date: order.createdAt,
    status: 'paid' as const
  })), [orders]);

  const allRecords = useMemo(() => [
    ...incomeFromOrders,
    ...manualRecords
  ].sort((a, b) => b.date.getTime() - a.date.getTime()), [incomeFromOrders, manualRecords]);

  // Cálculos de Projeção Reais
  const courierDebts = useMemo(() => {
    return couriers.map(c => {
      const courierOrders = orders.filter(o => o.courierId === c.id && o.status === 'delivered' && o.type === 'delivery');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const totalDaily = c.dailyFee || 0;
      const cashHand = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);

      // O que o restaurante DEVE ao motoboy
      const balance = (totalFees + totalDaily) - cashHand;
      return { courier: c, balance, orderCount: courierOrders.length };
    });
  }, [couriers, orders]);

  const financialProjection = useMemo(() => {
    const totalFiadoReceivable = customers.reduce((acc, c) => acc + (c.balance > 0 ? c.balance : 0), 0);
    const totalMotoboyPayable = courierDebts.reduce((acc, d) => acc + (d.balance > 0 ? d.balance : 0), 0);
    const totalMotoboyToReceive = courierDebts.reduce((acc, d) => acc + (d.balance < 0 ? Math.abs(d.balance) : 0), 0);
    const totalPendingExpenses = manualRecords
      .filter(r => r.type === 'expense' && r.status === 'pending')
      .reduce((acc, r) => acc + r.amount, 0);

    return {
      fiado: totalFiadoReceivable,
      motoboyPagar: totalMotoboyPayable,
      motoboyReceber: totalMotoboyToReceive,
      fornecedores: totalPendingExpenses,
      totalPayable: totalMotoboyPayable + totalPendingExpenses,
      totalReceivable: totalFiadoReceivable + totalMotoboyToReceive
    };
  }, [customers, courierDebts, manualRecords]);

  const stats = useMemo(() => {
    const totalIncome = allRecords.filter(r => r.type === 'income' && r.status === 'paid').reduce((acc, r) => acc + r.amount, 0);
    const totalExpense = allRecords.filter(r => r.type === 'expense' && r.status === 'paid').reduce((acc, r) => acc + r.amount, 0);
    const netProfit = totalIncome - totalExpense;
    return { totalIncome, totalExpense, netProfit };
  }, [allRecords]);

  const handleSaveRecord = () => {
    if (!formAmount || !formDesc) return;
    onAddRecord({
      type: formType,
      amount: parseFloat(formAmount),
      category: formCategory,
      description: formDesc,
      status: formStatus,
      date: new Date()
    });
    setShowAddModal(false);
    setFormAmount('');
    setFormDesc('');
  };

  const handleSettlePending = (recordId: string) => {
    onUpdateRecord(recordId, { status: 'paid', date: new Date() });
    alert("Conta liquidada com sucesso!");
  };

  const handleSettleFiado = (customer: Customer) => {
    const amount = customer.balance;
    const transaction: CustomerTransaction = {
      id: `baixa-${Date.now()}`,
      type: 'credit',
      amount: amount,
      description: `Liquidação total de fiado via Financeiro`,
      date: new Date(),
      paymentMethod: 'dinheiro'
    };

    onUpdateCustomer(customer.id, {
      balance: 0,
      history: [transaction, ...customer.history]
    });

    onAddRecord({
      type: 'income',
      amount: amount,
      category: 'Recebimento Fiado',
      description: `Baixa Financeira: ${customer.name}`,
      status: 'paid',
      date: new Date()
    });
    alert(`Recebimento de R$ ${amount.toFixed(2)} registrado.`);
  };

  const filteredRecords = allRecords.filter(r => {
    const matchesSearch = r.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          r.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = filterType === 'all' || r.type === filterType;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="flex bg-white p-1 rounded-2xl border shadow-sm">
          {[
            { id: 'overview', label: 'Balanço', icon: PieChart },
            { id: 'agenda', label: 'Contas Pagar/Receber', icon: Calendar },
            { id: 'transactions', label: 'Extrato Completo', icon: ArrowRightLeft },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveView(tab.id as any)}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeView === tab.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <tab.icon size={16} /> {tab.label}
            </button>
          ))}
        </div>

        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
        >
          <Plus size={18} strokeWidth={3} /> Novo Lançamento
        </button>
      </div>

      {activeView === 'overview' && (
        <div className="space-y-8">
          {/* Dashboard de Liquidez */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
             <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm relative overflow-hidden group">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Disponibilidade (Saldo Realizado)</p>
                   <h3 className="text-4xl font-black text-slate-800 tracking-tighter">R$ {stats.netProfit.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                   <div className="mt-4 flex items-center gap-2">
                      <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                      <span className="text-[10px] font-black text-emerald-600 uppercase">Dinheiro em Caixa / Banco</span>
                   </div>
                </div>

                <div className="bg-indigo-600 p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden text-white">
                   <div className="absolute top-0 right-0 p-6 opacity-10"><DollarSign size={64} /></div>
                   <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest mb-2">Projeção Realista (Líquido Esperado)</p>
                   <h3 className="text-4xl font-black tracking-tighter">R$ {(stats.netProfit + financialProjection.totalReceivable - financialProjection.totalPayable).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                   <div className="mt-4 flex items-center gap-2">
                      <TrendingUp size={14} className="text-indigo-300" />
                      <p className="text-[10px] font-bold text-indigo-100 uppercase">Considerando Fiados e Pendências</p>
                   </div>
                </div>
             </div>

             <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                <h4 className="text-xs font-black uppercase text-slate-400 tracking-widest flex items-center gap-2"><History size={16} /> Fluxo Projetado</h4>
                <div className="space-y-4">
                   <div className="flex justify-between items-center group cursor-help">
                      <div className="flex items-center gap-3"><div className="p-2 bg-emerald-50 text-emerald-600 rounded-xl"><UserCircle size={18} /></div><span className="text-xs font-bold text-slate-600">Fiado a Receber</span></div>
                      <span className="text-sm font-black text-emerald-600">+ R$ {financialProjection.fiado.toFixed(2)}</span>
                   </div>
                   <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3"><div className="p-2 bg-rose-50 text-rose-600 rounded-xl"><Bike size={18} /></div><span className="text-xs font-bold text-slate-600">Pagar Motoboys</span></div>
                      <span className="text-sm font-black text-rose-600">- R$ {financialProjection.motoboyPagar.toFixed(2)}</span>
                   </div>
                   <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3"><div className="p-2 bg-amber-50 text-amber-600 rounded-xl"><Truck size={18} /></div><span className="text-xs font-bold text-slate-600">Fornecedores Pend.</span></div>
                      <span className="text-sm font-black text-rose-600">- R$ {financialProjection.fornecedores.toFixed(2)}</span>
                   </div>
                </div>
                <button onClick={() => setActiveView('agenda')} className="w-full py-3 bg-slate-50 text-slate-500 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-100 transition-all">Ver Agenda de Pagamentos</button>
             </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-white p-8 rounded-[3rem] border shadow-sm">
               <h3 className="text-xl font-black text-slate-800 mb-8">Saúde das Margens</h3>
               <div className="h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{name:'Jan', profit: 12000, goal: 15000}, {name:'Fev', profit: 18000, goal: 15000}, {name:'Mar', profit: 14000, goal: 15000}]}>
                       <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                       <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 'bold', fill: '#94a3b8'}} />
                       <Tooltip contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)'}} />
                       <Area type="monotone" dataKey="profit" stroke="#6366f1" fill="#6366f11a" strokeWidth={4} name="Lucro Realizado" />
                    </AreaChart>
                  </ResponsiveContainer>
               </div>
            </div>

            <div className="bg-white p-8 rounded-[3rem] border shadow-sm">
               <h3 className="text-xl font-black text-slate-800 mb-8">Onde seu dinheiro está indo</h3>
               <div className="h-[300px] flex items-center">
                  <ResponsiveContainer width="100%" height="100%">
                     <RePieChart>
                        <Pie data={[{name:'Fornecedores', v:financialProjection.fornecedores || 1000},{name:'Motoboys', v:financialProjection.motoboyPagar || 500},{name:'Custos Oper.', v:stats.totalExpense || 3000}]} innerRadius={60} outerRadius={100} paddingAngle={5} dataKey="v">
                           {['#f43f5e', '#f59e0b', '#6366f1'].map((color, i) => <Cell key={i} fill={color} />)}
                        </Pie>
                        <Tooltip />
                        <Legend />
                     </RePieChart>
                  </ResponsiveContainer>
               </div>
            </div>
          </div>
        </div>
      )}

      {activeView === 'agenda' && (
        <div className="space-y-8 animate-in slide-in-from-bottom-4">
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Contas a Receber */}
              <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden flex flex-col">
                 <div className="p-8 border-b bg-emerald-50/50 flex justify-between items-center">
