                <button onClick={() => setFormStatus('pending')} className={`py-2 rounded-lg font-black text-[9px] uppercase tracking-widest transition-all ${formStatus === 'pending' ? 'bg-amber-500 text-white shadow-sm' : 'text-slate-400'}`}>Agendar (Pendente)</button>
