              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                <select className="w-full px-6 py-4 bg-slate-50 border rounded-2xl font-bold" value={formCategory} onChange={(e)=>setFormCategory(e.target.value)}>
                   {formType === 'expense' ? ['Fornecedores', 'Utilidades', 'Aluguel', 'Salários', 'Impostos', 'Outros'].map(c => <option key={c} value={c}>{c}</option>) : ['Vendas PDV', 'Aportes', 'Reembolsos'].map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input type="text" className="w-full px-6 py-4 bg-slate-50 border rounded-2xl outline-none font-medium" value={formDesc} onChange={(e) => setFormDesc(e.target.value)} placeholder="Ex: Boleto Carnes" />
              </div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4">
              <button onClick={() => setShowAddModal(false)} className="flex-1 py-4 font-black text-slate-500 uppercase tracking-widest text-[10px]">Cancelar</button>
              <button onClick={handleSaveRecord} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 shadow-xl shadow-indigo-100"><Save size={18} /> Salvar Lançamento</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

