                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
                <div className="p-6 bg-rose-50 rounded-2xl border border-rose-100">
                  <p className="text-xs font-black text-rose-400 uppercase tracking-widest">Saldo em Fiado</p>
                  <p className="text-2xl font-black text-rose-600">R$ {customers.reduce((a,b)=>a+b.balance,0).toFixed(2)}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables tables={tables} products={products} orders={orders} customers={customers} cashSession={cashSession} onUpdateTable={(id, items, status) => setTables(t => t.map(x => x.id === id ? {...x, items, status, total: items.reduce((a,b)=>a+(b.price*b.quantity),0)} : x))} onCloseTable={handleCloseTable} onSendToKitchen={() => {}} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} />;
      case 'customers':
        return <CustomersPanel customers={customers} onAddCustomer={handleAddCustomer} onUpdateCustomer={handleUpdateCustomer} onAddFinancialRecord={handleAddFinancialRecord} />;
      case 'delivery':
        return <Delivery orders={orders} couriers={couriers} deliveryFee={globalDeliveryFee} onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o))} onAssignCourier={(orderId, courierId) => setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o))} onAddCourier={(c) => setCouriers(prev => [...prev, { ...c, id: `c${Date.now()}`, status: 'available', createdAt: new Date() } as Courier])} onUpdateCourier={handleUpdateCourier} onUpdateDeliveryFee={setGlobalDeliveryFee} onAddFinancialRecord={handleAddFinancialRecord} />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={(p) => setProducts(prev => prev.map(x => x.id === p.id ? p : x))} />;
      case 'finance':
        return <Finance 
          orders={orders} 
          customers={customers} 
          couriers={couriers} 
          manualRecords={financialRecords} 
          onAddRecord={handleAddFinancialRecord} 
          onUpdateRecord={handleUpdateFinancialRecord}
          onUpdateCustomer={handleUpdateCustomer}
        />;
      case 'users':
        return <UsersPanel users={users} auditLogs={auditLogs} rolePermissions={rolePermissions} onAddUser={(u) => setUsers(prev => [...prev, { ...u, id: `u${Date.now()}`, status: 'online', createdAt: new Date() } as User])} onUpdateRole={()=>{}} onUpdateRolePermissions={()=>{}} />;
      case 'kds':
        return <KDS orders={orders} couriers={couriers} onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o))} onAssignCourier={(orderId, courierId) => setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o))} />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={(order) => setIncomingDigitalOrders(prev => [...prev, order])} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'settings':
        return <AdminSettingsComponent settings={adminSettings} onUpdateSettings={setAdminSettings} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black">GA</div>
        </header>
        {renderContent()}
      </main>

      {/* WHATSAPP NOTIFICATION MOCK */}
      {mockWhatsAppNotify && (
        <div className="fixed top-8 right-8 z-[300] w-full max-w-sm px-4 animate-in slide-in-from-right-10">
           <div className="bg-white border-l-4 border-emerald-500 rounded-2xl shadow-2xl p-4 flex gap-4 items-center ring-1 ring-black/5">
              <div className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-emerald-100"><MessageCircle size={24} /></div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase text-emerald-600 flex justify-between"><span>WhatsApp Cliente</span><span className="text-slate-300">Agora</span></p>
                 <p className="text-sm font-black text-slate-800 mt-0.5">{mockWhatsAppNotify.title}</p>
                 <p className="text-xs font-medium text-slate-500 line-clamp-2">{mockWhatsAppNotify.msg}</p>
              </div>
           </div>
        </div>
      )}

      {/* PEDIDOS DIGITAIS ENTRANDO */}
      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-2 border-indigo-600 rounded-[2rem] shadow-2xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center">
                  {order.type === 'delivery' ? <ShoppingBag size={24} /> : <Smartphone size={24} />}
                </div>
                <div>
                  <h4 className="font-black text-slate-800">Novo Pedido Digital</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => { setIncomingDigitalOrders(prev => prev.filter(o => o.id !== order.id)); addLog('u1', 'DIGITAL', `Pedido #${order.id.slice(-4)} RECUSADO`); }} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => {
                   const acceptedOrder = { ...order, status: 'preparing' as const, deliveryFee: globalDeliveryFee };
                   setOrders(prev => [acceptedOrder, ...prev]);
                   setIncomingDigitalOrders(prev => prev.filter(o => o.id !== order.id));
                   if (order.type === 'table' && order.tableNumber) {
                     setTables(prev => prev.map(t => t.id === order.tableNumber ? { ...t, status: 'occupied', items: [...t.items, ...order.items], total: t.total + order.total } : t));
                   }
                   triggerWhatsAppMock("✅ Pedido Aceito!", `Olá ${order.customerName}, seu pedido #${order.id.slice(-4)} foi aceito!`);
                   addLog('u1', 'DIGITAL', `Pedido #${order.id.slice(-4)} ACEITO`);
                }} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { CATEGORIES } from '../constants';
import { generateProductImage } from '../services/gemini';
import { 
  Edit3, Package, TrendingUp, AlertCircle, Save, X, 
  Search, Filter, Download, Plus, History, 
  Sparkles, Loader2, Image as ImageIcon, Zap, ChevronDown,
  CheckCircle2, Wand2
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface InventoryProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

const Inventory: React.FC<InventoryProps> = ({ products, onUpdateProduct }) => {
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('Todos');
  const [generatingId, setGeneratingId] = useState<string | null>(null);
  const [isGeneratingAll, setIsGeneratingAll] = useState(false);
  const [missingImagesCount, setMissingImagesCount] = useState(0);

  // Detecta produtos sem imagem real ao carregar
  useEffect(() => {
    const missing = products.filter(p => !p.image || p.image.includes('picsum')).length;
    setMissingImagesCount(missing);
  }, [products]);

  const handleEditClick = (product: Product) => {
    setEditingProduct({ ...product });
  };

  const handleSave = () => {
    if (editingProduct) {
      onUpdateProduct(editingProduct);
      setEditingProduct(null);
    }
  };

  const handleGenerateImage = async (product: Product) => {
    setGeneratingId(product.id);
    try {
      const imageUrl = await generateProductImage(product.name, product.category);
      if (imageUrl) {
        onUpdateProduct({ ...product, image: imageUrl });
      }
    } catch (err) {
      console.error("Erro ao gerar imagem individual:", err);
    } finally {
      setGeneratingId(null);
    }
  };

  const handleGenerateAllMissingImages = async () => {
    const missing = products.filter(p => !p.image || p.image.includes('picsum'));
    if (missing.length === 0) return;

    setIsGeneratingAll(true);
    // Processamento sequencial para respeitar limites de taxa e dar feedback visual
    for (const product of missing) {
      setGeneratingId(product.id);
      try {
        const imageUrl = await generateProductImage(product.name, product.category);
        if (imageUrl) {
          onUpdateProduct({ ...product, image: imageUrl });
        }
        // Pequeno delay para suavizar a interface
        await new Promise(resolve => setTimeout(resolve, 500));
      } catch (err) {
        console.error(`Erro ao gerar imagem para ${product.name}:`, err);
      }
    }
    setGeneratingId(null);
    setIsGeneratingAll(false);
  };

  const filteredProducts = products.filter(p => 
    (p.name.toLowerCase().includes(searchTerm.toLowerCase())) &&
    (categoryFilter === 'Todos' || p.category === categoryFilter)
  );

  const lowStockCount = products.filter(p => p.stock < 15).length;
  const totalStockValue = products.reduce((acc, p) => acc + (p.stock * p.cost), 0);

  const chartData = editingProduct?.priceHistory?.map(h => ({
    ...h,
    dateFormatted: new Date(h.date).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })
  })) || [];

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Alerta de Imagens Ausentes */}
      {missingImagesCount > 0 && !isGeneratingAll && (
        <div className="bg-indigo-600 rounded-[2rem] p-6 text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl shadow-indigo-100 animate-in slide-in-from-top-4">
          <div className="flex items-center gap-4">
            <div className="bg-white/20 p-4 rounded-2xl backdrop-blur-md">
              <Wand2 size={24} className="text-amber-300 animate-pulse" />
            </div>
            <div>
              <h4 className="text-lg font-black tracking-tight">Otimize seu Cardápio Digital</h4>
              <p className="text-indigo-100 text-sm font-medium">Detectamos {missingImagesCount} produtos sem fotos reais. A IA pode gerar imagens profissionais agora.</p>
            </div>
          </div>
          <button 
            onClick={handleGenerateAllMissingImages}
            className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all shadow-lg flex items-center gap-2 whitespace-nowrap"
          >
            <Sparkles size={18} /> Sincronizar Catálogo
          </button>
        </div>
      )}

      {/* Stats Header */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
            <Package size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Total de Itens</p>
            <p className="text-2xl font-black text-slate-800">{products.length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl">
            <AlertCircle size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Estoque Crítico</p>
            <p className="text-2xl font-black text-rose-600">{lowStockCount}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm flex items-center gap-4">
          <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Valor em Estoque</p>
            <p className="text-2xl font-black text-slate-800">R$ {totalStockValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
        </div>
      </div>

      {/* Toolbar / Filters Area */}
      <div className="bg-white p-6 rounded-[2rem] border shadow-sm space-y-4">
