  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<any | null>(null);
  const [editingCourier, setEditingCourier] = useState<Courier | null>(null);

  // Settlement Multimeios
  const [settlementPayments, setSettlementPayments] = useState<{ [key: string]: number }>({
    dinheiro: 0,
    pix: 0,
    cartao: 0
  });

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierDailyFee, setNewCourierDailyFee] = useState('0');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = orders.filter(o => o.type === 'delivery');

  // Cálculo de acerto de contas por motoboy
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);
      const dailyFee = courier.dailyFee || 0;

      // Saldo Final = (Taxas + Diária) - O que ele recebeu em dinheiro
      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, 
        cashCollected,
        dailyFee,
        balance: (totalFees + dailyFee) - cashCollected
      };
    });
  }, [couriers, deliveryOrders]);

  const handleEditCourier = (courier: Courier) => {
    setEditingCourier(courier);
    setNewCourierName(courier.name);
    setNewCourierPhone(courier.phone);
    setNewCourierPix(courier.pixKey || '');
    setNewCourierDailyFee(courier.dailyFee?.toString() || '0');
    setNewCourierVehicle(courier.vehicleType || 'moto');
    setShowAddCourierModal(true);
  };

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;

    const courierData = { 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      dailyFee: parseFloat(newCourierDailyFee) || 0,
      vehicleType: newCourierVehicle 
    };

    if (editingCourier) {
      onUpdateCourier(editingCourier.id, courierData);
    } else {
      onAddCourier(courierData);
    }

    resetCourierForm();
    setShowAddCourierModal(false);
  };

  const resetCourierForm = () => {
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setNewCourierDailyFee('0');
    setNewCourierVehicle('moto');
    setEditingCourier(null);
  };

  const openSettlement = (data: any) => {
    setShowSettlementModal(data);
    // Reset payments state based on balance
    setSettlementPayments({
      dinheiro: data.balance > 0 ? data.balance : 0,
      pix: 0,
      cartao: 0
    });
  };

  const handleRealizeSettlement = () => {
    if (!showSettlementModal) return;
    const { courier, balance, totalFees, dailyFee, cashCollected } = showSettlementModal;

    const totalSelected = (Object.values(settlementPayments) as number[]).reduce((a, b) => a + b, 0);

    if (Math.abs(totalSelected - Math.abs(balance)) > 0.01) {
      alert("A soma dos valores informados não confere com o saldo do acerto!");
      return;
    }

    // Criar registros financeiros para cada modalidade
    Object.entries(settlementPayments).forEach(([method, amount]) => {
      if ((amount as number) > 0) {
        onAddFinancialRecord({
          type: balance >= 0 ? 'expense' : 'income',
          amount: amount as number,
          category: 'Acerto Motoboy',
          description: `Acerto com ${courier.name} (${method.toUpperCase()}). Taxas: R$${totalFees.toFixed(2)} | Diária: R$${dailyFee.toFixed(2)} | Dinheiro rua: R$${cashCollected.toFixed(2)}`,
          date: new Date()
        });
      }
    });

    alert(`Acerto de ${courier.name} finalizado com sucesso via multimeios!`);
    setShowSettlementModal(null);
  };

  const totalSettlementInput = (Object.values(settlementPayments) as number[]).reduce((a, b) => a + b, 0);
  const remainingSettlement = showSettlementModal ? Math.abs(showSettlementModal.balance) - totalSettlementInput : 0;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navegação Secundária */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        {[
          { id: 'monitor', label: 'Monitor Despacho', icon: Navigation },
          { id: 'couriers', label: 'Equipe de Motoboys', icon: UserCheck },
          { id: 'settlement', label: 'Acertos Financeiros', icon: Wallet },
          { id: 'settings', label: 'Configurações', icon: Settings }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-4 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
              <Package size={16} /> Aguardando Motoboy ({deliveryOrders.filter(o => o.status === 'ready').length})
            </h3>
            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {deliveryOrders.filter(o => o.status === 'ready').map(order => (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm space-y-4 hover:border-indigo-200 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="text-xl font-black text-slate-800">#{order.id.slice(-4)}</h4>
                      <p className="text-[9px] font-black uppercase text-amber-600 flex items-center gap-1 mt-1"><Clock size={12} /> {Math.floor((Date.now() - new Date(order.createdAt).getTime()) / 60000)}m aguardando</p>
                    </div>
                    <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                  </div>
                  <div className="flex items-start gap-2 text-xs font-medium text-slate-500 bg-slate-50 p-3 rounded-2xl border">
                    <MapPin size={16} className="text-rose-500 shrink-0 mt-0.5" />
                    <span className="line-clamp-2 leading-relaxed">{order.customerAddress}</span>
                  </div>
                  <button onClick={() => setSelectedOrderId(order.id)} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-lg">Atribuir Entregador</button>
                </div>
              ))}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2"><Bike size={16} className="text-indigo-600" /> Motoboys em Atividade</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               {courierSettlementData.filter(c => c.courier.status !== 'offline').map(data => (
                  <div key={data.courier.id} className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden flex flex-col">
                     <div className="p-6 border-b flex justify-between items-center bg-slate-50/50">
                        <div className="flex items-center gap-4">
                           <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center font-black">{data.courier.name.charAt(0)}</div>
                           <div>
                              <p className="font-black text-slate-800">{data.courier.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{data.courier.vehicleType}</p>
                           </div>
                        </div>
                        <div className="text-right">
                           <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${data.courier.status === 'delivering' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {data.courier.status === 'delivering' ? 'Em Rota' : 'Livre'}
                           </span>
                        </div>
                     </div>
                     <div className="p-6 bg-indigo-50/30 flex justify-between items-center mx-4 my-2 rounded-2xl border border-indigo-100">
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Diária Fixa</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.dailyFee.toFixed(2)}</p>
                        </div>
                        <div className="h-6 w-px bg-indigo-100"></div>
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Taxas Acumuladas</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.totalFees.toFixed(2)}</p>
                        </div>
                     </div>
                     <div className="flex-1 p-6 space-y-3">
                        {deliveryOrders.filter(o => o.courierId === data.courier.id && o.status === 'delivering').map(order => (
                           <div key={order.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl shadow-sm">
                              <div className="flex items-center gap-3">
                                 <div className="w-8 h-8 bg-indigo-600 text-white rounded-lg flex items-center justify-center text-[10px] font-black">#{order.id.slice(-4)}</div>
                                 <p className="text-[10px] font-black text-slate-700 uppercase">{order.customerName?.split(' ')[0]}</p>
                              </div>
                              <button onClick={() => onUpdateStatus(order.id, 'delivered')} className="p-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 shadow-lg shadow-emerald-100"><CheckCircle2 size={16} /></button>
                           </div>
                        ))}
                     </div>
                  </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-slate-800">Equipe de Entrega</h3>
             <button onClick={() => { resetCourierForm(); setShowAddCourierModal(true); }} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-indigo-100"><Plus size={18} /> Cadastrar Entregador</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {couriers.map(courier => (
              <div key={courier.id} className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-6 group hover:shadow-xl transition-all">
                <div className="flex items-center gap-4">
                   <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-[1.5rem] flex items-center justify-center font-black text-xl">{courier.name.charAt(0)}</div>
                   <div>
                     <h4 className="font-black text-slate-800">{courier.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">R$ {(courier.dailyFee || 0).toFixed(2)} diária • {courier.vehicleType}</p>
                   </div>
                </div>
                <div className="space-y-4">
                   <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl"><Phone size={16} className="text-slate-400" /><span className="text-xs font-bold">{courier.phone}</span></div>
                   <div className="flex items-center gap-3 p-4 bg-indigo-50 rounded-2xl border border-indigo-100"><QrCode size={16} className="text-indigo-600" /><div className="flex-1 overflow-hidden"><p className="text-[9px] font-black text-indigo-400 uppercase">PIX</p><p className="text-xs font-bold text-indigo-700 truncate">{courier.pixKey || 'Não cadastrado'}</p></div></div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleEditCourier(courier)} 
                    className="flex-1 py-3 bg-indigo-50 text-indigo-600 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-100 transition-colors flex items-center justify-center gap-2"
                  >
                    <Edit3 size={14} /> Editar
                  </button>
                  <button className="flex-1 py-3 border text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest">Inativar</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'settlement' && (
        <div className="space-y-8 animate-in slide-in-from-right-4">
           <div className="bg-indigo-600 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-xl shadow-indigo-100">
              <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter">Acerto Financeiro</h2><p className="text-indigo-100 font-medium">Concilie taxas, diárias e dinheiro recebido em mãos.</p></div>
              <ArrowRightLeft size={64} className="opacity-20" />
           </div>
           <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b"><tr><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase">Entregador</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Diária</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Taxas</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Dinheiro em Mão</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Saldo Final</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-center">Ações</th></tr></thead>
                 <tbody className="divide-y">
                    {courierSettlementData.map((data, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                          <td className="px-10 py-8 font-black text-slate-800">{data.courier.name}</td>
                          <td className="px-10 py-8 text-right font-black text-indigo-400">R$ {data.dailyFee.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-emerald-600">R$ {data.totalFees.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-rose-600">R$ {data.cashCollected.toFixed(2)}</td>
                          <td className={`px-10 py-8 text-right font-black ${data.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(data.balance).toFixed(2)}</td>
                          <td className="px-10 py-8 text-center"><button onClick={() => openSettlement(data)} disabled={data.orderCount === 0 && data.dailyFee === 0} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30 shadow-lg shadow-indigo-100">Realizar Acerto</button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal de Seleção de Motoboy (Despacho) */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div><h2 className="text-xl font-black text-slate-800">Despachar Pedido</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Pedido #{selectedOrderId.slice(-4)}</p></div><button onClick={() => setSelectedOrderId(null)} className="p-2 hover:bg-white rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-3">
              {couriers.filter(c => c.status !== 'offline').map(courier => {
                const active = orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length;
                return (
                   <button key={courier.id} onClick={() => { onAssignCourier(selectedOrderId, courier.id); setSelectedOrderId(null); }} className="w-full flex items-center justify-between p-5 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left group">
                     <div className="flex items-center gap-4">
                        <div className="p-3 bg-white shadow-sm border rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><Bike size={24} /></div>
                        <div><p className="font-black text-slate-800">{courier.name}</p><p className="text-[9px] font-black uppercase text-slate-400">{active > 0 ? `${active} entregas ativas` : 'Livre'}</p></div>
                     </div>
                     <ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600" />
                   </button>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Cadastro / Edição Entregador */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg">
                  {editingCourier ? <Edit3 size={24} /> : <UserPlus size={24} />}
                </div>
                <div>
                  <h2 className="text-xl font-black">{editingCourier ? 'Editar Entregador' : 'Novo Entregador'}</h2>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{editingCourier ? 'Atualize os dados de perfil e pagamento' : 'Adicione um novo membro à frota'}</p>
                </div>
              </div>
              <button onClick={() => setShowAddCourierModal(false)} className="p-2 hover:bg-white rounded-full transition-colors"><X size={24} className="text-slate-400" /></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:border-indigo-500 transition-all" value={newCourierName} onChange={(e)=>setNewCourierName(e.target.value)} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp</label>
                    <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:border-indigo-500 transition-all" value={newCourierPhone} onChange={(e)=>setNewCourierPhone(e.target.value)} />
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Diária (R$)</label>
                    <input type="number" className="w-full px-5 py-4 bg-slate-50 border-2 border-indigo-100 rounded-2xl font-black text-indigo-600 outline-none focus:border-indigo-500 transition-all" value={newCourierDailyFee} onChange={(e)=>setNewCourierDailyFee(e.target.value)} />
                 </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave PIX</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:border-indigo-500 transition-all" value={newCourierPix} onChange={(e)=>setNewCourierPix(e.target.value)} />
              </div>
              <div className="grid grid-cols-3 gap-2">
                {(['moto', 'bike', 'car'] as const).map(v => (
                  <button key={v} onClick={() => setNewCourierVehicle(v)} className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>
                    {v}
                  </button>
                ))}
              </div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4">
              <button onClick={() => setShowAddCourierModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase text-[10px]">Cancelar</button>
              <button onClick={handleSaveCourier} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl hover:bg-indigo-700 transition-all">
                {editingCourier ? 'Salvar Alterações' : 'Cadastrar'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* NOVO Modal: Acerto Financeiro Multimeios */}
      {showSettlementModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b bg-indigo-600 text-white flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-white/20 rounded-2xl shadow-inner"><Wallet size={24} /></div>
                    <div>
                       <h2 className="text-xl font-black">Acerto: {showSettlementModal.courier.name}</h2>
                       <p className="text-[10px] font-bold uppercase tracking-widest opacity-80">Conciliação Multimeios</p>
                    </div>
                 </div>
                 <button onClick={() => setShowSettlementModal(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button>
              </div>

              <div className="p-8 flex flex-col lg:flex-row gap-8">
                 {/* Resumo Esquerda */}
                 <div className="flex-1 space-y-4">
                    <div className="bg-slate-50 p-6 rounded-[2rem] border space-y-4">
                       <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Resumo do Período</p>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Diária</span><span>+ R$ {showSettlementModal.dailyFee.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Taxas</span><span>+ R$ {showSettlementModal.totalFees.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Dinheiro rua</span><span className="text-rose-500">- R$ {showSettlementModal.cashCollected.toFixed(2)}</span></div>
                       <div className="pt-4 border-t flex justify-between items-center">
                          <span className="font-black text-slate-800">Saldo Final</span>
                          <span className={`text-2xl font-black ${showSettlementModal.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(showSettlementModal.balance).toFixed(2)}</span>
                       </div>
                    </div>
                    {showSettlementModal.balance < 0 && (
                       <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl flex gap-3 text-rose-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">O motoboy possui mais dinheiro em espécie do que tem a receber. Ele deve devolver a diferença.</p>
                       </div>
                    )}
                 </div>

                 {/* Checkout Direita */}
                 <div className="flex-1 space-y-4">
                    <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Como o acerto será pago?</p>
                    <div className="space-y-3">
                       {[
                         { id: 'dinheiro', label: 'Dinheiro', icon: Banknote },
                         { id: 'pix', label: 'PIX', icon: QrCode },
                         { id: 'cartao', label: 'Cartão / Depósito', icon: CreditCard }
                       ].map(m => (
                          <div key={m.id} className="relative group">
                             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><m.icon size={18} /></div>
                             <input 
                               type="number" 
                               placeholder={m.label}
                               className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black outline-none focus:border-indigo-500 transition-all"
                               value={settlementPayments[m.id] || ''}
                               onChange={(e) => setSettlementPayments({...settlementPayments, [m.id]: parseFloat(e.target.value) || 0})}
                             />
                          </div>
                       ))}
                    </div>

                    <div className="p-6 bg-indigo-50 rounded-[2rem] space-y-2 border border-indigo-100">
                       <div className="flex justify-between items-center text-[10px] font-black uppercase text-indigo-400"><span>Restante</span><span>Status</span></div>
                       <div className="flex justify-between items-center">
                          <span className={`text-xl font-black ${remainingSettlement === 0 ? 'text-emerald-500' : 'text-indigo-600'}`}>R$ {remainingSettlement.toFixed(2)}</span>
                          <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${remainingSettlement === 0 ? 'bg-emerald-500 text-white' : 'bg-indigo-200 text-indigo-700'}`}>
                             {remainingSettlement === 0 ? 'Conferido' : 'Pendente'}
                          </span>
                       </div>
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setShowSettlementModal(null)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                 <button 
                  onClick={handleRealizeSettlement} 
                  disabled={remainingSettlement !== 0}
                  className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-30 disabled:grayscale transition-all"
                 >
                    Confirmar e Gerar Lançamentos
                 </button>
              </div>
          </div>
        </div>
      )}
    </div>
  );
};

