    if (isCounter) {
      setCounterOrders(prev => prev.map(t => t.id === id ? { ...t, items, status, total: items.reduce((a, b) => a + (b.price * b.quantity), 0) } : t));
    } else {
      setTables(prev => prev.map(t => t.id === id ? { ...t, items, status, total: items.reduce((a, b) => a + (b.price * b.quantity), 0) } : t));
    }
  };

  const handleAddCounterOrder = () => {
    const newCounter: Table = {
      id: Date.now(), // ID único temporal para balcão
      status: 'occupied',
      items: [],
      total: 0
    };
    setCounterOrders(prev => [...prev, newCounter]);
    addLog('u1', 'BALCÃO', 'Nova comanda de balcão aberta');
    return newCounter.id;
  };

  const handleCloseTable = (tableId: number, method: PaymentMethod, fiscal: boolean, customerId?: string, isCounter?: boolean) => {
    const source = isCounter ? counterOrders : tables;
    const table = source.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 6).toUpperCase(),
      tableNumber: isCounter ? undefined : tableId,
      items: table.items,
      total: table.total,
      type: isCounter ? 'takeout' : 'table',
      status: 'delivered',
      createdAt: new Date(),
      paymentMethod: method,
      isFiscalIssued: fiscal,
      customerId: customerId
    };

    setOrders(prev => [newOrder, ...prev]);

    if (isCounter) {
      setCounterOrders(prev => prev.filter(t => t.id !== tableId));
    } else {
      setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], status: 'available', total: 0 } : t));
    }

    if (method === 'conta_cliente' && customerId) {
      const customer = customers.find(c => c.id === customerId);
      if (customer) {
        const transaction: CustomerTransaction = {
          id: `t${Date.now()}`,
          type: 'debit',
          amount: table.total,
          description: `Consumo ${isCounter ? 'Balcão' : `Mesa ${tableId}`} (Pedido #${newOrder.id})`,
          date: new Date()
        };
        handleUpdateCustomer(customerId, {
          balance: customer.balance + table.total,
          history: [transaction, ...customer.history]
        });
      }
    } else {
      handleAddFinancialRecord({
        type: 'income',
        amount: table.total,
        category: isCounter ? 'Vendas Balcão' : 'Vendas Mesa',
        description: `${isCounter ? 'Balcão' : `Mesa ${tableId}`} - Pagamento: ${method}`,
        date: new Date()
      });
    }

    addLog('u1', 'VENDA', `${isCounter ? 'Balcão' : `Mesa ${tableId}`} encerrada. Total: R$ ${table.total.toFixed(2)}`);
  };

  const addLog = (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({ isOpen: true, openingValue: value, openedAt: new Date() });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({ isOpen: false, openingValue: 0, openedAt: null });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

