    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts products={products} onNavigateToInventory={() => setActiveTab('inventory')} />
                <div className="bg-white p-6 rounded-3xl border shadow-sm h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{ name: 'Seg', sales: 4000 }, { name: 'Ter', sales: 3000 }, { name: 'Qua', sales: 5000 }, { name: 'Qui', sales: 4780 }, { name: 'Sex', sales: 8890 }, { name: 'Sáb', sales: 9390 }, { name: 'Dom', sales: 7490 }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fill="#4f46e51a" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit gap-6">
                <h3 className="text-xl font-bold">Resumo Diário</h3>
                <div className="p-6 bg-slate-50 rounded-2xl border">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
                <div className="p-6 bg-rose-50 rounded-2xl border border-rose-100">
                  <p className="text-xs font-black text-rose-400 uppercase tracking-widest">Saldo em Fiado</p>
                  <p className="text-2xl font-black text-rose-600">R$ {customers.reduce((a,b)=>a+b.balance,0).toFixed(2)}</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'tables':
        return <Tables 
          tables={tables} 
          counterOrders={counterOrders}
          products={products} 
          orders={orders} 
          customers={customers} 
          cashSession={cashSession} 
          onUpdateTable={handleUpdateTable}
          onCloseTable={handleCloseTable} 
          onSendToKitchen={handleSendToKitchen} 
          onOpenCash={handleOpenCash} 
          onCloseCash={handleCloseCash} 
          onAddCounterOrder={handleAddCounterOrder}
        />;
      case 'customers':
        return <CustomersPanel customers={customers} onAddCustomer={handleAddCustomer} onUpdateCustomer={handleUpdateCustomer} onAddFinancialRecord={handleAddFinancialRecord} />;
      case 'delivery':
        return <Delivery 
          orders={orders} 
          couriers={couriers} 
          deliveryFee={globalDeliveryFee} 
          onUpdateStatus={handleUpdateOrderStatus} 
          onAssignCourier={handleAssignCourier} 
          onAddCourier={(c) => setCouriers(prev => [...prev, { ...c, id: `c${Date.now()}`, status: 'available', createdAt: new Date() } as Courier])} 
          onUpdateCourier={handleUpdateCourier} 
          onUpdateDeliveryFee={setGlobalDeliveryFee} 
          onAddFinancialRecord={handleAddFinancialRecord} 
        />;
      case 'inventory':
        return <Inventory products={products} onUpdateProduct={(p) => setProducts(prev => prev.map(x => x.id === p.id ? p : x))} />;
      case 'finance':
        return <Finance 
          orders={orders} 
          customers={customers} 
          couriers={couriers} 
          manualRecords={financialRecords} 
          onAddRecord={handleAddFinancialRecord} 
          onUpdateRecord={handleUpdateFinancialRecord}
          onUpdateCustomer={handleUpdateCustomer}
        />;
      case 'users':
        return <UsersPanel users={users} auditLogs={auditLogs} rolePermissions={rolePermissions} onAddUser={(u) => setUsers(prev => [...prev, { ...u, id: `u${Date.now()}`, status: 'online', createdAt: new Date() } as User])} onUpdateRole={()=>{}} onUpdateRolePermissions={()=>{}} />;
      case 'kds':
        return <KDS orders={orders} couriers={couriers} onUpdateStatus={handleUpdateOrderStatus} onAssignCourier={handleAssignCourier} />;
      case 'digital-menu':
        return <DigitalMenuConfig settings={digitalMenuSettings} onUpdateSettings={setDigitalMenuSettings} products={products} tables={tables} onPlaceDigitalOrder={(order) => setIncomingDigitalOrders(prev => [...prev, order])} />;
      case 'ai-cmv':
        return <CMVAnalysis products={products} />;
      case 'settings':
        return <AdminSettingsComponent settings={adminSettings} onUpdateSettings={setAdminSettings} />;
      default:
        return <div className="p-12 text-center text-slate-400">Em desenvolvimento...</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab}</h1>
          </div>
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black">GA</div>
        </header>
        {renderContent()}
      </main>

      {/* WHATSAPP NOTIFICATION MOCK */}
      {mockWhatsAppNotify && (
        <div className="fixed top-8 right-8 z-[300] w-full max-w-sm px-4 animate-in slide-in-from-right-10">
           <div className="bg-white border-l-4 border-emerald-500 rounded-2xl shadow-2xl p-4 flex gap-4 items-center ring-1 ring-black/5">
              <div className="w-12 h-12 bg-emerald-500 text-white rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-emerald-100"><MessageCircle size={24} /></div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase text-emerald-600 flex justify-between"><span>WhatsApp Cliente</span><span className="text-slate-300">Agora</span></p>
                 <p className="text-sm font-black text-slate-800 mt-0.5">{mockWhatsAppNotify.title}</p>
                 <p className="text-xs font-medium text-slate-500 line-clamp-2">{mockWhatsAppNotify.msg}</p>
              </div>
           </div>
        </div>
      )}

      {/* PEDIDOS DIGITAIS ENTRANDO */}
      {incomingDigitalOrders.length > 0 && (
        <div className="fixed bottom-8 right-8 z-[200] flex flex-col gap-4 w-96 animate-in slide-in-from-right-10">
          {incomingDigitalOrders.map((order) => (
            <div key={order.id} className="bg-white border-2 border-indigo-600 rounded-[2rem] shadow-2xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center">
                  {order.type === 'delivery' ? <ShoppingBag size={24} /> : order.type === 'takeout' ? <Store size={24} /> : <Smartphone size={24} />}
                </div>
                <div>
                  <h4 className="font-black text-slate-800">Novo Pedido {order.type === 'takeout' ? 'Retirada' : 'Digital'}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{order.customerName} • R$ {order.total.toFixed(2)}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => { setIncomingDigitalOrders(prev => prev.filter(o => o.id !== order.id)); addLog('u1', 'DIGITAL', `Pedido #${order.id.slice(-4)} RECUSADO`); }} className="flex-1 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-[10px] uppercase">Recusar</button>
                <button onClick={() => {
                   // Quando aceito, entra direto como status 'preparing'
                   const acceptedOrder = { ...order, status: 'preparing' as const, deliveryFee: order.type === 'delivery' ? globalDeliveryFee : 0 };
                   setOrders(prev => [acceptedOrder, ...prev]);
                   setIncomingDigitalOrders(prev => prev.filter(o => o.id !== order.id));
                   if (order.type === 'table' && order.tableNumber) {
                     setTables(prev => prev.map(t => t.id === order.tableNumber ? { ...t, status: 'occupied', items: [...t.items, ...order.items], total: t.total + order.total } : t));
                   }
                   triggerWhatsAppMock("✅ Pedido Aceito!", `Olá ${order.customerName}, seu pedido #${order.id.slice(-4)} foi aceito e já está em produção!`);
                   addLog('u1', 'DIGITAL', `Pedido #${order.id.slice(-4)} ACEITO E ENVIADO À COZINHA`);
                }} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">Aceitar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

