  products: Product[];
  orders: Order[];
  customers: Customer[];
  cashSession: {
    isOpen: boolean;
    openingValue: number;
    openedAt: Date | null;
  };
  onUpdateTable: (tableId: number, items: OrderItem[], status: Table['status'], isCounter?: boolean) => void;
  onCloseTable: (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean, customerId?: string, isCounter?: boolean) => void;
  onSendToKitchen: (tableId: number, items: OrderItem[], isCounter?: boolean) => void;
  onOpenCash: (value: number) => void;
  onCloseCash: () => void;
  onAddCounterOrder: () => number;
}

const Tables: React.FC<TablesProps> = ({ 
  tables, counterOrders, products, orders, customers, cashSession, 
  onUpdateTable, onCloseTable, onSendToKitchen, onOpenCash, onCloseCash, onAddCounterOrder
}) => {
  const [selectedTable, setSelectedTable] = useState<Table | null>(null);
  const [isCounterContext, setIsCounterContext] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showCashModal, setShowCashModal] = useState(false);
  const [showCustomerSelection, setShowCustomerSelection] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string>('');

  const [isFiscalEmission, setIsFiscalEmission] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSendingToKitchen, setIsSendingToKitchen] = useState(false);
  const [showKitchenSuccess, setShowKitchenSuccess] = useState(false);
  const [productSearch, setProductSearch] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');

  const [openingValueInput, setOpeningValueInput] = useState('0');

  const cashReport = useMemo(() => {
    if (!cashSession.openedAt) return null;
    const sessionOrders = orders.filter(o => o.createdAt >= cashSession.openedAt!);
    const totalsByMethod = { dinheiro: 0, cartao_credito: 0, cartao_debito: 0, pix: 0, vale_refeicao: 0, conta_cliente: 0 };
    sessionOrders.forEach(o => { if (o.paymentMethod) totalsByMethod[o.paymentMethod] += o.total; });
    const totalSales = Object.values(totalsByMethod).reduce((a, b) => a + b, 0);
    return { totalsByMethod, totalSales, expectedFinalValue: totalSales + cashSession.openingValue, count: sessionOrders.length };
  }, [orders, cashSession]);

  const [activeSeat, setActiveSeat] = useState<string>('Geral');
  const [editingItemIndex, setEditingItemIndex] = useState<number | null>(null);
  const [tempObs, setTempObs] = useState('');
  const [tempSeat, setTempSeat] = useState('');
  const [tempQty, setTempQty] = useState<number>(1);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const filteredCustomerList = useMemo(() => 
    customers.filter(c => c.name.toLowerCase().includes(customerSearch.toLowerCase())),
    [customers, customerSearch]
  );

  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const openTable = (table: Table) => {
    if (!cashSession.isOpen) {
      alert("Por favor, abra o caixa antes de realizar atendimentos.");
      setShowCashModal(true);
      return;
    }
    setIsCounterContext(false);
    if (table.status === 'available') {
      onUpdateTable(table.id, [], 'occupied');
      setSelectedTable({ ...table, status: 'occupied', items: [], total: 0 });
    } else {
      setSelectedTable(table);
    }
    setActiveSeat('Geral');
  };

  const openCounterOrder = (order: Table) => {
    setIsCounterContext(true);
    setSelectedTable(order);
    setActiveSeat('Geral');
  };

  const handleNewCounter = () => {
    if (!cashSession.isOpen) {
      alert("Abra o caixa primeiro.");
      setShowCashModal(true);
      return;
    }
    const newId = onAddCounterOrder();
    setIsCounterContext(true);
    setSelectedTable({ id: newId, status: 'occupied', items: [], total: 0 });
  };

  const addToTable = (product: Product) => {
    if (!selectedTable) return;
    const existingIndex = selectedTable.items.findIndex(i => i.productId === product.id && i.seat === activeSeat && !i.observation);
    let newItems: OrderItem[];
    if (existingIndex > -1) {
      newItems = [...selectedTable.items];
      newItems[existingIndex] = { ...newItems[existingIndex], quantity: newItems[existingIndex].quantity + 1 };
    } else {
      newItems = [...selectedTable.items, { productId: product.id, name: product.name, price: product.price, quantity: 1, seat: activeSeat }];
    }
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
  };

  const removeItem = (index: number) => {
    if (!selectedTable) return;
    const newItems = selectedTable.items.filter((_, i) => i !== index);
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
  };

  const startEditItem = async (index: number) => {
    const item = selectedTable!.items[index];
    setEditingItemIndex(index);
    setTempObs(item.observation || '');
    setTempSeat(item.seat || 'Geral');
    setTempQty(item.quantity);
    setLoadingSuggestions(true);
    try {
      const res = await getObservationSuggestions(item.name);
      setSuggestions(res);
    } catch (err) {
      setSuggestions(["Sem cebola", "Bem passado", "Ponto da casa", "Sem gelo"]);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  const saveItemEdit = () => {
    if (!selectedTable || editingItemIndex === null) return;
    const newItems = [...selectedTable.items];
    newItems[editingItemIndex] = { ...newItems[editingItemIndex], observation: tempObs.trim(), seat: tempSeat.trim() || 'Geral', quantity: tempQty > 0 ? tempQty : 1 };
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
    setEditingItemIndex(null);
  };

  const handleSendToKitchenLocal = () => {
    if (!selectedTable || selectedTable.items.length === 0) return;
    setIsSendingToKitchen(true);
    setTimeout(() => {
      onSendToKitchen(selectedTable.id, [...selectedTable.items], isCounterContext);
      setIsSendingToKitchen(false);
      setShowKitchenSuccess(true);
      setTimeout(() => setShowKitchenSuccess(false), 3000);
    }, 1000);
  };

  const handleProcessPayment = (method: PaymentMethod) => {
    if (!selectedTable) return;

    if (method === 'conta_cliente') {
      setShowCustomerSelection(true);
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, method, isFiscalEmission, undefined, isCounterContext);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
    }, 2000);
  };

  const finishFiadoPayment = () => {
    if (!selectedTable || !selectedCustomerId) return;
    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, 'conta_cliente', isFiscalEmission, selectedCustomerId, isCounterContext);
      setIsProcessing(false);
      setShowCustomerSelection(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
      setSelectedCustomerId('');
      setCustomerSearch('');
    }, 1500);
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()));

  return (
    <div className="space-y-8">
      {/* Barra de Gestão Superior */}
      <div className="flex flex-col lg:flex-row justify-between items-center bg-white p-6 rounded-[2rem] border shadow-sm gap-6">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setShowCashModal(true)}
            className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-lg ${cashSession.isOpen ? 'bg-emerald-500 text-white shadow-emerald-100' : 'bg-rose-500 text-white shadow-rose-100'}`}
          >
            {cashSession.isOpen ? <Unlock size={20} /> : <Lock size={20} />}
            Caixa {cashSession.isOpen ? 'Aberto' : 'Fechado'}
          </button>

          {cashSession.isOpen && (
            <div className="hidden sm:flex gap-4">
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial</p>
                  <p className="font-black text-slate-700">R$ {cashSession.openingValue.toFixed(2)}</p>
               </div>
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Vendas Atual</p>
                  <p className="font-black text-indigo-600">R$ {cashReport?.totalSales.toFixed(2)}</p>
               </div>
            </div>
          )}
        </div>
        <div className="flex gap-3 w-full lg:w-auto">
           <div className="relative flex-1 lg:w-64">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="text" placeholder="Pesquisar mesa..." className="w-full pl-12 pr-6 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-sm" />
           </div>
           <button 
            onClick={handleNewCounter}
            className="flex items-center gap-2 bg-indigo-600 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all"
           >
              <Store size={18} /> Novo Balcão
           </button>
        </div>
      </div>

      <div className="space-y-8">
        <div>
           <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 ml-2 flex items-center gap-2">
              <Utensils size={16} /> Mapa de Mesas
           </h3>
           <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
              {tables.map(table => (
                <button key={table.id} onClick={() => openTable(table)} disabled={table.status === 'cleaning'} className={`aspect-square p-6 rounded-[2rem] border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${getTableStatusColor(table.status)} shadow-sm`}>
                  <div className="text-current">{table.status === 'available' ? <Utensils size={32} /> : table.status === 'occupied' ? <Users size={32} /> : table.status === 'billing' ? <CreditCard size={32} /> : <Utensils size={32} className="animate-spin" />}</div>
                  <div className="text-center"><h3 className="text-2xl font-black">Mesa {table.id}</h3><p className="text-[10px] uppercase font-black tracking-widest opacity-60">{table.status}</p></div>
                  {table.total > 0 && <div className="mt-1 text-sm font-black bg-white/60 px-4 py-1.5 rounded-2xl shadow-sm">R$ {table.total.toFixed(2)}</div>}
                </button>
              ))}
           </div>
        </div>

        {counterOrders.length > 0 && (
          <div>
            <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 ml-2 flex items-center gap-2">
                <Store size={16} /> Comandas de Balcão Ativas
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
               {counterOrders.map(order => (
                  <button 
                    key={order.id} 
                    onClick={() => openCounterOrder(order)}
                    className="flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 border-slate-100 hover:border-indigo-600 transition-all shadow-sm group"
                  >
                     <div className="flex items-center gap-4">
                        <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
                           <ShoppingBag size={24} />
                        </div>
                        <div className="text-left">
                           <p className="font-black text-slate-800">Balcão #{order.id.toString().slice(-4)}</p>
                           <p className="text-[10px] font-bold text-slate-400 uppercase">{order.items.length} itens lançados</p>
                        </div>
                     </div>
                     <p className="font-black text-indigo-600 text-lg">R$ {order.total.toFixed(2)}</p>
                  </button>
               ))}
            </div>
          </div>
        )}
      </div>

      {/* Modal: Caixa */}
      {showCashModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 flex flex-col">
              <div className={`p-8 border-b flex justify-between items-center text-white ${cashSession.isOpen ? 'bg-indigo-600' : 'bg-rose-500'}`}>
                 <div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl shadow-inner">{cashSession.isOpen ? <Unlock size={24} /> : <Lock size={24} />}</div><div><h2 className="text-2xl font-black">{cashSession.isOpen ? 'Fechar Caixa' : 'Abrir Novo Caixa'}</h2><p className="text-xs font-bold opacity-80 uppercase tracking-widest">{cashSession.isOpen ? 'Conferência de Valores' : 'Início de Turno'}</p></div></div>
                 <button onClick={() => setShowCashModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-10 space-y-8">
                 {!cashSession.isOpen ? (
                    <div className="space-y-6 text-center">
                       <p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor de Fundo / Troco</p>
                       <div className="relative max-w-[300px] mx-auto"><span className="absolute left-6 top-1/2 -translate-y-1/2 text-3xl font-black text-slate-300">R$</span><input type="number" className="w-full pl-20 pr-8 py-6 bg-slate-50 border-2 border-slate-100 rounded-[2rem] text-5xl font-black text-slate-800 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-center" value={openingValueInput} onChange={(e) => setOpeningValueInput(e.target.value)} autoFocus /></div>
                       <button onClick={() => { onOpenCash(parseFloat(openingValueInput) || 0); setShowCashModal(false); }} className="w-full bg-indigo-600 text-white py-6 rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-indigo-700 transition-all">Confirmar Abertura</button>
                    </div>
                 ) : (
                    <div className="space-y-8">
                       <div className="grid grid-cols-2 gap-6">
                          <div className="bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total em Vendas</p><h4 className="text-3xl font-black text-slate-800 tracking-tighter">R$ {cashReport?.totalSales.toFixed(2)}</h4></div>
                          <div className="bg-emerald-50 p-6 rounded-[2.5rem] border border-emerald-100"><p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Saldo Esperado</p><h4 className="text-3xl font-black text-emerald-700 tracking-tighter">R$ {cashReport?.expectedFinalValue.toFixed(2)}</h4></div>
                       </div>
                       <div className="space-y-3">
                          {[{ id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' }, { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' }, { id: 'conta_cliente', label: 'Fiado (Conta Cliente)', icon: UserCircle, color: 'text-rose-500' }].map(method => (
                             <div key={method.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                <div className="flex items-center gap-4"><div className={`p-2 bg-white rounded-xl ${method.color}`}><method.icon size={18} /></div><p className="font-black text-slate-700 text-sm">{method.label}</p></div>
                                <p className="font-black text-slate-800">R$ {cashReport?.totalsByMethod[method.id as keyof typeof cashReport.totalsByMethod].toFixed(2)}</p>
                             </div>
                          ))}
                       </div>
                       <button onClick={() => { if(confirm("Deseja fechar o caixa?")) { onCloseCash(); setShowCashModal(false); } }} className="w-full bg-rose-500 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-rose-100 hover:bg-rose-600 transition-all flex items-center justify-center gap-2"><Lock size={18} /> Encerrar Turno</button>
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Modal: Comanda (Mesa ou Balcão) */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-7xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white"><div className="flex justify-between items-center mb-6"><div><h2 className="text-2xl font-black text-slate-800">{isCounterContext ? `Pedido Balcão #${selectedTable.id.toString().slice(-4)}` : 'Cardápio Mesas'}</h2><p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Lançamento de itens em tempo real</p></div><div className="relative w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Pesquisar..." className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" value={productSearch} onChange={(e) => setProductSearch(e.target.value)} /></div></div></div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 lg:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                  <button key={product.id} onClick={() => addToTable(product)} className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-2 group shadow-sm">
                    <div className="w-full aspect-square bg-slate-100 rounded-2xl mb-2 overflow-hidden"><img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" /></div>
                    <p className="font-black text-slate-800 text-sm truncate">{product.name}</p>
                    <div className="flex justify-between items-center mt-auto"><p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p><Plus size={16} className="text-slate-300 group-hover:text-indigo-600" /></div>
                  </button>
                ))}
              </div>
            </div>
            <div className="w-[450px] flex flex-col bg-white border-l shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white"><div className="flex items-center gap-3"><div className="p-3 bg-white/20 rounded-2xl shadow-inner">{isCounterContext ? <Store size={24} /> : <Users size={24} />}</div><div><h2 className="text-xl font-black">{isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2><p className="text-[10px] font-bold uppercase opacity-70 tracking-widest mt-1">Gestão de Itens</p></div></div><button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
              {!isCounterContext && (
                 <div className="p-6 bg-slate-50 border-b space-y-3"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><UserIcon size={12} /> Lançar para:</p><div className="flex gap-2 overflow-x-auto scrollbar-hide">{['Geral', 'Cadeira 1', 'Cadeira 2', 'Cadeira 3', '+ Nova'].map(seat => (<button key={seat} onClick={() => setActiveSeat(seat)} className={`px-4 py-2 rounded-xl text-xs font-bold border-2 whitespace-nowrap transition-all ${activeSeat === seat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}>{seat}</button>))}</div></div>
              )}
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {selectedTable.items.length === 0 ? (<div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40"><div className="p-8 border-4 border-dashed rounded-full border-slate-200"><Utensils size={64} strokeWidth={1} /></div><p className="font-black uppercase tracking-tighter">Aguardando Pedidos...</p></div>) : 
                (selectedTable.items.map((item, index) => (
                  <div key={index} className="bg-slate-50 rounded-[2rem] border border-slate-100 overflow-hidden hover:shadow-md transition-shadow group"><div className="p-5 flex justify-between items-start"><div className="flex-1"><div className="flex items-center gap-2 mb-1"><span className="text-[10px] bg-indigo-100 text-indigo-700 font-black px-2 py-0.5 rounded-full uppercase">{item.seat || 'Geral'}</span><p className="font-black text-slate-800">{item.name}</p></div><p className="text-xs text-slate-500 font-bold">{item.quantity}x R$ {item.price.toFixed(2)}</p></div><div className="text-right flex flex-col items-end gap-2"><p className="font-black text-indigo-600">R$ {(item.price * item.quantity).toFixed(2)}</p><div className="flex gap-1"><button onClick={() => startEditItem(index)} className="p-2 text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 rounded-xl"><Edit3 size={16} /></button><button onClick={() => removeItem(index)} className="p-2 text-slate-400 hover:bg-rose-50 hover:text-rose-600 rounded-xl"><Trash2 size={16} /></button></div></div></div></div>
                )))}
              </div>
              <div className="p-8 border-t bg-slate-50/50 space-y-6"><div className="flex justify-between items-center text-3xl font-black text-slate-800 tracking-tighter"><span>Total</span><span className="text-indigo-600">R$ {selectedTable.total.toFixed(2)}</span></div><div className="grid grid-cols-2 gap-4"><button disabled={selectedTable.items.length === 0 || isSendingToKitchen} onClick={handleSendToKitchenLocal} className={`flex flex-col items-center justify-center gap-2 p-5 rounded-[1.5rem] transition-all font-black shadow-lg uppercase text-[10px] tracking-widest relative overflow-hidden ${showKitchenSuccess ? 'bg-emerald-500 text-white' : 'bg-violet-600 text-white hover:bg-violet-700'} disabled:opacity-50`}>{isSendingToKitchen ? <Loader2 size={20} className="animate-spin" /> : showKitchenSuccess ? <CheckCircle2 size={20} /> : <ChefHat size={20} />}<span>{showKitchenSuccess ? 'Enviado!' : 'Enviar Cozinha'}</span></button><button className="flex flex-col items-center justify-center gap-2 p-5 bg-white border-2 border-slate-200 rounded-[1.5rem] text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all font-bold group shadow-sm uppercase text-[10px] tracking-widest"><Printer size={20} /><span>Pré-Conta</span></button></div><button disabled={selectedTable.items.length === 0} onClick={() => setShowPaymentModal(true)} className="w-full flex items-center justify-center gap-3 p-5 bg-emerald-600 text-white rounded-[1.5rem] hover:bg-emerald-700 transition-all font-black shadow-xl uppercase text-xs tracking-widest"><Receipt size={20} /><span>Fechar Comanda</span></button></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Pagamento Refatorado */}
      {showPaymentModal && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col">
            {!showCustomerSelection ? (
              <>
                <div className="p-8 border-b flex justify-between items-center bg-emerald-600 text-white"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><Wallet size={24} /></div><div><h2 className="text-2xl font-black">Finalizar {isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2><p className="text-xs font-bold opacity-80 uppercase tracking-widest">Pagamento e Emissão</p></div></div><button onClick={() => setShowPaymentModal(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                <div className="p-10 space-y-10">
                  <div className="text-center space-y-2"><p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor Total</p><h1 className="text-6xl font-black text-slate-800 tracking-tighter">R$ {selectedTable.total.toFixed(2)}</h1></div>
                  <div className="space-y-4">
                    <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Escolha o Método</p>
                    <div className="grid grid-cols-2 gap-4">
                      {[
                        { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' },
                        { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' },
                        { id: 'cartao_credito', label: 'Crédito', icon: CreditCard, color: 'text-indigo-700' },
                        { id: 'conta_cliente', label: 'Lançar Fiado', icon: UserCircle, color: 'text-rose-500' },
                      ].map(method => (
                        <button key={method.id} disabled={isProcessing} onClick={() => handleProcessPayment(method.id as PaymentMethod)} className="p-6 rounded-3xl border-2 border-slate-100 bg-slate-50/50 hover:bg-white hover:border-indigo-500 transition-all text-left flex flex-col gap-4 group active:scale-95">
                          <div className={`p-3 bg-white shadow-sm border rounded-2xl w-fit ${method.color} group-hover:scale-110 transition-transform`}><method.icon size={24} /></div>
                          <p className="font-black text-slate-800">{method.label}</p>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            ) : (
              <div className="animate-in slide-in-from-right-10 duration-300">
                 <div className="p-8 border-b bg-rose-600 text-white flex justify-between items-center"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><UserCircle size={24} /></div><div><h2 className="text-xl font-black">Selecionar Cliente</h2><p className="text-xs font-bold uppercase opacity-80">Lançamento em Conta Fiado</p></div></div><button onClick={() => setShowCustomerSelection(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                 <div className="p-8 space-y-6">
                    <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Nome do cliente..." className="w-full pl-12 pr-6 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={customerSearch} onChange={(e)=>setCustomerSearch(e.target.value)} /></div>
                    <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar">
                       {filteredCustomerList.map(c => (
                          <button key={c.id} onClick={() => setSelectedCustomerId(c.id)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedCustomerId === c.id ? 'border-rose-600 bg-rose-50' : 'border-slate-50 bg-white hover:border-slate-200'}`}>
                             <div className="text-left"><p className="font-black text-slate-800">{c.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{c.document}</p></div>
                             {selectedCustomerId === c.id && <CheckCircle2 size={24} className="text-rose-600" />}
                          </button>
                       ))}
                    </div>
                 </div>
                 <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowCustomerSelection(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Voltar</button><button onClick={finishFiadoPayment} disabled={!selectedCustomerId || isProcessing} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-50">Lançar Fiado (R$ {selectedTable.total.toFixed(2)})</button></div>
              </div>
            )}

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in"><div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div><p className="text-xl font-black text-slate-800">Finalizando Operação...</p></div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Tables;

import React, { useState, useMemo } from 'react';
import { DigitalMenuSettings, Product, Table, Order } from '../types';
import { 
  Smartphone, Palette, QrCode, 
  Save, Eye, Check, 
  Plus, Globe, 
  ShoppingCart, Copy, Share2, X, MousePointer2,
  Minus, MapPin, User, Wallet,
  CheckCircle2, ArrowLeft, MessageCircle,
  Bike, Home, UserCircle, Phone, Store
} from 'lucide-react';

interface DigitalMenuConfigProps {
  settings: DigitalMenuSettings;
  onUpdateSettings: (settings: DigitalMenuSettings) => void;
  products: Product[];
  tables: Table[];
  onPlaceDigitalOrder: (order: Order) => void;
}

interface SimCartItem {
  product: Product;
  quantity: number;
}

const DigitalMenuConfig: React.FC<DigitalMenuConfigProps> = ({ settings, onUpdateSettings, products, tables, onPlaceDigitalOrder }) => {
  const [activeTab, setActiveTab] = useState<'visual' | 'behavior' | 'qrcode'>('visual');
  const [showTestMode, setShowTestMode] = useState(false);
  const [isLinkCopied, setIsLinkCopied] = useState(false);

  // States para a Simulação Interativa
  const [orderType, setOrderType] = useState<'table' | 'delivery' | 'takeout'>('table');
  const [testStep, setTestStep] = useState<'welcome' | 'menu' | 'cart' | 'checkout' | 'success'>('welcome');
  const [simCart, setSimCart] = useState<SimCartItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [tableNumber, setTableNumber] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('');

  const categories = Array.from(new Set(products.map(p => p.category)));
  const menuUrl = `https://gastroai.me/cardapio/${settings.restaurantName.toLowerCase().replace(/\s+/g, '-')}`;

  const handleCopyLink = () => {
    navigator.clipboard.writeText(menuUrl);
    setIsLinkCopied(true);
    setTimeout(() => setIsLinkCopied(false), 2000);
  };

  const addToSimCart = (product: Product) => {
    setSimCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
  };

  const removeFromSimCart = (productId: string) => {
    setSimCart(prev => prev.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity - 1 } : item
    ).filter(item => item.quantity > 0));
  };

  const simCartTotal = useMemo(() => {
    return simCart.reduce((acc, item) => acc + (item.product.price * item.quantity), 0);
  }, [simCart]);

  const resetSimulation = () => {
    setShowTestMode(false);
    setTestStep('welcome');
    setSimCart([]);
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setTableNumber('');
    setPaymentMethod('');
  };

  const handleFinishSimulation = () => {
    const finalOrder: Order = {
      id: `DIG-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      createdAt: new Date(),
      items: simCart.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        price: item.product.price,
        quantity: item.quantity,
      })),
      total: simCartTotal + (orderType === 'delivery' ? 7 : 0),
      status: 'pending',
      type: orderType,
      tableNumber: orderType === 'table' ? parseInt(tableNumber) : undefined,
      customerName: customerName,
      customerPhone: customerPhone,
      customerAddress: orderType === 'delivery' ? customerAddress : undefined,
      paymentMethod: paymentMethod as any
    };

    onPlaceDigitalOrder(finalOrder);
    setTestStep('success');
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-10rem)] animate-in fade-in duration-500">
      {/* Coluna Esquerda: Configurações */}
      <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-8 rounded-[3rem] text-white shadow-xl shadow-indigo-100 flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10"><Share2 size={120} /></div>
          <div className="relative z-10 flex flex-col gap-2">
            <h3 className="text-xl font-black tracking-tight">Cardápio Digital Ativo</h3>
            <p className="text-indigo-100 text-sm font-medium">Aceite pedidos de Mesa, Delivery e Retirada.</p>
            <div className="mt-4 flex items-center gap-2 bg-black/20 p-2 rounded-2xl backdrop-blur-md border border-white/10">
               <Globe size={14} className="text-indigo-300 ml-2" />
               <span className="text-xs font-mono font-bold truncate max-w-[200px]">{menuUrl}</span>
            </div>
          </div>
          <div className="relative z-10 flex gap-3">
             <button onClick={handleCopyLink} className={`flex items-center gap-2 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${isLinkCopied ? 'bg-emerald-500 text-white' : 'bg-white text-indigo-600 hover:bg-indigo-50 shadow-lg'}`}>
                {isLinkCopied ? <Check size={16} /> : <Copy size={16} />}
                {isLinkCopied ? 'Link Copiado' : 'Copiar Link'}
             </button>
             <button onClick={() => setShowTestMode(true)} className="flex items-center gap-2 px-6 py-4 bg-indigo-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-400 border border-indigo-400 shadow-lg transition-all">
                <MousePointer2 size={16} /> Ver Simulador
             </button>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-8">
           <div className="flex bg-slate-50 p-1.5 rounded-2xl w-fit border">
            <button onClick={() => setActiveTab('visual')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'visual' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}>
              <Palette size={16} /> Visual
            </button>
            <button onClick={() => setActiveTab('behavior')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'behavior' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}>
              <Smartphone size={16} /> Comportamento
            </button>
          </div>

          {activeTab === 'visual' && (
            <div className="space-y-6 animate-in slide-in-from-left-4">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cor Primária</label>
                <div className="flex items-center gap-4">
                  <input type="color" className="w-16 h-16 rounded-2xl cursor-pointer" value={settings.primaryColor} onChange={(e) => onUpdateSettings({ ...settings, primaryColor: e.target.value })} />
                  <span className="text-sm font-mono text-slate-500 font-bold">{settings.primaryColor}</span>
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Restaurante</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl outline-none font-bold" value={settings.restaurantName} onChange={(e) => onUpdateSettings({ ...settings, restaurantName: e.target.value })} />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Preview Mobile Simulator */}
      <div className="w-full lg:w-[400px] flex flex-col gap-4">
        <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2 ml-4">
          <Eye size={16} /> Mobile Preview
        </h3>
        <div className="flex-1 bg-slate-900 rounded-[3.5rem] border-[12px] border-slate-800 shadow-2xl overflow-hidden relative group">
           <div className="h-full bg-white flex flex-col items-center justify-center p-12 text-center gap-6">
              <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center animate-bounce">
                 <Smartphone size={48} />
              </div>
              <div>
                 <p className="font-black text-slate-800">Simulador Mobile</p>
                 <p className="text-xs text-slate-400 mt-2">Teste a experiência de compra do seu cliente.</p>
              </div>
           </div>
           <button onClick={() => setShowTestMode(true)} className="absolute inset-0 bg-indigo-600/20 backdrop-blur-[2px] opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center z-40">
              <div className="bg-white text-indigo-600 px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl">Abrir Simulador</div>
           </button>
        </div>
      </div>

      {/* MODAL SIMULATOR */}
      {showTestMode && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="absolute top-8 right-8"><button onClick={resetSimulation} className="p-4 bg-white/10 text-white rounded-full"><X size={32} /></button></div>
          <div className="w-[380px] h-[780px] bg-slate-900 rounded-[3.5rem] border-[12px] border-slate-800 shadow-2xl overflow-hidden relative">
             <div className="h-full bg-white flex flex-col relative overflow-hidden">
                {testStep === 'welcome' && (
                  <div className="h-full flex flex-col items-center justify-center p-8 text-center gap-10 animate-in fade-in zoom-in-95 overflow-y-auto">
                     <div className="w-20 h-20 bg-indigo-50 rounded-[2rem] flex items-center justify-center shrink-0"><img src={settings.logoUrl || 'https://picsum.photos/200'} className="w-14 h-14 rounded-xl object-cover" /></div>
                     <div className="space-y-2">
                        <h2 className="text-2xl font-black text-slate-800 tracking-tighter">{settings.restaurantName}</h2>
                        <p className="text-xs font-medium text-slate-500 leading-relaxed">{settings.welcomeMessage}</p>
                     </div>
                     <div className="w-full flex flex-col gap-3">
                        <button onClick={() => { setOrderType('table'); setTestStep('menu'); }} className="w-full py-5 bg-slate-100 rounded-3xl flex items-center justify-center gap-4 hover:border-indigo-600 border-2 border-transparent transition-all">
                           <QrCode className="text-indigo-600" />
                           <div className="text-left"><p className="font-black text-slate-800 text-sm">Estou na Mesa</p><p className="text-[9px] font-bold text-slate-400 uppercase">Peça por QR Code</p></div>
                        </button>
                        <button onClick={() => { setOrderType('delivery'); setTestStep('menu'); }} className="w-full py-5 bg-slate-100 rounded-3xl flex items-center justify-center gap-4 hover:border-rose-600 border-2 border-transparent transition-all">
                           <Bike className="text-rose-600" />
                           <div className="text-left"><p className="font-black text-slate-800 text-sm">Delivery Online</p><p className="text-[9px] font-bold text-slate-400 uppercase">Receba em casa</p></div>
                        </button>
                        <button onClick={() => { setOrderType('takeout'); setTestStep('menu'); }} className="w-full py-5 bg-slate-100 rounded-3xl flex items-center justify-center gap-4 hover:border-emerald-600 border-2 border-transparent transition-all">
                           <Store className="text-emerald-600" />
                           <div className="text-left"><p className="font-black text-slate-800 text-sm">Vou buscar</p><p className="text-[9px] font-bold text-slate-400 uppercase">Retirada no Balcão</p></div>
                        </button>
                     </div>
                  </div>
                )}

                {testStep === 'menu' && (
                  <div className="h-full flex flex-col animate-in slide-in-from-right-10">
                     <div className="h-32 shrink-0 relative bg-indigo-600 flex items-end p-6 overflow-hidden">
                        <img src={settings.bannerUrl} className="absolute inset-0 w-full h-full object-cover opacity-50" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                        <div className="relative z-10 text-white">
                           <h3 className="text-xl font-black">{settings.restaurantName}</h3>
                           <p className="text-[10px] font-bold opacity-80 uppercase tracking-widest">{orderType === 'table' ? 'Mesa' : orderType === 'delivery' ? 'Delivery' : 'Retirada'}</p>
                        </div>
                     </div>
                     <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-24">
                        <div className="flex gap-2 overflow-x-auto scrollbar-hide">
                           {categories.map(cat => <button key={cat} className="px-4 py-2 rounded-full bg-slate-50 border text-[10px] font-black uppercase whitespace-nowrap">{cat}</button>)}
                        </div>
                        {products.map(product => (
                           <div key={product.id} className="flex gap-4 p-4 border rounded-[2rem] items-center">
                              <img src={product.image} className="w-14 h-14 rounded-xl object-cover" />
                              <div className="flex-1">
                                 <p className="font-bold text-slate-800 text-xs">{product.name}</p>
                                 <p className="font-black text-indigo-600 text-[10px]">R$ {product.price.toFixed(2)}</p>
                              </div>
                              <button onClick={() => addToSimCart(product)} className="w-8 h-8 rounded-lg text-white flex items-center justify-center" style={{ backgroundColor: settings.primaryColor }}><Plus size={16} /></button>
                           </div>
                        ))}
                     </div>
                     <div className="absolute bottom-6 inset-x-6">
                        <button onClick={() => setTestStep('cart')} disabled={simCart.length === 0} className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3" style={{ backgroundColor: settings.primaryColor }}>
                           <ShoppingCart size={18} /> Meu Carrinho ({simCart.reduce((a,b)=>a+b.quantity, 0)})
                        </button>
                     </div>
                  </div>
                )}

                {testStep === 'cart' && (
                  <div className="h-full flex flex-col animate-in slide-in-from-right-10">
                     <div className="p-6 border-b flex items-center gap-4">
                        <button onClick={() => setTestStep('menu')} className="p-2 hover:bg-slate-100 rounded-xl"><ArrowLeft size={20} /></button>
                        <h3 className="text-lg font-black text-slate-800">Meu Pedido</h3>
                     </div>
                     <div className="flex-1 overflow-y-auto p-6 space-y-4">
                        {simCart.map(item => (
                           <div key={item.product.id} className="flex justify-between items-center p-4 border rounded-2xl">
                              <div className="flex-1"><p className="font-bold text-xs">{item.product.name}</p><p className="text-[10px] text-indigo-600 font-black">R$ {item.product.price.toFixed(2)}</p></div>
                              <div className="flex items-center gap-3 bg-slate-100 p-1 rounded-xl">
                                 <button onClick={() => removeFromSimCart(item.product.id)} className="w-6 h-6 bg-white rounded-lg flex items-center justify-center shadow-sm"><Minus size={12} /></button>
                                 <span className="font-black text-xs">{item.quantity}</span>
                                 <button onClick={() => addToSimCart(item.product)} className="w-6 h-6 bg-white rounded-lg flex items-center justify-center shadow-sm"><Plus size={12} /></button>
                              </div>
                           </div>
                        ))}
                        <div className="bg-slate-50 p-6 rounded-[2rem] border mt-8 space-y-2">
                           <div className="flex justify-between text-[10px] font-bold text-slate-400"><span>Subtotal</span><span>R$ {simCartTotal.toFixed(2)}</span></div>
                           {orderType === 'delivery' && <div className="flex justify-between text-[10px] font-bold text-slate-400"><span>Taxa de Entrega</span><span>R$ 7.00</span></div>}
                           <div className="pt-2 border-t flex justify-between font-black text-lg text-slate-800"><span>Total</span><span>R$ {(simCartTotal + (orderType === 'delivery' ? 7 : 0)).toFixed(2)}</span></div>
                        </div>
                     </div>
                     <div className="p-6 border-t mt-auto">
                        <button onClick={() => setTestStep('checkout')} className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl" style={{ backgroundColor: settings.primaryColor }}>Finalizar Pedido</button>
                     </div>
                  </div>
                )}

                {testStep === 'checkout' && (
                  <div className="h-full flex flex-col animate-in slide-in-from-right-10">
                     <div className="p-6 border-b flex items-center gap-4">
                        <button onClick={() => setTestStep('cart')} className="p-2 hover:bg-slate-100 rounded-xl"><ArrowLeft size={20} /></button>
                        <h3 className="text-lg font-black text-slate-800">Checkout</h3>
                     </div>
                     <div className="flex-1 overflow-y-auto p-6 space-y-6">
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><User size={12} /> Seus Dados</label>
                           <input type="text" placeholder="Seu Nome" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" value={customerName} onChange={(e)=>setCustomerName(e.target.value)} />
                           <input type="tel" placeholder="WhatsApp (DDD)" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" value={customerPhone} onChange={(e)=>setCustomerPhone(e.target.value)} />
                        </div>
                        {orderType === 'delivery' ? (
                          <div className="space-y-4">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><MapPin size={12} /> Endereço de Entrega</label>
                             <textarea rows={3} placeholder="Rua, Número, Bairro e Referência" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold resize-none" value={customerAddress} onChange={(e)=>setCustomerAddress(e.target.value)} />
                          </div>
                        ) : orderType === 'table' ? (
                           <div className="space-y-4">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><QrCode size={12} /> Localização</label>
                              <input type="number" placeholder="Número da Mesa" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" value={tableNumber} onChange={(e)=>setTableNumber(e.target.value)} />
                           </div>
                        ) : (
                           <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl flex gap-3 text-indigo-700">
                              <Store size={20} className="shrink-0" />
                              <p className="text-[10px] font-bold leading-tight uppercase">Seu pedido será preparado e você poderá retirá-lo diretamente no balcão.</p>
                           </div>
                        )}
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> Forma de Pagamento</label>
                           <div className="grid grid-cols-1 gap-2">
                              {['PIX', 'Cartão (Entregador)', 'Dinheiro'].map(method => (
                                 <button key={method} onClick={()=>setPaymentMethod(method)} className={`p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${paymentMethod === method ? 'border-indigo-600 bg-indigo-50' : 'bg-slate-50 border-slate-100'}`}>
                                    <span className="font-bold text-sm">{method}</span>
                                    {paymentMethod === method && <CheckCircle2 size={18} className="text-indigo-600" />}
                                 </button>
                              ))}
                           </div>
                        </div>
                     </div>
                     <div className="p-6 border-t mt-auto">
                        <button onClick={handleFinishSimulation} disabled={!customerName || !customerPhone || (orderType === 'delivery' ? !customerAddress : orderType === 'table' ? !tableNumber : false) || !paymentMethod} className="w-full py-5 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl disabled:opacity-50" style={{ backgroundColor: settings.primaryColor }}>Enviar Pedido ao Restaurante</button>
                     </div>
                  </div>
                )}

                {testStep === 'success' && (
                  <div className="h-full flex flex-col items-center justify-center p-10 text-center space-y-8 animate-in zoom-in-95">
                     <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-xl shadow-emerald-50 shrink-0"><CheckCircle2 size={48} /></div>
                     <div className="space-y-2">
                        <h3 className="text-2xl font-black text-slate-800 tracking-tighter">Tudo pronto!</h3>
                        <p className="text-xs font-medium text-slate-500 leading-relaxed">Seu pedido foi enviado com sucesso. Você receberá atualizações de status via WhatsApp.</p>
                     </div>
                     <div className="w-full p-6 bg-slate-50 rounded-[2rem] border text-left space-y-4">
                        <div className="flex items-center gap-3"><div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><MessageCircle size={16} /></div><p className="text-[9px] font-black uppercase text-indigo-600">Acompanhamento Ativo</p></div>
                        <p className="text-[10px] font-medium text-slate-600">Fique atento às notificações de status: Produção, Entrega e Concluído.</p>
                     </div>
                     <button onClick={resetSimulation} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl">Entendido</button>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

