      tableNumber: isCounter ? undefined : tableId,
      type: isCounter ? 'takeout' : 'table',
      status: 'preparing',
      items: items,
      total: items.reduce((acc, i) => acc + (i.price * i.quantity), 0),
      createdAt: new Date()
