import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { analyzeCMV } from '../services/gemini';
import { 
  BrainCircuit, Sparkles, TrendingUp, DollarSign, 
  ArrowRight, AlertCircle, CheckCircle2, RefreshCw,
  Zap, Info, Calculator, Percent, Loader2, Search, Brain,
  Save, Check
} from 'lucide-react';

interface CMVAnalysisProps {
  products: Product[];
  onUpdateProduct: (product: Product) => void;
}

interface AnalysisResult {
  productName: string;
  currentCMV: number;
  suggestion: string;
  newPrice: number;
}

const CMVAnalysis: React.FC<CMVAnalysisProps> = ({ products, onUpdateProduct }) => {
  const [loading, setLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [appliedProducts, setAppliedProducts] = useState<string[]>([]);

  const runAnalysis = async () => {
    setLoading(true);
    setLoadingProgress(10);
    setAppliedProducts([]);

    // Simular progresso enquanto a IA pensa
    const interval = setInterval(() => {
       setLoadingProgress(prev => {
          if (prev >= 90) return prev;
          return prev + 5;
       });
    }, 300);

    try {
      const data = await analyzeCMV(products);
      setResults(data);
    } catch (err) {
      console.error(err);
    } finally {
      clearInterval(interval);
      setLoadingProgress(100);
      setTimeout(() => {
        setLoading(false);
      }, 500);
    }
  };

  const handleApplyAdjustment = (result: AnalysisResult) => {
    const product = products.find(p => p.name === result.productName);
    if (product) {
      const updatedProduct: Product = {
        ...product,
        price: result.newPrice,
        priceHistory: [
          ...(product.priceHistory || []),
          { date: new Date().toISOString().split('T')[0], price: result.newPrice, cost: product.cost }
        ]
      };
      onUpdateProduct(updatedProduct);
      setAppliedProducts(prev => [...prev, result.productName]);
    }
  };

  useEffect(() => {
    runAnalysis();
  }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* AI Header Banner */}
      <div className="bg-gradient-to-r from-indigo-900 via-indigo-800 to-violet-900 text-white p-10 rounded-[3rem] shadow-xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-10 opacity-10 animate-pulse">
