            return (
              <div key={idx} className={`bg-white rounded-[2.5rem] border-2 shadow-sm flex flex-col group hover:shadow-xl transition-all duration-300 ${isApplied ? 'border-emerald-200 bg-emerald-50/10' : isCritical ? 'border-rose-100' : 'border-slate-100 hover:border-indigo-200'}`}>
                <div className="p-8 space-y-6 flex-1">
                  <div className="flex justify-between items-start">
