                    <p>{res.suggestion}</p>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <p className="text-[9px] font-black text-slate-400 uppercase mb-1">CMV Atual</p>
                      <div className="flex items-center gap-1.5">
                        <Percent size={14} className={isCritical ? 'text-rose-500' : 'text-slate-400'} />
                        <span className={`text-lg font-black ${isCritical ? 'text-rose-600' : 'text-slate-700'}`}>
                          {res.currentCMV.toFixed(1)}%
                        </span>
                      </div>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Novo Preço</p>
                      <div className="flex items-center gap-1.5">
                        <DollarSign size={14} className="text-indigo-600" />
                        <span className="text-lg font-black text-indigo-600">
                          R$ {res.newPrice.toFixed(2)}
                        </span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="p-6 bg-slate-50/50 border-t rounded-b-[2.5rem] flex items-center justify-between group-hover:bg-indigo-50 transition-colors">
                  <div className="space-y-0.5">
                    <p className="text-[9px] font-black text-slate-400 uppercase">Novo Lucro Est.</p>
                    <p className="text-sm font-black text-slate-700">
                      R$ {(res.newPrice - (product?.cost || 0)).toFixed(2)} / un
                    </p>
                  </div>
                  {!isApplied ? (
                    <button 
                      onClick={() => handleApplyAdjustment(res)}
                      className="bg-indigo-600 text-white px-5 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 hover:shadow-lg transition-all flex items-center gap-2"
                    >
                      <Save size={14} /> Aplicar Ajuste
                    </button>
                  ) : (
                    <div className="text-[10px] font-black text-emerald-600 uppercase tracking-widest flex items-center gap-2">
                       Preço Atualizado
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* General Advice Card */}
      <div className="bg-indigo-50 border-2 border-indigo-100 p-8 rounded-[2.5rem] flex flex-col md:flex-row items-center gap-8 shadow-sm">
        <div className="bg-indigo-600 p-6 rounded-[2rem] text-white shadow-xl shadow-indigo-100 shrink-0">
          <Calculator size={40} />
        </div>
        <div className="space-y-2 text-center md:text-left">
          <h4 className="text-xl font-black text-indigo-900 tracking-tight">Estratégia de Precificação Inteligente</h4>
          <p className="text-indigo-700/80 font-medium">
            Lembre-se que o CMV ideal para o setor gira entre <span className="font-black">28% e 32%</span>. 
            Ajustes graduais de até <span className="font-black">5%</span> no cardápio costumam ser bem aceitos pelos clientes se acompanhados de melhorias na experiência.
          </p>
        </div>
      </div>
    </div>
  );
};

