                          <Line type="monotone" dataKey="price" name="Venda" stroke="#4f46e5" strokeWidth={3} dot={{r: 4, fill: '#4f46e5', strokeWidth: 2, stroke: '#fff'}} activeDot={{r: 6}} />
                          <Line type="monotone" dataKey="cost" name="Custo" stroke="#ef4444" strokeWidth={3} strokeDasharray="5 5" dot={{r: 4, fill: '#ef4444', strokeWidth: 2, stroke: '#fff'}} />
                        </LineChart>
                      </ResponsiveContainer>
                    </div>
                  </section>

                  <section className="flex-1 space-y-6 flex flex-col min-h-0">
                    <h3 className="text-sm font-black uppercase text-slate-400 border-b pb-2 tracking-widest flex items-center gap-2">
                      <ClipboardList size={16} /> Registros de Alteração
                    </h3>
                    <div className="flex-1 overflow-y-auto custom-scrollbar border rounded-3xl bg-slate-50/50">
                       <table className="w-full text-left border-collapse">
                          <thead className="bg-white border-b sticky top-0 z-10">
                             <tr>
                                <th className="px-6 py-3 font-black text-slate-400 text-[9px] uppercase tracking-widest">Data</th>
                                <th className="px-6 py-3 font-black text-slate-400 text-[9px] uppercase tracking-widest text-right">Custo</th>
                                <th className="px-6 py-3 font-black text-slate-400 text-[9px] uppercase tracking-widest text-right">Venda</th>
                                <th className="px-6 py-3 font-black text-slate-400 text-[9px] uppercase tracking-widest text-center">Margem</th>
                             </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                             {sortedHistory.map((entry, idx) => {
                                const nextEntry = sortedHistory[idx + 1];
                                const costTrend = nextEntry ? (entry.cost > nextEntry.cost ? 'up' : entry.cost < nextEntry.cost ? 'down' : 'stable') : 'stable';
                                const margin = ((entry.price - entry.cost) / entry.price) * 100;

                                return (
                                   <tr key={idx} className="hover:bg-white transition-colors group">
                                      <td className="px-6 py-4">
                                         <p className="text-xs font-bold text-slate-600">{new Date(entry.date).toLocaleDateString('pt-BR')}</p>
                                      </td>
                                      <td className="px-6 py-4 text-right">
                                         <div className="flex items-center justify-end gap-1.5">
                                            <span className="text-xs font-black text-slate-700">R$ {entry.cost.toFixed(2)}</span>
                                            {costTrend === 'up' ? <ArrowUpRight size={14} className="text-rose-500" /> : costTrend === 'down' ? <ArrowDownRight size={14} className="text-emerald-500" /> : <Minus size={14} className="text-slate-300" />}
                                         </div>
                                      </td>
                                      <td className="px-6 py-4 text-right">
                                         <span className="text-xs font-black text-indigo-600">R$ {entry.price.toFixed(2)}</span>
                                      </td>
                                      <td className="px-6 py-4 text-center">
                                         <div className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-black ${margin > 50 ? 'bg-emerald-100 text-emerald-700' : margin > 30 ? 'bg-indigo-100 text-indigo-700' : 'bg-rose-100 text-rose-700'}`}>
                                            {margin.toFixed(0)}%
                                         </div>
                                      </td>
                                   </tr>
                                );
                             })}
                             {sortedHistory.length === 0 && (
