    await db.orders.add(kitchenOrder);
    setOrders(prev => [kitchenOrder, ...prev]);
    addLog('u1', 'COZINHA', `Pedido enviado para cozinha: ${isCounter ? 'Balcão' : `Mesa ${tableId}`}`);
  };

  const handleUpdateOrderStatus = async (id: string, status: Order['status']) => {
    await db.orders.update(id, { status });
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    addLog('u1', 'PEDIDO', `Pedido ${id} alterado para ${status}`);
  };

  const handleAssignCourier = async (orderId: string, courierId: string) => {
    await db.orders.update(orderId, { courierId, status: 'delivering' });
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, courierId, status: 'delivering' } : o));
    addLog('u1', 'ENTREGA', `Entregador atribuído ao pedido ${orderId}`);
  };

  const handleUpdateTable = async (id: number, items: OrderItem[], status: Table['status'], isCounter?: boolean) => {
    if (isCounter) {
      setCounterOrders(prev => prev.map(t => t.id === id ? { ...t, items, status, total: items.reduce((a, b) => a + (b.price * b.quantity), 0) } : t));
    } else {
      await db.diningTables.update(id, { items, status, total: items.reduce((a, b) => a + (b.price * b.quantity), 0) });
      setTables(prev => prev.map(t => t.id === id ? { ...t, items, status, total: items.reduce((a, b) => a + (b.price * b.quantity), 0) } : t));
    }
  };

  const handleAddCounterOrder = () => {
    const newCounter: Table = {
      id: Date.now(),
      status: 'occupied',
      items: [],
      total: 0
    };
    setCounterOrders(prev => [...prev, newCounter]);
    addLog('u1', 'BALCÃO', 'Nova comanda de balcão aberta');
    return newCounter.id;
  };

  const handleCloseTable = async (tableId: number, method: PaymentMethod, fiscal: boolean, customerId?: string, isCounter?: boolean) => {
    const source = isCounter ? counterOrders : tables;
    const table = source.find(t => t.id === tableId);
    if (!table) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 6).toUpperCase(),
      tableNumber: isCounter ? undefined : tableId,
      items: table.items,
      total: table.total,
      type: isCounter ? 'takeout' : 'table',
      status: 'delivered',
      createdAt: new Date(),
      paymentMethod: method,
      isFiscalIssued: fiscal,
      customerId: customerId
    };

    await db.orders.add(newOrder);
    setOrders(prev => [newOrder, ...prev]);

    if (isCounter) {
      setCounterOrders(prev => prev.filter(t => t.id !== tableId));
    } else {
      await db.diningTables.update(tableId, { items: [], status: 'available', total: 0 });
      setTables(prev => prev.map(t => t.id === tableId ? { ...t, items: [], status: 'available', total: 0 } : t));
    }

    if (method === 'conta_cliente' && customerId) {
      const customer = customers.find(c => c.id === customerId);
      if (customer) {
        const transaction: CustomerTransaction = {
          id: `t${Date.now()}`,
          type: 'debit',
          amount: table.total,
          description: `Consumo ${isCounter ? 'Balcão' : `Mesa ${tableId}`} (Pedido #${newOrder.id})`,
          date: new Date()
        };
        await handleUpdateCustomer(customerId, {
          balance: customer.balance + table.total,
          history: [transaction, ...customer.history]
        });
      }
    } else {
      await handleAddFinancialRecord({
        type: 'income',
        amount: table.total,
        category: isCounter ? 'Vendas Balcão' : 'Vendas Mesa',
        description: `${isCounter ? 'Balcão' : `Mesa ${tableId}`} - Pagamento: ${method}`,
        date: new Date()
      });
    }

    addLog('u1', 'VENDA', `${isCounter ? 'Balcão' : `Mesa ${tableId}`} encerrada. Total: R$ ${table.total.toFixed(2)}`);
  };

  const addLog = async (userId: string, action: string, description: string) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      action,
      description,
      timestamp: new Date()
    };
    await db.auditLogs.add(newLog);
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const handleUpdateProduct = async (product: Product) => {
    await db.products.put(product);
    setProducts(prev => prev.map(p => p.id === product.id ? product : p));
    addLog('u1', 'ESTOQUE', `Produto atualizado: ${product.name}`);
  };

  const handleOpenCash = (value: number) => {
    setCashSession({ isOpen: true, openingValue: value, openedAt: new Date() });
    addLog('u1', 'CAIXA', `Caixa aberto com R$ ${value.toFixed(2)}`);
  };

  const handleCloseCash = () => {
    setCashSession({ isOpen: false, openingValue: 0, openedAt: null });
    addLog('u1', 'CAIXA', 'Caixa fechado');
  };

  if (!isDbLoaded) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center gap-6">
        <div className="w-20 h-20 bg-indigo-600 rounded-[2.5rem] flex items-center justify-center animate-bounce shadow-2xl shadow-indigo-500/50">
           <Database className="text-white" size={40} />
        </div>
        <div className="text-center">
           <h1 className="text-white text-2xl font-black tracking-tighter">GastroAI POS</h1>
           <p className="text-indigo-400 font-bold uppercase text-[10px] tracking-widest mt-1">Carregando Banco de Dados Local...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-slate-50 relative overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-sm font-bold text-indigo-600 uppercase tracking-widest mb-1">GastroAI - Management</h2>
            <h1 className="text-3xl font-black text-slate-800 capitalize">{activeTab.replace('-', ' ')}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 bg-emerald-50 px-4 py-2 rounded-xl border border-emerald-100">
                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-black text-emerald-600 uppercase">Banco Local Ativo</span>
             </div>
             <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg">GA</div>
          </div>
        </header>
        {activeTab === 'dashboard' && (
          <div className="space-y-8 animate-in fade-in duration-500">
            <AIInsights sales={orders} inventory={products} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <DashboardAlerts products={products} onNavigateToInventory={() => setActiveTab('inventory')} />
                <div className="bg-white p-6 rounded-3xl border shadow-sm h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={[{ name: 'Seg', sales: 4000 }, { name: 'Ter', sales: 3000 }, { name: 'Qua', sales: 5000 }, { name: 'Qui', sales: 4780 }, { name: 'Sex', sales: 8890 }, { name: 'Sáb', sales: 9390 }, { name: 'Dom', sales: 7490 }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <Tooltip />
                      <Area type="monotone" dataKey="sales" stroke="#4f46e5" fill="#4f46e51a" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white p-6 rounded-3xl border shadow-sm flex flex-col h-fit gap-6">
                <h3 className="text-xl font-bold">Resumo Diário</h3>
                <div className="p-6 bg-slate-50 rounded-2xl border">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Vendido</p>
                  <p className="text-2xl font-black text-slate-800">R$ {orders.reduce((acc, o) => acc + o.total, 0).toFixed(2)}</p>
                </div>
                <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Pedidos</p>
                  <p className="text-2xl font-black text-indigo-600">{orders.length}</p>
                </div>
                <div className="p-6 bg-rose-50 rounded-2xl border border-rose-100">
                  <p className="text-xs font-black text-rose-400 uppercase tracking-widest">Saldo em Fiado</p>
                  <p className="text-2xl font-black text-rose-600">R$ {customers.reduce((a,b)=>a+b.balance,0).toFixed(2)}</p>
                </div>
              </div>
            </div>
          </div>
        )}
        {activeTab === 'tables' && <Tables tables={tables} counterOrders={counterOrders} products={products} orders={orders} customers={customers} cashSession={cashSession} onUpdateTable={handleUpdateTable} onCloseTable={handleCloseTable} onSendToKitchen={handleSendToKitchen} onOpenCash={handleOpenCash} onCloseCash={handleCloseCash} onAddCounterOrder={handleAddCounterOrder} />}
        {activeTab === 'customers' && <CustomersPanel customers={customers} onAddCustomer={handleAddCustomer} onUpdateCustomer={handleUpdateCustomer} onAddFinancialRecord={handleAddFinancialRecord} />}
        {activeTab === 'delivery' && <Delivery orders={orders} couriers={couriers} deliveryFee={globalDeliveryFee} onUpdateStatus={handleUpdateOrderStatus} onAssignCourier={handleAssignCourier} onAddCourier={(c) => db.couriers.add(c as Courier).then(()=>db.couriers.toArray().then(setCouriers))} onUpdateCourier={handleUpdateCourier} onUpdateDeliveryFee={setGlobalDeliveryFee} onAddFinancialRecord={handleAddFinancialRecord} />}
        {activeTab === 'inventory' && <Inventory products={products} onUpdateProduct={handleUpdateProduct} />}
        {activeTab === 'finance' && <Finance orders={orders} customers={customers} couriers={couriers} manualRecords={financialRecords} onAddRecord={handleAddFinancialRecord} onUpdateRecord={handleUpdateFinancialRecord} onUpdateCustomer={handleUpdateCustomer} />}
