                           </div>
                           <div className="relative group">
                              <Phone className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                              <input type="tel" placeholder="WhatsApp (DDD)" className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-transparent rounded-[1.5rem] font-bold outline-none focus:border-indigo-500 focus:bg-white transition-all" value={customerPhone} onChange={(e)=>setCustomerPhone(e.target.value)} />
                           </div>
                        </div>

                        {orderType === 'delivery' ? (
                          <div className="space-y-4">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Local de Entrega</label>
                             <div className="relative group">
                                <MapPin className="absolute left-5 top-5 text-slate-300" size={18} />
                                <textarea rows={3} placeholder="Rua, Número, Bairro e Complemento" className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-transparent rounded-[1.5rem] font-bold outline-none focus:border-indigo-500 focus:bg-white transition-all resize-none" value={customerAddress} onChange={(e)=>setCustomerAddress(e.target.value)} />
                             </div>
                          </div>
                        ) : (
                           <div className="space-y-4">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Em qual mesa você está?</label>
                              <div className="relative group">
                                 <Store className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                                 <input type="number" placeholder="Número da Mesa" className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-transparent rounded-[1.5rem] font-bold outline-none focus:border-indigo-500 focus:bg-white transition-all" value={tableNumber} onChange={(e)=>setTableNumber(e.target.value)} />
                              </div>
                           </div>
                        )}

                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pagamento</label>
                           <div className="grid grid-cols-1 gap-3">
                              {['PIX', 'Cartão', 'Dinheiro'].map(method => (
                                 <button key={method} onClick={()=>setPaymentMethod(method)} className={`p-5 rounded-[1.5rem] border-2 flex items-center justify-between transition-all font-black text-xs uppercase tracking-widest ${paymentMethod === method ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'bg-slate-50 border-transparent text-slate-400'}`}>
                                    <div className="flex items-center gap-4"><div className={`p-2 rounded-xl bg-white shadow-sm ${paymentMethod === method ? 'text-indigo-600' : 'text-slate-300'}`}><Wallet size={16} /></div>{method}</div>
                                    {paymentMethod === method && <CheckCircle2 size={20} />}
                                 </button>
                              ))}
                           </div>
                        </div>
                     </div>
                     <div className="p-8 pb-12">
                        <button onClick={handleFinishSimulation} disabled={!customerName || !customerPhone || (orderType === 'delivery' ? !customerAddress : !tableNumber) || !paymentMethod} className="w-full py-6 rounded-[2rem] text-white font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all disabled:opacity-50 disabled:grayscale" style={{ backgroundColor: settings.primaryColor }}>Confirmar Pedido</button>
                     </div>
                  </div>
                )}

                {testStep === 'success' && (
                  <div className="h-full flex flex-col items-center justify-center p-12 text-center space-y-10 animate-in zoom-in-95">
                     <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-2xl shadow-emerald-50 shrink-0 border-8 border-white"><CheckCircle2 size={64} /></div>
                     <div className="space-y-3">
                        <h3 className="text-3xl font-black text-slate-800 tracking-tighter leading-none">Pedido Enviado!</h3>
                        <p className="text-sm font-medium text-slate-500 leading-relaxed px-2">Sucesso! Agora nossa equipe está preparando seu pedido.</p>
                     </div>
                     <div className="w-full p-6 bg-slate-50 rounded-[2.5rem] border-2 border-slate-100 text-left space-y-4">
                        <div className="flex items-center gap-3"><div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-100"><MessageCircle size={18} /></div><p className="text-[10px] font-black uppercase text-indigo-600 tracking-widest">Canal de Status</p></div>
                        <p className="text-[10px] font-bold text-slate-500 leading-relaxed uppercase">Você receberá atualizações automáticas via WhatsApp conforme o pedido avança para a cozinha e entrega.</p>
                     </div>
                     <button onClick={resetSimulation} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">Sair do Simulador</button>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DigitalMenuConfig;

import React, { useState, useMemo } from 'react';
import { DigitalMenuSettings, Product, Table, Order } from '../types';
import { 
  Smartphone, Palette, QrCode, 
  Save, Eye, Check, 
  Plus, Globe, 
  ShoppingCart, Copy, Share2, X, MousePointer2,
  Minus, MapPin, User, Wallet,
  CheckCircle2, ArrowLeft, MessageCircle,
  Bike, Home, UserCircle, Phone, Store,
  Image as ImageIcon, Sparkles, ArrowUp, ArrowDown, Zap, Tag, Star,
  Search, Filter
} from 'lucide-react';

interface DigitalMenuConfigProps {
  settings: DigitalMenuSettings;
  onUpdateSettings: (settings: DigitalMenuSettings) => void;
  products: Product[];
  tables: Table[];
  onUpdateProduct: (product: Product) => void;
  onPlaceDigitalOrder: (order: Order) => void;
}

interface SimCartItem {
  product: Product;
  quantity: number;
}

const DigitalMenuConfig: React.FC<DigitalMenuConfigProps> = ({ 
  settings, 
  onUpdateSettings, 
  products, 
  tables, 
  onUpdateProduct,
  onPlaceDigitalOrder 
}) => {
  const [activeTab, setActiveTab] = useState<'visual' | 'management' | 'qrcode'>('visual');
  const [showTestMode, setShowTestMode] = useState(false);
  const [isLinkCopied, setIsLinkCopied] = useState(false);

  // States para a Simulação Interativa
  const [orderType, setOrderType] = useState<'table' | 'delivery' | 'takeout'>('table');
  const [testStep, setTestStep] = useState<'welcome' | 'menu' | 'cart' | 'checkout' | 'success'>('welcome');
  const [simCart, setSimCart] = useState<SimCartItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [tableNumber, setTableNumber] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('');
  const [activeSimCategory, setActiveSimCategory] = useState<string | null>(null);

  const categories = useMemo(() => Array.from(new Set(products.map(p => p.category))), [products]);

  const sortedProducts = useMemo(() => {
    return [...products].sort((a, b) => (a.displayOrder || 0) - (b.displayOrder || 0));
  }, [products]);

  const menuUrl = `https://gastroai.me/cardapio/${settings.restaurantName.toLowerCase().replace(/\s+/g, '-')}`;

  const handleCopyLink = () => {
    navigator.clipboard.writeText(menuUrl);
    setIsLinkCopied(true);
    setTimeout(() => setIsLinkCopied(false), 2000);
  };

  const handleUpdateCatImage = (category: string, url: string) => {
    const currentMap = settings.categoryImages || {};
    onUpdateSettings({
      ...settings,
      categoryImages: { ...currentMap, [category]: url }
    });
  };

  const togglePromo = (product: Product) => {
    onUpdateProduct({ ...product, isPromotional: !product.isPromotional });
  };

  const moveOrder = (product: Product, direction: 'up' | 'down') => {
    const currentOrder = product.displayOrder || 0;
    const newOrder = direction === 'up' ? Math.max(0, currentOrder - 1) : currentOrder + 1;
    onUpdateProduct({ ...product, displayOrder: newOrder });
  };

  const addToSimCart = (product: Product) => {
    setSimCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { product, quantity: 1 }];
    });
  };

  const removeFromSimCart = (productId: string) => {
    setSimCart(prev => prev.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity - 1 } : item
    ).filter(item => item.quantity > 0));
  };

  const simCartTotal = useMemo(() => {
    return simCart.reduce((acc, item) => acc + (item.product.price * item.quantity), 0);
  }, [simCart]);

  const resetSimulation = () => {
    setShowTestMode(false);
    setTestStep('welcome');
    setSimCart([]);
    setCustomerName('');
    setCustomerPhone('');
    setCustomerAddress('');
    setTableNumber('');
    setPaymentMethod('');
    setActiveSimCategory(null);
  };

  const handleFinishSimulation = () => {
    const finalOrder: Order = {
      id: `DIG-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      createdAt: new Date(),
      items: simCart.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        price: item.product.price,
        quantity: item.quantity,
      })),
      total: simCartTotal + (orderType === 'delivery' ? 7 : 0),
      status: 'pending',
      type: orderType,
      tableNumber: orderType === 'table' ? parseInt(tableNumber) : undefined,
      customerName: customerName,
      customerPhone: customerPhone,
      customerAddress: orderType === 'delivery' ? customerAddress : undefined,
      paymentMethod: paymentMethod as any
    };

    onPlaceDigitalOrder(finalOrder);
    setTestStep('success');
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-10rem)] animate-in fade-in duration-500">
      {/* Coluna Esquerda: Configurações */}
      <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-8 rounded-[3rem] text-white shadow-xl shadow-indigo-100 flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10"><Share2 size={120} /></div>
          <div className="relative z-10 flex flex-col gap-2">
            <h3 className="text-xl font-black tracking-tight">Merchandising do Cardápio</h3>
            <p className="text-indigo-100 text-sm font-medium">Personalize visualmente seu ponto de venda online.</p>
            <div className="mt-4 flex items-center gap-2 bg-black/20 p-2 rounded-2xl backdrop-blur-md border border-white/10">
               <Globe size={14} className="text-indigo-300 ml-2" />
               <span className="text-xs font-mono font-bold truncate max-w-[200px]">{menuUrl}</span>
            </div>
          </div>
          <div className="relative z-10 flex gap-3">
             <button onClick={handleCopyLink} className={`flex items-center gap-2 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${isLinkCopied ? 'bg-emerald-500 text-white' : 'bg-white text-indigo-600 hover:bg-indigo-50 shadow-lg'}`}>
                {isLinkCopied ? <Check size={16} /> : <Copy size={16} />}
                {isLinkCopied ? 'Link Copiado' : 'Copiar Link'}
             </button>
             <button onClick={() => setShowTestMode(true)} className="flex items-center gap-2 px-6 py-4 bg-indigo-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-400 border border-indigo-400 shadow-lg transition-all">
                <MousePointer2 size={16} /> Ver Simulador
             </button>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-8">
           <div className="flex bg-slate-50 p-1.5 rounded-2xl w-fit border">
            <button onClick={() => setActiveTab('visual')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'visual' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}>
              <Palette size={16} /> Estilo Visual
            </button>
            <button onClick={() => setActiveTab('management')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'management' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}>
              <Zap size={16} /> Categorias & Itens
            </button>
          </div>

          {activeTab === 'visual' && (
            <div className="space-y-8 animate-in slide-in-from-left-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cor de Identidade</label>
                  <div className="flex items-center gap-4">
                    <input type="color" className="w-16 h-16 rounded-2xl cursor-pointer border-4 border-slate-100" value={settings.primaryColor} onChange={(e) => onUpdateSettings({ ...settings, primaryColor: e.target.value })} />
                    <span className="text-sm font-mono text-slate-500 font-bold">{settings.primaryColor}</span>
                  </div>
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Banner Principal</label>
                  <input type="text" placeholder="URL da imagem..." className="w-full px-5 py-4 bg-slate-50 border rounded-2xl outline-none font-medium text-xs" value={settings.bannerUrl} onChange={(e) => onUpdateSettings({ ...settings, bannerUrl: e.target.value })} />
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome de Exibição</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl outline-none font-bold" value={settings.restaurantName} onChange={(e) => onUpdateSettings({ ...settings, restaurantName: e.target.value })} />
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Mensagem de Boas-vindas</label>
                <textarea className="w-full px-5 py-4 bg-slate-50 border rounded-2xl outline-none font-medium resize-none" rows={2} value={settings.welcomeMessage} onChange={(e) => onUpdateSettings({ ...settings, welcomeMessage: e.target.value })} />
              </div>
            </div>
          )}

          {activeTab === 'management' && (
            <div className="space-y-12 animate-in slide-in-from-left-4">
              {/* Gestão de Imagens de Categoria */}
              <section className="space-y-6">
                 <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <ImageIcon size={16} className="text-indigo-600" /> Imagens das Categorias
                 </h4>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {categories.map(cat => (
                       <div key={cat} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                          <div className="w-16 h-16 rounded-xl bg-slate-200 overflow-hidden relative border shadow-inner">
                             {settings.categoryImages?.[cat] ? (
                                <img src={settings.categoryImages[cat]} className="w-full h-full object-cover" />
                             ) : (
                                <div className="w-full h-full flex items-center justify-center text-slate-400"><ImageIcon size={20} /></div>
                             )}
                          </div>
                          <div className="flex-1 space-y-1">
                             <p className="font-black text-slate-700 text-xs">{cat}</p>
                             <input 
                              type="text" 
                              placeholder="URL da imagem..."
                              className="w-full px-3 py-2 bg-white border rounded-lg text-[10px] outline-none focus:border-indigo-500"
                              value={settings.categoryImages?.[cat] || ''}
                              onChange={(e) => handleUpdateCatImage(cat, e.target.value)}
                             />
                          </div>
                       </div>
                    ))}
                 </div>
              </section>

              {/* Promoções e Ordenação */}
              <section className="space-y-6">
                 <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <Star size={16} className="text-amber-500" /> Destaques e Promoções
                 </h4>
                 <div className="space-y-3">
                    {sortedProducts.map(product => (
                       <div key={product.id} className="flex items-center justify-between p-5 bg-white border border-slate-100 rounded-[2rem] shadow-sm hover:shadow-md transition-shadow group">
                          <div className="flex items-center gap-4">
                             <div className="flex flex-col gap-1">
                                <button onClick={() => moveOrder(product, 'up')} className="p-1 text-slate-300 hover:text-indigo-600 transition-colors"><ArrowUp size={14} /></button>
                                <button onClick={() => moveOrder(product, 'down')} className="p-1 text-slate-300 hover:text-indigo-600 transition-colors"><ArrowDown size={14} /></button>
                             </div>
                             <div className="w-12 h-12 rounded-xl border bg-slate-50 overflow-hidden shadow-inner"><img src={product.image} className="w-full h-full object-cover" /></div>
                             <div>
                                <p className="font-black text-slate-800 text-xs">{product.name}</p>
                                <div className="flex items-center gap-2">
                                   <span className="text-[9px] font-bold text-slate-400 uppercase">{product.category}</span>
                                   <span className="text-[10px] font-black text-indigo-600">R$ {product.price.toFixed(2)}</span>
                                </div>
                             </div>
                          </div>
                          <div className="flex items-center gap-3">
                             <button 
                                onClick={() => togglePromo(product)}
                                className={`flex items-center gap-2 px-4 py-2 rounded-full font-black text-[9px] uppercase tracking-widest transition-all ${product.isPromotional ? 'bg-amber-100 text-amber-600 border border-amber-200' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:border-slate-200'}`}
                             >
                                <Zap size={14} fill={product.isPromotional ? 'currentColor' : 'none'} />
                                {product.isPromotional ? 'Em Destaque' : 'Destacar'}
                             </button>
                          </div>
                       </div>
                    ))}
                 </div>
              </section>
            </div>
          )}
        </div>
      </div>

      {/* Preview Mobile Simulator */}
      <div className="w-full lg:w-[420px] flex flex-col gap-4">
        <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2 ml-4">
          <Eye size={16} /> Canal do Cliente
        </h3>
        <div className="flex-1 bg-slate-900 rounded-[3.5rem] border-[12px] border-slate-800 shadow-2xl overflow-hidden relative group">
           {/* Visual estático se não estiver em modo teste */}
           {!showTestMode ? (
              <div className="h-full bg-white flex flex-col overflow-hidden">
                 <div className="h-32 bg-slate-100 flex items-center justify-center border-b"><ImageIcon className="text-slate-300" size={48} /></div>
                 <div className="p-8 space-y-6">
                    <div className="h-4 bg-slate-100 rounded-full w-3/4"></div>
                    <div className="h-4 bg-slate-100 rounded-full w-1/2"></div>
                    <div className="grid grid-cols-2 gap-4">
                       <div className="h-20 bg-slate-50 rounded-2xl"></div>
                       <div className="h-20 bg-slate-50 rounded-2xl"></div>
                    </div>
