                    <div className="w-20 h-20 bg-white text-indigo-600 rounded-full flex items-center justify-center shadow-2xl animate-pulse"><Smartphone size={40} /></div>
                    <div><p className="font-black text-slate-800">Simulador Mobile</p><p className="text-xs text-slate-500 mt-2">Clique para simular a compra.</p></div>
                    <button onClick={() => setShowTestMode(true)} className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl border">Iniciar Teste</button>
                 </div>
              </div>
           ) : null}
        </div>
      </div>

      {/* MODAL SIMULATOR OVERLAY */}
