                             <h4 className="text-2xl font-black text-slate-800 tracking-tighter">R$ {cashReport?.totalSales.toFixed(2)}</h4>
                          </div>
                          <div className="bg-emerald-50 p-6 rounded-[2.5rem] border border-emerald-100">
                             <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Total em Espécie (Gaveta)</p>
                             <h4 className="text-2xl font-black text-emerald-700 tracking-tighter">R$ {cashReport?.expectedFinalValue.toFixed(2)}</h4>
                          </div>
                       </div>

                       <div className="space-y-4">
                          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 ml-1">
                             <PieChart size={14} /> Detalhamento por Meio de Pagamento
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {[
                               { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500', bg: 'bg-emerald-50' },
                               { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500', bg: 'bg-indigo-50' },
                               { id: 'cartao_credito', label: 'C. Crédito', icon: CardIcon, color: 'text-blue-500', bg: 'bg-blue-50' },
                               { id: 'cartao_debito', label: 'C. Débito', icon: CardIcon, color: 'text-sky-500', bg: 'bg-sky-50' },
                               { id: 'vale_refeicao', label: 'Ticket / VR', icon: Landmark, color: 'text-amber-500', bg: 'bg-amber-50' },
                               { id: 'conta_cliente', label: 'Fiado', icon: UserCircle, color: 'text-rose-500', bg: 'bg-rose-50' },
                             ].map(method => (
                                <div key={method.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                   <div className="flex items-center gap-3">
                                      <div className={`p-2 rounded-xl ${method.bg} ${method.color}`}><method.icon size={18} /></div>
                                      <p className="font-bold text-slate-700 text-xs">{method.label}</p>
                                   </div>
                                   <p className="font-black text-slate-800 text-sm">R$ {cashReport?.totalsByMethod[method.id as keyof typeof cashReport.totalsByMethod].toFixed(2)}</p>
                                </div>
                             ))}
                          </div>
                       </div>

                       <div className="p-6 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
                          <div className="flex items-center gap-4">
                             <div className="p-4 bg-white rounded-2xl shadow-sm border"><DollarSign className="text-indigo-600" /></div>
                             <div>
                                <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial de Troco</p>
                                <p className="font-black text-slate-800">R$ {cashSession.openingValue.toFixed(2)}</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className="text-[10px] font-black text-slate-400 uppercase">Meios Eletrônicos</p>
                             <p className="font-black text-slate-800">R$ {cashReport?.electronicTotal.toFixed(2)}</p>
                          </div>
                       </div>

                       <div className="p-4 bg-amber-50 border border-amber-200 rounded-2xl flex gap-3 text-amber-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">Confira os valores na gaveta e no terminal de cartão antes de confirmar o encerramento. Divergências devem ser justificadas no log.</p>
                       </div>

                       <button onClick={() => { if(confirm("Deseja fechar o caixa agora? Um relatório de fechamento será gerado.")) { onCloseCash(); setShowCashModal(false); } }} className="w-full bg-rose-500 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-rose-100 hover:bg-rose-600 transition-all flex items-center justify-center gap-2"><Lock size={18} /> Encerrar Turno e Gerar Resumo</button>
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Modal: Comanda (Mesa ou Balcão) */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-7xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white"><div className="flex justify-between items-center mb-6"><div><h2 className="text-2xl font-black text-slate-800">{isCounterContext ? `Pedido Balcão #${selectedTable.id.toString().slice(-4)}` : 'Cardápio Mesas'}</h2><p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Lançamento de itens em tempo real</p></div><div className="relative w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Pesquisar..." className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" value={productSearch} onChange={(e) => setProductSearch(e.target.value)} /></div></div></div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 lg:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                  <button key={product.id} onClick={() => addToTable(product)} className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-2 group shadow-sm">
                    <div className="w-full aspect-square bg-slate-100 rounded-2xl mb-2 overflow-hidden"><img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" /></div>
                    <p className="font-black text-slate-800 text-sm truncate">{product.name}</p>
                    <div className="flex justify-between items-center mt-auto"><p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p><Plus size={16} className="text-slate-300 group-hover:text-indigo-600" /></div>
                  </button>
                ))}
              </div>
            </div>
            <div className="w-[450px] flex flex-col bg-white border-l shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white"><div className="flex items-center gap-3"><div className="p-3 bg-white/20 rounded-2xl shadow-inner">{isCounterContext ? <Store size={24} /> : <Users size={24} />}</div><div><h2 className="text-xl font-black">{isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2><p className="text-[10px] font-bold uppercase opacity-70 tracking-widest mt-1">Gestão de Itens</p></div></div><button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
              {!isCounterContext && (
                 <div className="p-6 bg-slate-50 border-b space-y-3"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><UserIcon size={12} /> Lançar para:</p><div className="flex gap-2 overflow-x-auto scrollbar-hide">{['Geral', 'Cadeira 1', 'Cadeira 2', 'Cadeira 3', '+ Nova'].map(seat => (<button key={seat} onClick={() => setActiveSeat(seat)} className={`px-4 py-2 rounded-xl text-xs font-bold border-2 whitespace-nowrap transition-all ${activeSeat === seat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}>{seat}</button>))}</div></div>
              )}
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {selectedTable.items.length === 0 ? (<div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40"><div className="p-8 border-4 border-dashed rounded-full border-slate-200"><Utensils size={64} strokeWidth={1} /></div><p className="font-black uppercase tracking-tighter">Aguardando Pedidos...</p></div>) : 
                (selectedTable.items.map((item, index) => (
                  <div key={index} className="bg-slate-50 rounded-[2rem] border border-slate-100 overflow-hidden hover:shadow-md transition-shadow group"><div className="p-5 flex justify-between items-start"><div className="flex-1"><div className="flex items-center gap-2 mb-1"><span className="text-[10px] bg-indigo-100 text-indigo-700 font-black px-2 py-0.5 rounded-full uppercase">{item.seat || 'Geral'}</span><p className="font-black text-slate-800">{item.name}</p></div><p className="text-xs text-slate-500 font-bold">{item.quantity}x R$ {item.price.toFixed(2)}</p></div><div className="text-right flex flex-col items-end gap-2"><p className="font-black text-indigo-600">R$ {(item.price * item.quantity).toFixed(2)}</p><div className="flex gap-1"><button onClick={() => startEditItem(index)} className="p-2 text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 rounded-xl"><Edit3 size={16} /></button><button onClick={() => removeItem(index)} className="p-2 text-slate-400 hover:bg-rose-50 hover:text-rose-600 rounded-xl"><Trash2 size={16} /></button></div></div></div></div>
                )))}
