                          <div className={`p-3 bg-white shadow-sm border rounded-2xl w-fit ${method.color} group-hover:scale-110 transition-transform`}><method.icon size={24} /></div>
                          <p className="font-black text-slate-800">{method.label}</p>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              </>
