              </div>
            )}

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in"><div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div><p className="text-xl font-black text-slate-800">Finalizando Operação...</p></div>
            )}
