                                               <div className="flex items-center gap-3">
                                                  <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-all ${selectedSplitItems.includes(idx) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-200'}`}>{selectedSplitItems.includes(idx) && <Check size={14} strokeWidth={4} />}</div>
                                                  <div className="text-left"><p className="text-xs font-black text-slate-700">{item.name}</p><p className="text-[10px] font-bold text-slate-400">{item.quantity}x R$ {item.price.toFixed(2)}</p></div>
                                               </div>
                                               <p className="font-black text-slate-800 text-sm">R$ {(item.price * item.quantity).toFixed(2)}</p>
                                            </button>
                                         ))}
                                      </div>
                                   </div>
                                )}

                                {!isSplitting && (
                                   <div className="text-center py-6">
                                      <p className="text-sm font-bold text-slate-500">Deseja realizar o pagamento total da conta agora?</p>
                                   </div>
                                )}
                             </div>

                             {/* Métodos de Pagamento */}
                             <div className="space-y-4 flex-1">
                                <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Selecione o Método para esta {isSplitting ? 'parte' : 'conta'}</p>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                  {[
                                    { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' },
                                    { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' },
                                    { id: 'cartao_credito', label: 'Cartão', icon: CreditCard, color: 'text-blue-600' },
                                    { id: 'conta_cliente', label: 'Fiado', icon: UserCircle, color: 'text-rose-500' },
                                  ].map(method => (
                                    <button key={method.id} disabled={isProcessing || (splitMode === 'items' && selectedSplitItems.length === 0)} onClick={() => handleProcessPayment(method.id as PaymentMethod)} className="p-6 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-md transition-all text-center flex flex-col items-center gap-3 group active:scale-95 disabled:opacity-30 disabled:grayscale">
                                      <div className={`p-4 bg-slate-50 shadow-sm border rounded-2xl w-fit ${method.color} group-hover:scale-110 transition-transform`}><method.icon size={28} /></div>
                                      <p className="font-black text-slate-800 text-xs uppercase tracking-tighter">{method.label}</p>
                                    </button>
                                  ))}
                                </div>
                             </div>
                          </div>
                       )}
                    </div>
                  ) : (
                    <div className="animate-in slide-in-from-right-10 duration-300">
                       <div className="p-8 border-b bg-rose-600 text-white flex justify-between items-center rounded-t-3xl"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><UserCircle size={24} /></div><div><h2 className="text-xl font-black">Selecionar Cliente</h2><p className="text-xs font-bold uppercase opacity-80">Lançamento em Conta Fiado</p></div></div><button onClick={() => setShowCustomerSelection(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                       <div className="p-8 space-y-6">
                          <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Nome do cliente..." className="w-full pl-12 pr-6 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={customerSearch} onChange={(e)=>setCustomerSearch(e.target.value)} /></div>
                          <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar">
                             {filteredCustomerList.map(c => (
                                <button key={c.id} onClick={() => setSelectedCustomerId(c.id)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedCustomerId === c.id ? 'border-rose-600 bg-rose-50' : 'border-slate-50 bg-white hover:border-slate-200'}`}>
                                   <div className="text-left"><p className="font-black text-slate-800">{c.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{c.document}</p></div>
                                   {selectedCustomerId === c.id && <CheckCircle2 size={24} className="text-rose-600" />}
                                </button>
                             ))}
                          </div>
                       </div>
                       <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowCustomerSelection(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Voltar</button><button onClick={finishFiadoPayment} disabled={!selectedCustomerId || isProcessing} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-50">Lançar Fiado (R$ {remainingBalance.toFixed(2)})</button></div>
                    </div>
                  )}
               </div>
            </div>

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in"><div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div><p className="text-xl font-black text-slate-800">Processando Pagamento...</p></div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Tables;

import React, { useState, useMemo } from 'react';
import { Table, Product, OrderItem, PaymentMethod, Order, Customer } from '../types';
import { getObservationSuggestions } from '../services/gemini';
import { 
  Users, CreditCard, Utensils, X, Plus, Trash2, 
  Receipt, Wallet, Smartphone, Banknote, ShieldCheck,
  CheckCircle2, Printer, Search, Edit3, User as UserIcon, MessageSquare, Save,
  Minus, Sparkles, Loader2, Send, ChefHat, Lock, Unlock, Coins, 
  History, DollarSign, ArrowRightLeft, PieChart, UserCircle, Store, ShoppingBag,
  CreditCard as CardIcon, Landmark, AlertTriangle, Calculator, ListChecks, ArrowRight,
  // Add Check icon to the imports
  Check
} from 'lucide-react';

interface TablesProps {
  tables: Table[];
  counterOrders: Table[];
  products: Product[];
  orders: Order[];
  customers: Customer[];
  cashSession: {
    isOpen: boolean;
    openingValue: number;
    openedAt: Date | null;
  };
  onUpdateTable: (tableId: number, items: OrderItem[], status: Table['status'], isCounter?: boolean) => void;
  onCloseTable: (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean, customerId?: string, isCounter?: boolean) => void;
  onSendToKitchen: (tableId: number, items: OrderItem[], isCounter?: boolean) => void;
  onOpenCash: (value: number) => void;
  onCloseCash: () => void;
  onAddCounterOrder: () => number;
}

interface SplitPart {
  id: string;
  amount: number;
  method: PaymentMethod;
  isPaid: boolean;
}

const Tables: React.FC<TablesProps> = ({ 
  tables, counterOrders, products, orders, customers, cashSession, 
  onUpdateTable, onCloseTable, onSendToKitchen, onOpenCash, onCloseCash, onAddCounterOrder
}) => {
  const [selectedTable, setSelectedTable] = useState<Table | null>(null);
  const [isCounterContext, setIsCounterContext] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showCashModal, setShowCashModal] = useState(false);
  const [showCustomerSelection, setShowCustomerSelection] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string>('');

  // Split logic states
  const [isSplitting, setIsSplitting] = useState(false);
  const [splitMode, setSplitMode] = useState<'value' | 'items' | null>(null);
  const [selectedSplitItems, setSelectedSplitItems] = useState<number[]>([]); // indexes of selected items
  const [customSplitValue, setCustomSplitValue] = useState('');
  const [splitParts, setSplitParts] = useState<SplitPart[]>([]);
  const [remainingBalance, setRemainingBalance] = useState(0);

  const [isFiscalEmission, setIsFiscalEmission] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSendingToKitchen, setIsSendingToKitchen] = useState(false);
  const [showKitchenSuccess, setShowKitchenSuccess] = useState(false);
  const [productSearch, setProductSearch] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');

  const [openingValueInput, setOpeningValueInput] = useState('0');

  const cashReport = useMemo(() => {
    if (!cashSession.openedAt) return null;
    const sessionOrders = orders.filter(o => o.createdAt >= cashSession.openedAt!);
    const totalsByMethod = { 
      dinheiro: 0, 
      cartao_credito: 0, 
      cartao_debito: 0, 
      pix: 0, 
      vale_refeicao: 0, 
      conta_cliente: 0 
    };

    sessionOrders.forEach(o => { 
      if (o.paymentMethod) totalsByMethod[o.paymentMethod] += o.total; 
    });

    const totalSales = Object.values(totalsByMethod).reduce((a, b) => a + b, 0);
    const electronicTotal = totalsByMethod.cartao_credito + totalsByMethod.cartao_debito + totalsByMethod.pix + totalsByMethod.vale_refeicao;

    return { 
      totalsByMethod, 
      totalSales, 
      electronicTotal,
      expectedFinalValue: totalsByMethod.dinheiro + cashSession.openingValue, 
      count: sessionOrders.length 
    };
  }, [orders, cashSession]);

  const [activeSeat, setActiveSeat] = useState<string>('Geral');
  const [editingItemIndex, setEditingItemIndex] = useState<number | null>(null);
  const [tempObs, setTempObs] = useState('');
  const [tempSeat, setTempSeat] = useState('');
  const [tempQty, setTempQty] = useState<number>(1);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const filteredCustomerList = useMemo(() => 
    customers.filter(c => c.name.toLowerCase().includes(customerSearch.toLowerCase())),
    [customers, customerSearch]
  );

  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-rose-50 text-rose-700 border-rose-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const openTable = (table: Table) => {
    if (!cashSession.isOpen) {
      alert("Por favor, abra o caixa antes de realizar atendimentos.");
      setShowCashModal(true);
      return;
    }
    setIsCounterContext(false);
    if (table.status === 'available') {
      onUpdateTable(table.id, [], 'occupied');
      setSelectedTable({ ...table, status: 'occupied', items: [], total: 0 });
    } else {
      setSelectedTable(table);
    }
    setActiveSeat('Geral');
  };

  const openCounterOrder = (order: Table) => {
    setIsCounterContext(true);
    setSelectedTable(order);
    setActiveSeat('Geral');
  };

  const handleNewCounter = () => {
    if (!cashSession.isOpen) {
      alert("Abra o caixa primeiro.");
      setShowCashModal(true);
      return;
    }
    const newId = onAddCounterOrder();
    setIsCounterContext(true);
    setSelectedTable({ id: newId, status: 'occupied', items: [], total: 0 });
  };

  const addToTable = (product: Product) => {
    if (!selectedTable) return;
    const existingIndex = selectedTable.items.findIndex(i => i.productId === product.id && i.seat === activeSeat && !i.observation);
    let newItems: OrderItem[];
    if (existingIndex > -1) {
      newItems = [...selectedTable.items];
      newItems[existingIndex] = { ...newItems[existingIndex], quantity: newItems[existingIndex].quantity + 1 };
    } else {
      newItems = [...selectedTable.items, { productId: product.id, name: product.name, price: product.price, quantity: 1, seat: activeSeat }];
    }
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
  };

  const removeItem = (index: number) => {
    if (!selectedTable) return;
    const newItems = selectedTable.items.filter((_, i) => i !== index);
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
  };

  const startEditItem = async (index: number) => {
    const item = selectedTable!.items[index];
    setEditingItemIndex(index);
    setTempObs(item.observation || '');
    setTempSeat(item.seat || 'Geral');
    setTempQty(item.quantity);
    setLoadingSuggestions(true);
    try {
      const res = await getObservationSuggestions(item.name);
      setSuggestions(res);
    } catch (err) {
      setSuggestions(["Sem cebola", "Bem passado", "Ponto da casa", "Sem gelo"]);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  const saveItemEdit = () => {
    if (!selectedTable || editingItemIndex === null) return;
    const newItems = [...selectedTable.items];
    newItems[editingItemIndex] = { ...newItems[editingItemIndex], observation: tempObs.trim(), seat: tempSeat.trim() || 'Geral', quantity: tempQty > 0 ? tempQty : 1 };
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
    setEditingItemIndex(null);
  };

  const handleSendToKitchenLocal = () => {
    if (!selectedTable || selectedTable.items.length === 0) return;
    setIsSendingToKitchen(true);
    setTimeout(() => {
      onSendToKitchen(selectedTable.id, [...selectedTable.items], isCounterContext);
      setIsSendingToKitchen(false);
      setShowKitchenSuccess(true);
      setTimeout(() => setShowKitchenSuccess(false), 3000);
    }, 1000);
  };

  // Logic for opening payment and handling splits
  const openPayment = () => {
    if (!selectedTable) return;
    setRemainingBalance(selectedTable.total);
    setSplitParts([]);
    setIsSplitting(false);
    setSplitMode(null);
    setShowPaymentModal(true);
  };

  const handleProcessPayment = (method: PaymentMethod) => {
    if (!selectedTable) return;

    if (method === 'conta_cliente') {
      setShowCustomerSelection(true);
      return;
    }

    if (isSplitting) {
      // Add current remaining or custom value to split parts
      const amountToPay = splitMode === 'value' ? (parseFloat(customSplitValue) || remainingBalance) : 
                          splitMode === 'items' ? selectedSplitItems.reduce((acc, idx) => acc + (selectedTable.items[idx].price * selectedTable.items[idx].quantity), 0) :
                          remainingBalance;

      const newPart: SplitPart = {
        id: Math.random().toString(36).substr(2, 9),
        amount: amountToPay,
        method: method,
        isPaid: true
      };

      const newRemaining = remainingBalance - amountToPay;
      setSplitParts([...splitParts, newPart]);
      setRemainingBalance(newRemaining);

      // Reset split step
      setSplitMode(null);
      setSelectedSplitItems([]);
      setCustomSplitValue('');

      if (newRemaining <= 0.01) {
        finishSplitPayment();
      }
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, method, isFiscalEmission, undefined, isCounterContext);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
    }, 1500);
  };

  const finishSplitPayment = () => {
    setIsProcessing(true);
    // In a real app, we'd store multiple transactions. 
    // Here we'll close with the primary method of the largest part for simplicity in the basic model.
    const mainMethod = splitParts.sort((a,b) => b.amount - a.amount)[0].method;

    setTimeout(() => {
      onCloseTable(selectedTable!.id, mainMethod, isFiscalEmission, undefined, isCounterContext);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
      setIsSplitting(false);
    }, 2000);
  };

  const finishFiadoPayment = () => {
    if (!selectedTable || !selectedCustomerId) return;
    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, 'conta_cliente', isFiscalEmission, selectedCustomerId, isCounterContext);
      setIsProcessing(false);
      setShowCustomerSelection(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
      setSelectedCustomerId('');
      setCustomerSearch('');
    }, 1500);
  };

  const toggleSplitItem = (idx: number) => {
    setSelectedSplitItems(prev => 
      prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
    );
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()));

  return (
    <div className="space-y-8">
      {/* Barra de Gestão Superior */}
      <div className="flex flex-col lg:flex-row justify-between items-center bg-white p-6 rounded-[2rem] border shadow-sm gap-6">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setShowCashModal(true)}
            className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-lg ${cashSession.isOpen ? 'bg-emerald-500 text-white shadow-emerald-100' : 'bg-rose-500 text-white shadow-rose-100'}`}
          >
            {cashSession.isOpen ? <Unlock size={20} /> : <Lock size={20} />}
            Caixa {cashSession.isOpen ? 'Aberto' : 'Fechado'}
          </button>

          {cashSession.isOpen && (
            <div className="hidden sm:flex gap-4">
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial</p>
                  <p className="font-black text-slate-700">R$ {cashSession.openingValue.toFixed(2)}</p>
               </div>
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Vendas Atual</p>
                  <p className="font-black text-indigo-600">R$ {cashReport?.totalSales.toFixed(2)}</p>
               </div>
            </div>
          )}
        </div>
        <div className="flex gap-3 w-full lg:w-auto">
           <div className="relative flex-1 lg:w-64">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="text" placeholder="Pesquisar mesa..." className="w-full pl-12 pr-6 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-sm" />
           </div>
           <button 
            onClick={handleNewCounter}
            className="flex items-center gap-2 bg-indigo-600 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all"
           >
              <Store size={18} /> Novo Balcão
           </button>
        </div>
      </div>

      <div className="space-y-8">
        <div>
           <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 ml-2 flex items-center gap-2">
              <Utensils size={16} /> Mapa de Mesas
           </h3>
           <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
              {tables.map(table => (
                <button key={table.id} onClick={() => openTable(table)} disabled={table.status === 'cleaning'} className={`aspect-square p-6 rounded-[2.5rem] border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${getTableStatusColor(table.status)} shadow-sm`}>
                  <div className="text-current">{table.status === 'available' ? <Utensils size={32} /> : table.status === 'occupied' ? <Users size={32} /> : table.status === 'billing' ? <CreditCard size={32} /> : <Utensils size={32} className="animate-spin" />}</div>
                  <div className="text-center"><h3 className="text-2xl font-black">Mesa {table.id}</h3><p className="text-[10px] uppercase font-black tracking-widest opacity-60">{table.status}</p></div>
                  {table.total > 0 && <div className="mt-1 text-sm font-black bg-white/60 px-4 py-1.5 rounded-2xl shadow-sm">R$ {table.total.toFixed(2)}</div>}
                </button>
              ))}
           </div>
        </div>

        {counterOrders.length > 0 && (
          <div>
            <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 ml-2 flex items-center gap-2">
                <Store size={16} /> Comandas de Balcão Ativas
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
               {counterOrders.map(order => (
                  <button 
                    key={order.id} 
                    onClick={() => openCounterOrder(order)}
                    className="flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 border-slate-100 hover:border-indigo-600 transition-all shadow-sm group"
                  >
                     <div className="flex items-center gap-4">
                        <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
                           <ShoppingBag size={24} />
                        </div>
                        <div className="text-left">
                           <p className="font-black text-slate-800">Balcão #{order.id.toString().slice(-4)}</p>
                           <p className="text-[10px] font-bold text-slate-400 uppercase">{order.items.length} itens lançados</p>
                        </div>
                     </div>
                     <p className="font-black text-indigo-600 text-lg">R$ {order.total.toFixed(2)}</p>
                  </button>
               ))}
            </div>
          </div>
        )}
      </div>

      {/* Modal: Caixa */}
      {showCashModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 flex flex-col max-h-[90vh]">
              <div className={`p-8 border-b flex justify-between items-center text-white shrink-0 ${cashSession.isOpen ? 'bg-indigo-600' : 'bg-rose-500'}`}>
                 <div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl shadow-inner">{cashSession.isOpen ? <Unlock size={24} /> : <Lock size={24} />}</div><div><h2 className="text-2xl font-black">{cashSession.isOpen ? 'Fechamento de Caixa' : 'Abertura de Caixa'}</h2><p className="text-xs font-bold opacity-80 uppercase tracking-widest">{cashSession.isOpen ? 'Conferência de Vendas e Valores' : 'Defina o fundo de troco'}</p></div></div>
                 <button onClick={() => setShowCashModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-8 overflow-y-auto custom-scrollbar flex-1">
                 {!cashSession.isOpen ? (
                    <div className="space-y-6 text-center py-10">
                       <p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor de Fundo Inicial / Troco</p>
                       <div className="relative max-w-[300px] mx-auto">
                          <span className="absolute left-6 top-1/2 -translate-y-1/2 text-3xl font-black text-slate-300">R$</span>
                          <input type="number" className="w-full pl-20 pr-8 py-6 bg-slate-50 border-2 border-slate-100 rounded-[2rem] text-5xl font-black text-slate-800 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-center" value={openingValueInput} onChange={(e) => setOpeningValueInput(e.target.value)} autoFocus />
                       </div>
                       <button onClick={() => { onOpenCash(parseFloat(openingValueInput) || 0); setShowCashModal(false); }} className="w-full max-w-[300px] bg-indigo-600 text-white py-6 rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-indigo-700 transition-all">Confirmar Abertura</button>
                    </div>
                 ) : (
                    <div className="space-y-8">
                       <div className="grid grid-cols-2 gap-4">
                          <div className="bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100">
                             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Vendido (Sessão)</p>
                             <h4 className="text-2xl font-black text-slate-800 tracking-tighter">R$ {cashReport?.totalSales.toFixed(2)}</h4>
                          </div>
                          <div className="bg-emerald-50 p-6 rounded-[2.5rem] border border-emerald-100">
                             <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Total em Espécie (Gaveta)</p>
                             <h4 className="text-2xl font-black text-emerald-700 tracking-tighter">R$ {cashReport?.expectedFinalValue.toFixed(2)}</h4>
                          </div>
                       </div>

                       <div className="space-y-4">
                          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 ml-1">
                             <PieChart size={14} /> Detalhamento por Meio de Pagamento
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {[
                               { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500', bg: 'bg-emerald-50' },
                               { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500', bg: 'bg-indigo-50' },
                               { id: 'cartao_credito', label: 'C. Crédito', icon: CardIcon, color: 'text-blue-500', bg: 'bg-blue-50' },
                               { id: 'cartao_debito', label: 'C. Débito', icon: CardIcon, color: 'text-sky-500', bg: 'bg-sky-50' },
                               { id: 'vale_refeicao', label: 'Ticket / VR', icon: Landmark, color: 'text-amber-500', bg: 'bg-amber-50' },
                               { id: 'conta_cliente', label: 'Fiado', icon: UserCircle, color: 'text-rose-500', bg: 'bg-rose-50' },
                             ].map(method => (
                                <div key={method.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                   <div className="flex items-center gap-3">
                                      <div className={`p-2 rounded-xl ${method.bg} ${method.color}`}><method.icon size={18} /></div>
                                      <p className="font-bold text-slate-700 text-xs">{method.label}</p>
                                   </div>
                                   <p className="font-black text-slate-800 text-sm">R$ {cashReport?.totalsByMethod[method.id as keyof typeof cashReport.totalsByMethod].toFixed(2)}</p>
                                </div>
                             ))}
                          </div>
                       </div>

                       <div className="p-6 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
                          <div className="flex items-center gap-4">
                             <div className="p-4 bg-white rounded-2xl shadow-sm border"><DollarSign className="text-indigo-600" /></div>
                             <div>
                                <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial de Troco</p>
                                <p className="font-black text-slate-800">R$ {cashSession.openingValue.toFixed(2)}</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className="text-[10px] font-black text-slate-400 uppercase">Meios Eletrônicos</p>
                             <p className="font-black text-slate-800">R$ {cashReport?.electronicTotal.toFixed(2)}</p>
                          </div>
                       </div>

                       <div className="p-4 bg-amber-50 border border-amber-200 rounded-2xl flex gap-3 text-amber-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">Confira os valores na gaveta e no terminal de cartão antes de confirmar o encerramento. Divergências devem ser justificadas no log.</p>
                       </div>

                       <button onClick={() => { if(confirm("Deseja fechar o caixa agora? Um relatório de fechamento será gerado.")) { onCloseCash(); setShowCashModal(false); } }} className="w-full bg-rose-500 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-rose-100 hover:bg-rose-600 transition-all flex items-center justify-center gap-2"><Lock size={18} /> Encerrar Turno e Gerar Resumo</button>
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Modal: Comanda (Mesa ou Balcão) */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-7xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white"><div className="flex justify-between items-center mb-6"><div><h2 className="text-2xl font-black text-slate-800">{isCounterContext ? `Pedido Balcão #${selectedTable.id.toString().slice(-4)}` : 'Cardápio Mesas'}</h2><p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Lançamento de itens em tempo real</p></div><div className="relative w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Pesquisar..." className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" value={productSearch} onChange={(e) => setProductSearch(e.target.value)} /></div></div></div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 lg:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                  <button key={product.id} onClick={() => addToTable(product)} className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-2 group shadow-sm">
                    <div className="w-full aspect-square bg-slate-100 rounded-2xl mb-2 overflow-hidden"><img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" /></div>
                    <p className="font-black text-slate-800 text-sm truncate">{product.name}</p>
                    <div className="flex justify-between items-center mt-auto"><p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p><Plus size={16} className="text-slate-300 group-hover:text-indigo-600" /></div>
                  </button>
                ))}
              </div>
            </div>
            <div className="w-[450px] flex flex-col bg-white border-l shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white"><div className="flex items-center gap-3"><div className="p-3 bg-white/20 rounded-2xl shadow-inner">{isCounterContext ? <Store size={24} /> : <Users size={24} />}</div><div><h2 className="text-xl font-black">{isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2><p className="text-[10px] font-bold uppercase opacity-70 tracking-widest mt-1">Gestão de Itens</p></div></div><button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
              {!isCounterContext && (
                 <div className="p-6 bg-slate-50 border-b space-y-3"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><UserIcon size={12} /> Lançar para:</p><div className="flex gap-2 overflow-x-auto scrollbar-hide">{['Geral', 'Cadeira 1', 'Cadeira 2', 'Cadeira 3', '+ Nova'].map(seat => (<button key={seat} onClick={() => setActiveSeat(seat)} className={`px-4 py-2 rounded-xl text-xs font-bold border-2 whitespace-nowrap transition-all ${activeSeat === seat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}>{seat}</button>))}</div></div>
              )}
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {selectedTable.items.length === 0 ? (<div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40"><div className="p-8 border-4 border-dashed rounded-full border-slate-200"><Utensils size={64} strokeWidth={1} /></div><p className="font-black uppercase tracking-tighter">Aguardando Pedidos...</p></div>) : 
                (selectedTable.items.map((item, index) => (
                  <div key={index} className="bg-slate-50 rounded-[2rem] border border-slate-100 overflow-hidden hover:shadow-md transition-shadow group"><div className="p-5 flex justify-between items-start"><div className="flex-1"><div className="flex items-center gap-2 mb-1"><span className="text-[10px] bg-indigo-100 text-indigo-700 font-black px-2 py-0.5 rounded-full uppercase">{item.seat || 'Geral'}</span><p className="font-black text-slate-800">{item.name}</p></div><p className="text-xs text-slate-500 font-bold">{item.quantity}x R$ {item.price.toFixed(2)}</p></div><div className="text-right flex flex-col items-end gap-2"><p className="font-black text-indigo-600">R$ {(item.price * item.quantity).toFixed(2)}</p><div className="flex gap-1"><button onClick={() => startEditItem(index)} className="p-2 text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 rounded-xl"><Edit3 size={16} /></button><button onClick={() => removeItem(index)} className="p-2 text-slate-400 hover:bg-rose-50 hover:text-rose-600 rounded-xl"><Trash2 size={16} /></button></div></div></div></div>
                )))}
              </div>
              <div className="p-8 border-t bg-slate-50/50 space-y-6"><div className="flex justify-between items-center text-3xl font-black text-slate-800 tracking-tighter"><span>Total</span><span className="text-indigo-600">R$ {selectedTable.total.toFixed(2)}</span></div><div className="grid grid-cols-2 gap-4"><button disabled={selectedTable.items.length === 0 || isSendingToKitchen} onClick={handleSendToKitchenLocal} className={`flex flex-col items-center justify-center gap-2 p-5 rounded-[1.5rem] transition-all font-black shadow-lg uppercase text-[10px] tracking-widest relative overflow-hidden ${showKitchenSuccess ? 'bg-emerald-500 text-white' : 'bg-violet-600 text-white hover:bg-violet-700'} disabled:opacity-50`}>{isSendingToKitchen ? <Loader2 size={20} className="animate-spin" /> : showKitchenSuccess ? <CheckCircle2 size={20} /> : <ChefHat size={20} />}<span>{showKitchenSuccess ? 'Enviado!' : 'Enviar Cozinha'}</span></button><button className="flex flex-col items-center justify-center gap-2 p-5 bg-white border-2 border-slate-200 rounded-[1.5rem] text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all font-bold group shadow-sm uppercase text-[10px] tracking-widest"><Printer size={20} /><span>Pré-Conta</span></button></div><button disabled={selectedTable.items.length === 0} onClick={openPayment} className="w-full flex items-center justify-center gap-3 p-5 bg-emerald-600 text-white rounded-[1.5rem] hover:bg-emerald-700 transition-all font-black shadow-xl uppercase text-xs tracking-widest"><Receipt size={20} /><span>Fechar Comanda</span></button></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Pagamento & Divisão de Conta */}
      {showPaymentModal && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col h-[90vh]">
            <div className="p-8 border-b flex justify-between items-center bg-emerald-600 text-white shrink-0">
               <div className="flex items-center gap-4">
                  <div className="bg-white/20 p-3 rounded-2xl"><Wallet size={24} /></div>
                  <div>
                    <h2 className="text-2xl font-black">Finalizar {isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2>
                    <p className="text-xs font-bold opacity-80 uppercase tracking-widest">Total: R$ {selectedTable.total.toFixed(2)}</p>
                  </div>
               </div>
               <button onClick={() => setShowPaymentModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
               {/* Esquerda: Status da Divisão / Saldo */}
               <div className="w-full lg:w-[400px] border-r bg-slate-50/50 p-8 flex flex-col space-y-8 overflow-y-auto custom-scrollbar">
                  <div className="space-y-2 text-center bg-white p-8 rounded-[2rem] shadow-sm border">
                     <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Saldo Remanescente</p>
                     <h1 className={`text-5xl font-black tracking-tighter ${remainingBalance > 0 ? 'text-slate-800' : 'text-emerald-600'}`}>R$ {remainingBalance.toFixed(2)}</h1>
                     {remainingBalance <= 0 && <div className="mt-2 flex items-center justify-center gap-1 text-emerald-600 font-black text-[10px] uppercase"><CheckCircle2 size={12} /> Conta Liquidada</div>}
                  </div>

                  <div className="space-y-4">
                     <div className="flex justify-between items-center">
                        <p className="text-xs font-black uppercase text-slate-400 tracking-widest ml-2">Pagamentos Efetuados</p>
                        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{splitParts.length} partes</span>
                     </div>
                     <div className="space-y-2">
                        {splitParts.map(part => (
                           <div key={part.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex justify-between items-center shadow-sm animate-in slide-in-from-left-2">
                              <div className="flex items-center gap-3">
                                 {/* Check icon is now properly imported */}
                                 <div className="p-2 bg-emerald-50 text-emerald-600 rounded-lg"><Check size={14} strokeWidth={4} /></div>
                                 <p className="text-xs font-black text-slate-700 uppercase">{part.method.replace('_', ' ')}</p>
                              </div>
                              <p className="font-black text-slate-800 text-sm">R$ {part.amount.toFixed(2)}</p>
                           </div>
                        ))}
                        {splitParts.length === 0 && (
                           <div className="py-10 text-center opacity-30 grayscale flex flex-col items-center gap-2">
                              <History size={32} />
                              <p className="text-[10px] font-black uppercase tracking-widest">Nenhum pagamento</p>
                           </div>
                        )}
                     </div>
                  </div>

                  {!isSplitting && remainingBalance > 0 && (
                     <button 
                        onClick={() => setIsSplitting(true)}
                        className="w-full flex items-center justify-center gap-2 py-4 bg-indigo-50 text-indigo-600 border-2 border-indigo-100 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-100 transition-all"
                     >
                        <Calculator size={16} /> Dividir Conta
                     </button>
                  )}
               </div>

               {/* Direita: Seleção de Valor / Método */}
               <div className="flex-1 p-8 overflow-y-auto custom-scrollbar">
                  {!showCustomerSelection ? (
                    <div className="space-y-8 h-full">
                       {isSplitting && !splitMode && (
                          <div className="space-y-6 animate-in fade-in duration-300">
                             <h3 className="text-lg font-black text-slate-800">Como deseja dividir?</h3>
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <button onClick={() => setSplitMode('value')} className="p-8 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col gap-4 group">
                                   <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl w-fit group-hover:bg-indigo-600 group-hover:text-white transition-all"><DollarSign size={24} /></div>
                                   <div><p className="font-black text-slate-800">Valor Específico</p><p className="text-[10px] font-bold text-slate-400 uppercase">Defina o quanto pagar agora</p></div>
                                </button>
                                <button onClick={() => setSplitMode('items')} className="p-8 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col gap-4 group">
                                   <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl w-fit group-hover:bg-emerald-600 group-hover:text-white transition-all"><ListChecks size={24} /></div>
                                   <div><p className="font-black text-slate-800">Por Itens</p><p className="text-[10px] font-bold text-slate-400 uppercase">Selecione o que pagar</p></div>
                                </button>
                             </div>
                             <button onClick={() => setIsSplitting(false)} className="text-xs font-black text-slate-400 uppercase tracking-widest hover:text-rose-500 transition-colors">Voltar ao pagamento total</button>
                          </div>
                       )}

                       {( (!isSplitting) || (isSplitting && splitMode) ) && (
                          <div className="space-y-8 animate-in slide-in-from-right-4 duration-300 h-full flex flex-col">
                             {/* Header da Seleção */}
                             <div className="flex justify-between items-end">
                                <div>
                                   <h3 className="text-xl font-black text-slate-800">{isSplitting ? (splitMode === 'value' ? 'Lançar Valor Manual' : 'Pagar Itens Selecionados') : 'Pagamento Único'}</h3>
                                   <p className="text-[10px] font-black uppercase text-indigo-600 tracking-widest">Etapa final do despacho</p>
                                </div>
                                {splitMode && <button onClick={() => setSplitMode(null)} className="text-xs font-bold text-slate-400 hover:text-indigo-600">Alterar Modo</button>}
                             </div>

                             {/* Área de Seleção (Valor ou Itens) */}
                             <div className="bg-slate-50/50 p-6 rounded-[2.5rem] border border-slate-100">
                                {splitMode === 'value' && (
                                   <div className="space-y-4">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Informe o Valor</label>
                                      <div className="relative">
                                         <span className="absolute left-6 top-1/2 -translate-y-1/2 text-3xl font-black text-slate-300">R$</span>
                                         <input 
                                          type="number" 
                                          className="w-full pl-20 pr-8 py-6 bg-white border-2 border-indigo-100 rounded-[2rem] text-4xl font-black text-indigo-600 focus:border-indigo-500 outline-none transition-all" 
                                          value={customSplitValue}
                                          onChange={(e) => setCustomSplitValue(e.target.value)}
                                          placeholder={remainingBalance.toFixed(2)}
                                          autoFocus
                                         />
                                      </div>
                                   </div>
                                )}

                                {splitMode === 'items' && (
                                   <div className="space-y-4">
                                      <div className="flex justify-between items-center px-1">
                                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Marque os Itens</label>
                                         <p className="text-xs font-black text-indigo-600">Subtotal: R$ {selectedSplitItems.reduce((acc, idx) => acc + (selectedTable.items[idx].price * selectedTable.items[idx].quantity), 0).toFixed(2)}</p>
                                      </div>
                                      <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar pr-2">
                                         {selectedTable.items.map((item, idx) => (
                                            <button key={idx} onClick={() => toggleSplitItem(idx)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedSplitItems.includes(idx) ? 'border-indigo-600 bg-indigo-50' : 'bg-white border-slate-50'}`}>
                                               <div className="flex items-center gap-3">
                                                  {/* Check icon is now properly imported */}
                                                  <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-all ${selectedSplitItems.includes(idx) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-200'}`}>{selectedSplitItems.includes(idx) && <Check size={14} strokeWidth={4} />}</div>
                                                  <div className="text-left"><p className="text-xs font-black text-slate-700">{item.name}</p><p className="text-[10px] font-bold text-slate-400">{item.quantity}x R$ {item.price.toFixed(2)}</p></div>
                                               </div>
                                               <p className="font-black text-slate-800 text-sm">R$ {(item.price * item.quantity).toFixed(2)}</p>
                                            </button>
                                         ))}
                                      </div>
                                   </div>
                                )}

                                {!isSplitting && (
                                   <div className="text-center py-6">
                                      <p className="text-sm font-bold text-slate-500">Deseja realizar o pagamento total da conta agora?</p>
                                   </div>
                                )}
                             </div>

                             {/* Métodos de Pagamento */}
                             <div className="space-y-4 flex-1">
                                <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Selecione o Método para esta {isSplitting ? 'parte' : 'conta'}</p>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                  {[
                                    { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' },
                                    { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' },
                                    { id: 'cartao_credito', label: 'Cartão', icon: CreditCard, color: 'text-blue-600' },
                                    { id: 'conta_cliente', label: 'Fiado', icon: UserCircle, color: 'text-rose-500' },
                                  ].map(method => (
                                    <button key={method.id} disabled={isProcessing || (splitMode === 'items' && selectedSplitItems.length === 0)} onClick={() => handleProcessPayment(method.id as PaymentMethod)} className="p-6 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-md transition-all text-center flex flex-col items-center gap-3 group active:scale-95 disabled:opacity-30 disabled:grayscale">
                                      <div className={`p-4 bg-slate-50 shadow-sm border rounded-2xl w-fit ${method.color} group-hover:scale-110 transition-transform`}><method.icon size={28} /></div>
                                      <p className="font-black text-slate-800 text-xs uppercase tracking-tighter">{method.label}</p>
                                    </button>
                                  ))}
                                </div>
                             </div>
                          </div>
                       )}
                    </div>
                  ) : (
                    <div className="animate-in slide-in-from-right-10 duration-300">
                       <div className="p-8 border-b bg-rose-600 text-white flex justify-between items-center rounded-t-3xl"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><UserCircle size={24} /></div><div><h2 className="text-xl font-black">Selecionar Cliente</h2><p className="text-xs font-bold uppercase opacity-80">Lançamento em Conta Fiado</p></div></div><button onClick={() => setShowCustomerSelection(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                       <div className="p-8 space-y-6">
                          <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Nome do cliente..." className="w-full pl-12 pr-6 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={customerSearch} onChange={(e)=>setCustomerSearch(e.target.value)} /></div>
                          <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar">
                             {filteredCustomerList.map(c => (
                                <button key={c.id} onClick={() => setSelectedCustomerId(c.id)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedCustomerId === c.id ? 'border-rose-600 bg-rose-50' : 'border-slate-50 bg-white hover:border-slate-200'}`}>
                                   <div className="text-left"><p className="font-black text-slate-800">{c.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{c.document}</p></div>
                                   {selectedCustomerId === c.id && <CheckCircle2 size={24} className="text-rose-600" />}
                                </button>
                             ))}
                          </div>
                       </div>
                       <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowCustomerSelection(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Voltar</button><button onClick={finishFiadoPayment} disabled={!selectedCustomerId || isProcessing} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-50">Lançar Fiado (R$ {remainingBalance.toFixed(2)})</button></div>
                    </div>
                  )}
               </div>
            </div>

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in"><div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div><p className="text-xl font-black text-slate-800">Processando Pagamento...</p></div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Tables;

import React, { useState, useMemo } from 'react';
import { Table, Product, OrderItem, PaymentMethod, Order, Customer } from '../types';
import { getObservationSuggestions } from '../services/gemini';
import { 
  Users, CreditCard, Utensils, X, Plus, Trash2, 
  Receipt, Wallet, Smartphone, Banknote, ShieldCheck,
  CheckCircle2, Printer, Search, Edit3, User as UserIcon, MessageSquare, Save,
  Minus, Sparkles, Loader2, Send, ChefHat, Lock, Unlock, Coins, 
  History, DollarSign, ArrowRightLeft, PieChart, UserCircle, Store, ShoppingBag,
  CreditCard as CardIcon, Landmark, AlertTriangle, Calculator, ListChecks, ArrowRight,
  Check
} from 'lucide-react';

interface TablesProps {
  tables: Table[];
  counterOrders: Table[];
  products: Product[];
  orders: Order[];
  customers: Customer[];
  cashSession: {
    isOpen: boolean;
    openingValue: number;
    openedAt: Date | null;
  };
  onUpdateTable: (tableId: number, items: OrderItem[], status: Table['status'], isCounter?: boolean) => void;
  onCloseTable: (tableId: number, paymentMethod: PaymentMethod, isFiscal: boolean, customerId?: string, isCounter?: boolean) => void;
  onSendToKitchen: (tableId: number, items: OrderItem[], isCounter?: boolean) => void;
  onOpenCash: (value: number) => void;
  onCloseCash: () => void;
  onAddCounterOrder: () => number;
}

interface SplitPart {
  id: string;
  amount: number;
  method: PaymentMethod;
  isPaid: boolean;
}

const Tables: React.FC<TablesProps> = ({ 
  tables, counterOrders, products, orders, customers, cashSession, 
  onUpdateTable, onCloseTable, onSendToKitchen, onOpenCash, onCloseCash, onAddCounterOrder
}) => {
  const [selectedTable, setSelectedTable] = useState<Table | null>(null);
  const [isCounterContext, setIsCounterContext] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showCashModal, setShowCashModal] = useState(false);
  const [showCustomerSelection, setShowCustomerSelection] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string>('');

  // Split logic states
  const [isSplitting, setIsSplitting] = useState(false);
  const [splitMode, setSplitMode] = useState<'value' | 'items' | null>(null);
  const [selectedSplitItems, setSelectedSplitItems] = useState<number[]>([]); 
  const [customSplitValue, setCustomSplitValue] = useState('');
  const [splitParts, setSplitParts] = useState<SplitPart[]>([]);
  const [remainingBalance, setRemainingBalance] = useState(0);

  const [isFiscalEmission, setIsFiscalEmission] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSendingToKitchen, setIsSendingToKitchen] = useState(false);
  const [showKitchenSuccess, setShowKitchenSuccess] = useState(false);
  const [productSearch, setProductSearch] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');

  const [openingValueInput, setOpeningValueInput] = useState('0');

  // Item Edit States
  const [activeSeat, setActiveSeat] = useState<string>('Geral');
  const [editingItemIndex, setEditingItemIndex] = useState<number | null>(null);
  const [tempObs, setTempObs] = useState('');
  const [tempSeat, setTempSeat] = useState('');
  const [tempQty, setTempQty] = useState<number>(1);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const cashReport = useMemo(() => {
    if (!cashSession.openedAt) return null;
    const sessionOrders = orders.filter(o => o.createdAt >= cashSession.openedAt!);
    const totalsByMethod = { 
      dinheiro: 0, 
      cartao_credito: 0, 
      cartao_debito: 0, 
      pix: 0, 
      vale_refeicao: 0, 
      conta_cliente: 0 
    };

    sessionOrders.forEach(o => { 
      if (o.paymentMethod) totalsByMethod[o.paymentMethod] += o.total; 
    });

    const totalSales = Object.values(totalsByMethod).reduce((a, b) => a + b, 0);
    const electronicTotal = totalsByMethod.cartao_credito + totalsByMethod.cartao_debito + totalsByMethod.pix + totalsByMethod.vale_refeicao;

    return { 
      totalsByMethod, 
      totalSales, 
      electronicTotal,
      expectedFinalValue: totalsByMethod.dinheiro + cashSession.openingValue, 
      count: sessionOrders.length 
    };
  }, [orders, cashSession]);

  const filteredCustomerList = useMemo(() => 
    customers.filter(c => c.name.toLowerCase().includes(customerSearch.toLowerCase())),
    [customers, customerSearch]
  );

  const getTableStatusColor = (status: Table['status']) => {
    switch (status) {
      case 'available': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'occupied': return 'bg-rose-50 text-rose-700 border-rose-200';
      case 'billing': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'cleaning': return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const openTable = (table: Table) => {
    if (!cashSession.isOpen) {
      alert("Por favor, abra o caixa antes de realizar atendimentos.");
      setShowCashModal(true);
      return;
    }
    setIsCounterContext(false);
    if (table.status === 'available') {
      onUpdateTable(table.id, [], 'occupied');
      setSelectedTable({ ...table, status: 'occupied', items: [], total: 0 });
    } else {
      setSelectedTable(table);
    }
    setActiveSeat('Geral');
  };

  const openCounterOrder = (order: Table) => {
    setIsCounterContext(true);
    setSelectedTable(order);
    setActiveSeat('Geral');
  };

  const handleNewCounter = () => {
    if (!cashSession.isOpen) {
      alert("Abra o caixa primeiro.");
      setShowCashModal(true);
      return;
    }
    const newId = onAddCounterOrder();
    setIsCounterContext(true);
    setSelectedTable({ id: newId, status: 'occupied', items: [], total: 0 });
  };

  const addToTable = (product: Product) => {
    if (!selectedTable) return;
    const existingIndex = selectedTable.items.findIndex(i => i.productId === product.id && i.seat === activeSeat && !i.observation);
    let newItems: OrderItem[];
    if (existingIndex > -1) {
      newItems = [...selectedTable.items];
      newItems[existingIndex] = { ...newItems[existingIndex], quantity: newItems[existingIndex].quantity + 1 };
    } else {
      newItems = [...selectedTable.items, { productId: product.id, name: product.name, price: product.price, quantity: 1, seat: activeSeat }];
    }
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
  };

  const removeItem = (index: number) => {
    if (!selectedTable) return;
    const newItems = selectedTable.items.filter((_, i) => i !== index);
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
  };

  const startEditItem = async (index: number) => {
    const item = selectedTable!.items[index];
    setEditingItemIndex(index);
    setTempObs(item.observation || '');
    setTempSeat(item.seat || 'Geral');
    setTempQty(item.quantity);
    setLoadingSuggestions(true);
    try {
      const res = await getObservationSuggestions(item.name);
      setSuggestions(res);
    } catch (err) {
      setSuggestions(["Sem cebola", "Bem passado", "Ponto da casa", "Sem gelo"]);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  const saveItemEdit = () => {
    if (!selectedTable || editingItemIndex === null) return;
    const newItems = [...selectedTable.items];
    newItems[editingItemIndex] = { 
      ...newItems[editingItemIndex], 
      observation: tempObs.trim(), 
      seat: tempSeat.trim() || 'Geral', 
      quantity: tempQty > 0 ? tempQty : 1 
    };
    const newTotal = newItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const updated = { ...selectedTable, items: newItems, total: newTotal };
    setSelectedTable(updated);
    onUpdateTable(selectedTable.id, newItems, 'occupied', isCounterContext);
    setEditingItemIndex(null);
  };

  const handleSendToKitchenLocal = () => {
    if (!selectedTable || selectedTable.items.length === 0) return;
    setIsSendingToKitchen(true);
    setTimeout(() => {
      onSendToKitchen(selectedTable.id, [...selectedTable.items], isCounterContext);
      setIsSendingToKitchen(false);
      setShowKitchenSuccess(true);
      setTimeout(() => setShowKitchenSuccess(false), 3000);
    }, 1000);
  };

  const openPayment = () => {
    if (!selectedTable) return;
    setRemainingBalance(selectedTable.total);
    setSplitParts([]);
    setIsSplitting(false);
    setSplitMode(null);
    setShowPaymentModal(true);
  };

  const handleProcessPayment = (method: PaymentMethod) => {
    if (!selectedTable) return;
    if (method === 'conta_cliente') {
      setShowCustomerSelection(true);
      return;
    }
    if (isSplitting) {
      const amountToPay = splitMode === 'value' ? (parseFloat(customSplitValue) || remainingBalance) : 
                          splitMode === 'items' ? selectedSplitItems.reduce((acc, idx) => acc + (selectedTable.items[idx].price * selectedTable.items[idx].quantity), 0) :
                          remainingBalance;

      const newPart: SplitPart = {
        id: Math.random().toString(36).substr(2, 9),
        amount: amountToPay,
        method: method,
        isPaid: true
      };
      const newRemaining = remainingBalance - amountToPay;
      setSplitParts([...splitParts, newPart]);
      setRemainingBalance(newRemaining);
      setSplitMode(null);
      setSelectedSplitItems([]);
      setCustomSplitValue('');
      if (newRemaining <= 0.01) {
        finishSplitPayment();
      }
      return;
    }
    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, method, isFiscalEmission, undefined, isCounterContext);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
    }, 1500);
  };

  const finishSplitPayment = () => {
    setIsProcessing(true);
    const mainMethod = splitParts.sort((a,b) => b.amount - a.amount)[0].method;
    setTimeout(() => {
      onCloseTable(selectedTable!.id, mainMethod, isFiscalEmission, undefined, isCounterContext);
      setIsProcessing(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
      setIsSplitting(false);
    }, 2000);
  };

  const finishFiadoPayment = () => {
    if (!selectedTable || !selectedCustomerId) return;
    setIsProcessing(true);
    setTimeout(() => {
      onCloseTable(selectedTable.id, 'conta_cliente', isFiscalEmission, selectedCustomerId, isCounterContext);
      setIsProcessing(false);
      setShowCustomerSelection(false);
      setShowPaymentModal(false);
      setSelectedTable(null);
      setSelectedCustomerId('');
      setCustomerSearch('');
    }, 1500);
  };

  const toggleSplitItem = (idx: number) => {
    setSelectedSplitItems(prev => 
      prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
    );
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()));

  return (
    <div className="space-y-8">
      {/* Barra de Gestão Superior */}
      <div className="flex flex-col lg:flex-row justify-between items-center bg-white p-6 rounded-[2rem] border shadow-sm gap-6">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setShowCashModal(true)}
            className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-lg ${cashSession.isOpen ? 'bg-emerald-500 text-white shadow-emerald-100' : 'bg-rose-500 text-white shadow-rose-100'}`}
          >
            {cashSession.isOpen ? <Unlock size={20} /> : <Lock size={20} />}
            Caixa {cashSession.isOpen ? 'Aberto' : 'Fechado'}
          </button>

          {cashSession.isOpen && (
            <div className="hidden sm:flex gap-4">
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial</p>
                  <p className="font-black text-slate-700">R$ {cashSession.openingValue.toFixed(2)}</p>
               </div>
               <div className="text-left border-l pl-6">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Vendas Atual</p>
                  <p className="font-black text-indigo-600">R$ {cashReport?.totalSales.toFixed(2)}</p>
               </div>
            </div>
          )}
        </div>
        <div className="flex gap-3 w-full lg:w-auto">
           <div className="relative flex-1 lg:w-64">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="text" placeholder="Pesquisar mesa..." className="w-full pl-12 pr-6 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-sm" />
           </div>
           <button 
            onClick={handleNewCounter}
            className="flex items-center gap-2 bg-indigo-600 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all"
           >
              <Store size={18} /> Novo Balcão
           </button>
        </div>
      </div>

      <div className="space-y-8">
        <div>
           <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 ml-2 flex items-center gap-2">
              <Utensils size={16} /> Mapa de Mesas
           </h3>
           <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-6">
              {tables.map(table => (
                <button key={table.id} onClick={() => openTable(table)} disabled={table.status === 'cleaning'} className={`aspect-square p-6 rounded-[2.5rem] border-2 transition-all flex flex-col items-center justify-center gap-4 hover:shadow-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${getTableStatusColor(table.status)} shadow-sm`}>
                  <div className="text-current">{table.status === 'available' ? <Utensils size={32} /> : table.status === 'occupied' ? <Users size={32} /> : table.status === 'billing' ? <CreditCard size={32} /> : <Utensils size={32} className="animate-spin" />}</div>
                  <div className="text-center"><h3 className="text-2xl font-black">Mesa {table.id}</h3><p className="text-[10px] uppercase font-black tracking-widest opacity-60">{table.status}</p></div>
                  {table.total > 0 && <div className="mt-1 text-sm font-black bg-white/60 px-4 py-1.5 rounded-2xl shadow-sm">R$ {table.total.toFixed(2)}</div>}
                </button>
              ))}
           </div>
        </div>

        {counterOrders.length > 0 && (
          <div>
            <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 ml-2 flex items-center gap-2">
                <Store size={16} /> Comandas de Balcão Ativas
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
               {counterOrders.map(order => (
                  <button 
                    key={order.id} 
                    onClick={() => openCounterOrder(order)}
                    className="flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 border-slate-100 hover:border-indigo-600 transition-all shadow-sm group"
                  >
                     <div className="flex items-center gap-4">
                        <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
                           <ShoppingBag size={24} />
                        </div>
                        <div className="text-left">
                           <p className="font-black text-slate-800">Balcão #{order.id.toString().slice(-4)}</p>
                           <p className="text-[10px] font-bold text-slate-400 uppercase">{order.items.length} itens lançados</p>
                        </div>
                     </div>
                     <p className="font-black text-indigo-600 text-lg">R$ {order.total.toFixed(2)}</p>
                  </button>
               ))}
            </div>
          </div>
        )}
      </div>

      {/* Modal: Caixa */}
      {showCashModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 flex flex-col max-h-[90vh]">
              <div className={`p-8 border-b flex justify-between items-center text-white shrink-0 ${cashSession.isOpen ? 'bg-indigo-600' : 'bg-rose-500'}`}>
                 <div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl shadow-inner">{cashSession.isOpen ? <Unlock size={24} /> : <Lock size={24} />}</div><div><h2 className="text-2xl font-black">{cashSession.isOpen ? 'Fechamento de Caixa' : 'Abertura de Caixa'}</h2><p className="text-xs font-bold opacity-80 uppercase tracking-widest">{cashSession.isOpen ? 'Conferência de Vendas e Valores' : 'Defina o fundo de troco'}</p></div></div>
                 <button onClick={() => setShowCashModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-8 overflow-y-auto custom-scrollbar flex-1">
                 {!cashSession.isOpen ? (
                    <div className="space-y-6 text-center py-10">
                       <p className="text-slate-500 font-black uppercase text-xs tracking-widest">Valor de Fundo Inicial / Troco</p>
                       <div className="relative max-w-[300px] mx-auto">
                          <span className="absolute left-6 top-1/2 -translate-y-1/2 text-3xl font-black text-slate-300">R$</span>
                          <input type="number" className="w-full pl-20 pr-8 py-6 bg-slate-50 border-2 border-slate-100 rounded-[2rem] text-5xl font-black text-slate-800 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-center" value={openingValueInput} onChange={(e) => setOpeningValueInput(e.target.value)} autoFocus />
                       </div>
                       <button onClick={() => { onOpenCash(parseFloat(openingValueInput) || 0); setShowCashModal(false); }} className="w-full max-w-[300px] bg-indigo-600 text-white py-6 rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-indigo-700 transition-all">Confirmar Abertura</button>
                    </div>
                 ) : (
                    <div className="space-y-8">
                       <div className="grid grid-cols-2 gap-4">
                          <div className="bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100">
                             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Vendido (Sessão)</p>
                             <h4 className="text-2xl font-black text-slate-800 tracking-tighter">R$ {cashReport?.totalSales.toFixed(2)}</h4>
                          </div>
                          <div className="bg-emerald-50 p-6 rounded-[2.5rem] border border-emerald-100">
                             <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Total em Espécie (Gaveta)</p>
                             <h4 className="text-2xl font-black text-emerald-700 tracking-tighter">R$ {cashReport?.expectedFinalValue.toFixed(2)}</h4>
                          </div>
                       </div>

                       <div className="space-y-4">
                          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 ml-1">
                             <PieChart size={14} /> Detalhamento por Meio de Pagamento
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {[
                               { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500', bg: 'bg-emerald-50' },
                               { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500', bg: 'bg-indigo-50' },
                               { id: 'cartao_credito', label: 'C. Crédito', icon: CardIcon, color: 'text-blue-500', bg: 'bg-blue-50' },
                               { id: 'cartao_debito', label: 'C. Débito', icon: CardIcon, color: 'text-sky-500', bg: 'bg-sky-50' },
                               { id: 'vale_refeicao', label: 'Ticket / VR', icon: Landmark, color: 'text-amber-500', bg: 'bg-amber-50' },
                               { id: 'conta_cliente', label: 'Fiado', icon: UserCircle, color: 'text-rose-500', bg: 'bg-rose-50' },
                             ].map(method => (
                                <div key={method.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-100 shadow-sm">
                                   <div className="flex items-center gap-3">
                                      <div className={`p-2 rounded-xl ${method.bg} ${method.color}`}><method.icon size={18} /></div>
                                      <p className="font-bold text-slate-700 text-xs">{method.label}</p>
                                   </div>
                                   <p className="font-black text-slate-800 text-sm">R$ {cashReport?.totalsByMethod[method.id as keyof typeof cashReport.totalsByMethod].toFixed(2)}</p>
                                </div>
                             ))}
                          </div>
                       </div>

                       <div className="p-6 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
                          <div className="flex items-center gap-4">
                             <div className="p-4 bg-white rounded-2xl shadow-sm border"><DollarSign className="text-indigo-600" /></div>
                             <div>
                                <p className="text-[10px] font-black text-slate-400 uppercase">Fundo Inicial de Troco</p>
                                <p className="font-black text-slate-800">R$ {cashSession.openingValue.toFixed(2)}</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className="text-[10px] font-black text-slate-400 uppercase">Meios Eletrônicos</p>
                             <p className="font-black text-slate-800">R$ {cashReport?.electronicTotal.toFixed(2)}</p>
                          </div>
                       </div>

                       <div className="p-4 bg-amber-50 border border-amber-200 rounded-2xl flex gap-3 text-amber-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">Confira os valores na gaveta e no terminal de cartão antes de confirmar o encerramento. Divergências devem ser justificadas no log.</p>
                       </div>

                       <button onClick={() => { if(confirm("Deseja fechar o caixa agora? Um relatório de fechamento será gerado.")) { onCloseCash(); setShowCashModal(false); } }} className="w-full bg-rose-500 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-rose-100 hover:bg-rose-600 transition-all flex items-center justify-center gap-2"><Lock size={18} /> Encerrar Turno e Gerar Resumo</button>
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Modal: Comanda (Mesa ou Balcão) */}
      {selectedTable && !showPaymentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-7xl rounded-[3rem] shadow-2xl overflow-hidden flex h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="flex-1 border-r flex flex-col bg-slate-50/50">
              <div className="p-8 border-b bg-white"><div className="flex justify-between items-center mb-6"><div><h2 className="text-2xl font-black text-slate-800">{isCounterContext ? `Pedido Balcão #${selectedTable.id.toString().slice(-4)}` : 'Cardápio Mesas'}</h2><p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Lançamento de itens em tempo real</p></div><div className="relative w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Pesquisar..." className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" value={productSearch} onChange={(e) => setProductSearch(e.target.value)} /></div></div></div>
              <div className="flex-1 overflow-y-auto p-8 grid grid-cols-2 lg:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                  <button key={product.id} onClick={() => addToTable(product)} className="bg-white p-4 rounded-3xl border-2 border-transparent hover:border-indigo-500 hover:shadow-xl transition-all text-left flex flex-col gap-2 group shadow-sm">
                    <div className="w-full aspect-square bg-slate-100 rounded-2xl mb-2 overflow-hidden"><img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform" /></div>
                    <p className="font-black text-slate-800 text-sm truncate">{product.name}</p>
                    <div className="flex justify-between items-center mt-auto"><p className="text-indigo-600 font-black text-sm">R$ {product.price.toFixed(2)}</p><Plus size={16} className="text-slate-300 group-hover:text-indigo-600" /></div>
                  </button>
                ))}
              </div>
            </div>
            <div className="w-[450px] flex flex-col bg-white border-l shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-600 text-white"><div className="flex items-center gap-3"><div className="p-3 bg-white/20 rounded-2xl shadow-inner">{isCounterContext ? <Store size={24} /> : <Users size={24} />}</div><div><h2 className="text-xl font-black">{isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2><p className="text-[10px] font-bold uppercase opacity-70 tracking-widest mt-1">Gestão de Itens</p></div></div><button onClick={() => setSelectedTable(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
              {!isCounterContext && (
                 <div className="p-6 bg-slate-50 border-b space-y-3"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><UserIcon size={12} /> Lançar para:</p><div className="flex gap-2 overflow-x-auto scrollbar-hide">{['Geral', 'Cadeira 1', 'Cadeira 2', 'Cadeira 3', '+ Nova'].map(seat => (<button key={seat} onClick={() => setActiveSeat(seat)} className={`px-4 py-2 rounded-xl text-xs font-bold border-2 whitespace-nowrap transition-all ${activeSeat === seat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}>{seat}</button>))}</div></div>
              )}
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {selectedTable.items.length === 0 ? (<div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4 opacity-40"><div className="p-8 border-4 border-dashed rounded-full border-slate-200"><Utensils size={64} strokeWidth={1} /></div><p className="font-black uppercase tracking-tighter">Aguardando Pedidos...</p></div>) : 
                (selectedTable.items.map((item, index) => (
                  <div key={index} className="bg-slate-50 rounded-[2rem] border border-slate-100 overflow-hidden hover:shadow-md transition-shadow group">
                    <div className="p-5 flex justify-between items-start">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="text-[10px] bg-indigo-100 text-indigo-700 font-black px-2 py-0.5 rounded-full uppercase">{item.seat || 'Geral'}</span>
                          <p className="font-black text-slate-800">{item.name}</p>
                        </div>
                        <p className="text-xs text-slate-500 font-bold">{item.quantity}x R$ {item.price.toFixed(2)}</p>
                        {item.observation && (
                          <div className="mt-1 flex items-center gap-1.5 text-rose-500">
                             <MessageSquare size={10} fill="currentColor" className="opacity-20" />
                             <span className="text-[10px] font-black italic uppercase tracking-tighter">{item.observation}</span>
                          </div>
                        )}
                      </div>
                      <div className="text-right flex flex-col items-end gap-2">
                        <p className="font-black text-indigo-600">R$ {(item.price * item.quantity).toFixed(2)}</p>
                        <div className="flex gap-1">
                          <button onClick={() => startEditItem(index)} className="p-2 text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 rounded-xl transition-colors"><Edit3 size={16} /></button>
                          <button onClick={() => removeItem(index)} className="p-2 text-slate-400 hover:bg-rose-50 hover:text-rose-600 rounded-xl transition-colors"><Trash2 size={16} /></button>
                        </div>
                      </div>
                    </div>
                  </div>
                )))}
              </div>
              <div className="p-8 border-t bg-slate-50/50 space-y-6"><div className="flex justify-between items-center text-3xl font-black text-slate-800 tracking-tighter"><span>Total</span><span className="text-indigo-600">R$ {selectedTable.total.toFixed(2)}</span></div><div className="grid grid-cols-2 gap-4"><button disabled={selectedTable.items.length === 0 || isSendingToKitchen} onClick={handleSendToKitchenLocal} className={`flex flex-col items-center justify-center gap-2 p-5 rounded-[1.5rem] transition-all font-black shadow-lg uppercase text-[10px] tracking-widest relative overflow-hidden ${showKitchenSuccess ? 'bg-emerald-500 text-white' : 'bg-violet-600 text-white hover:bg-violet-700'} disabled:opacity-50`}>{isSendingToKitchen ? <Loader2 size={20} className="animate-spin" /> : showKitchenSuccess ? <CheckCircle2 size={20} /> : <ChefHat size={20} />}<span>{showKitchenSuccess ? 'Enviado!' : 'Enviar Cozinha'}</span></button><button className="flex flex-col items-center justify-center gap-2 p-5 bg-white border-2 border-slate-200 rounded-[1.5rem] text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all font-bold group shadow-sm uppercase text-[10px] tracking-widest"><Printer size={20} /><span>Pré-Conta</span></button></div><button disabled={selectedTable.items.length === 0} onClick={openPayment} className="w-full flex items-center justify-center gap-3 p-5 bg-emerald-600 text-white rounded-[1.5rem] hover:bg-emerald-700 transition-all font-black shadow-xl uppercase text-xs tracking-widest"><Receipt size={20} /><span>Fechar Comanda</span></button></div>
            </div>
          </div>
        </div>
      )}

      {/* NOVO Modal: Edição de Detalhes do Item (Observação) */}
      {editingItemIndex !== null && selectedTable && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b flex justify-between items-center bg-indigo-50/50">
                 <div className="flex items-center gap-4">
                    <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg"><Edit3 size={24} /></div>
                    <div>
                       <h2 className="text-xl font-black">Detalhes do Item</h2>
                       <p className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">{selectedTable.items[editingItemIndex].name}</p>
                    </div>
                 </div>
                 <button onClick={() => setEditingItemIndex(null)} className="p-2 text-slate-400 hover:bg-white rounded-full transition-colors"><X size={24} /></button>
              </div>

              <div className="p-8 space-y-8">
                 {/* Observações com IA */}
                 <div className="space-y-4">
                    <div className="flex justify-between items-center">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-1.5"><MessageSquare size={12} /> Observações de Preparo</label>
                       {loadingSuggestions && <Loader2 size={12} className="animate-spin text-indigo-500" />}
                    </div>
                    <textarea 
                       className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-indigo-500 focus:bg-white transition-all resize-none text-sm"
                       rows={3}
                       placeholder="Ex: Sem cebola, bem passado..."
                       value={tempObs}
                       onChange={(e) => setTempObs(e.target.value)}
                       autoFocus
                    />

                    {suggestions.length > 0 && (
                       <div className="space-y-2">
                          <p className="text-[9px] font-black text-indigo-400 uppercase tracking-tighter flex items-center gap-1"><Sparkles size={10} /> Sugestões GastroAI</p>
                          <div className="flex flex-wrap gap-2">
                             {suggestions.map((sug, i) => (
                                <button 
                                   key={i} 
                                   onClick={() => setTempObs(sug)}
                                   className="px-3 py-1.5 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded-lg border border-indigo-100 hover:bg-indigo-600 hover:text-white transition-all"
                                >
                                   {sug}
                                </button>
                             ))}
                          </div>
                       </div>
                    )}
                 </div>

                 {/* Ajustes de Assento e Quantidade */}
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Para quem?</label>
                       <input 
                          type="text" 
                          className="w-full px-5 py-3 bg-slate-50 border rounded-xl font-bold outline-none focus:border-indigo-500"
                          value={tempSeat}
                          onChange={(e) => setTempSeat(e.target.value)}
                       />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Quantidade</label>
                       <div className="flex items-center gap-3 bg-slate-50 p-1 rounded-xl border">
                          <button onClick={() => setTempQty(Math.max(1, tempQty - 1))} className="w-8 h-8 bg-white text-slate-400 rounded-lg flex items-center justify-center shadow-sm"><Minus size={14} /></button>
                          <span className="flex-1 text-center font-black text-slate-800">{tempQty}</span>
                          <button onClick={() => setTempQty(tempQty + 1)} className="w-8 h-8 bg-white text-slate-400 rounded-lg flex items-center justify-center shadow-sm"><Plus size={14} /></button>
                       </div>
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setEditingItemIndex(null)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Descartar</button>
                 <button onClick={saveItemEdit} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-indigo-100 flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all"><Save size={18} /> Salvar Alterações</button>
              </div>
           </div>
        </div>
      )}

      {/* Modal de Pagamento & Divisão de Conta */}
      {showPaymentModal && selectedTable && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col h-[90vh]">
            <div className="p-8 border-b flex justify-between items-center bg-emerald-600 text-white shrink-0">
               <div className="flex items-center gap-4">
                  <div className="bg-white/20 p-3 rounded-2xl"><Wallet size={24} /></div>
                  <div>
                    <h2 className="text-2xl font-black">Finalizar {isCounterContext ? 'Balcão' : `Mesa ${selectedTable.id}`}</h2>
                    <p className="text-xs font-bold opacity-80 uppercase tracking-widest">Total: R$ {selectedTable.total.toFixed(2)}</p>
                  </div>
               </div>
               <button onClick={() => setShowPaymentModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
               {/* Esquerda: Status da Divisão / Saldo */}
               <div className="w-full lg:w-[400px] border-r bg-slate-50/50 p-8 flex flex-col space-y-8 overflow-y-auto custom-scrollbar">
                  <div className="space-y-2 text-center bg-white p-8 rounded-[2rem] shadow-sm border">
                     <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Saldo Remanescente</p>
                     <h1 className={`text-5xl font-black tracking-tighter ${remainingBalance > 0 ? 'text-slate-800' : 'text-emerald-600'}`}>R$ {remainingBalance.toFixed(2)}</h1>
                     {remainingBalance <= 0 && <div className="mt-2 flex items-center justify-center gap-1 text-emerald-600 font-black text-[10px] uppercase"><CheckCircle2 size={12} /> Conta Liquidada</div>}
                  </div>

                  <div className="space-y-4">
                     <div className="flex justify-between items-center">
                        <p className="text-xs font-black uppercase text-slate-400 tracking-widest ml-2">Pagamentos Efetuados</p>
                        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{splitParts.length} partes</span>
                     </div>
                     <div className="space-y-2">
                        {splitParts.map(part => (
                           <div key={part.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex justify-between items-center shadow-sm animate-in slide-in-from-left-2">
                              <div className="flex items-center gap-3">
                                 <div className="p-2 bg-emerald-50 text-emerald-600 rounded-lg"><Check size={14} strokeWidth={4} /></div>
                                 <p className="text-xs font-black text-slate-700 uppercase">{part.method.replace('_', ' ')}</p>
                              </div>
                              <p className="font-black text-slate-800 text-sm">R$ {part.amount.toFixed(2)}</p>
                           </div>
                        ))}
                        {splitParts.length === 0 && (
                           <div className="py-10 text-center opacity-30 grayscale flex flex-col items-center gap-2">
                              <History size={32} />
                              <p className="text-[10px] font-black uppercase tracking-widest">Nenhum pagamento</p>
                           </div>
                        )}
                     </div>
                  </div>

                  {!isSplitting && remainingBalance > 0 && (
                     <button 
                        onClick={() => setIsSplitting(true)}
                        className="w-full flex items-center justify-center gap-2 py-4 bg-indigo-50 text-indigo-600 border-2 border-indigo-100 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-100 transition-all"
                     >
                        <Calculator size={16} /> Dividir Conta
                     </button>
                  )}
               </div>

               {/* Direita: Seleção de Valor / Método */}
               <div className="flex-1 p-8 overflow-y-auto custom-scrollbar">
                  {!showCustomerSelection ? (
                    <div className="space-y-8 h-full">
                       {isSplitting && !splitMode && (
                          <div className="space-y-6 animate-in fade-in duration-300">
                             <h3 className="text-lg font-black text-slate-800">Como deseja dividir?</h3>
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <button onClick={() => setSplitMode('value')} className="p-8 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col gap-4 group">
                                   <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl w-fit group-hover:bg-indigo-600 group-hover:text-white transition-all"><DollarSign size={24} /></div>
                                   <div><p className="font-black text-slate-800">Valor Específico</p><p className="text-[10px] font-bold text-slate-400 uppercase">Defina o quanto pagar agora</p></div>
                                </button>
                                <button onClick={() => setSplitMode('items')} className="p-8 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-lg transition-all text-left flex flex-col gap-4 group">
                                   <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl w-fit group-hover:bg-emerald-600 group-hover:text-white transition-all"><ListChecks size={24} /></div>
                                   <div><p className="font-black text-slate-800">Por Itens</p><p className="text-[10px] font-bold text-slate-400 uppercase">Selecione o que pagar</p></div>
                                </button>
                             </div>
                             <button onClick={() => setIsSplitting(false)} className="text-xs font-black text-slate-400 uppercase tracking-widest hover:text-rose-500 transition-colors">Voltar ao pagamento total</button>
                          </div>
                       )}

                       {( (!isSplitting) || (isSplitting && splitMode) ) && (
                          <div className="space-y-8 animate-in slide-in-from-right-4 duration-300 h-full flex flex-col">
                             <div className="flex justify-between items-end">
                                <div>
                                   <h3 className="text-xl font-black text-slate-800">{isSplitting ? (splitMode === 'value' ? 'Lançar Valor Manual' : 'Pagar Itens Selecionados') : 'Pagamento Único'}</h3>
                                   <p className="text-[10px] font-black uppercase text-indigo-600 tracking-widest">Etapa final do despacho</p>
                                </div>
                                {splitMode && <button onClick={() => setSplitMode(null)} className="text-xs font-bold text-slate-400 hover:text-indigo-600">Alterar Modo</button>}
                             </div>

                             <div className="bg-slate-50/50 p-6 rounded-[2.5rem] border border-slate-100">
                                {splitMode === 'value' && (
                                   <div className="space-y-4">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Informe o Valor</label>
                                      <div className="relative">
                                         <span className="absolute left-6 top-1/2 -translate-y-1/2 text-3xl font-black text-slate-300">R$</span>
                                         <input 
                                          type="number" 
                                          className="w-full pl-20 pr-8 py-6 bg-white border-2 border-indigo-100 rounded-[2rem] text-4xl font-black text-indigo-600 focus:border-indigo-500 outline-none transition-all" 
                                          value={customSplitValue}
                                          onChange={(e) => setCustomSplitValue(e.target.value)}
                                          placeholder={remainingBalance.toFixed(2)}
                                          autoFocus
                                         />
                                      </div>
                                   </div>
                                )}

                                {splitMode === 'items' && (
                                   <div className="space-y-4">
                                      <div className="flex justify-between items-center px-1">
                                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Marque os Itens</label>
                                         <p className="text-xs font-black text-indigo-600">Subtotal: R$ {selectedSplitItems.reduce((acc, idx) => acc + (selectedTable.items[idx].price * selectedTable.items[idx].quantity), 0).toFixed(2)}</p>
                                      </div>
                                      <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar pr-2">
                                         {selectedTable.items.map((item, idx) => (
                                            <button key={idx} onClick={() => toggleSplitItem(idx)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedSplitItems.includes(idx) ? 'border-indigo-600 bg-indigo-50' : 'bg-white border-slate-50'}`}>
                                               <div className="flex items-center gap-3">
                                                  <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-all ${selectedSplitItems.includes(idx) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-200'}`}>{selectedSplitItems.includes(idx) && <Check size={14} strokeWidth={4} />}</div>
                                                  <div className="text-left"><p className="text-xs font-black text-slate-700">{item.name}</p><p className="text-[10px] font-bold text-slate-400">{item.quantity}x R$ {item.price.toFixed(2)}</p></div>
                                               </div>
                                               <p className="font-black text-slate-800 text-sm">R$ {(item.price * item.quantity).toFixed(2)}</p>
                                            </button>
                                         ))}
                                      </div>
                                   </div>
                                )}

                                {!isSplitting && (
                                   <div className="text-center py-6">
                                      <p className="text-sm font-bold text-slate-500">Deseja realizar o pagamento total da conta agora?</p>
                                   </div>
                                )}
                             </div>

                             <div className="space-y-4 flex-1">
                                <p className="text-xs font-black uppercase text-slate-400 ml-2 tracking-widest">Selecione o Método para esta {isSplitting ? 'parte' : 'conta'}</p>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                  {[
                                    { id: 'dinheiro', label: 'Dinheiro', icon: Banknote, color: 'text-emerald-500' },
                                    { id: 'pix', label: 'PIX', icon: Smartphone, color: 'text-indigo-500' },
                                    { id: 'cartao_credito', label: 'Cartão', icon: CreditCard, color: 'text-blue-600' },
                                    { id: 'conta_cliente', label: 'Fiado', icon: UserCircle, color: 'text-rose-500' },
                                  ].map(method => (
                                    <button key={method.id} disabled={isProcessing || (splitMode === 'items' && selectedSplitItems.length === 0)} onClick={() => handleProcessPayment(method.id as PaymentMethod)} className="p-6 rounded-[2rem] border-2 border-slate-100 bg-white hover:border-indigo-500 hover:shadow-md transition-all text-center flex flex-col items-center gap-3 group active:scale-95 disabled:opacity-30 disabled:grayscale">
                                      <div className={`p-4 bg-slate-50 shadow-sm border rounded-2xl w-fit ${method.color} group-hover:scale-110 transition-transform`}><method.icon size={28} /></div>
                                      <p className="font-black text-slate-800 text-xs uppercase tracking-tighter">{method.label}</p>
                                    </button>
                                  ))}
                                </div>
                             </div>
                          </div>
                       )}
                    </div>
                  ) : (
                    <div className="animate-in slide-in-from-right-10 duration-300">
                       <div className="p-8 border-b bg-rose-600 text-white flex justify-between items-center rounded-t-3xl"><div className="flex items-center gap-4"><div className="bg-white/20 p-3 rounded-2xl"><UserCircle size={24} /></div><div><h2 className="text-xl font-black">Selecionar Cliente</h2><p className="text-xs font-bold uppercase opacity-80">Lançamento em Conta Fiado</p></div></div><button onClick={() => setShowCustomerSelection(false)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button></div>
                       <div className="p-8 space-y-6">
                          <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Nome do cliente..." className="w-full pl-12 pr-6 py-4 bg-slate-50 border rounded-2xl font-bold outline-none" value={customerSearch} onChange={(e)=>setCustomerSearch(e.target.value)} /></div>
                          <div className="max-h-[300px] overflow-y-auto space-y-2 custom-scrollbar">
                             {filteredCustomerList.map(c => (
                                <button key={c.id} onClick={() => setSelectedCustomerId(c.id)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedCustomerId === c.id ? 'border-rose-600 bg-rose-50' : 'border-slate-50 bg-white hover:border-slate-200'}`}>
                                   <div className="text-left"><p className="font-black text-slate-800">{c.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{c.document}</p></div>
                                   {selectedCustomerId === c.id && <CheckCircle2 size={24} className="text-rose-600" />}
                                </button>
                             ))}
                          </div>
                       </div>
                       <div className="p-8 border-t bg-slate-50 flex gap-4"><button onClick={() => setShowCustomerSelection(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Voltar</button><button onClick={finishFiadoPayment} disabled={!selectedCustomerId || isProcessing} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-50">Lançar Fiado (R$ {remainingBalance.toFixed(2)})</button></div>
                    </div>
                  )}
               </div>
            </div>

            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-md flex flex-col items-center justify-center gap-6 z-[70] animate-in fade-in"><div className="w-24 h-24 border-t-4 border-indigo-600 rounded-full animate-spin"></div><p className="text-xl font-black text-slate-800">Processando Pagamento...</p></div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Tables;

import React, { useState, useMemo } from 'react';
import { Order, Courier, FinancialRecord } from '../types';
import { 
  Navigation, CheckCircle2, 
  User as UserIcon, Phone, MapPin, Package,
  ChevronRight, Bike, X, UserCheck, 
  TrendingUp, Settings, Plus,
  Save, UserPlus, Wallet, ArrowRightLeft,
  Banknote, QrCode, ClipboardList, Timer, Clock,
  Coins, CreditCard, DollarSign, Calculator, AlertTriangle, Edit3,
  Search, Filter
} from 'lucide-react';

interface DeliveryProps {
  orders: Order[];
  couriers: Courier[];
  deliveryFee: number;
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onAssignCourier: (orderId: string, courierId: string) => void;
  onAddCourier: (courier: Partial<Courier>) => void;
  onUpdateCourier: (id: string, updates: Partial<Courier>) => void;
  onUpdateDeliveryFee: (fee: number) => void;
  onAddFinancialRecord: (record: Partial<FinancialRecord>) => void;
}

const Delivery: React.FC<DeliveryProps> = ({ 
  orders, 
  couriers, 
  deliveryFee,
  onUpdateStatus, 
  onAssignCourier,
  onAddCourier,
  onUpdateCourier,
  onUpdateDeliveryFee,
  onAddFinancialRecord
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'monitor' | 'couriers' | 'settlement' | 'settings'>('monitor');
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [showAddCourierModal, setShowAddCourierModal] = useState(false);
  const [showSettlementModal, setShowSettlementModal] = useState<any | null>(null);
  const [editingCourier, setEditingCourier] = useState<Courier | null>(null);

  // States para filtros do monitor
  const [monitorSearch, setMonitorSearch] = useState('');
  const [monitorStatusFilter, setMonitorStatusFilter] = useState<'ready' | 'preparing' | 'all'>('ready');

  // Settlement Multimeios
  const [settlementPayments, setSettlementPayments] = useState<{ [key: string]: number }>({
    dinheiro: 0,
    pix: 0,
    cartao: 0
  });

  // Courier Form
  const [newCourierName, setNewCourierName] = useState('');
  const [newCourierPhone, setNewCourierPhone] = useState('');
  const [newCourierPix, setNewCourierPix] = useState('');
  const [newCourierDailyFee, setNewCourierDailyFee] = useState('0');
  const [newCourierVehicle, setNewCourierVehicle] = useState<'moto' | 'bike' | 'car'>('moto');

  const deliveryOrders = useMemo(() => orders.filter(o => o.type === 'delivery'), [orders]);

  // Filtro dinâmico para a coluna de despacho
  const filteredDispatchOrders = useMemo(() => {
    return deliveryOrders.filter(o => {
      const matchesStatus = monitorStatusFilter === 'all' 
        ? ['preparing', 'ready'].includes(o.status) 
        : o.status === monitorStatusFilter;

      const matchesSearch = 
        o.id.toLowerCase().includes(monitorSearch.toLowerCase()) ||
        (o.customerName || '').toLowerCase().includes(monitorSearch.toLowerCase()) ||
        (o.customerAddress || '').toLowerCase().includes(monitorSearch.toLowerCase());

      return matchesStatus && matchesSearch;
    });
  }, [deliveryOrders, monitorStatusFilter, monitorSearch]);

  // Cálculo de acerto de contas por motoboy
  const courierSettlementData = useMemo(() => {
    return couriers.map(courier => {
      const courierOrders = deliveryOrders.filter(o => o.courierId === courier.id && o.status === 'delivered');
      const totalFees = courierOrders.reduce((acc, o) => acc + (o.deliveryFee || 0), 0);
      const cashCollected = courierOrders.filter(o => o.paymentMethod === 'dinheiro').reduce((acc, o) => acc + o.total, 0);
      const dailyFee = courier.dailyFee || 0;

      return {
        courier,
        orderCount: courierOrders.length,
        totalFees, 
        cashCollected,
        dailyFee,
        balance: (totalFees + dailyFee) - cashCollected
      };
    });
  }, [couriers, deliveryOrders]);

  const handleEditCourier = (courier: Courier) => {
    setEditingCourier(courier);
    setNewCourierName(courier.name);
    setNewCourierPhone(courier.phone);
    setNewCourierPix(courier.pixKey || '');
    setNewCourierDailyFee(courier.dailyFee?.toString() || '0');
    setNewCourierVehicle(courier.vehicleType || 'moto');
    setShowAddCourierModal(true);
  };

  const handleSaveCourier = () => {
    if (!newCourierName || !newCourierPhone) return;

    const courierData = { 
      name: newCourierName, 
      phone: newCourierPhone, 
      pixKey: newCourierPix,
      dailyFee: parseFloat(newCourierDailyFee) || 0,
      vehicleType: newCourierVehicle 
    };

    if (editingCourier) {
      onUpdateCourier(editingCourier.id, courierData);
    } else {
      onAddCourier(courierData);
    }

    resetCourierForm();
    setShowAddCourierModal(false);
  };

  const resetCourierForm = () => {
    setNewCourierName('');
    setNewCourierPhone('');
    setNewCourierPix('');
    setNewCourierDailyFee('0');
    setNewCourierVehicle('moto');
    setEditingCourier(null);
  };

  const openSettlement = (data: any) => {
    setShowSettlementModal(data);
    setSettlementPayments({
      dinheiro: data.balance > 0 ? data.balance : 0,
      pix: 0,
      cartao: 0
    });
  };

  const handleRealizeSettlement = () => {
    if (!showSettlementModal) return;
    const { courier, balance, totalFees, dailyFee, cashCollected } = showSettlementModal;

    const totalSelected = (Object.values(settlementPayments) as number[]).reduce((a, b) => a + b, 0);

    if (Math.abs(totalSelected - Math.abs(balance)) > 0.01) {
      alert("A soma dos valores informados não confere com o saldo do acerto!");
      return;
    }

    Object.entries(settlementPayments).forEach(([method, amount]) => {
      if ((amount as number) > 0) {
        onAddFinancialRecord({
          type: balance >= 0 ? 'expense' : 'income',
          amount: amount as number,
          category: 'Acerto Motoboy',
          description: `Acerto com ${courier.name} (${method.toUpperCase()}). Taxas: R$${totalFees.toFixed(2)} | Diária: R$${dailyFee.toFixed(2)} | Dinheiro rua: R$${cashCollected.toFixed(2)}`,
          date: new Date()
        });
      }
    });

    alert(`Acerto de ${courier.name} finalizado com sucesso via multimeios!`);
    setShowSettlementModal(null);
  };

  const totalSettlementInput = (Object.values(settlementPayments) as number[]).reduce((a, b) => a + b, 0);
  const remainingSettlement = showSettlementModal ? Math.abs(showSettlementModal.balance) - totalSettlementInput : 0;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navegação Secundária */}
      <div className="flex bg-white p-1 rounded-2xl border shadow-sm w-fit">
        {[
          { id: 'monitor', label: 'Monitor Despacho', icon: Navigation },
          { id: 'couriers', label: 'Equipe de Motoboys', icon: UserCheck },
          { id: 'settlement', label: 'Acertos Financeiros', icon: Wallet },
          { id: 'settings', label: 'Configurações', icon: Settings }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'monitor' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Coluna de Despacho com Filtros */}
          <div className="lg:col-span-5 space-y-6">
            <div className="space-y-4">
              <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2">
                <Package size={16} /> Aguardando Envio ({filteredDispatchOrders.length})
              </h3>

              <div className="bg-white p-4 rounded-[2rem] border shadow-sm space-y-3">
                 <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                       type="text" 
                       placeholder="Buscar por cliente ou endereço..."
                       className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold outline-none focus:border-indigo-500 transition-all"
                       value={monitorSearch}
                       onChange={(e) => setMonitorSearch(e.target.value)}
                    />
                 </div>
                 <div className="flex gap-2">
                    {(['ready', 'preparing', 'all'] as const).map(status => (
                       <button
                          key={status}
                          onClick={() => setMonitorStatusFilter(status)}
                          className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest border transition-all ${monitorStatusFilter === status ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}
                       >
                          {status === 'ready' ? 'Prontos' : status === 'preparing' ? 'Em Preparo' : 'Todos'}
                       </button>
                    ))}
                 </div>
              </div>
            </div>

            <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredDispatchOrders.map(order => (
                <div key={order.id} className={`bg-white p-6 rounded-[2.5rem] border-2 shadow-sm space-y-4 hover:border-indigo-200 transition-colors ${order.status === 'ready' ? 'border-amber-100' : 'border-slate-50 opacity-80'}`}>
                  <div className="flex justify-between items-start">
                    <div>
                      <div className="flex items-center gap-2">
                         <h4 className="text-xl font-black text-slate-800">#{order.id.slice(-4)}</h4>
                         <span className={`px-2 py-0.5 rounded-full text-[8px] font-black uppercase ${order.status === 'ready' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-50 text-indigo-500'}`}>
                            {order.status === 'ready' ? 'Pronto' : 'Cozinha'}
                         </span>
                      </div>
                      <p className="text-[9px] font-black uppercase text-slate-400 flex items-center gap-1 mt-1">
                         <Clock size={12} /> {Math.floor((Date.now() - new Date(order.createdAt).getTime()) / 60000)}m desde o pedido
                      </p>
                    </div>
                    <p className="text-lg font-black text-indigo-600">R$ {order.total.toFixed(2)}</p>
                  </div>

                  <div className="space-y-1">
                     <p className="text-xs font-black text-slate-700 uppercase">{order.customerName}</p>
                     <div className="flex items-start gap-2 text-[11px] font-medium text-slate-500 bg-slate-50 p-3 rounded-2xl border">
                        <MapPin size={14} className="text-rose-500 shrink-0 mt-0.5" />
                        <span className="line-clamp-2 leading-relaxed">{order.customerAddress}</span>
                     </div>
                  </div>

                  <button 
                    disabled={order.status !== 'ready'}
                    onClick={() => setSelectedOrderId(order.id)} 
                    className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-lg disabled:opacity-30 disabled:grayscale transition-all"
                  >
                     {order.status === 'ready' ? 'Atribuir Entregador' : 'Aguardando Cozinha'}
                  </button>
                </div>
              ))}

              {filteredDispatchOrders.length === 0 && (
                 <div className="h-full flex flex-col items-center justify-center text-center opacity-20 grayscale">
                    <Package size={64} strokeWidth={1} />
                    <p className="font-black uppercase tracking-widest mt-4">Nenhum pedido encontrado</p>
                 </div>
              )}
            </div>
          </div>

          <div className="lg:col-span-7 space-y-6">
            <h3 className="text-sm font-black uppercase text-slate-400 flex items-center gap-2"><Bike size={16} className="text-indigo-600" /> Motoboys em Atividade</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               {courierSettlementData.filter(c => c.courier.status !== 'offline').map(data => (
                  <div key={data.courier.id} className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden flex flex-col">
                     <div className="p-6 border-b flex justify-between items-center bg-slate-50/50">
                        <div className="flex items-center gap-4">
                           <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center font-black">{data.courier.name.charAt(0)}</div>
                           <div>
                              <p className="font-black text-slate-800">{data.courier.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{data.courier.vehicleType}</p>
                           </div>
                        </div>
                        <div className="text-right">
                           <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${data.courier.status === 'delivering' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {data.courier.status === 'delivering' ? 'Em Rota' : 'Livre'}
                           </span>
                        </div>
                     </div>
                     <div className="p-6 bg-indigo-50/30 flex justify-between items-center mx-4 my-2 rounded-2xl border border-indigo-100">
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Diária Fixa</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.dailyFee.toFixed(2)}</p>
                        </div>
                        <div className="h-6 w-px bg-indigo-100"></div>
                        <div className="text-center flex-1">
                           <p className="text-[8px] font-black uppercase text-indigo-400">Taxas Acumuladas</p>
                           <p className="text-xs font-black text-indigo-700">R$ {data.totalFees.toFixed(2)}</p>
                        </div>
                     </div>
                     <div className="flex-1 p-6 space-y-3">
                        {deliveryOrders.filter(o => o.courierId === data.courier.id && o.status === 'delivering').map(order => (
                           <div key={order.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl shadow-sm">
                              <div className="flex items-center gap-3">
                                 <div className="w-8 h-8 bg-indigo-600 text-white rounded-lg flex items-center justify-center text-[10px] font-black">#{order.id.slice(-4)}</div>
                                 <p className="text-[10px] font-black text-slate-700 uppercase">{order.customerName?.split(' ')[0]}</p>
                              </div>
                              <button onClick={() => onUpdateStatus(order.id, 'delivered')} className="p-2 bg-emerald-500 text-white rounded-xl hover:bg-emerald-600 shadow-lg shadow-emerald-100"><CheckCircle2 size={16} /></button>
                           </div>
                        ))}
                        {deliveryOrders.filter(o => o.courierId === data.courier.id && o.status === 'delivering').length === 0 && (
                           <div className="py-8 text-center opacity-20 text-[10px] font-black uppercase tracking-widest">Sem entregas em curso</div>
                        )}
                     </div>
                  </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {activeSubTab === 'couriers' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-slate-800">Equipe de Entrega</h3>
             <button onClick={() => { resetCourierForm(); setShowAddCourierModal(true); }} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-indigo-100"><Plus size={18} /> Cadastrar Entregador</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {couriers.map(courier => (
              <div key={courier.id} className="bg-white p-8 rounded-[3rem] border shadow-sm space-y-6 group hover:shadow-xl transition-all">
                <div className="flex items-center gap-4">
                   <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-[1.5rem] flex items-center justify-center font-black text-xl">{courier.name.charAt(0)}</div>
                   <div>
                     <h4 className="font-black text-slate-800">{courier.name}</h4>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">R$ {(courier.dailyFee || 0).toFixed(2)} diária • {courier.vehicleType}</p>
                   </div>
                </div>
                <div className="space-y-4">
                   <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl"><Phone size={16} className="text-slate-400" /><span className="text-xs font-bold">{courier.phone}</span></div>
                   <div className="flex items-center gap-3 p-4 bg-indigo-50 rounded-2xl border border-indigo-100"><QrCode size={16} className="text-indigo-600" /><div className="flex-1 overflow-hidden"><p className="text-[9px] font-black text-indigo-400 uppercase">PIX</p><p className="text-xs font-bold text-indigo-700 truncate">{courier.pixKey || 'Não cadastrado'}</p></div></div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleEditCourier(courier)} 
                    className="flex-1 py-3 bg-indigo-50 text-indigo-600 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-100 transition-colors flex items-center justify-center gap-2"
                  >
                    <Edit3 size={14} /> Editar
                  </button>
                  <button className="flex-1 py-3 border text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest">Inativar</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'settlement' && (
        <div className="space-y-8 animate-in slide-in-from-right-4">
           <div className="bg-indigo-600 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-xl shadow-indigo-100">
              <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter">Acerto Financeiro</h2><p className="text-indigo-100 font-medium">Concilie taxas, diárias e dinheiro recebido em mãos.</p></div>
              <ArrowRightLeft size={64} className="opacity-20" />
           </div>
           <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b"><tr><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase">Entregador</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Diária</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Taxas</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Dinheiro em Mão</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-right">Saldo Final</th><th className="px-10 py-6 font-black text-slate-400 text-[10px] uppercase text-center">Ações</th></tr></thead>
                 <tbody className="divide-y">
                    {courierSettlementData.map((data, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                          <td className="px-10 py-8 font-black text-slate-800">{data.courier.name}</td>
                          <td className="px-10 py-8 text-right font-black text-indigo-400">R$ {data.dailyFee.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-emerald-600">R$ {data.totalFees.toFixed(2)}</td>
                          <td className="px-10 py-8 text-right font-black text-rose-600">R$ {data.cashCollected.toFixed(2)}</td>
                          <td className={`px-10 py-8 text-right font-black ${data.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(data.balance).toFixed(2)}</td>
                          <td className="px-10 py-8 text-center"><button onClick={() => openSettlement(data)} disabled={data.orderCount === 0 && data.dailyFee === 0} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest disabled:opacity-30 shadow-lg shadow-indigo-100">Realizar Acerto</button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal de Seleção de Motoboy (Despacho) */}
      {selectedOrderId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center"><div><h2 className="text-xl font-black text-slate-800">Despachar Pedido</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Pedido #{selectedOrderId.slice(-4)}</p></div><button onClick={() => setSelectedOrderId(null)} className="p-2 hover:bg-white rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-3">
              {couriers.filter(c => c.status !== 'offline').map(courier => {
                const active = orders.filter(o => o.courierId === courier.id && o.status === 'delivering').length;
                return (
                   <button key={courier.id} onClick={() => { onAssignCourier(selectedOrderId, courier.id); setSelectedOrderId(null); }} className="w-full flex items-center justify-between p-5 rounded-2xl border-2 border-slate-50 hover:border-indigo-600 hover:bg-indigo-50 transition-all text-left group">
                     <div className="flex items-center gap-4">
                        <div className="p-3 bg-white shadow-sm border rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><Bike size={24} /></div>
                        <div><p className="font-black text-slate-800">{courier.name}</p><p className="text-[9px] font-black uppercase text-slate-400">{active > 0 ? `${active} entregas ativas` : 'Livre'}</p></div>
                     </div>
                     <ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600" />
                   </button>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Modal: Cadastro / Edição Entregador */}
      {showAddCourierModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b bg-indigo-50/30 flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg">
                  {editingCourier ? <Edit3 size={24} /> : <UserPlus size={24} />}
                </div>
                <div>
                  <h2 className="text-xl font-black">{editingCourier ? 'Editar Entregador' : 'Novo Entregador'}</h2>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{editingCourier ? 'Atualize os dados de perfil e pagamento' : 'Adicione um novo membro à frota'}</p>
                </div>
              </div>
              <button onClick={() => setShowAddCourierModal(false)} className="p-2 hover:bg-white rounded-full transition-colors"><X size={24} className="text-slate-400" /></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:border-indigo-500 transition-all" value={newCourierName} onChange={(e)=>setNewCourierName(e.target.value)} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp</label>
                    <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:border-indigo-500 transition-all" value={newCourierPhone} onChange={(e)=>setNewCourierPhone(e.target.value)} />
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Diária (R$)</label>
                    <input type="number" className="w-full px-5 py-4 bg-slate-50 border-2 border-indigo-100 rounded-2xl font-black text-indigo-600 outline-none focus:border-indigo-500 transition-all" value={newCourierDailyFee} onChange={(e)=>setNewCourierDailyFee(e.target.value)} />
                 </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave PIX</label>
                <input type="text" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold outline-none focus:border-indigo-500 transition-all" value={newCourierPix} onChange={(e)=>setNewCourierPix(e.target.value)} />
              </div>
              <div className="grid grid-cols-3 gap-2">
                {(['moto', 'bike', 'car'] as const).map(v => (
                  <button key={v} onClick={() => setNewCourierVehicle(v)} className={`py-3 rounded-xl border-2 font-black text-[10px] uppercase transition-all ${newCourierVehicle === v ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>
                    {v}
                  </button>
                ))}
              </div>
            </div>
            <div className="p-8 border-t bg-slate-50 flex gap-4">
              <button onClick={() => setShowAddCourierModal(false)} className="flex-1 py-4 font-black text-slate-400 uppercase text-[10px]">Cancelar</button>
              <button onClick={handleSaveCourier} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-[10px] shadow-xl hover:bg-indigo-700 transition-all">
                {editingCourier ? 'Salvar Alterações' : 'Cadastrar'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* NOVO Modal: Acerto Financeiro Multimeios */}
      {showSettlementModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b bg-indigo-600 text-white flex justify-between items-center">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-white/20 rounded-2xl shadow-inner"><Wallet size={24} /></div>
                    <div>
                       <h2 className="text-xl font-black">Acerto: {showSettlementModal.courier.name}</h2>
                       <p className="text-[10px] font-bold uppercase tracking-widest opacity-80">Conciliação Multimeios</p>
                    </div>
                 </div>
                 <button onClick={() => setShowSettlementModal(null)} className="p-2 hover:bg-white/20 rounded-full"><X size={24} /></button>
              </div>

              <div className="p-8 flex flex-col lg:flex-row gap-8">
                 {/* Resumo Esquerda */}
                 <div className="flex-1 space-y-4">
                    <div className="bg-slate-50 p-6 rounded-[2rem] border space-y-4">
                       <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Resumo do Período</p>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Diária</span><span>+ R$ {showSettlementModal.dailyFee.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Taxas</span><span>+ R$ {showSettlementModal.totalFees.toFixed(2)}</span></div>
                       <div className="flex justify-between items-center text-sm font-bold text-slate-600"><span>Dinheiro rua</span><span className="text-rose-500">- R$ {showSettlementModal.cashCollected.toFixed(2)}</span></div>
                       <div className="pt-4 border-t flex justify-between items-center">
                          <span className="font-black text-slate-800">Saldo Final</span>
                          <span className={`text-2xl font-black ${showSettlementModal.balance >= 0 ? 'text-indigo-600' : 'text-rose-600'}`}>R$ {Math.abs(showSettlementModal.balance).toFixed(2)}</span>
                       </div>
                    </div>
                    {showSettlementModal.balance < 0 && (
                       <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl flex gap-3 text-rose-700">
                          <AlertTriangle size={20} className="shrink-0" />
                          <p className="text-[10px] font-bold leading-tight uppercase">O motoboy possui mais dinheiro em espécie do que tem a receber. Ele deve devolver a diferença.</p>
                       </div>
                    )}
                 </div>

                 {/* Checkout Direita */}
                 <div className="flex-1 space-y-4">
                    <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Como o acerto será pago?</p>
                    <div className="space-y-3">
                       {[
                         { id: 'dinheiro', label: 'Dinheiro', icon: Banknote },
                         { id: 'pix', label: 'PIX', icon: QrCode },
                         { id: 'cartao', label: 'Cartão / Depósito', icon: CreditCard }
                       ].map(m => (
                          <div key={m.id} className="relative group">
                             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><m.icon size={18} /></div>
                             <input 
                               type="number" 
                               placeholder={m.label}
                               className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black outline-none focus:border-indigo-500 transition-all"
                               value={settlementPayments[m.id] || ''}
                               onChange={(e) => setSettlementPayments({...settlementPayments, [m.id]: parseFloat(e.target.value) || 0})}
                             />
                          </div>
                       ))}
                    </div>

                    <div className="p-6 bg-indigo-50 rounded-[2rem] space-y-2 border border-indigo-100">
                       <div className="flex justify-between items-center text-[10px] font-black uppercase text-indigo-400"><span>Restante</span><span>Status</span></div>
                       <div className="flex justify-between items-center">
                          <span className={`text-xl font-black ${remainingSettlement === 0 ? 'text-emerald-500' : 'text-indigo-600'}`}>R$ {remainingSettlement.toFixed(2)}</span>
                          <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${remainingSettlement === 0 ? 'bg-emerald-500 text-white' : 'bg-indigo-200 text-indigo-700'}`}>
                             {remainingSettlement === 0 ? 'Conferido' : 'Pendente'}
                          </span>
                       </div>
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t bg-slate-50 flex gap-4">
                 <button onClick={() => setShowSettlementModal(null)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                 <button 
                  onClick={handleRealizeSettlement} 
                  disabled={remainingSettlement !== 0}
                  className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl disabled:opacity-30 disabled:grayscale transition-all"
                 >
                    Confirmar e Gerar Lançamentos
                 </button>
              </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Delivery;
